// =============================================
// LOCAL NOTIFICATIONS - Native Push via Capacitor
// =============================================
var _notifId = 1;

function sendLocalNotification(title, body) {
  // Quiet Hours prüfen (Kunden-App)
  var settings = JSON.parse(localStorage.getItem('suppTreeNotificationSettings') || '{}');
  if (settings.quietHours) {
    var now = new Date();
    var h = now.getHours() * 60 + now.getMinutes();
    var qs = (settings.quietStart || '22:00').split(':');
    var qe = (settings.quietEnd || '07:00').split(':');
    var start = parseInt(qs[0]) * 60 + parseInt(qs[1]);
    var end = parseInt(qe[0]) * 60 + parseInt(qe[1]);
    if (start > end ? (h >= start || h < end) : (h >= start && h < end)) return;
  }

  if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.LocalNotifications) {
    window.Capacitor.Plugins.LocalNotifications.schedule({
      notifications: [{
        title: title,
        body: body,
        id: _notifId++,
        schedule: { at: new Date(Date.now() + 100) },
        sound: null,
        smallIcon: 'ic_stat_icon_config_sample',
        iconColor: '#00A67E'
      }]
    });
  }
}

// =============================================
// CAPACITOR STATUS BAR - System UI sichtbar machen
// =============================================
document.addEventListener('DOMContentLoaded', function() {
  if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.StatusBar) {
    const { StatusBar } = window.Capacitor.Plugins;
    // Status Bar nicht über WebView legen
    StatusBar.setOverlaysWebView({ overlay: false });
    // Status Bar anzeigen
    StatusBar.show();
    // Hintergrundfarbe setzen (grün passend zur App)
    StatusBar.setBackgroundColor({ color: '#2E7D32' });
    // Dunkle Icons für hellen Hintergrund
    StatusBar.setStyle({ style: 'DARK' });
    console.log('✅ Status Bar konfiguriert');
  }
  
  // Local Notifications Permission
  if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.LocalNotifications) {
    window.Capacitor.Plugins.LocalNotifications.requestPermissions();
    console.log('✅ Local Notifications Permission angefordert');
  }

  // Navigation Bar (unten) sichtbar machen
  if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.NavigationBar) {
    const { NavigationBar } = window.Capacitor.Plugins;
    NavigationBar.show();
    console.log('✅ Navigation Bar konfiguriert');
  }

  // Android Back Button Handler - mit verzögerter Initialisierung
  // Android Back Button Handler
  if (window.Capacitor && window.Capacitor.Plugins && window.Capacitor.Plugins.App) {
    const { App } = window.Capacitor.Plugins;
    App.addListener('backButton', ({ canGoBack }) => {
      console.log('🔙 Back Button gedrückt');
      
      // Benutze die handleAndroidBack Funktion für komplette Logik
      if (typeof handleAndroidBack === 'function') {
        const handled = handleAndroidBack();
        console.log('🔙 Handled:', handled);
        
        // Wenn nicht handled (auf Home Screen), App minimieren
        if (!handled) {
          App.minimizeApp();
        }
      } else {
        // Fallback wenn handleAndroidBack noch nicht definiert ist
        console.log('🔙 Fallback - handleAndroidBack nicht gefunden');
        const currentScreen = document.querySelector('.screen.active');
        if (currentScreen && currentScreen.id === 'homeScreen') {
          App.minimizeApp();
        } else {
          switchScreen('homeScreen');
        }
      }
    });
    console.log('✅ Back Button Handler konfiguriert (Capacitor App Plugin)');
  } else {
    console.log('⚠️ Capacitor App Plugin nicht verfügbar - Back Button funktioniert nicht');
    console.log('💡 Tipp: npm install @capacitor/app && npx cap sync');
  }
  
  // Alternative: History API für Web-ähnliches Back-Verhalten
  window.addEventListener('popstate', function(e) {
    console.log('🔙 Popstate Event');
    if (typeof handleAndroidBack === 'function') {
      handleAndroidBack();
    }
  });
  
  // =============================================
  // SWIPE GESTURE NAVIGATION (für Handys ohne Back-Button)
  // =============================================
  let swipeStartX = 0;
  let swipeStartY = 0;
  let swipeStartTime = 0;
  let isEdgeSwipe = false;
  let isRightEdgeSwipe = false;
  const SWIPE_THRESHOLD = 80; // Mindestens 80px swipe
  const SWIPE_EDGE_WIDTH = 40; // Edge-Swipe nur von den ersten/letzten 40px
  const SWIPE_TIME_LIMIT = 400; // Max 400ms für Swipe
  const SWIPE_VERTICAL_LIMIT = 100; // Max vertikale Bewegung
  
  // Haupt-Screens für Navigation
  const mainScreens = ['homeScreen', 'productsScreen', 'meinScreen', 'einkaufScreen'];
  
  const swipeIndicator = document.getElementById('swipeBackIndicator');
  
  // Forward-Indikator erstellen
  let swipeForwardIndicator = document.getElementById('swipeForwardIndicator');
  if (!swipeForwardIndicator) {
    swipeForwardIndicator = document.createElement('div');
    swipeForwardIndicator.id = 'swipeForwardIndicator';
    swipeForwardIndicator.className = 'swipe-forward-indicator';
    document.body.appendChild(swipeForwardIndicator);
  }
  
  document.addEventListener('touchstart', function(e) {
    const touch = e.touches[0];
    const screenWidth = window.innerWidth;
    swipeStartX = touch.clientX;
    swipeStartY = touch.clientY;
    swipeStartTime = Date.now();
    
    // Prüfe ob es ein Edge-Swipe ist (links oder rechts)
    isEdgeSwipe = swipeStartX <= SWIPE_EDGE_WIDTH;
    isRightEdgeSwipe = swipeStartX >= screenWidth - SWIPE_EDGE_WIDTH;
    
    // Prüfe aktuellen Status
    const currentScreen = document.querySelector('.screen.active');
    const currentScreenId = currentScreen ? currentScreen.id : 'homeScreen';
    const hasOpenOverlay = document.querySelector('.overlay.visible, .overlay.active, .bottom-sheet.visible, .bottom-sheet.active');
    const currentIndex = mainScreens.indexOf(currentScreenId);
    
    // Zeige Back-Indikator wenn Links-Edge-Swipe
    if (isEdgeSwipe && (currentScreenId !== 'homeScreen' || hasOpenOverlay) && swipeIndicator) {
      swipeIndicator.style.opacity = '0.5';
    }
    
    // Zeige Forward-Indikator wenn Rechts-Edge-Swipe (nur auf Haupt-Screens, nicht letzter)
    if (isRightEdgeSwipe && !hasOpenOverlay && currentIndex !== -1 && currentIndex < mainScreens.length - 1 && swipeForwardIndicator) {
      swipeForwardIndicator.style.opacity = '0.5';
    }
  }, { passive: true });
  
  document.addEventListener('touchmove', function(e) {
    const touch = e.touches[0];
    const diffX = touch.clientX - swipeStartX;
    const diffY = Math.abs(touch.clientY - swipeStartY);
    
    // Abbrechen wenn zu viel vertikal
    if (diffY > SWIPE_VERTICAL_LIMIT) {
      isEdgeSwipe = false;
      isRightEdgeSwipe = false;
      if (swipeIndicator) {
        swipeIndicator.classList.remove('active');
        swipeIndicator.style.opacity = '0';
      }
      if (swipeForwardIndicator) {
        swipeForwardIndicator.classList.remove('active');
        swipeForwardIndicator.style.opacity = '0';
      }
      return;
    }
    
    // Back-Indikator Fortschritt (links nach rechts)
    if (isEdgeSwipe && swipeIndicator && diffX > 20) {
      const progress = Math.min(diffX / SWIPE_THRESHOLD, 1);
      swipeIndicator.style.opacity = (0.5 + progress * 0.5).toString();
      if (diffX > SWIPE_THRESHOLD * 0.7) {
        swipeIndicator.classList.add('active');
      }
    }
    
    // Forward-Indikator Fortschritt (rechts nach links)
    if (isRightEdgeSwipe && swipeForwardIndicator && diffX < -20) {
      const progress = Math.min(Math.abs(diffX) / SWIPE_THRESHOLD, 1);
      swipeForwardIndicator.style.opacity = (0.5 + progress * 0.5).toString();
      if (Math.abs(diffX) > SWIPE_THRESHOLD * 0.7) {
        swipeForwardIndicator.classList.add('active');
      }
    }
  }, { passive: true });
  
  document.addEventListener('touchend', function(e) {
    // Verstecke Indikatoren
    if (swipeIndicator) {
      swipeIndicator.classList.remove('active');
      swipeIndicator.style.opacity = '0';
    }
    if (swipeForwardIndicator) {
      swipeForwardIndicator.classList.remove('active');
      swipeForwardIndicator.style.opacity = '0';
    }
    
    const touch = e.changedTouches[0];
    const screenWidth = window.innerWidth;
    const swipeEndX = touch.clientX;
    const swipeEndY = touch.clientY;
    const swipeTime = Date.now() - swipeStartTime;
    
    const diffX = swipeEndX - swipeStartX;
    const diffY = Math.abs(swipeEndY - swipeStartY);
    
    // Prüfe ob es ein gültiger horizontaler Swipe ist
    if (swipeTime > SWIPE_TIME_LIMIT) {
      isEdgeSwipe = false;
      isRightEdgeSwipe = false;
      return;
    }
    if (diffY > SWIPE_VERTICAL_LIMIT) {
      isEdgeSwipe = false;
      isRightEdgeSwipe = false;
      return;
    }
    
    // Prüfe ob wir in einem horizontal scrollbaren Element sind
    const target = e.target;
    const isInHorizontalScroll = target.closest('.horizontal-scroll, .swiper, .carousel');
    
    // Edge Swipe von links nach rechts (ZURÜCK)
    if (isEdgeSwipe && diffX > SWIPE_THRESHOLD && !isInHorizontalScroll) {
      handleAndroidBack();
    }
    
    // Edge Swipe von rechts nach links (VORWÄRTS)
    if (isRightEdgeSwipe && diffX < -SWIPE_THRESHOLD && !isInHorizontalScroll) {
      handleSwipeForward();
    }
    
    isEdgeSwipe = false;
    isRightEdgeSwipe = false;
    
  }, { passive: true });
  
  document.addEventListener('touchcancel', function() {
    isEdgeSwipe = false;
    isRightEdgeSwipe = false;
    if (swipeIndicator) {
      swipeIndicator.classList.remove('active');
      swipeIndicator.style.opacity = '0';
    }
    if (swipeForwardIndicator) {
      swipeForwardIndicator.classList.remove('active');
      swipeForwardIndicator.style.opacity = '0';
    }
  }, { passive: true });
  
  console.log('✅ Swipe Gesture Navigation konfiguriert');
});

