function showCustomerAuth() {
  var el = document.getElementById('customerAuthOverlay');
  if (el) { el.classList.add('visible'); document.body.style.overflow = 'hidden'; }
}
function hideCustomerAuth() {
  var el = document.getElementById('customerAuthOverlay');
  if (el) { el.classList.remove('visible'); document.body.style.overflow = ''; }
}
function setCustomerAuthMode(mode) {
  var lf = document.getElementById('custLoginForm');
  var rf = document.getElementById('custRegisterForm');
  var sf = document.getElementById('custResetForm');
  if (lf) lf.classList.toggle('active', mode === 'login');
  if (rf) rf.classList.toggle('active', mode === 'register');
  if (sf) sf.classList.toggle('active', mode === 'reset');
  document.querySelectorAll('.ca-tab').forEach(function(t, i) {
    t.classList.toggle('active', (i === 0 && mode === 'login') || (i === 1 && mode === 'register'));
  });
  document.querySelectorAll('.ca-alert').forEach(function(a) { a.classList.remove('show'); });
}
function toggleCustomerPw(id, btn) {
  var el = document.getElementById(id);
  if (!el) return;
  el.type = el.type === 'password' ? 'text' : 'password';
  btn.textContent = el.type === 'password' ? '👁️' : '🙈';
}
function showCaAlert(id, msg) {
  var el = document.getElementById(id);
  if (el) { el.textContent = msg; el.classList.add('show'); }
}
function hideCaAlerts() {
  document.querySelectorAll('.ca-alert').forEach(function(a) { a.classList.remove('show'); a.textContent = ''; });
}
function setCaLoading(btn, on) {
  if (!btn) return;
  if (on) { btn.disabled = true; btn.dataset.text = btn.textContent; btn.innerHTML = '<span class="ca-spinner"></span>Bitte warten...'; }
  else { btn.disabled = false; btn.textContent = btn.dataset.text || 'Anmelden'; }
}

async function handleCustomerLogin() {
  hideCaAlerts();
  var emailEl = document.getElementById('caLoginEmail');
  var pwEl = document.getElementById('caLoginPassword');
  var email = emailEl ? emailEl.value.trim() : '';
  var pw = pwEl ? pwEl.value : '';
  var btn = document.getElementById('caLoginBtn');

  var hasErr = false;
  if (!email) { if (emailEl) emailEl.classList.add('ca-error'); hasErr = true; }
  if (!pw) { if (pwEl) pwEl.classList.add('ca-error'); hasErr = true; }
  if (hasErr) { showCaAlert('caLoginError', 'Bitte alle Felder ausfüllen'); return; }
  if (emailEl) emailEl.classList.remove('ca-error');
  if (pwEl) pwEl.classList.remove('ca-error');

  // Supabase nochmal initialisieren falls SDK erst nach DOMContentLoaded geladen wurde
  if (!supabase) {
    try { initSupabase(); } catch(e) {}
  }
  if (!supabase) {
    showCaAlert('caLoginError', 'Verbindung wird aufgebaut... bitte nochmal versuchen.');
    return;
  }

  setCaLoading(btn, true);
  var result = await signIn(email, pw);
  setCaLoading(btn, false);

  if (!result.success) {
    var msg = (result.error && result.error.message) || 'Ungültige Anmeldedaten';
    showCaAlert('caLoginError', msg);
    return;
  }

  // Erfolg — signIn setzt currentUser und ruft onAuthStateChange auf
  localStorage.setItem('suppTreeAppMode', 'production');
  hideCustomerAuth();
  hideMeinLoginHint();
}

async function handleCustomerRegister() {
  hideCaAlerts();
  var anredeEl = document.getElementById('caRegAnrede');
  var titelEl = document.getElementById('caRegTitel');
  var firstNameEl = document.getElementById('caRegFirstName');
  var lastNameEl = document.getElementById('caRegLastName');
  var emailEl = document.getElementById('caRegEmail');
  var pwEl = document.getElementById('caRegPassword');
  var pwcEl = document.getElementById('caRegPasswordConfirm');
  var anrede = anredeEl ? anredeEl.value : '';
  var titel = titelEl ? titelEl.value : '';
  var firstName = firstNameEl ? firstNameEl.value.trim() : '';
  var lastName = lastNameEl ? lastNameEl.value.trim() : '';
  var email = emailEl ? emailEl.value.trim() : '';
  var pw = pwEl ? pwEl.value : '';
  var pwc = pwcEl ? pwcEl.value : '';
  var btn = document.getElementById('caRegBtn');

  var hasErr = false;
  if (!anrede) { if (anredeEl) anredeEl.classList.add('ca-error'); hasErr = true; }
  if (!firstName) { if (firstNameEl) firstNameEl.classList.add('ca-error'); hasErr = true; }
  if (!lastName) { if (lastNameEl) lastNameEl.classList.add('ca-error'); hasErr = true; }
  if (!email) { if (emailEl) emailEl.classList.add('ca-error'); hasErr = true; }
  if (!pw) { if (pwEl) pwEl.classList.add('ca-error'); hasErr = true; }
  if (!pwc) { if (pwcEl) pwcEl.classList.add('ca-error'); hasErr = true; }
  if (hasErr) { showCaAlert('caRegError', 'Bitte alle Pflichtfelder ausfüllen'); return; }

  if (pw.length < 6) { showCaAlert('caRegError', 'Passwort muss mindestens 6 Zeichen haben'); return; }
  if (pw !== pwc) { showCaAlert('caRegError', 'Passwörter stimmen nicht überein'); return; }

  document.querySelectorAll('#custRegisterForm input, #custRegisterForm select').forEach(function(i) { i.classList.remove('ca-error'); });

  var name = [firstName, lastName].filter(Boolean).join(' ');
  var userData = { anrede: anrede, titel: titel, firstName: firstName, lastName: lastName };

  setCaLoading(btn, true);
  var result = await signUp(email, pw, name, userData);
  setCaLoading(btn, false);

  if (!result.success) {
    showCaAlert('caRegError', result.error?.message || 'Registrierung fehlgeschlagen');
    return;
  }

  // Erfolg
  if (result.data?.session) {
    showCaAlert('caRegSuccess', 'Konto erstellt! Du wirst weitergeleitet...');
    setTimeout(function() { hideCustomerAuth(); }, 1500);
    return;
  }

  showCaAlert('caRegSuccess', 'Konto erstellt! Bitte bestätige deine E-Mail und melde dich dann an.');
  setTimeout(function() { setCustomerAuthMode('login'); }, 3000);
}

async function handleCustomerReset() {
  hideCaAlerts();
  var emailEl = document.getElementById('caResetEmail');
  var email = emailEl ? emailEl.value.trim() : '';
  if (!email) { if (emailEl) emailEl.classList.add('ca-error'); showCaAlert('caResetError', 'Bitte E-Mail eingeben'); return; }
  if (emailEl) emailEl.classList.remove('ca-error');

  var result = await resetPassword(email);
  if (!result.success) { showCaAlert('caResetError', result.error?.message || 'Fehler beim Senden'); return; }

  showCaAlert('caResetSuccess', 'Link gesendet! Prüfe deinen Posteingang.');
  setTimeout(function() { setCustomerAuthMode('login'); }, 3000);
}

// Supabase initialisieren (sicher)
function initSupabase() {
  try {
    var sdk = _supabaseSDK || window.supabase;
    if (sdk && typeof sdk.createClient === 'function') {
      supabase = sdk.createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
      console.log('✅ Supabase verbunden');
      
      // Auth State Listener
      supabase.auth.onAuthStateChange(async (event, session) => {
        console.log('Auth State:', event);
        if (session?.user) {
          currentUser = session.user;
          await loadUserProfile();
          await loadUserDataFromSupabase();
          startCustomerRealtime();
          updateUIForLoggedInUser();
        } else {
          currentUser = null;
          userProfile = null;
          if (supabase) supabase.removeAllChannels();
          updateUIForLoggedOutUser();
        }
      });
      
      return true;
    }
  } catch (e) {
    console.log('Supabase init error:', e);
  }
  console.log('⚠️ Supabase nicht verfügbar - Offline-Modus');
  return false;
}

// =============================================
// AUTH FUNKTIONEN
// =============================================

// Registrieren
async function signUp(email, password, name, userData) {
  if (!supabase) {
    showToast('❌ Verbindung nicht möglich');
    return { success: false };
  }
  try {
    showLoading('Konto wird erstellt...');

    const { data, error } = await supabase.auth.signUp({
      email: email,
      password: password,
      options: {
        data: {
          name: name
        }
      }
    });

    hideLoading();

    if (error) throw error;

    // Profil updaten mit Name + personal_data
    if (data.user) {
      var profileUpdate = { name: name };
      if (userData) {
        profileUpdate.personal_data = {
          anrede: userData.anrede || '',
          titel: userData.titel || '',
          firstName: userData.firstName || '',
          lastName: userData.lastName || ''
        };
      }
      await supabase.from('profiles').update(profileUpdate).eq('id', data.user.id);
      // Auch in localStorage speichern für sofortigen Zugriff
      if (userData) {
        var existingProfile = {};
        try { existingProfile = JSON.parse(localStorage.getItem('suppTreeProfile') || '{}'); } catch(e) {}
        Object.assign(existingProfile, userData, { email: email });
        localStorage.setItem('suppTreeProfile', JSON.stringify(existingProfile));
      }
    }
    
    showToast('✅ Konto erstellt! Bitte bestätige deine E-Mail.');
    return { success: true, data };
  } catch (error) {
    hideLoading();
    console.error('SignUp Error:', error);
    showToast('❌ ' + (error.message || 'Registrierung fehlgeschlagen'));
    return { success: false, error };
  }
}

// Einloggen
async function signIn(email, password) {
  if (!supabase) {
    showToast('❌ Verbindung nicht möglich. Bitte Seite neu laden.');
    return { success: false };
  }
  try {
    showLoading('Anmelden...');

    const { data, error } = await supabase.auth.signInWithPassword({
      email: email,
      password: password
    });

    hideLoading();

    if (error) throw error;

    currentUser = data.user;
    try { await loadUserProfile(); } catch(e) { console.warn('Profil laden:', e); }

    // Sync im Hintergrund (blockiert Login nicht)
    syncLocalDataToSupabase().catch(function(e) { console.warn('Sync:', e); });

    showToast('✅ Willkommen zurück!');
    closeAuthSheet();
    updateUIForLoggedInUser();

    return { success: true, data };
  } catch (error) {
    hideLoading();
    console.error('SignIn Error:', error);
    showToast('❌ ' + (error.message || 'Anmeldung fehlgeschlagen'));
    return { success: false, error };
  }
}

// Ausloggen
async function signOut() {
  if (!supabase) {
    currentUser = null;
    userProfile = null;
    showToast('👋 Abgemeldet');
    updateUIForLoggedOutUser();
    return { success: true };
  }
  try {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
    
    currentUser = null;
    userProfile = null;
    
    showToast('👋 Erfolgreich abgemeldet');
    updateUIForLoggedOutUser();
    
    return { success: true };
  } catch (error) {
    console.error('SignOut Error:', error);
    showToast('❌ Abmeldung fehlgeschlagen');
    return { success: false, error };
  }
}

// Passwort zurücksetzen
async function resetPassword(email) {
  if (!supabase) {
    showToast('❌ Verbindung nicht möglich');
    return { success: false };
  }
  try {
    showLoading('E-Mail wird gesendet...');
    
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: window.location.origin
    });
    
    hideLoading();
    
    if (error) throw error;
    
    showToast('✅ E-Mail zum Zurücksetzen gesendet!');
    return { success: true };
  } catch (error) {
    hideLoading();
    showToast('❌ ' + (error.message || 'Fehler beim Senden'));
    return { success: false, error };
  }
}

// =============================================
// PROFIL FUNKTIONEN
// =============================================

// User Profil laden
async function loadUserProfile() {
  if (!currentUser || !supabase) return null;
  
  try {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', currentUser.id)
      .single();
    
    if (error) throw error;
    
    userProfile = data;
    return data;
  } catch (error) {
    console.error('Load Profile Error:', error);
    return null;
  }
}

// Profil updaten
async function updateProfile(updates) {
  if (!currentUser || !supabase) return { success: false };
  
  try {
    const { data, error } = await supabase
      .from('profiles')
      .update(updates)
      .eq('id', currentUser.id)
      .select()
      .single();
    
    if (error) throw error;
    
    userProfile = data;
    showToast('✅ Profil gespeichert');
    return { success: true, data };
  } catch (error) {
    console.error('Update Profile Error:', error);
    showToast('❌ Speichern fehlgeschlagen');
    return { success: false, error };
  }
}

// =============================================
// DATEN SYNC FUNKTIONEN
// =============================================

// Lokale Daten zu Supabase hochladen (bei erstem Login)
async function syncLocalDataToSupabase() {
  if (!currentUser || !supabase) return;
  
  try {
    // Supplements sync
    const localSupps = JSON.parse(localStorage.getItem('mySupplements') || '[]');
    for (const supp of localSupps) {
      await supabase.from('my_supplements').upsert({
        user_id: currentUser.id,
        name: supp.name,
        brand: supp.brand,
        icon: supp.icon,
        dosage_form: supp.dosageForm,
        dosage_amount: supp.dosage,
        doses_per_day: supp.dosePerDay || 1,
        take_morning: supp.times?.includes('morning'),
        take_noon: supp.times?.includes('noon'),
        take_evening: supp.times?.includes('evening'),
        take_night: supp.times?.includes('night'),
        status: supp.status || 'active'
      }, { onConflict: 'id' });
    }
    
    // Medikamente sync
    const localMeds = JSON.parse(localStorage.getItem('myMedications') || '[]');
    for (const med of localMeds) {
      await supabase.from('my_medications').upsert({
        user_id: currentUser.id,
        name: med.name,
        icon: med.icon,
        dosage: med.dosage,
        doses_per_day: med.dosePerDay || 1,
        is_active: med.isActive !== false
      }, { onConflict: 'id' });
    }
    
    console.log('✅ Lokale Daten synchronisiert');
  } catch (error) {
    console.error('Sync Error:', error);
  }
}

// Daten von Supabase laden
async function loadUserDataFromSupabase() {
  if (!currentUser || !supabase) return;
  
  try {
    // Supplements laden
    const { data: supps } = await supabase
      .from('my_supplements')
      .select('*')
      .eq('user_id', currentUser.id);
    
    if (supps && supps.length > 0) {
      mySupplements = supps.map(s => ({
        id: s.id,
        name: s.name,
        brand: s.brand,
        icon: s.icon,
        dosageForm: s.dosage_form,
        dosage: s.dosage_amount,
        dosePerDay: s.doses_per_day,
        times: [
          s.take_morning && 'morning',
          s.take_noon && 'noon',
          s.take_evening && 'evening',
          s.take_night && 'night'
        ].filter(Boolean),
        status: s.status
      }));
    }
    
    // Medikamente laden
    const { data: meds } = await supabase
      .from('my_medications')
      .select('*')
      .eq('user_id', currentUser.id);
    
    if (meds && meds.length > 0) {
      myMedications = meds.map(m => ({
        id: m.id,
        name: m.name,
        icon: m.icon,
        dosage: m.dosage,
        dosePerDay: m.doses_per_day,
        isActive: m.is_active
      }));
    }
    
    // Favoriten laden
    const { data: favs } = await supabase
      .from('favorites')
      .select('product_id')
      .eq('user_id', currentUser.id);

    if (favs) {
      favorites = new Set(favs.map(f => f.product_id));
      localStorage.setItem('suppTreeFavorites', JSON.stringify([...favorites]));
    }

    // Health Profile & Personal Data aus Profil laden
    if (userProfile) {
      if (userProfile.health_profile) {
        healthProfileData = userProfile.health_profile;
        localStorage.setItem('suppTreeHealthProfile', JSON.stringify(healthProfileData));
      }
      if (userProfile.personal_data) {
        localStorage.setItem('suppTreePersonalData', JSON.stringify(userProfile.personal_data));
        // Profil-Formular-Daten aus Supabase in localStorage mergen
        var localProfile = JSON.parse(localStorage.getItem('suppTreeProfile') || '{}');
        var pd = userProfile.personal_data;
        if (pd.firstName && !localProfile.firstName) localProfile.firstName = pd.firstName;
        if (pd.lastName && !localProfile.lastName) localProfile.lastName = pd.lastName;
        if (pd.birthdate && !localProfile.birthdate) localProfile.birthdate = pd.birthdate;
        if (pd.gender && !localProfile.gender) localProfile.gender = pd.gender;
        if (pd.height && !localProfile.height) localProfile.height = pd.height;
        if (pd.weight && !localProfile.weight) localProfile.weight = pd.weight;
        if (pd.phone && !localProfile.phone) localProfile.phone = pd.phone;
        localStorage.setItem('suppTreeProfile', JSON.stringify(localProfile));
      }
    }

    // Berater-Verbindungen laden
    const { data: berater } = await supabase
      .from('customer_berater')
      .select('*')
      .eq('customer_id', currentUser.id)
      .eq('status', 'active');

    if (berater && berater.length) {
      const beraterList = berater.map(b => ({
        id: b.partner_id,
        name: b.partner_name,
        avatar: b.partner_avatar || '👨‍🏫',
        role: b.partner_role,
        roleLabel: b.partner_role_label,
        connectedAt: b.connected_at
      }));
      localStorage.setItem('suppTreeMeineBerater', JSON.stringify(beraterList));
    }

    // Gesendete Pläne aus Supabase laden
    const { data: sentPlans } = await supabase
      .from('sent_plans')
      .select('*')
      .eq('customer_id', currentUser.id)
      .order('sent_at', { ascending: false });

    if (sentPlans && sentPlans.length > 0) {
      var plans = sentPlans.map(function(sp) {
        var p = sp.plan_data;
        p.isNew = !sp.is_read;
        p.dbPlanId = sp.id;
        return p;
      });
      localStorage.setItem('suppTreeBeraterPlaene', JSON.stringify(plans));
    }

    // Buchungen (Termin-Anfragen) aus Supabase laden
    const { data: dbBookings } = await supabase
      .from('bookings')
      .select('*')
      .eq('customer_id', currentUser.id)
      .order('created_at', { ascending: false });

    if (dbBookings && dbBookings.length > 0) {
      var statusMap = { requested: 'pending', proposed: 'termin_vorgeschlagen', confirmed: 'confirmed', declined: 'declined', cancelled: 'storniert', completed: 'completed' };
      var dbAnfragen = dbBookings.map(function(b) {
        return {
          id: b.id,
          dbId: b.id,
          practitionerId: b.partner_id,
          practitionerName: b.partner_name,
          practitionerAvatar: '',
          practitionerTitle: '',
          practitionerCity: '',
          service: { name: b.service, price: Number(b.price) || 0, duration: b.duration || 60 },
          mode: b.mode || 'praxis',
          verfuegbarkeit: b.customer_message || '',
          message: b.notes || '',
          status: statusMap[b.status] || b.status,
          terminVorschlag: b.termin_vorschlag || null,
          zahlung: b.zahlung || null,
          storno: b.storno || null,
          paidAt: b.zahlung ? b.zahlung.paidAt : null,
          createdAt: b.created_at,
          updatedAt: b.created_at,
          partnerAnfrageId: null
        };
      });
      // Merge: DB hat Vorrang, lokale ohne dbId behalten
      var existingLocal = taGetAnfragen().filter(function(a) { return !a.dbId; });
      var merged = dbAnfragen.concat(existingLocal);
      taSaveAnfragen(merged);
    }

    // Bluttest-Buchungen aus Supabase laden
    const { data: dbBloodTests } = await supabase
      .from('blood_tests')
      .select('*')
      .eq('customer_id', currentUser.id)
      .order('test_date', { ascending: false });

    if (dbBloodTests && dbBloodTests.length > 0) {
      var dbHpBookings = dbBloodTests.map(function(bt) {
        return {
          id: bt.id,
          dbId: bt.id,
          heilpraktiker: { id: bt.partner_id, name: bt.partner_name },
          testType: bt.test_name,
          date: bt.test_date,
          time: bt.notes || '',
          status: bt.status === 'completed' ? 'completed' : bt.status === 'cancelled' ? 'cancelled' : 'confirmed',
          createdAt: bt.created_at
        };
      });
      var localHpBookings = JSON.parse(localStorage.getItem('supptree_hp_bookings') || '[]').filter(function(b) { return !b.dbId; });
      localStorage.setItem('supptree_hp_bookings', JSON.stringify(dbHpBookings.concat(localHpBookings)));
    }

    console.log('✅ User Daten geladen');
  } catch (error) {
    console.error('Load Data Error:', error);
  }
}

// =============================================
// REALTIME SUBSCRIPTIONS
// =============================================

function startCustomerRealtime() {
  if (!supabase || !currentUser) return;

  supabase.removeAllChannels();

  // Bookings: Terminvorschläge + Status-Updates
  supabase.channel('customer-bookings')
    .on('postgres_changes', {
      event: 'UPDATE',
      schema: 'public',
      table: 'bookings',
      filter: 'customer_id=eq.' + currentUser.id
    }, function(payload) {
      handleCustomerBookingUpdate(payload);
    })
    .subscribe();

  // Pläne: Neue Pläne vom Berater
  supabase.channel('customer-plans')
    .on('postgres_changes', {
      event: 'INSERT',
      schema: 'public',
      table: 'sent_plans',
      filter: 'customer_id=eq.' + currentUser.id
    }, function(payload) {
      handleNewPlan(payload);
    })
    .subscribe();
}

function handleCustomerBookingUpdate(payload) {
  var b = payload.new;
  if (!b) return;

  var statusMap = { requested: 'pending', proposed: 'termin_vorgeschlagen', confirmed: 'confirmed', declined: 'declined', cancelled: 'storniert', completed: 'completed' };
  var anfragen = taGetAnfragen();
  var anf = anfragen.find(function(a) { return a.dbId === b.id; });

  if (!anf) return;

  anf.status = statusMap[b.status] || b.status;
  if (b.termin_vorschlag) anf.terminVorschlag = b.termin_vorschlag;
  if (b.zahlung) anf.zahlung = b.zahlung;
  if (b.storno) anf.storno = b.storno;
  taSaveAnfragen(anfragen);

  // UI updaten falls sichtbar
  if (typeof renderEkMeineAnfragen === 'function') {
    try { renderEkMeineAnfragen(); } catch(e) {}
  }

  if (b.status === 'proposed') {
    showToast('Neuer Terminvorschlag erhalten!');
    sendLocalNotification('SuppTree', 'Neuer Terminvorschlag erhalten!');
  } else if (b.status === 'completed') {
    showToast('Termin als abgeschlossen markiert');
    sendLocalNotification('SuppTree', 'Dein Termin wurde als abgeschlossen markiert.');
  }
}

function handleNewPlan(payload) {
  var sp = payload.new;
  if (!sp) return;

  var plans = JSON.parse(localStorage.getItem('suppTreeBeraterPlaene') || '[]');
  var p = sp.plan_data || {};
  p.isNew = true;
  p.dbPlanId = sp.id;
  plans.unshift(p);
  localStorage.setItem('suppTreeBeraterPlaene', JSON.stringify(plans));

  showToast('Neuer Plan von deinem Berater!');
  sendLocalNotification('SuppTree', 'Neuer Plan von deinem Berater!');
}

// =============================================
// PRODUKTE LADEN (aus Supabase)
// =============================================

async function loadProductsFromSupabase() {
  if (!supabase) return;
  
  try {
    const { data, error } = await supabase
      .from('products')
      .select(`
        *,
        brands (name, logo_url),
        categories (name, icon)
      `)
      .eq('is_active', true)
      .order('created_at', { ascending: false });
    
    if (error) throw error;
    
    if (data && data.length > 0) {
      // Mapping zu unserem Format
      products = data.map(p => ({
        id: p.id,
        name: p.name,
        brand: p.brands?.name || '',
        category: p.category_id,
        price: p.price.toString(),
        rating: p.rating,
        reviews: p.review_count,
        icon: p.icon,
        image: p.image_url,
        description: p.description,
        dosageForm: p.dosage_form,
        dosage: p.dosage_amount,
        servings: p.servings_per_container,
        aboAvailable: p.abo_available,
        aboDiscount: p.abo_discount_percent,
        isFeatured: p.is_featured,
        isSTCertified: p.is_st_certified
      }));
      
      console.log(`✅ ${products.length} Produkte geladen`);
    }
  } catch (error) {
    console.error('Load Products Error:', error);
    // Fallback zu lokalen Demo-Produkten
  }
}

// =============================================
// AUTH UI FUNKTIONEN
// =============================================

function openAuthSheet(mode = 'login') {
  // Zum neuen Customer-Auth-Overlay weiterleiten
  setCustomerAuthMode(mode);
  showCustomerAuth();
}

function closeAuthSheet() {
  const sheet = document.getElementById('authSheet');
  const overlay = document.getElementById('authOverlay');
  if (!sheet || !overlay) return;
  
  overlay.classList.remove('visible');
  sheet.classList.remove('visible');
  unlockBody();
}

function setAuthMode(mode) {
  const loginForm = document.getElementById('loginForm');
  const registerForm = document.getElementById('registerForm');
  const resetForm = document.getElementById('resetForm');
  const authTitle = document.getElementById('authTitle');
  
  loginForm.style.display = mode === 'login' ? 'block' : 'none';
  registerForm.style.display = mode === 'register' ? 'block' : 'none';
  resetForm.style.display = mode === 'reset' ? 'block' : 'none';
  
  authTitle.textContent = mode === 'login' ? '🔐 Anmelden' : 
                          mode === 'register' ? '📝 Registrieren' : 
                          '🔑 Passwort zurücksetzen';
}

function updateUIForLoggedInUser() {
  // Profile Button updaten
  const profileBtn = document.getElementById('menuAvatarEmoji');
  if (profileBtn && userProfile?.avatar_emoji) {
    profileBtn.textContent = userProfile.avatar_emoji;
  }
  
  const userName = document.getElementById('menuUserName');
  if (userName && userProfile?.name) {
    userName.textContent = userProfile.name;
  }

  // Mein-Screen Greeting mit Name
  var meinName = document.getElementById('meinGreetingName');
  if (meinName) {
    var displayName = userProfile?.name || currentUser?.user_metadata?.name || '';
    meinName.textContent = displayName ? displayName + '! 👋' : '👋';
  }

  // Login Button verstecken, Logout zeigen
  const loginBtn = document.getElementById('loginBtn');
  const logoutBtn = document.getElementById('logoutBtn');
  if (loginBtn) loginBtn.style.display = 'none';
  if (logoutBtn) logoutBtn.style.display = 'flex';
  
  // Punkte anzeigen
  if (userProfile?.points !== undefined) {
    totalPoints = userProfile.points;
    if (typeof updatePointsDisplay === 'function') updatePointsDisplay();
  }

  // Partner-Bereich Button für Seller/Admin anzeigen
  var partnerBtn = document.getElementById('partnerSwitchBtn');
  if (partnerBtn) {
    var role = (userProfile && userProfile.role) || (currentUser && currentUser.user_metadata && currentUser.user_metadata.role);
    partnerBtn.style.display = (role === 'seller' || role === 'admin') ? 'block' : 'none';
  }

  // Home-Greeting mit Name aktualisieren
  if (typeof updateHomeGreeting === 'function') updateHomeGreeting();

  // Persönliche Home-Sektionen einblenden + rendern
  if (typeof showPersonalHomeSections === 'function') showPersonalHomeSections();
  try { initHomePage(); } catch(e) {}
}

function updateUIForLoggedOutUser() {
  const loginBtn = document.getElementById('loginBtn');
  const logoutBtn = document.getElementById('logoutBtn');
  if (loginBtn) loginBtn.style.display = 'flex';
  if (logoutBtn) logoutBtn.style.display = 'none';

  // Reset Profile display
  const profileBtn = document.getElementById('menuAvatarEmoji');
  if (profileBtn) profileBtn.textContent = '👤';

  const userName = document.getElementById('menuUserName');
  if (userName) userName.textContent = 'Mein Profil';

  // Partner-Button verstecken
  var partnerBtn = document.getElementById('partnerSwitchBtn');
  if (partnerBtn) partnerBtn.style.display = 'none';

  // Mein-Screen Name zurücksetzen
  var meinName = document.getElementById('meinGreetingName');
  if (meinName) meinName.textContent = '👋';

  // Greeting zurücksetzen (kein Name)
  if (typeof updateHomeGreeting === 'function') updateHomeGreeting();

  // Persönliche Home-Sektionen verstecken
  if (typeof hidePersonalHomeSections === 'function') hidePersonalHomeSections();
}

// =============================================
// HELPER FUNKTIONEN
// =============================================

function showLoading(text = 'Laden...') {
  // Einfaches Loading Overlay
  let overlay = document.getElementById('loadingOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'loadingOverlay';
    overlay.innerHTML = `
      <div style="position:fixed;inset:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:99999;">
        <div style="background:white;padding:24px 32px;border-radius:7px;text-align:center;">
          <div style="font-size:32px;margin-bottom:12px;">⏳</div>
          <div style="font-size:15px;color:#333;">${text}</div>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);
  } else {
    overlay.querySelector('div > div > div:last-child').textContent = text;
    overlay.style.display = 'block';
  }
}

function hideLoading() {
  const overlay = document.getElementById('loadingOverlay');
  if (overlay) overlay.remove();
}

