// Current language
let currentLang = localStorage.getItem('supptree-language') || 'de';

// ===== TRANSLATION FUNCTION =====
function t(key, params = {}) {
  const entry = i18n[key];
  if (!entry) {
    return key;
  }
  let text = entry[currentLang] || entry['de'] || key;
  
  // Replace parameters like {name}
  Object.keys(params).forEach(param => {
    text = text.replace(new RegExp(`{${param}}`, 'g'), params[param]);
  });
  
  return text;
}

// ===== APPLY TRANSLATIONS TO DOM =====
function applyI18n() {
  // Translate data-i18n elements (text content)
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const translated = t(key);
    if (translated !== key) {
      el.textContent = translated;
    }
  });
  
  // Translate data-i18n-placeholder (input placeholders)
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    el.placeholder = t(key);
  });
  
  // Translate data-i18n-title (tooltips)
  document.querySelectorAll('[data-i18n-title]').forEach(el => {
    const key = el.getAttribute('data-i18n-title');
    el.title = t(key);
  });
  
  // Translate data-i18n-html (innerHTML)
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    const key = el.getAttribute('data-i18n-html');
    el.innerHTML = t(key);
  });
  
  // Update html lang attribute
  document.documentElement.lang = currentLang;
}

// ===== SET LANGUAGE =====
function setLanguage(lang) {
  if (!['de', 'en', 'fr'].includes(lang)) return;
  currentLang = lang;
  localStorage.setItem('supptree-language', lang);
  applyI18n();
  
  // Dispatch event for other scripts to react
  window.dispatchEvent(new CustomEvent('languageChanged', { detail: { lang } }));
}

// ===== MUTATION OBSERVER FOR DYNAMIC CONTENT =====
const i18nObserver = new MutationObserver(mutations => {
  let needsUpdate = false;
  mutations.forEach(mutation => {
    mutation.addedNodes.forEach(node => {
      if (node.nodeType === 1) { // Element node
        if (node.hasAttribute && (
          node.hasAttribute('data-i18n') ||
          node.hasAttribute('data-i18n-placeholder') ||
          node.querySelector('[data-i18n], [data-i18n-placeholder]')
        )) {
          needsUpdate = true;
        }
      }
    });
  });
  if (needsUpdate) {
    applyI18n();
  }
});

