// Dosierungs-Datenbank — wird aus Supabase geladen
var kwDosierungen = {};

// Knowledge Articles — wird aus Supabase geladen
var knowledgeArticles = [];
var _kwDataLoaded = false;
var _kwArticleCache = {}; // Cache für Detail-Daten (Quellen, Dosierungen etc.)
var kwSelectedCountry = 'DE';
var kwDetectedCountry = 'DE';

// Emoji/Sonderzeichen aus Text entfernen
function _kwCleanText(text) {
  if (!text) return '';
  // Remove leading non-alphanumeric/non-letter characters (emojis, stars, etc.)
  return text.replace(/^[^\w\dÄÖÜäöüßA-Za-z(]+/, '').replace(/\s{2,}/g, ' ').trim();
}

// Supabase Knowledge Fetch Helper
async function _kwFetch(table, query) {
  var url = SUPABASE_URL + '/rest/v1/' + table + '?' + query;
  var resp = await fetch(url, {
    headers: { 'apikey': SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + SUPABASE_ANON_KEY }
  });
  if (!resp.ok) return [];
  return resp.json();
}

// Kategorie-Icons für die Darstellung
var _kwCategoryIcons = {
  'Vitamine': '💊', 'Mineralstoffe': '⚡', 'Mineralien': '⚡', 'Aminosaeuren': '🧬',
  'Fettsaeuren': '🐟', 'Pflanzenextrakte': '🌿', 'Probiotika': '🦠',
  'Enzyme': '⚗️', 'Sonstige': '📦', 'Hormone': '🧪', 'Ballaststoffe': '🌾',
  'Carotinoide / Provitamine': '🥕', 'Fettloesliche Vitamine': '☀️',
  'Wasserloesliche Vitamine': '💧', 'B-Vitamine': '🔴',
  'Spurenelemente': '🔬', 'Mengenelemente': '⚡',
  'Adaptogene': '🌿', 'Polyphenole': '🍇'
};

// Mapping Supabase kategorie → knowledgeCategories key
function _kwMapCategory(kat) {
  if (!kat) return 'sonstige';
  var k = kat.toLowerCase().replace(/[⚠️⛔🔬]/g, '').trim();
  if (k.includes('vitamin') || k.includes('carotin')) return 'vitamine';
  if (k.includes('mineral') || k.includes('spurenelement') || k.includes('mengenelement')) return 'mineralien';
  if (k.includes('pflanzen') || k.includes('adaptogen') || k.includes('polyphenol') || k.includes('algen') || k.includes('vitalpilz') || k.includes('phytosterol') || k.includes('phytochem') || k.includes('alkaloid') || k.includes('terpen') || k.includes('saponin')) return 'pflanzen';
  if (k.includes('fetts') || k.includes('omega') || k.includes('phospholipid') || k.includes('lipid') || k.includes('fettalko')) return 'omega';
  if (k.includes('probio') || k.includes('präbio') || k.includes('postbio') || k.includes('synbio') || k.includes('darm') || k.includes('ballast') || k.includes('verdauung') || k.includes('ferment')) return 'darm';
  if (k.includes('amino') || k.includes('protein')) return 'amino';
  if (k.includes('sport') || k.includes('kreatin')) return 'sport';
  return 'sonstige';
}

// Map Supabase subcategory
function _kwMapSubcategory(unterkat) {
  if (!unterkat) return '';
  var u = unterkat.toLowerCase();
  if (u.includes('fettl')) return 'fettloeslich';
  if (u.includes('wasserl')) return 'wasserloeslich';
  if (u.includes('b-vita')) return 'b-vitamine';
  if (u.includes('mengen')) return 'mengenelemente';
  if (u.includes('spuren')) return 'spurenelemente';
  if (u.includes('adaptogen')) return 'adaptogene';
  return u.replace(/\s+/g, '-');
}

// Hilfsfunktion: Stichpunkte in Fließtext mit Aufzählung
function _kwListify(str) {
  if (!str) return '';
  return str.split(',').map(function(k) {
    var t = _kwCleanText(k.trim()).replace(/-/g, ' ');
    // Nur ersten Buchstaben großschreiben
    if (t.length > 0) t = t.charAt(0).toUpperCase() + t.slice(1);
    return '• ' + t;
  }).join('\n');
}

// Hilfsfunktion: Umlaute in Supabase-Text korrigieren (ae→ä etc.)
// Nur ersetzen wenn es typische deutsche Umlaut-Muster sind, nicht in Fachbegriffen
function _kwFixUmlauts(t) {
  if (!t) return '';
  // Häufige deutsche Wörter mit ae/oe/ue korrigieren
  var replacements = {
    'fuer': 'für', 'ueber': 'über', 'Ueber': 'Über', 'aeusser': 'äußer', 'Aeusser': 'Äußer',
    'Traegt': 'Trägt', 'traegt': 'trägt', 'Muedigkeit': 'Müdigkeit', 'muedigkeit': 'müdigkeit',
    'Uebelkeit': 'Übelkeit', 'uebelkeit': 'übelkeit', 'Durchfuehr': 'Durchführ',
    'Verfuegbar': 'Verfügbar', 'verfuegbar': 'verfügbar', 'Bioverfuegbar': 'Bioverfügbar',
    'bioverfuegbar': 'bioverfügbar', 'Vertraeglichkeit': 'Verträglichkeit', 'vertraeglichkeit': 'verträglichkeit',
    'aerztlich': 'ärztlich', 'Aerztlich': 'Ärztlich', 'haeufig': 'häufig', 'Haeufig': 'Häufig',
    'Erhoehter': 'Erhöhter', 'erhoehter': 'erhöhter', 'erhoehten': 'erhöhten', 'Erhoehten': 'Erhöhten',
    'hoechst': 'höchst', 'Hoechst': 'Höchst', 'moeglich': 'möglich', 'Moeglich': 'Möglich',
    'oeffentlich': 'öffentlich', 'Oeffentlich': 'Öffentlich',
    'Kuerbis': 'Kürbis', 'kuerbis': 'kürbis', 'natuerlich': 'natürlich', 'Natuerlich': 'Natürlich',
    'koennen': 'können', 'Koennen': 'Können', 'koennte': 'könnte',
    'genuegend': 'genügend', 'unzulaessig': 'unzulässig',
    'abfuehrend': 'abführend', 'Abfuehrend': 'Abführend',
    'empfaenglich': 'empfänglich', 'unguenstig': 'ungünstig',
    'Saeuglings': 'Säuglings', 'saeuglings': 'säuglings',
    'Foerdert': 'Fördert', 'foerdert': 'fördert',
    'Loeslich': 'Löslich', 'loeslich': 'löslich', 'wasserloeslich': 'wasserlöslich', 'fettloeslich': 'fettlöslich',
    'Oel': 'Öl', 'oel': 'öl',
    'Aelter': 'Älter', 'aelter': 'älter', 'Aelteren': 'Älteren',
    'Mangelsymptome': 'Mangelsymptome',
    'Qualitaet': 'Qualität', 'qualitaet': 'qualität',
    'Schaedlich': 'Schädlich', 'schaedlich': 'schädlich',
    'Stueck': 'Stück', 'stueck': 'stück',
    'Waerme': 'Wärme', 'waerme': 'wärme',
    'genuegen': 'genügen', 'unterstuetzt': 'unterstützt', 'Unterstuetzt': 'Unterstützt',
    'Schlafqualitaet': 'Schlafqualität', 'schlafqualitaet': 'schlafqualität',
    'Suesse': 'Süße', 'suesse': 'süße',
    'schwaechend': 'schwächend', 'Muskelschwaeche': 'Muskelschwäche',
    'Saeure': 'Säure', 'saeure': 'säure',
    'Aehnlich': 'Ähnlich', 'aehnlich': 'ähnlich',
    'Schaerfere': 'Schärfere', 'Kaelte': 'Kälte'
  };
  var result = t;
  for (var key in replacements) {
    result = result.split(key).join(replacements[key]);
  }
  // Deutsche Abkürzungen ausschreiben (mit Wortgrenzen via Regex)
  var abbrevs = [
    [/\bbes\./g, 'besonders'],
    [/\binsb\./g, 'insbesondere'],
    [/\bz\.B\./g, 'zum Beispiel'],
    [/\bz\.b\./g, 'zum Beispiel'],
    [/\bu\.a\./g, 'unter anderem'],
    [/\bv\.a\./g, 'vor allem'],
    [/\bd\.h\./g, 'das heißt'],
    [/\bbzw\./g, 'beziehungsweise'],
    [/\bbspw\./g, 'beispielsweise'],
    [/\bbzgl\./g, 'bezüglich'],
    [/\bca\./g, 'circa'],
    [/\bmax\./g, 'maximal'],
    [/\bmin\./g, 'minimal'],
    [/\binkl\./g, 'inklusive'],
    [/\bevtl\./g, 'eventuell'],
    [/\bggf\./g, 'gegebenenfalls'],
    [/\busw\./g, 'usw.'],
    [/\betc\./g, 'etc.'],
    [/\bi\.d\.R\./g, 'in der Regel'],
    [/\blt\./g, 'laut'],
    [/\bvgl\./g, 'vergleiche'],
    [/\bsog\./g, 'sogenannte'],
    [/\besp\./g, 'especially'],
    [/\bv\./g, 'von']
  ];
  abbrevs.forEach(function(pair) { result = result.replace(pair[0], pair[1]); });
  // Vitamin-Buchstaben immer groß: "vitamin d3" → "Vitamin D3", "vitamin-b12" → "Vitamin B12"
  result = result.replace(/\bvitamin[-\s]+([a-z])(\d*[a-z]?\d*)/gi, function(m, letter, rest) {
    return 'Vitamin ' + letter.toUpperCase() + rest;
  });
  // Satzanfänge großschreiben (nach ". " oder am Textbeginn)
  result = result.replace(/(^|\.\s+)([a-zäöü])/g, function(m, pre, letter) {
    return pre + letter.toUpperCase();
  });
  return result;
}

// Build "Was ist X?" Erklärungstext aus Supabase-Feldern
function _kwBuildWasIst(s) {
  var name = _kwCleanText(s.name || '');
  var fix = _kwFixUmlauts;
  var paragraphs = [];

  // Paragraph 1: Definition — was für ein Supplement ist es?
  var kat = ((s.unterkategorie || '') + ' ' + (s.kategorie || '')).toLowerCase();
  var typ = 'ein Nahrungsergänzungsmittel';
  if (kat.includes('mineral')) typ = 'ein essenzielles Mineral';
  else if (kat.includes('vitamin')) typ = 'ein Vitamin';
  else if (kat.includes('aminosäure') || kat.includes('aminosaeure')) typ = 'eine Aminosäure';
  else if (kat.includes('fettsäure') || kat.includes('fettsaeure') || kat.includes('omega')) typ = 'eine essentielle Fettsäure';
  else if (kat.includes('adaptogen')) typ = 'ein pflanzliches Adaptogen';
  else if (kat.includes('antioxidans')) typ = 'ein Antioxidans';
  else if (kat.includes('probiotik')) typ = 'ein Probiotikum';
  else if (kat.includes('coenzym')) typ = 'ein Coenzym';
  else if (kat.includes('pflanzlich') || kat.includes('extrakt')) typ = 'ein pflanzlicher Wirkstoff';
  else if (kat.includes('spurenelement')) typ = 'ein Spurenelement';

  var p1 = name + ' ist ' + typ + '.';
  if (s.wirkung_kurz) p1 += ' ' + fix(s.wirkung_kurz).replace(/\.$/, '') + '.';
  paragraphs.push(p1);

  // Paragraph 2: Bekannte Namen / Synonyme
  if (s.auch_bekannt_als) {
    var aliases = s.auch_bekannt_als.split(',').map(function(a) { return a.trim(); }).filter(function(a) { return a.length > 1; });
    if (aliases.length > 0) {
      paragraphs.push(name + ' wird auch bezeichnet als: ' + aliases.join(', ') + '.');
    }
  }

  // Paragraph 3: Natürliche Quellen
  if (s.natuerliche_quellen && s.natuerliche_quellen !== 'None') {
    var quellen = fix(s.natuerliche_quellen).split(',').map(function(q) { return q.trim(); }).filter(Boolean);
    if (quellen.length > 0) {
      paragraphs.push('Natürlich kommt ' + name + ' in folgenden Lebensmitteln vor: ' + quellen.slice(0, 5).join(', ') + (quellen.length > 5 ? ' und weiteren.' : '.'));
    }
  }

  // Paragraph 4: Besonderheiten (fettlöslich, vegan, bluttest)
  var extras = [];
  if (s.fettloeslich === 'Ja' || s.fettloeslich === true) extras.push(name + ' ist fettlöslich — es wird am besten zusammen mit einer fetthaltigen Mahlzeit aufgenommen.');
  if (s.vegan_verfuegbar === 'Ja') extras.push('Vegane Produkte sind verfügbar.');
  if (s.bluttest_empfohlen === 'Ja' && s.welcher_blutwert) extras.push('Ein Bluttest auf ' + fix(s.welcher_blutwert) + ' kann sinnvoll sein, um einen Mangel festzustellen.');
  if (extras.length > 0) paragraphs.push(extras.join(' '));

  // Paragraph 5: Empfohlene Tagesdosis
  if (s.rda_erwachsene && s.rda_einheit) {
    paragraphs.push('Die empfohlene Tagesdosis (RDA) für Erwachsene beträgt ' + s.rda_erwachsene + '\u00a0' + s.rda_einheit + '.');
  }

  return paragraphs;
}

// Build article content sections from Supabase fields — schöne Fließtexte
function _kwBuildSections(s) {
  var sections = [];
  var name = _kwCleanText(s.name || '');
  var fix = _kwFixUmlauts;

  // 0. Was ist X? — erste Section, aus _kwBuildWasIst
  var wasIstParas = _kwBuildWasIst(s);
  if (wasIstParas.length > 0) {
    sections.push({ title: 'Was ist ' + name + '?', content: wasIstParas.join('\n\n') });
  }

  // 1. Wirkung
  if (s.wirkung) {
    var wRaw = _kwCleanText(s.wirkung || '');
    var wText = fix(wRaw);
    // Als saubere Aufzählung darstellen
    var wParts = wText.split(/[,;]/).map(function(p){ return p.trim(); }).filter(function(p){ return p.length > 2; });
    var intro = '';
    if (wParts.length > 1) {
      intro = wParts.map(function(p){ return '• ' + p.charAt(0).toUpperCase() + p.slice(1); }).join('\n');
    } else {
      intro = wText;
    }
    // EFSA Health Claims
    if (s.health_claims_efsa) {
      intro += '\n\n**Wissenschaftlich bestätigt (EFSA):**\n' + fix(s.health_claims_efsa).split(';').map(function(c){ return '• ' + c.trim(); }).join('\n');
    }
    sections.push({ title: 'Was macht ' + name + ' im Körper?', content: intro });
  }

  // 2. Einnahme — als lesbarer Leitfaden
  var einnahme = '';
  if (s.einnahme_zeitpunkt) {
    einnahme += name + ' wird am besten **' + fix(s.einnahme_zeitpunkt).toLowerCase() + '** eingenommen.';
  }
  if (s.einnahme_mit) {
    einnahme += (einnahme ? ' ' : '') + 'Für eine optimale Aufnahme sollte ' + name + ' **' + fix(s.einnahme_mit) + '** eingenommen werden.';
  }
  if (s.einnahme_ohne) {
    einnahme += '\n\n**Bitte beachten:** ' + fix(s.einnahme_ohne) + '.';
  }
  if (s.einnahme_hinweis) {
    einnahme += '\n\n' + fix(s.einnahme_hinweis) + '.';
  }
  if (s.max_einzeldosis) {
    einnahme += '\n\n**Maximale Einzeldosis:** ' + fix(s.max_einzeldosis);
  }
  if (einnahme.trim()) {
    var einnahmeSection = { title: 'Richtige Einnahme', content: einnahme.trim() };
    if (s.beste_form) {
      einnahmeSection.infoBox = { type: 'tip', title: 'Empfohlene Form', content: fix(s.beste_form) };
    }
    sections.push(einnahmeSection);
  }

  // 3. Dosierung wird über renderDosierungBox() als Länderkarten dargestellt (keine Section nötig)

  // 4. Kombinationen — mit Erklärungen
  var kombi = '';
  if (s.kombiniert_gut_mit) {
    var gutMit = s.kombiniert_gut_mit.split(',').map(function(k){ var t=k.trim().replace(/-/g,' '); return t.charAt(0).toUpperCase()+t.slice(1); });
    kombi += name + ' wirkt besonders gut in Kombination mit:\n' + gutMit.map(function(k){ return '• ' + k; }).join('\n') + '\n\n';
  }
  if (s.nicht_zusammen_mit) {
    var nichtMit = s.nicht_zusammen_mit.split(',').map(function(k){ var t=k.trim().replace(/-/g,' '); return t.charAt(0).toUpperCase()+t.slice(1); });
    kombi += '**Nicht gleichzeitig einnehmen mit:**\n' + nichtMit.map(function(k){ return '• ' + k; }).join('\n');
  }
  if (s.zeitlicher_abstand_h && s.zeitlicher_abstand_h !== 'None' && s.zeitlicher_abstand_h !== '0' && s.zeitlicher_abstand_h !== 0) {
    kombi += '\n\nHalte mindestens **' + s.zeitlicher_abstand_h + ' Stunden Abstand** zu den oben genannten Stoffen.';
  }
  // kombinations_hinweis nur zeigen wenn es neue Info enthält (nicht redundant mit nicht_zusammen_mit)
  if (s.kombinations_hinweis && !s.nicht_zusammen_mit) {
    kombi += '\n\n' + fix(s.kombinations_hinweis) + '.';
  }
  if (kombi.trim()) {
    sections.push({ title: 'Kombinationen & Wechselwirkungen', content: kombi.trim() });
  }

  // 5. Bioverfügbarkeit & Qualität
  if (s.bioverfuegbarkeit_info || s.qualitaetsmerkmale) {
    var bio = '';
    if (s.bioverfuegbarkeit_info && s.bioverfuegbarkeit_info !== 'None') {
      bio += fix(s.bioverfuegbarkeit_info) + '.';
    }
    if (s.qualitaetsmerkmale) {
      bio += (bio ? '\n\n' : '') + '**Qualitätsmerkmale:** ' + fix(s.qualitaetsmerkmale) + '.';
    }
    if (bio.trim()) {
      sections.push({ title: 'Bioverfügbarkeit & Qualität', content: bio.trim() });
    }
  }

  // 6. Besondere Zielgruppen
  var zielgruppen = '';
  if (s.schwangerschaft && s.schwangerschaft !== 'Nein') {
    zielgruppen += '**Schwangerschaft & Stillzeit:** ' + fix(s.schwangerschaft);
    if (s.stillzeit && s.stillzeit !== s.schwangerschaft) zielgruppen += ' | Stillzeit: ' + fix(s.stillzeit);
    zielgruppen += '\n\n';
  }
  if (s.kinder_geeignet && s.kinder_geeignet !== 'Nein') {
    zielgruppen += '**Kinder:** ' + fix(s.kinder_geeignet) + '\n\n';
  }
  if (s.senioren_hinweis) {
    zielgruppen += '**Senioren:** ' + fix(s.senioren_hinweis) + '\n\n';
  }
  if (zielgruppen.trim()) {
    sections.push({ title: 'Besondere Zielgruppen', content: zielgruppen.trim() });
  }

  // 7. Warnhinweise — klar und deutlich
  var warn = '';
  if (s.warnhinweise) warn += fix(s.warnhinweise) + '.\n\n';
  if (s.kontraindikationen) warn += '**Nicht einnehmen bei:**\n• ' + fix(s.kontraindikationen).split(',').map(function(k){ return k.trim(); }).join('\n• ') + '\n\n';
  if (s.nebenwirkungen_ueberdosis) warn += '**Bei Überdosierung:**\n' + fix(s.nebenwirkungen_ueberdosis);
  if (s.ueberdosis_symptome && s.ueberdosis_symptome !== s.nebenwirkungen_ueberdosis) {
    warn += (warn ? '\n\n' : '') + '**Symptome einer Überdosierung:** ' + fix(s.ueberdosis_symptome);
  }
  if (warn.trim()) {
    sections.push({ title: 'Sicherheit & Warnhinweise', content: warn.trim() });
  }

  // 8. Natürliche Quellen — als Liste
  if (s.natuerliche_quellen && s.natuerliche_quellen !== 'None') {
    var quellen = fix(s.natuerliche_quellen).split(',').map(function(q){ return '• ' + q.trim(); }).join('\n');
    sections.push({
      title: 'Natürliche Quellen',
      content: name + ' kommt natürlich in folgenden Lebensmitteln vor:\n\n' + quellen
    });
  }

  return sections;
}

// Tags aus den Supabase-Feldern bauen
function _kwBuildTags(s) {
  var tags = [];
  if (s.name) tags.push(s.name);
  if (s.auch_bekannt_als) {
    s.auch_bekannt_als.split(',').slice(0, 3).forEach(function(t) {
      var tag = t.trim();
      if (tag && tag.length < 30) tags.push(tag);
    });
  }
  if (s.symptome_ziele) {
    s.symptome_ziele.split(',').slice(0, 3).forEach(function(t) {
      var tag = t.trim();
      if (tag && tag.length < 25) tags.push(tag.charAt(0).toUpperCase() + tag.slice(1));
    });
  }
  return tags.slice(0, 6);
}

