// ==================== CENTRALIZED USER PROFILE ====================
// This profile is shared across the entire app (Profile screen, Symptom-Checker, etc.)

function getUserProfile() {
  return JSON.parse(localStorage.getItem('suppTreeUserProfile') || '{}');
}

function saveUserProfile(profile) {
  localStorage.setItem('suppTreeUserProfile', JSON.stringify(profile));
}

// Get medications from the central medications system
function getUserMedications() {
  return JSON.parse(localStorage.getItem('suppTreeMedications') || '[]');
}

// Map medication names to supplement-relevant categories
function getMedicationCategories() {
  const meds = getUserMedications();
  const categories = [];
  
  meds.forEach(med => {
    const name = (med.name || '').toLowerCase();
    
    // PPI / Protonenpumpenhemmer
    if (name.includes('pantoprazol') || name.includes('omeprazol') || name.includes('esomeprazol') || 
        name.includes('lansoprazol') || name.includes('rabeprazol') || name.includes('nexium') ||
        name.includes('pantozol') || name.includes('antra')) {
      if (!categories.includes('ppi')) categories.push('ppi');
    }
    
    // Metformin
    if (name.includes('metformin') || name.includes('glucophage') || name.includes('siofor')) {
      if (!categories.includes('metformin')) categories.push('metformin');
    }
    
    // Blutdrucksenker
    if (name.includes('ramipril') || name.includes('lisinopril') || name.includes('enalapril') ||
        name.includes('amlodipin') || name.includes('bisoprolol') || name.includes('metoprolol') ||
        name.includes('valsartan') || name.includes('candesartan')) {
      if (!categories.includes('bloodpressure')) categories.push('bloodpressure');
    }
    
    // Hormonelle Verhütung
    if (name.includes('pille') || name.includes('maxim') || name.includes('evaluna') ||
        name.includes('lamuna') || name.includes('yasmin') || name.includes('minisiston') ||
        name.includes('leona') || name.includes('jubrele') || name.includes('cerazette')) {
      if (!categories.includes('contraceptive')) categories.push('contraceptive');
    }
    
    // Schilddrüse
    if (name.includes('l-thyroxin') || name.includes('euthyrox') || name.includes('thyronajod')) {
      if (!categories.includes('thyroid')) categories.push('thyroid');
    }
    
    // Statine
    if (name.includes('simvastatin') || name.includes('atorvastatin') || name.includes('pravastatin') ||
        name.includes('rosuvastatin') || name.includes('sortis')) {
      if (!categories.includes('statin')) categories.push('statin');
    }
    
    // Antidepressiva
    if (name.includes('sertralin') || name.includes('citalopram') || name.includes('escitalopram') ||
        name.includes('fluoxetin') || name.includes('venlafaxin') || name.includes('mirtazapin')) {
      if (!categories.includes('antidepressant')) categories.push('antidepressant');
    }
  });
  
  return categories;
}

// ==================== MAIN PROFILE SCREEN FUNCTIONS ====================

function updateMainProfileSummary() {
  const container = document.getElementById('mainProfileSummary');
  if (!container) return;
  
  const profile = getUserProfile();
  const meds = getUserMedications();
  const tags = [];
  
  if (profile.age) tags.push(profile.age + ' Jahre');
  if (profile.gender === 'male') tags.push('👨 Männlich');
  if (profile.gender === 'female') tags.push('👩 Weiblich');
  if (profile.diet === 'vegan') tags.push('🌱 Vegan');
  if (profile.diet === 'vegetarian') tags.push('🥬 Vegetarisch');
  if (profile.shiftwork === 'yes') tags.push('🌙 Schichtarbeit');
  if (profile.stress === 'high') tags.push('😰 Hoher Stress');
  if (meds.length > 0) tags.push(`💊 ${meds.length} Medikament${meds.length > 1 ? 'e' : ''}`);
  
  // Calculate completeness
  const fields = ['age', 'gender', 'diet', 'activity', 'stress', 'shiftwork', 'sunlight'];
  let filled = fields.filter(f => profile[f]).length;
  if (meds.length > 0) filled++;
  const percentage = Math.round((filled / (fields.length + 1)) * 100);
  
  if (tags.length === 0) {
    container.innerHTML = `
      <div class="summary-empty">
        <p>Noch keine Gesundheitsdaten hinterlegt</p>
        <p>Dein Profil hilft uns, bessere Empfehlungen zu geben.</p>
      </div>
    `;
  } else {
    container.innerHTML = `
      <div class="summary-tags">
        ${tags.map(t => `<span class="summary-tag">${t}</span>`).join('')}
      </div>
      <div class="completeness-mini">
        <span>${percentage}% vollständig</span>
        <div class="completeness-mini-bar">
          <div class="completeness-mini-fill" style="width: ${percentage}%"></div>
        </div>
      </div>
    `;
  }
}

