function openNutrientInfo(nutrient) {
  // Try to find matching article in knowledge hub
  const info = nutrientInfo[nutrient];
  if (!info) return;
  
  const article = knowledgeArticles.find(a => 
    a.title.toLowerCase().includes(info.name.toLowerCase().split(' ')[0])
  );
  
  if (article) {
    switchScreen('knowledgeScreen');
    setTimeout(() => openKnowledgeArticle(article.id), 300);
  } else {
    showToast('Artikel wird bald verfügbar sein');
  }
}

function showNutrientProducts(nutrient) {
  const info = nutrientInfo[nutrient];
  if (!info) return;
  
  switchScreen('productsScreen');
  setTimeout(() => {
    openProductSearch();
    const searchInput = document.querySelector('.product-search-input');
    if (searchInput) {
      searchInput.value = info.name;
      performProductSearch(info.name);
    }
  }, 300);
}

// ==================== LEXIKON FUNCTIONS ====================

function filterLexikonCategory(category) {
  currentLexikonCategory = category;
  document.querySelectorAll('.lex-cat').forEach(c => c.classList.remove('active'));
  event.target.classList.add('active');
  renderLexikonList();
}

function filterLexikon() {
  renderLexikonList();
}

function renderLexikonList() {
  const container = document.getElementById('lexikonList');
  const searchTerm = document.getElementById('lexikonSearch')?.value?.toLowerCase() || '';
  
  let symptoms = symptomDatabase;
  
  if (currentLexikonCategory !== 'alle') {
    symptoms = symptoms.filter(s => s.category === currentLexikonCategory);
  }
  
  if (searchTerm) {
    symptoms = symptoms.filter(s => 
      s.name.toLowerCase().includes(searchTerm) ||
      s.description.toLowerCase().includes(searchTerm)
    );
  }
  
  if (symptoms.length === 0) {
    container.innerHTML = `
      <div style="text-align: center; padding: 40px; color: var(--text-muted);">
        <span style="font-size: 48px;">🔍</span>
        <p>Keine Symptome gefunden</p>
      </div>
    `;
    return;
  }
  
  container.innerHTML = symptoms.map(s => {
    const nutrientTags = s.nutrients.slice(0, 4).map(n => {
      const info = nutrientInfo[n];
      return info ? `<span class="nutrient-tag">${info.icon} ${info.name}</span>` : '';
    }).join('');
    
    return `
      <div class="lexikon-item" onclick="openSymptomDetail('${s.id}')">
        <div class="lexikon-item-header">
          <div class="lexikon-item-icon">${s.icon}</div>
          <div class="lexikon-item-title">
            <h4>${s.name}</h4>
            <span>${s.description}</span>
          </div>
        </div>
        <div class="lexikon-item-nutrients">
          ${nutrientTags}
          ${s.nutrients.length > 4 ? `<span class="nutrient-tag">+${s.nutrients.length - 4}</span>` : ''}
        </div>
      </div>
    `;
  }).join('');
}

function openSymptomDetail(symptomId) {
  const symptom = symptomDatabase.find(s => s.id === symptomId);
  if (!symptom) return;
  
  const categoryNames = {
    'kopf': 'Kopf & Geist',
    'energie': 'Energie & Schlaf',
    'muskeln': 'Muskeln & Gelenke',
    'haut': 'Haut, Haare, Nägel',
    'verdauung': 'Verdauung',
    'immunsystem': 'Immunsystem',
    'herz': 'Herz & Kreislauf',
    'stimmung': 'Stimmung & Psyche'
  };
  
  document.getElementById('symptomDetailTitle').textContent = symptom.name;
  
  const nutrientsHtml = symptom.nutrients.map(n => {
    const info = nutrientInfo[n];
    if (!info) return '';
    return `
      <div class="detail-nutrient-item" onclick="openNutrientInfo('${n}')">
        <span class="detail-nutrient-icon">${info.icon}</span>
        <div class="detail-nutrient-info">
          <strong>${info.name}</strong>
          <span data-i18n="misc.tapForInfo">Tippen für mehr Infos</span>
        </div>
        <span class="arrow">→</span>
      </div>
    `;
  }).join('');
  
  document.getElementById('symptomDetailContent').innerHTML = `
    <div class="detail-symptom-header">
      <div class="detail-symptom-icon">${symptom.icon}</div>
      <div class="detail-symptom-info">
        <h3>${symptom.name}</h3>
        <span>${categoryNames[symptom.category] || symptom.category}</span>
      </div>
    </div>
    
    <div class="detail-section">
      <h4>📋 Beschreibung</h4>
      <p>${symptom.description}</p>
    </div>
    
    <div class="detail-section">
      <h4>🔬 Hintergrund</h4>
      <p>${symptom.details}</p>
    </div>
    
    <div class="detail-section">
      <h4>💊 Mögliche Nährstoffmängel</h4>
      <div class="detail-nutrients">
        ${nutrientsHtml}
      </div>
    </div>
    
    <div class="disclaimer-box" style="margin-top: 20px;">
      <span class="disclaimer-icon">⚠️</span>
      <p>Diese Informationen dienen nur zu Bildungszwecken und ersetzen keine ärztliche Diagnose.</p>
    </div>
  `;
  
  document.getElementById('symptomDetailOverlay').classList.add('active');
  document.getElementById('symptomDetailSheet').classList.add('active');
  lockBody();
}

function closeSymptomDetail() {
  document.getElementById('symptomDetailOverlay').classList.remove('active');
  document.getElementById('symptomDetailSheet').classList.remove('active');
  unlockBody();
}

function showSymptomInfo() {
  showToast('Der Symptom-Checker hilft dir, mögliche Nährstoffmängel zu identifizieren.');
}

