let mySupplements = [];

// Migrate old supplement structure to new consistent structure
function migrateSupplementStructure(supp) {
  // Auto-detect form from name if not set
  let form = supp.form;
  if (!form) {
    const name = (supp.name || '').toLowerCase();
    if (name.includes('tropfen') || name.includes('drops') || name.includes('öl')) {
      form = 'drops';
    } else if (name.includes('spray')) {
      form = 'spray';
    } else if (name.includes('pulver') || name.includes('powder') || name.includes('kreatin') || name.includes('creatine')) {
      form = 'powder';
    } else if (name.includes('softgel') || name.includes('fischöl') || name.includes('fish oil') || name.includes('omega')) {
      form = 'softgel';
    } else if (name.includes('gummi') || name.includes('gummy')) {
      form = 'gummy';
    } else if (name.includes('lutsch') || name.includes('lozenge')) {
      form = 'lozenge';
    } else if (name.includes('tablette') || name.includes('tablet')) {
      form = 'tablet';
    } else {
      form = 'capsule';
    }
  }
  
  // If already has correct structure with valid stock, return as is but ensure form is included
  if (supp.dosagePerDay !== undefined && supp.stock !== undefined && supp.packSize !== undefined) {
    // Just validate dosagePerDay
    const dosage = Math.min(supp.dosagePerDay, 6);
    return {
      ...supp,
      dosagePerDay: dosage,
      form: form,
      doseUnit: supp.doseUnit || null
    };
  }
  
  // Get dosagePerDay from either field, with validation
  let dosage = supp.dosePerDay || supp.dosagePerDay || 1;
  
  // Validate dosagePerDay - max 6 per day is realistic for any supplement
  if (dosage > 6) {
    dosage = 1;
  }
  
  // Get stock value - prioritize actual stock count over percentage
  let stock;
  if (supp.stock !== undefined && supp.stock > 0) {
    stock = supp.stock;
  } else if (supp.currentStock !== undefined) {
    // currentStock is typically a percentage (0-100), convert to actual count
    const packSize = supp.packSize || 60;
    stock = Math.round((supp.currentStock / 100) * packSize);
  } else {
    stock = 60; // Default full pack
  }
  
  return {
    id: supp.id,
    name: supp.name,
    icon: supp.icon || '💊',
    brand: supp.brand || '',
    dosagePerDay: dosage,
    stock: stock > 0 ? stock : 60,
    packSize: supp.packSize || 60,
    source: supp.source || 'shop',
    time: supp.time || 'auto',
    autoAbo: supp.autoAbo || supp.hasAbo || false,
    roburScheduled: supp.roburScheduled !== false,
    hasAbo: supp.hasAbo || supp.autoAbo || false,
    notes: supp.notes || '',
    form: form,
    doseUnit: supp.doseUnit || null
  };
}

// Ensure supplements are loaded from localStorage
async function ensureSupplementsLoaded() {
  // Supabase: versuche zuerst von Supabase zu laden (wenn eingeloggt)
  if (supabase && currentUser) {
    try {
      const { data } = await supabase
        .from('my_supplements')
        .select('*')
        .eq('user_id', currentUser.id);
      if (data && data.length > 0) {
        mySupplements = data.map(s => ({
          id: s.id, name: s.name, brand: s.brand, icon: s.icon,
          form: s.dosage_form, dosagePerDay: s.doses_per_day,
          times: [s.take_morning && 'morning', s.take_noon && 'noon',
                  s.take_evening && 'evening', s.take_night && 'night'].filter(Boolean),
          status: s.status, stock: s.current_stock, notes: s.notes
        }));
        localStorage.setItem('suppTreeMySupplements', JSON.stringify(mySupplements));
        syncAbosToSupplements();
        return;
      }
    } catch(e) {
      console.warn('Supabase supplements load failed, using localStorage:', e);
    }
  }

  // Demo-Modus / Fallback: localStorage
  const saved = localStorage.getItem('suppTreeMySupplements');
  if (saved) {
    const parsed = JSON.parse(saved);
    mySupplements = Array.isArray(parsed) ? parsed.map(migrateSupplementStructure) : [];
    saveMySupplements();
  } else if (!localStorage.getItem('suppTreeWasReset')) {
    // Only load demo data if never reset
    mySupplements = [
      { id: 'vitd3', name: 'Vitamin D3 5000 I.E.', brand: 'PureVital', icon: '☀️', source: 'shop', dosagePerDay: 1, form: 'tablet', stock: 45, packSize: 60, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'magnesium', name: 'Magnesium Citrat 400mg', brand: 'NaturPlus', icon: '⚡', source: 'shop', dosagePerDay: 2, form: 'capsule', stock: 12, packSize: 60, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'omega3', name: 'Omega 3 Fischöl', brand: 'DM Bio', icon: '🐟', source: 'external', dosagePerDay: 2, form: 'softgel', stock: 36, packSize: 60, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'zink', name: 'Zink 25mg', brand: 'SuppTree Essentials', icon: '🛡️', source: 'shop', dosagePerDay: 1, form: 'tablet', stock: 24, packSize: 30, time: 'auto', autoAbo: true, aboThreshold: 14, roburScheduled: true },
      { id: 'bcomplex', name: 'Vitamin B-Komplex', brand: 'VitaMax', icon: '🧬', source: 'shop', dosagePerDay: 1, form: 'capsule', stock: 3, packSize: 90, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'melatonin', name: 'Melatonin 1mg', brand: 'Rossmann', icon: '😴', source: 'external', dosagePerDay: 1, form: 'tablet', stock: 54, packSize: 60, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'ashwagandha', name: 'Ashwagandha KSM-66', brand: 'Natural Elements', icon: '🌿', source: 'external', dosagePerDay: 2, form: 'capsule', stock: 40, packSize: 60, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'iron', name: 'Eisen 14mg', brand: 'SuppTree Essentials', icon: '🩸', source: 'shop', dosagePerDay: 1, form: 'capsule', stock: 28, packSize: 30, time: 'auto', autoAbo: true, aboThreshold: 7, roburScheduled: true },
      { id: 'vitamin-d-drops', name: 'Vitamin D3 Tropfen', brand: 'Sunday Natural', icon: '☀️', source: 'external', dosagePerDay: 10, form: 'drops', stock: 200, packSize: 500, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'melatonin-spray', name: 'Melatonin Spray', brand: 'PureVital', icon: '😴', source: 'shop', dosagePerDay: 2, form: 'spray', stock: 60, packSize: 120, time: 'auto', autoAbo: false, roburScheduled: true },
      { id: 'kreatin', name: 'Creapure® Kreatin', brand: 'CoreLabs', icon: '💪', source: 'shop', dosagePerDay: 1, form: 'powder', doseUnit: '5g (1 Messlöffel)', stock: 50, packSize: 100, time: 'auto', autoAbo: false, roburScheduled: true }
    ];
    saveMySupplements();
  } else {
    mySupplements = [];
  }
  
  // Sync active subscriptions to mySupplements
  syncAbosToSupplements();
}

// Ensure all active Abos are also in mySupplements
function syncAbosToSupplements() {
  if (typeof subscriptions === 'undefined' || !subscriptions) return;
  
  let added = false;
  
  subscriptions.forEach((sub, productId) => {
    // Only sync active abos (not pending or cancelled)
    if (sub.status !== 'active' && sub.status !== 'paused') return;
    
    // Check if already in mySupplements
    const exists = mySupplements.some(s => s.id === productId);
    if (exists) return;
    
    // Find product info
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    // Add to mySupplements with correct structure
    const dosage = Math.min(sub.dosePerDay || 1, 6); // Max 6 per day
    
    mySupplements.push({
      id: product.id,
      name: product.name,
      icon: product.icon,
      brand: product.brand,
      dosagePerDay: dosage,
      stock: 60,
      packSize: 60,
      source: 'shop',
      time: 'auto',
      autoAbo: true,
      roburScheduled: true,
      hasAbo: true,
      notes: 'Abo-Produkt'
    });
    
    added = true;
    
  });
  
  if (added) {
    saveMySupplements();
  }
}

