// Check supplement name against interaction keywords
function matchesInteractionKeyword(suppName, keywords) {
  const nameLower = suppName.toLowerCase();
  return keywords.some(keyword => nameLower.includes(keyword.toLowerCase()));
}

// Check for interactions when user selects time slots
function checkSupplementInteractions() {
  const warningArea = document.getElementById('interactionWarningArea');
  if (!warningArea || !currentSupplementId) return;
  
  const currentSupp = mySupplements.find(s => s.id === currentSupplementId);
  if (!currentSupp) return;
  
  // Get selected time slots
  const selectedSlots = Array.from(document.querySelectorAll('input[name="timeSlot"]:checked'))
    .map(cb => cb.value);
  
  if (selectedSlots.length === 0) {
    warningArea.style.display = 'none';
    return;
  }
  
  // Find other supplements in the same time slots
  const conflictingSupps = mySupplements.filter(s => {
    if (s.id === currentSupplementId) return false;
    if (!s.timeSlots || s.timeSlots.length === 0) return false;
    return s.timeSlots.some(slot => selectedSlots.includes(slot));
  });
  
  if (conflictingSupps.length === 0) {
    warningArea.style.display = 'none';
    return;
  }
  
  // Check for interactions
  let foundInteractions = [];
  
  conflictingSupps.forEach(otherSupp => {
    // Check negative interactions
    supplementInteractions.negative.forEach(interaction => {
      const currentMatches = matchesInteractionKeyword(currentSupp.name, interaction.supplements);
      const otherMatchesConflict = matchesInteractionKeyword(otherSupp.name, interaction.conflicts);
      
      const currentMatchesConflict = matchesInteractionKeyword(currentSupp.name, interaction.conflicts);
      const otherMatches = matchesInteractionKeyword(otherSupp.name, interaction.supplements);
      
      if ((currentMatches && otherMatchesConflict) || (currentMatchesConflict && otherMatches)) {
        foundInteractions.push({
          type: 'negative',
          severity: interaction.severity,
          supp1: currentSupp,
          supp2: otherSupp,
          reason: interaction.reason,
          recommendation: interaction.recommendation
        });
      }
    });
    
    // Check positive interactions (synergies)
    supplementInteractions.positive.forEach(interaction => {
      const currentMatches = matchesInteractionKeyword(currentSupp.name, interaction.supplements);
      const otherMatchesSynergy = matchesInteractionKeyword(otherSupp.name, interaction.synergies);
      
      const currentMatchesSynergy = matchesInteractionKeyword(currentSupp.name, interaction.synergies);
      const otherMatches = matchesInteractionKeyword(otherSupp.name, interaction.supplements);
      
      if ((currentMatches && otherMatchesSynergy) || (currentMatchesSynergy && otherMatches)) {
        foundInteractions.push({
          type: 'positive',
          benefit: interaction.benefit,
          supp1: currentSupp,
          supp2: otherSupp,
          reason: interaction.reason,
          recommendation: interaction.recommendation
        });
      }
    });
  });
  
  // Display interactions
  if (foundInteractions.length === 0) {
    warningArea.style.display = 'none';
    return;
  }
  
  // Prioritize negative interactions
  const negativeInteractions = foundInteractions.filter(i => i.type === 'negative');
  const positiveInteractions = foundInteractions.filter(i => i.type === 'positive');
  
  let html = '';
  
  // Show negative interactions first
  if (negativeInteractions.length > 0) {
    html += `
      <div class="interaction-warning-header">
        <span class="warn-icon">⚠️</span>
        <h4>Mögliche Wechselwirkung</h4>
      </div>
    `;
    
    negativeInteractions.forEach(interaction => {
      html += `
        <div class="interaction-conflict">
          <div class="conflict-supplements">
            <span class="conflict-supp">
              <span class="supp-icon">${interaction.supp1.icon}</span>
              ${interaction.supp1.name.split(' ').slice(0, 2).join(' ')}
            </span>
            <span class="conflict-plus">+</span>
            <span class="conflict-supp">
              <span class="supp-icon">${interaction.supp2.icon}</span>
              ${interaction.supp2.name.split(' ').slice(0, 2).join(' ')}
            </span>
          </div>
          <p class="conflict-reason">❌ ${interaction.reason}</p>
          <div class="conflict-recommendation">
            <span class="rec-icon">💡</span>
            <p>${interaction.recommendation}</p>
          </div>
        </div>
      `;
    });
    
    html += `
      <div class="interaction-actions">
        <button class="interaction-btn accept" onclick="applyInteractionRecommendation()">
          ✓ Empfehlung übernehmen
        </button>
        <button class="interaction-btn ignore" onclick="ignoreInteractionWarning()">
          Trotzdem zusammen
        </button>
      </div>
    `;
    
    warningArea.className = 'interaction-warning-area';
  } 
  // Show positive interactions if no negative ones
  else if (positiveInteractions.length > 0) {
    html += `
      <div class="interaction-warning-header">
        <span class="warn-icon">✅</span>
        <h4>Gute Kombination!</h4>
      </div>
    `;
    
    positiveInteractions.forEach(interaction => {
      html += `
        <div class="interaction-conflict">
          <div class="conflict-supplements">
            <span class="conflict-supp">
              <span class="supp-icon">${interaction.supp1.icon}</span>
              ${interaction.supp1.name.split(' ').slice(0, 2).join(' ')}
            </span>
            <span class="conflict-plus" style="color: #16a34a;">+</span>
            <span class="conflict-supp">
              <span class="supp-icon">${interaction.supp2.icon}</span>
              ${interaction.supp2.name.split(' ').slice(0, 2).join(' ')}
            </span>
          </div>
          <p class="conflict-reason" style="color: #166534;">✓ ${interaction.reason}</p>
        </div>
      `;
    });
    
    warningArea.className = 'interaction-warning-area positive';
  }
  
  warningArea.innerHTML = html;
  warningArea.style.display = 'block';
}

// Apply the recommended time separation
function applyInteractionRecommendation() {
  // Uncheck all slots and suggest alternative
  const checkboxes = document.querySelectorAll('input[name="timeSlot"]:checked');
  checkboxes.forEach(cb => cb.checked = false);
  
  // Select 'abends' as alternative if 'morgens' was selected, vice versa
  const eveningCheckbox = document.querySelector('input[name="timeSlot"][value="evening"]');
  if (eveningCheckbox) {
    eveningCheckbox.checked = true;
  }
  
  checkSupplementInteractions();
  showToast('Zeitslot angepasst! ✓');
}

// Ignore the warning
function ignoreInteractionWarning() {
  const warningArea = document.getElementById('interactionWarningArea');
  if (warningArea) {
    warningArea.style.display = 'none';
  }
  showToast('Du kannst die Zeit jederzeit ändern');
}

