// Get supplement rules by name
function getSupplementRules(name) {
  const nameLower = name.toLowerCase();
  for (const [key, rules] of Object.entries(supplementRules)) {
    if (nameLower.includes(key)) {
      return { ...rules, matched: key };
    }
  }
  // Default rules
  return {
    bestTime: 'morning',
    withFood: true,
    warnings: [],
    avoidWith: [],
    idealTiming: { early: '+30min', day: '+30min', late: '+30min', night: '+30min' },
    matched: null
  };
}

// Calculate optimal intake time based on shift
function calculateOptimalTime(supplement, shiftType, shiftConfig) {
  const rules = getSupplementRules(supplement.name);
  const shift = shiftConfig[shiftType] || shiftConfig.off;
  
  // Get wake and sleep times from config
  const wakeTime = shift.wake || '08:00';
  const sleepTime = shift.sleep || '23:00';
  const shiftStart = shift.start;
  const shiftEnd = shift.end;
  
  // Calculate midday (middle between wake and sleep)
  const middayTime = calculateMidday(wakeTime, sleepTime);
  
  // No shift data - use wake/sleep times
  if (!shiftStart) {
    const relativeTimes = {
      morning: addMinutesToTime(wakeTime, 30),  // 30 min after wake
      evening: addMinutesToTime(sleepTime, -180), // 3h before sleep
      night: addMinutesToTime(sleepTime, -30),   // 30 min before sleep
      any: addMinutesToTime(wakeTime, 60)        // 1h after wake
    };
    return {
      time: relativeTimes[rules.bestTime] || addMinutesToTime(wakeTime, 30),
      reason: 'Nach dem Aufstehen',
      warnings: rules.warnings,
      withFood: rules.withFood,
      coffeeRestriction: rules.coffeeRestriction
    };
  }
  
  const timing = rules.idealTiming[shiftType] || 'aufstehen';
  
  let calculatedTime;
  let reason;
  
  // Parse timing instruction
  if (timing.startsWith('+')) {
    // After shift start
    const minutes = parseInt(timing.substring(1)) || 30;
    calculatedTime = addMinutesToTime(shiftStart, minutes);
    reason = `${minutes} Min. nach Schichtbeginn`;
  } else if (timing.startsWith('-')) {
    // Before shift start
    const minutes = parseInt(timing.substring(1)) || 30;
    calculatedTime = addMinutesToTime(shiftStart, -minutes);
    reason = `${minutes} Min. vor Schichtbeginn`;
  } else {
    // Named timing - NOW USING WAKE/SLEEP TIMES
    switch(timing) {
      case 'aufstehen':
        calculatedTime = addMinutesToTime(wakeTime, 30);
        reason = 'Nach dem Aufstehen';
        break;
      case 'fruehstueck':
        calculatedTime = addMinutesToTime(wakeTime, 45);
        reason = 'Mit dem Frühstück';
        break;
      case 'mittag':
        calculatedTime = middayTime;
        reason = 'Zur Mittagszeit';
        break;
      case 'abends':
        calculatedTime = addMinutesToTime(sleepTime, -180);
        reason = 'Am Abend';
        break;
      case 'abendessen':
        calculatedTime = addMinutesToTime(sleepTime, -150);
        reason = 'Mit dem Abendessen';
        break;
      case 'vorschlaf':
        calculatedTime = addMinutesToTime(sleepTime, -30);
        reason = 'Vor dem Schlafengehen';
        break;
      case 'schichtende':
        calculatedTime = shiftEnd || addMinutesToTime(sleepTime, -120);
        reason = 'Nach Schichtende';
        break;
      case 'schichtstart':
        calculatedTime = shiftStart || addMinutesToTime(wakeTime, 60);
        reason = 'Zu Schichtbeginn';
        break;
      case 'nachschlaf':
        // After night shift sleep period
        calculatedTime = addMinutesToTime(wakeTime, 30);
        reason = 'Nach dem Aufwachen';
        break;
      default:
        calculatedTime = addMinutesToTime(wakeTime, 30);
        reason = 'Nach dem Aufstehen';
    }
  }
  
  return {
    time: calculatedTime,
    reason: reason,
    warnings: rules.warnings,
    withFood: rules.withFood,
    coffeeRestriction: rules.coffeeRestriction
  };
}

// Calculate midday between wake and sleep times
function calculateMidday(wakeTime, sleepTime) {
  const [wakeH, wakeM] = wakeTime.split(':').map(Number);
  const [sleepH, sleepM] = sleepTime.split(':').map(Number);
  
  let wakeMinutes = wakeH * 60 + wakeM;
  let sleepMinutes = sleepH * 60 + sleepM;
  
  // Handle overnight sleep (e.g., wake at 19:00, sleep at 08:00)
  if (sleepMinutes < wakeMinutes) {
    sleepMinutes += 24 * 60;
  }
  
  const middayMinutes = Math.floor((wakeMinutes + sleepMinutes) / 2) % (24 * 60);
  const middayH = Math.floor(middayMinutes / 60);
  const middayM = middayMinutes % 60;
  
  return `${String(middayH).padStart(2, '0')}:${String(middayM).padStart(2, '0')}`;
}

// Add minutes to time string
function addMinutesToTime(timeStr, minutes) {
  const [hours, mins] = timeStr.split(':').map(Number);
  let totalMins = hours * 60 + mins + minutes;
  
  // Handle overflow/underflow
  while (totalMins < 0) totalMins += 24 * 60;
  totalMins = totalMins % (24 * 60);
  
  const newHours = Math.floor(totalMins / 60);
  const newMins = totalMins % 60;
  
  return `${String(newHours).padStart(2, '0')}:${String(newMins).padStart(2, '0')}`;
}

// Calculate intelligent distribution of capsules across the day
function calculateDistribution(totalCapsules, preferredSlot, rules, isSleepSupp, isEnergySupp) {
  const distributions = [];
  
  // Define slot order based on supplement type
  let slotOrder;
  if (isSleepSupp) {
    // Sleep supplements: prefer evening/night, avoid morning
    slotOrder = ['evening', 'night'];
  } else if (isEnergySupp) {
    // Energy supplements: prefer morning/noon, avoid night
    slotOrder = ['morning', 'noon'];
  } else {
    // Normal supplements: spread across day
    slotOrder = ['morning', 'noon', 'evening'];
  }
  
  // Distribute capsules
  if (totalCapsules === 2) {
    // 2 capsules: split evenly
    distributions.push({
      slot: slotOrder[0],
      count: 1,
      reason: slotOrder[0] === 'morning' ? 'Morgens (1/2)' : slotOrder[0] === 'noon' ? 'Mittags (1/2)' : 'Abends (1/2)'
    });
    distributions.push({
      slot: slotOrder[1] || slotOrder[0],
      count: 1,
      reason: slotOrder[1] === 'noon' ? 'Mittags (2/2)' : slotOrder[1] === 'evening' ? 'Abends (2/2)' : slotOrder[1] === 'night' ? 'Nachts (2/2)' : 'Später (2/2)'
    });
  } else if (totalCapsules === 3) {
    // 3 capsules: morning, noon, evening/night
    distributions.push({ slot: slotOrder[0], count: 1, reason: 'Morgens (1/3)' });
    distributions.push({ slot: slotOrder[1] || 'noon', count: 1, reason: 'Mittags (2/3)' });
    distributions.push({ slot: slotOrder[2] || 'evening', count: 1, reason: 'Abends (3/3)' });
  } else if (totalCapsules === 4) {
    // 4 capsules: 2 morning, 2 evening
    distributions.push({ slot: slotOrder[0], count: 2, reason: 'Morgens (2 Stk.)' });
    distributions.push({ slot: slotOrder[slotOrder.length - 1], count: 2, reason: isSleepSupp ? 'Abends (2 Stk.)' : 'Abends (2 Stk.)' });
  } else if (totalCapsules >= 5) {
    // 5+ capsules: distribute more evenly
    const perSlot = Math.floor(totalCapsules / 3);
    const remainder = totalCapsules % 3;
    
    distributions.push({ 
      slot: slotOrder[0], 
      count: perSlot + (remainder > 0 ? 1 : 0), 
      reason: `Morgens (${perSlot + (remainder > 0 ? 1 : 0)} Stk.)` 
    });
    distributions.push({ 
      slot: 'noon', 
      count: perSlot + (remainder > 1 ? 1 : 0), 
      reason: `Mittags (${perSlot + (remainder > 1 ? 1 : 0)} Stk.)` 
    });
    distributions.push({ 
      slot: slotOrder[slotOrder.length - 1] || 'evening', 
      count: perSlot, 
      reason: `Abends (${perSlot} Stk.)` 
    });
  }
  
  return distributions;
}

// Schedule supplements for a date
function scheduleSupplementsForDate(dateStr) {
  const shiftType = shifts[dateStr] || 'off';
  const shift = shiftConfig[shiftType] || shiftConfig.off;
  
  // Get wake and sleep times for this shift
  const wakeTime = shift.wake || '08:00';
  const sleepTime = shift.sleep || '23:00';
  const middayTime = calculateMidday(wakeTime, sleepTime);
  
  // Define FIXED time slots based on shift wake/sleep times
  const timeSlots = {
    'morning': addMinutesToTime(wakeTime, 30),      // 30 min after wake
    'noon': middayTime,                              // Midday
    'evening': addMinutesToTime(sleepTime, -180),   // 3h before sleep
    'night': addMinutesToTime(sleepTime, -30)       // 30 min before sleep
  };
  
  // Labels for the slots - now as functions that consider withFood
  const skipBreakfast = localStorage.getItem('suppTreeSkipBreakfast') === 'true';
  
  function getSlotLabel(slot, withFood) {
    if (slot === 'morning') {
      if (skipBreakfast) return 'Morgens (nüchtern)';
      return withFood ? 'Mit dem Frühstück' : 'Vor dem Frühstück';
    }
    if (slot === 'noon') {
      return withFood ? 'Mit dem Mittagessen' : 'Vor dem Mittagessen';
    }
    if (slot === 'evening') {
      return withFood ? 'Mit dem Abendessen' : 'Am Abend';
    }
    if (slot === 'night') {
      return 'Vor dem Schlafen';
    }
    return 'Zur optimalen Zeit';
  }
  
  // Filter out waiting supplements - only schedule active ones
  const activeSupplements = mySupplements.filter(s => s.status !== 'waiting');
  
  // Collect all supplement intakes - ONE entry per supplement
  const intakesBySlot = {
    'morning': [],
    'noon': [],
    'evening': [],
    'night': []
  };
  
  activeSupplements.forEach(supp => {
    const totalCapsules = supp.dosagePerDay || 1;
    const rules = getSupplementRules(supp.name);
    
    // Check user preference for distribution
    const distributionMode = supp.distributionMode || 'auto'; // 'auto', 'all-at-once', 'custom'
    const customSchedule = supp.customSchedule || null;
    
    // Use custom schedule if set
    if (distributionMode === 'custom' && customSchedule && customSchedule.length > 0) {
      customSchedule.forEach(entry => {
        const slotTime = entry.time || timeSlots['morning'];
        // Find closest slot or create custom
        let targetSlot = 'morning';
        const entryMinutes = timeToMinutes(entry.time);
        let minDiff = Infinity;
        Object.keys(timeSlots).forEach(slot => {
          const diff = Math.abs(timeToMinutes(timeSlots[slot]) - entryMinutes);
          if (diff < minDiff) {
            minDiff = diff;
            targetSlot = slot;
          }
        });
        
        intakesBySlot[targetSlot].push({
          suppId: supp.id,
          name: supp.name,
          icon: supp.icon,
          reason: entry.reason || 'Individuell eingestellt',
          reasonDetail: entry.reasonDetail || 'Du hast diese Zeit selbst gewählt.',
          warnings: rules.warnings || [],
          withFood: entry.withFood !== undefined ? entry.withFood : rules.withFood,
          coffeeRestriction: rules.coffeeRestriction,
          capsules: entry.count || totalCapsules,
          form: supp.form || 'capsule',
          doseUnit: supp.doseUnit || null,
          customTime: entry.time, // Override slot time
          doseIndex: entry.index || 1,
          totalDoses: customSchedule.length
        });
      });
      return; // Skip auto-scheduling
    }
    
    // Determine best slot based on supplement type
    let bestSlot = 'morning';
    
    // Check if user skips breakfast
    const skipBreakfast = localStorage.getItem('suppTreeSkipBreakfast') === 'true';
    
    // Sleep-related supplements → night slot
    const sleepSupps = ['melatonin', 'magnesium', 'glycin', 'ashwagandha', 'baldrian', 'passionsblume', 'l-theanin', 'gaba'];
    const isSleepSupp = sleepSupps.some(s => supp.name.toLowerCase().includes(s));
    if (isSleepSupp) {
      bestSlot = 'night';
    }
    
    // Energy supplements → morning slot
    const energySupps = ['koffein', 'caffeine', 'b-vitamin', 'b12', 'b-komplex', 'eisen', 'iron', 'coq10', 'rhodiola', 'ginseng'];
    const isEnergySupp = energySupps.some(s => supp.name.toLowerCase().includes(s));
    if (isEnergySupp) {
      bestSlot = 'morning';
    }
    
    // Fat-soluble vitamins → with meal (morning or noon)
    const fatSoluble = ['vitamin d', 'd3', 'vitamin e', 'vitamin a', 'vitamin k', 'omega', 'fischöl', 'fish oil', 'k2'];
    const isFatSoluble = fatSoluble.some(s => supp.name.toLowerCase().includes(s));
    if (isFatSoluble) {
      // If user skips breakfast, move to noon
      bestSlot = skipBreakfast && rules.bestTimeNoBreakfast ? rules.bestTimeNoBreakfast : 'morning';
    }
    
    // Kreatin - can be any time, but morning is common
    if (supp.name.toLowerCase().includes('kreatin') || supp.name.toLowerCase().includes('creatine')) {
      bestSlot = 'morning';
    }
    
    // Manual override if user set a relative time
    if (!supp.roburScheduled && supp.relativeTime) {
      bestSlot = supp.relativeTime;
    }
    
    // INTELLIGENT DISTRIBUTION LOGIC
    const canSplit = rules.canSplit !== false;
    const splitThreshold = rules.splitThreshold || 3;
    const shouldSplit = canSplit && totalCapsules >= splitThreshold && distributionMode !== 'all-at-once';
    
    if (shouldSplit && distributionMode === 'auto') {
      // Distribute capsules across multiple times
      const distributions = calculateDistribution(totalCapsules, bestSlot, rules, isSleepSupp, isEnergySupp);
      
      distributions.forEach((dist, idx) => {
        intakesBySlot[dist.slot].push({
          suppId: supp.id,
          name: supp.name,
          icon: supp.icon,
          reason: dist.reason,
          reasonDetail: rules.splitReason || 'Verteilung verbessert die Aufnahme.',
          warnings: rules.warnings || [],
          withFood: rules.withFood || isFatSoluble,
          coffeeRestriction: isSleepSupp && supp.name.toLowerCase().includes('melatonin') ? 8 : rules.coffeeRestriction,
          capsules: dist.count,
          form: supp.form || 'capsule',
          doseUnit: supp.doseUnit || null,
          doseIndex: idx + 1,
          totalDoses: distributions.length
        });
      });
    } else {
      // Single intake - all capsules at once
      let reasonDetail = rules.singleReason || rules.optimalTimeReason || 'Optimaler Zeitpunkt basierend auf dem Supplement-Typ.';
      const withFood = rules.withFood || isFatSoluble;
      let reason = getSlotLabel(bestSlot, withFood);
      
      // Special handling for fat-soluble vitamins when skipping breakfast
      if (isFatSoluble && skipBreakfast && bestSlot === 'noon') {
        reason = 'Mit dem Mittagessen';
        reasonDetail = rules.noBreakfastTip || 'Mit einer fetthaltigen Mahlzeit einnehmen.';
      }
      
      intakesBySlot[bestSlot].push({
        suppId: supp.id,
        name: supp.name,
        icon: supp.icon,
        reason: reason,
        reasonDetail: reasonDetail,
        warnings: rules.warnings || [],
        withFood: withFood,
        coffeeRestriction: isSleepSupp && supp.name.toLowerCase().includes('melatonin') ? 8 : rules.coffeeRestriction,
        capsules: totalCapsules,
        form: supp.form || 'capsule',
        doseUnit: supp.doseUnit || null,
        doseIndex: 1,
        totalDoses: 1
      });
    }
  });
  
  // Convert to flat array with EXACT slot times
  const intakes = [];
  
  Object.keys(intakesBySlot).forEach(slot => {
    const slotTime = timeSlots[slot];
    const items = intakesBySlot[slot];
    
    items.forEach(item => {
      intakes.push({
        ...item,
        slot: slot,
        time: slotTime,
        taken: false
      });
    });
  });
  
  // Sort by time
  intakes.sort((a, b) => {
    const aMin = timeToMinutes(a.time);
    const bMin = timeToMinutes(b.time);
    return aMin - bMin;
  });
  
  return intakes;
}

// Helper: Convert time string to minutes
function timeToMinutes(timeStr) {
  if (!timeStr) return 0;
  const [h, m] = timeStr.split(':').map(Number);
  return h * 60 + m;
}

// Update scheduled intakes for next 30 days
// Update scheduled intakes for next 30 days
function updateAllScheduledIntakes() {
  scheduledIntakes = {};
  const today = new Date();
  
  for (let i = 0; i < 30; i++) {
    const date = new Date(today);
    date.setDate(date.getDate() + i);
    const dateStr = formatDate(date);
    scheduledIntakes[dateStr] = scheduleSupplementsForDate(dateStr);
  }
  
  // Save to localStorage
  localStorage.setItem('suppTreeScheduledIntakes', JSON.stringify(scheduledIntakes));
}

// Load scheduled intakes - always recalculate to ensure shift changes are reflected
function loadScheduledIntakes() {
  // Always recalculate instead of using cache - this ensures shift changes are applied
  updateAllScheduledIntakes();
}

function initMySupplements() {
  // Ensure supplements are loaded
  ensureSupplementsLoaded();
  
  // Migrate old data structure if needed
  let needsSave = false;
  mySupplements = mySupplements.map(supp => {
    let updated = { ...supp };
    
    // Migrate basic fields
    if (!supp.dosagePerDay || !supp.stock) {
      needsSave = true;
      updated = {
        ...updated,
        dosagePerDay: supp.dosagePerDay || 1,
        stock: supp.stock || 60,
        packSize: supp.packSize || 60,
        source: supp.source || 'external',
        time: supp.time || 'auto',
        autoAbo: supp.autoAbo || false,
        roburScheduled: supp.roburScheduled !== false
      };
    }
    
    // Migrate form field - guess based on product name
    if (!supp.form) {
      needsSave = true;
      const name = (supp.name || '').toLowerCase();
      if (name.includes('tropfen') || name.includes('drops') || name.includes('öl')) {
        updated.form = 'drops';
      } else if (name.includes('spray')) {
        updated.form = 'spray';
      } else if (name.includes('pulver') || name.includes('powder') || name.includes('kreatin') || name.includes('creatine')) {
        updated.form = 'powder';
      } else if (name.includes('softgel') || name.includes('fischöl') || name.includes('fish oil') || name.includes('omega')) {
        updated.form = 'softgel';
      } else if (name.includes('gummi') || name.includes('gummy')) {
        updated.form = 'gummy';
      } else if (name.includes('lutsch') || name.includes('lozenge')) {
        updated.form = 'lozenge';
      } else {
        updated.form = 'capsule'; // Default
      }
    }
    
    return updated;
  });
  
  if (needsSave) {
    saveMySupplements();
  }
  
  loadScheduledIntakes();
  updateAllScheduledIntakes();
  renderMySupplements('all');
  updateSupplementStats();
}

function saveMySupplements() {
  localStorage.setItem('suppTreeMySupplements', JSON.stringify(mySupplements));
  if (supabase && currentUser) {
    DataStore.set('my_supplements', 'suppTreeMySupplements', mySupplements, {
      replaceAll: true,
      transform: (s) => ({
        user_id: currentUser.id,
        name: s.name,
        brand: s.brand,
        icon: s.icon || '💊',
        dosage_form: s.form || s.dosageForm,
        dosage_amount: s.dosage || (s.dosagePerDay ? String(s.dosagePerDay) : null),
        doses_per_day: s.dosagePerDay || s.dosePerDay || 1,
        take_morning: s.time === 'morning' || (s.times && s.times.includes('morning')),
        take_noon: s.time === 'noon' || (s.times && s.times.includes('noon')),
        take_evening: s.time === 'evening' || (s.times && s.times.includes('evening')),
        take_night: s.time === 'night' || (s.times && s.times.includes('night')),
        status: s.status || 'active',
        current_stock: s.stock,
        notes: s.notes
      })
    }).catch(e => console.error('Supplements sync error:', e));
  }
}

