function startBarcodeScanner() {
  const viewport = document.getElementById('scannerViewport');
  
  if (typeof Quagga === 'undefined') {
    document.getElementById('scannerStatus').textContent = t('scanner.notAvailable') || 'Scanner nicht verfügbar. Bitte manuell eingeben.';
    return;
  }
  
  Quagga.init({
    inputStream: {
      name: "Live",
      type: "LiveStream",
      target: viewport,
      constraints: {
        width: { min: 640 },
        height: { min: 480 },
        facingMode: "environment" // Rückkamera
      }
    },
    locator: {
      patchSize: "medium",
      halfSample: true
    },
    numOfWorkers: navigator.hardwareConcurrency || 4,
    decoder: {
      readers: [
        "ean_reader",      // EAN-13
        "ean_8_reader",    // EAN-8
        "upc_reader",      // UPC-A
        "upc_e_reader"     // UPC-E
      ]
    },
    locate: true
  }, function(err) {
    if (err) {
      console.error('Quagga init error:', err);
      document.getElementById('scannerStatus').textContent = t('scanner.denied') || 'Kamera-Zugriff verweigert. Bitte manuell eingeben.';
      return;
    }
    
    Quagga.start();
    scannerActive = true;
    document.getElementById('scannerStatus').textContent = t('scanner.holdBarcode') || 'Barcode in den Rahmen halten...';
  });
  
  // Barcode detected handler
  Quagga.onDetected(function(result) {
    if (!scannerActive) return;
    
    const code = result.codeResult.code;
    const format = result.codeResult.format;
    
    // Validate barcode (basic check)
    if (code && (code.length === 8 || code.length === 13)) {
      // Vibrate feedback
      if (navigator.vibrate) navigator.vibrate(100);
      
      // Stop scanner
      stopBarcodeScanner();
      
      // Lookup product
      lookupProductByBarcode(code);
    }
  });
}

function stopBarcodeScanner() {
  if (typeof Quagga !== 'undefined' && scannerActive) {
    Quagga.stop();
    scannerActive = false;
  }
}

function closeBarcodeScanner() {
  stopBarcodeScanner();
  document.getElementById('scannerOverlay').classList.remove('visible');
  document.getElementById('scannerSheet').classList.remove('visible');
  unlockBody();
}

// Open Food Facts API Lookup
async function lookupProductByBarcode(barcode) {
  // Show loading state
  document.getElementById('scannerResult').style.display = 'block';
  document.getElementById('resultLoading').style.display = 'flex';
  document.getElementById('resultFound').style.display = 'none';
  document.getElementById('resultNotFound').style.display = 'none';
  document.getElementById('scannerActions').style.display = 'none';
  
  try {
    // Open Food Facts API
    const response = await fetch(`https://world.openfoodfacts.org/api/v2/product/${barcode}.json`);
    const data = await response.json();
    
    document.getElementById('resultLoading').style.display = 'none';
    
    if (data.status === 1 && data.product) {
      const product = data.product;
      
      // Extract product info
      scannedProductData = {
        barcode: barcode,
        name: product.product_name || product.product_name_de || 'Unbekanntes Produkt',
        brand: product.brands || 'Unbekannte Marke',
        categories: product.categories || '',
        image: product.image_url || null,
        nutrients: product.nutriments || {}
      };
      
      // Determine icon based on category
      scannedProductData.icon = getSupplementIcon(scannedProductData.name, scannedProductData.categories);
      
      // Show found result
      document.getElementById('resultIcon').textContent = scannedProductData.icon;
      document.getElementById('resultName').textContent = scannedProductData.name;
      document.getElementById('resultBrand').textContent = scannedProductData.brand;
      document.getElementById('resultBarcode').textContent = `EAN: ${barcode}`;
      document.getElementById('resultFound').style.display = 'block';
      
    } else {
      // Product not found
      document.getElementById('notFoundBarcode').textContent = `Barcode: ${barcode}`;
      document.getElementById('resultNotFound').style.display = 'block';
      
      // Store barcode for manual entry
      scannedProductData = { barcode: barcode };
    }
    
  } catch (error) {
    console.error('API error:', error);
    document.getElementById('resultLoading').style.display = 'none';
    document.getElementById('notFoundBarcode').textContent = `Barcode: ${barcode} (Netzwerkfehler)`;
    document.getElementById('resultNotFound').style.display = 'block';
    scannedProductData = { barcode: barcode };
  }
}

// Determine supplement icon based on name/category
function getSupplementIcon(name, categories) {
  const nameLower = (name + ' ' + categories).toLowerCase();
  
  if (nameLower.includes('vitamin d') || nameLower.includes('d3')) return '☀️';
  if (nameLower.includes('vitamin c')) return '🍊';
  if (nameLower.includes('vitamin b') || nameLower.includes('b12') || nameLower.includes('b-komplex')) return '🧬';
  if (nameLower.includes('omega') || nameLower.includes('fischöl') || nameLower.includes('fish oil')) return '🐟';
  if (nameLower.includes('magnesium')) return '⚡';
  if (nameLower.includes('zink') || nameLower.includes('zinc')) return '🛡️';
  if (nameLower.includes('eisen') || nameLower.includes('iron')) return '🩸';
  if (nameLower.includes('calcium') || nameLower.includes('kalzium')) return '🦴';
  if (nameLower.includes('melatonin') || nameLower.includes('schlaf') || nameLower.includes('sleep')) return '😴';
  if (nameLower.includes('ashwagandha') || nameLower.includes('ginseng') || nameLower.includes('adaptogen')) return '🌿';
  if (nameLower.includes('protein') || nameLower.includes('whey') || nameLower.includes('eiweiß')) return '💪';
  if (nameLower.includes('kreatin') || nameLower.includes('creatine')) return '🏋️';
  if (nameLower.includes('kollagen') || nameLower.includes('collagen') || nameLower.includes('haut') || nameLower.includes('haar')) return '✨';
  if (nameLower.includes('probiotik') || nameLower.includes('probiotic') || nameLower.includes('darm')) return '🦠';
  if (nameLower.includes('multi')) return '💊';
  
  return '💊'; // Default
}

