// Update the Robur schedule preview
function updateRoburSchedulePreview() {
  const previewEl = document.getElementById('roburSchedulePreview');
  const timesEl = document.getElementById('previewTimes');
  const warningsEl = document.getElementById('previewWarnings');
  const isEnabled = document.getElementById('roburAutoSchedule').checked;
  
  if (!isEnabled) {
    previewEl.classList.add('hidden');
    return;
  }
  
  previewEl.classList.remove('hidden');
  
  // Get today's shift
  const today = formatDate(new Date());
  const shiftType = shifts[today];
  
  if (!shiftType || shiftType === 'off' || shiftType === 'vacation' || shiftType === 'sick') {
    timesEl.innerHTML = `<div class="no-shift-warning">
      <p>📅 Heute keine Schicht hinterlegt</p>
      <p style="font-size: 11px;">Trage deinen Schichtplan ein für optimale Zeiten</p>
    </div>`;
    warningsEl.innerHTML = '';
    return;
  }
  
  // Calculate optimal time for this supplement
  const tempSupp = {
    name: scannedProductData?.name || 'Supplement',
    dosagePerDay: selectedDosage
  };
  
  const optimal = calculateOptimalTime(tempSupp, shiftType, shiftConfig);
  
  // Generate preview times based on dosage
  let timesHtml = '';
  for (let i = 0; i < selectedDosage; i++) {
    let time = optimal.time;
    if (selectedDosage === 2) {
      time = i === 0 ? optimal.time : addMinutesToTime(optimal.time, 12 * 60);
    } else if (selectedDosage === 3) {
      time = addMinutesToTime(optimal.time, i * 6 * 60);
    } else if (selectedDosage >= 4) {
      time = addMinutesToTime(optimal.time, i * 4 * 60);
    }
    
    timesHtml += `
      <div class="preview-time-item">
        <span class="preview-time-badge">${time}</span>
        <div class="preview-time-info">
          <strong>Dosis ${i + 1}</strong>
          <span>${optimal.reason}${optimal.withFood ? ' • Mit Mahlzeit' : ''}</span>
        </div>
      </div>
    `;
  }
  timesEl.innerHTML = timesHtml;
  
  // Show warnings
  let warningsHtml = '';
  if (optimal.warnings && optimal.warnings.length > 0) {
    optimal.warnings.forEach(warning => {
      const isInfo = !warning.includes('☕') && !warning.includes('Nicht');
      warningsHtml += `<div class="preview-warning ${isInfo ? 'info' : ''}">${warning}</div>`;
    });
  }
  warningsEl.innerHTML = warningsHtml;
}

