function saveScannedProduct() {
  if (!scannedProductData) return;
  
  // Ensure supplements are loaded
  ensureSupplementsLoaded();
  
  const roburScheduled = document.getElementById('roburAutoSchedule').checked;
  const autoAboToggle = document.getElementById('addWithAutoAbo');
  const autoAboEnabled = autoAboToggle ? autoAboToggle.checked : false;
  const aboThreshold = autoAboEnabled ? parseInt(document.getElementById('addAboThreshold').value) || 14 : 14;
  
  const newSupplement = {
    id: scannedProductData.shopProductId ? 'shop_' + scannedProductData.shopProductId : 'scan_' + Date.now(),
    shopProductId: scannedProductData.shopProductId || null,
    name: scannedProductData.name || 'Gescanntes Supplement',
    brand: scannedProductData.brand || 'Unbekannt',
    icon: scannedProductData.icon || '💊',
    barcode: scannedProductData.barcode || null,
    source: scannedProductData.source || 'external',
    dosagePerDay: selectedDosage,
    stock: parseInt(document.getElementById('scannedStock').value) || 60,
    packSize: parseInt(document.getElementById('scannedPackSize').value) || 60,
    time: roburScheduled ? 'auto' : 'manual',
    autoAbo: autoAboEnabled,
    aboThreshold: aboThreshold,
    roburScheduled: roburScheduled
  };
  
  // If auto-abo is enabled, also add to autoReplenItems
  if (autoAboEnabled && scannedProductData.shopProductId) {
    const product = products.find(p => p.id === scannedProductData.shopProductId);
    if (product) {
      autoReplenItems.set(scannedProductData.shopProductId, {
        productId: scannedProductData.shopProductId,
        name: product.name,
        icon: product.icon,
        price: product.price,
        enabled: true,
        frequency: 30, // Monthly default
        nextDelivery: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        threshold: aboThreshold
      });
      saveAutoReplenItems();
    }
  }
  
  // Close the add scanned sheet first
  closeAddScanned();
  scannedProductData = null;
  
  // Check if product has active subscription - if yes, add directly as active
  if (hasActiveSubscription(newSupplement.shopProductId) || autoAboEnabled) {
    newSupplement.status = 'active';
    newSupplement.startDate = new Date().toISOString();
    newSupplement.addedAt = new Date().toISOString();
    
    mySupplements.push(newSupplement);
    saveMySupplements();
    
    if (roburScheduled) {
      updateAllScheduledIntakes();
    }
    
    renderMySupplements('all');
    updateSupplementStats();
    
    if (autoAboEnabled) {
      showToast('✅ Hinzugefügt mit Auto-Abo! 🔄 -8%');
    } else {
      showToast('✅ Hinzugefügt! (Abo aktiv)');
    }
  } else {
    // Open the "When do you start?" dialog
    openSuppStartDialog(newSupplement);
  }
}

