// Supplement Detail
let currentSupplementId = null;

function openSupplementDetail(suppId) {
  currentSupplementId = suppId;
  const supp = mySupplements.find(s => s.id === suppId);
  if (!supp) {
    showToast('Supplement nicht gefunden');
    return;
  }
  
  // Safe defaults for calculations
  const stock = supp.stock || 0;
  const dosagePerDay = supp.dosagePerDay || 1;
  const daysLeft = dosagePerDay > 0 ? Math.floor(stock / dosagePerDay) : 0;
  
  const emptyDate = new Date();
  emptyDate.setDate(emptyDate.getDate() + daysLeft);
  
  // Safe month name lookup
  const monthIndex = emptyDate.getMonth();
  const monthName = (monthNames && monthNames[monthIndex]) ? monthNames[monthIndex].substring(0, 3) : 'N/A';
  const emptyDateStr = `~${emptyDate.getDate()}. ${monthName}`;
  
  // Populate detail sheet
  document.querySelector('.detail-icon').textContent = supp.icon || '💊';
  document.getElementById('detailName').textContent = supp.name || 'Unbekannt';
  document.getElementById('detailBrand').textContent = supp.brand || 'Unbekannt';
  document.getElementById('detailSource').textContent = supp.source === 'shop' ? 'Aus SuppTree Shop' : 'Externes Produkt';
  document.getElementById('detailStock').textContent = `${stock} Stück`;
  document.getElementById('detailDays').textContent = `~${daysLeft} Tage`;
  document.getElementById('detailEmpty').textContent = emptyDateStr;
  document.getElementById('dosageAmount').textContent = dosagePerDay;
  
  // Set intake mode based on supplement settings
  const isRoburScheduled = supp.roburScheduled !== false;
  const intakeModeRadios = document.querySelectorAll('input[name="intakeMode"]');
  intakeModeRadios.forEach(radio => {
    radio.checked = (radio.value === 'robur' && isRoburScheduled) || 
                    (radio.value === 'manual' && !isRoburScheduled);
  });
  
  // Show/hide manual options
  const manualOptions = document.getElementById('manualOptionsSection');
  if (manualOptions) {
    manualOptions.style.display = isRoburScheduled ? 'none' : 'block';
  }
  
  // Set manual type (together vs distributed)
  const manualType = supp.manualType || 'together';
  const manualTypeRadios = document.querySelectorAll('input[name="manualType"]');
  manualTypeRadios.forEach(radio => {
    radio.checked = radio.value === manualType;
  });
  
  // Show/hide time slots section
  const timeSlotsCompact = document.getElementById('timeSlotsCompact');
  if (timeSlotsCompact) {
    timeSlotsCompact.style.display = manualType === 'distributed' ? 'flex' : 'none';
  }
  
  // Set together time
  const togetherTimeSelect = document.getElementById('togetherTimeSelect');
  if (togetherTimeSelect && supp.togetherTime) {
    togetherTimeSelect.value = supp.togetherTime;
  }
  
  // Load saved time slots
  const timeSlotCheckboxes = document.querySelectorAll('input[name="timeSlot"]');
  timeSlotCheckboxes.forEach(cb => {
    cb.checked = supp.timeSlots && supp.timeSlots.includes(cb.value);
  });
  
  // Hide interaction warning initially
  const warningArea = document.getElementById('interactionWarningArea');
  if (warningArea) warningArea.style.display = 'none';
  
  // Update current times display
  updateCurrentTimesDisplay(supp);
  
  // Check interactions if manual mode with distributed slots
  if (!isRoburScheduled && manualType === 'distributed' && supp.timeSlots && supp.timeSlots.length > 0) {
    setTimeout(checkSupplementInteractions, 100);
  }
  
  // Auto-Abo settings
  document.getElementById('autoAboToggle').checked = supp.autoAbo;
  document.getElementById('autoAboSettings').style.display = supp.autoAbo ? 'block' : 'none';
  
  if (supp.aboThreshold) {
    document.getElementById('aboThreshold').value = supp.aboThreshold;
  }
  
  // Show/hide reorder button based on source
  const reorderBtn = document.querySelector('.detail-btn.reorder');
  if (reorderBtn) {
    if (supp.source === 'external') {
      reorderBtn.innerHTML = '🔍 ' + (t('btn.searchShop') || 'Im Shop suchen');
    } else {
      reorderBtn.innerHTML = '🛒 ' + (t('btn.reorder') || 'Nachbestellen');
    }
  }
  
  document.getElementById('suppDetailOverlay').classList.add('visible');
  document.getElementById('suppDetailSheet').classList.add('visible');
  lockBody();
}

