function switchIntakeMode(mode) {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  const manualOptions = document.getElementById('manualOptionsSection');
  
  if (mode === 'robur') {
    supp.roburScheduled = true;
    if (manualOptions) manualOptions.style.display = 'none';
    showToast('🤖 Robur optimiert deine Einnahmezeiten');
  } else {
    supp.roburScheduled = false;
    if (manualOptions) manualOptions.style.display = 'block';
    
    // Default to 'together' if no manual type set
    if (!supp.manualType) {
      supp.manualType = 'together';
      const togetherRadio = document.querySelector('input[name="manualType"][value="together"]');
      if (togetherRadio) togetherRadio.checked = true;
    }
  }
  
  updateCurrentTimesDisplay(supp);
  saveMySupplements();
  updateAllScheduledIntakes();
}

function switchManualType(type) {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  supp.manualType = type;
  
  const timeSlotsCompact = document.getElementById('timeSlotsCompact');
  if (timeSlotsCompact) {
    timeSlotsCompact.style.display = type === 'distributed' ? 'flex' : 'none';
  }
  
  // Hide warning when switching types
  const warningArea = document.getElementById('interactionWarningArea');
  if (warningArea) warningArea.style.display = 'none';
  
  updateCurrentTimesDisplay(supp);
  saveMySupplements();
  updateAllScheduledIntakes();
}

function updateManualTime() {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  const togetherTimeSelect = document.getElementById('togetherTimeSelect');
  if (togetherTimeSelect) {
    supp.togetherTime = togetherTimeSelect.value;
  }
  
  updateCurrentTimesDisplay(supp);
  saveMySupplements();
  updateAllScheduledIntakes();
}

function updateDistributedTimes() {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  const selectedSlots = Array.from(document.querySelectorAll('input[name="timeSlot"]:checked'))
    .map(cb => cb.value);
  
  supp.timeSlots = selectedSlots;
  
  updateCurrentTimesDisplay(supp);
  checkSupplementInteractions();
  saveMySupplements();
  updateAllScheduledIntakes();
}

function updateCurrentTimesDisplay(supp) {
  const container = document.getElementById('currentTimesList');
  if (!container) return;
  
  // Get today's shift and calculate dynamic times
  const today = formatDate(new Date());
  const shiftType = shifts[today] || 'off';
  const shift = shiftConfig[shiftType] || shiftConfig.off;
  
  const wakeTime = shift.wake || '08:00';
  const sleepTime = shift.sleep || '23:00';
  const middayTime = calculateMidday(wakeTime, sleepTime);
  
  // Dynamic time slot mapping based on today's shift
  const timeSlotLabels = {
    'morning': { time: addMinutesToTime(wakeTime, 30), icon: '🌅', note: 'Nach dem Aufstehen' },
    'noon': { time: middayTime, icon: '☀️', note: 'Mittags' },
    'evening': { time: addMinutesToTime(sleepTime, -180), icon: '🌆', note: 'Abends' },
    'night': { time: addMinutesToTime(sleepTime, -30), icon: '🌙', note: 'Vor dem Schlafen' }
  };
  
  let times = [];
  
  if (supp.roburScheduled) {
    // Get Robur-optimized times
    const dayIntakes = scheduledIntakes[today] || scheduleSupplementsForDate(today);
    const suppIntakes = dayIntakes.filter(i => i.suppId === supp.id);
    
    times = suppIntakes.map(intake => ({
      time: intake.time,
      icon: '🤖',
      note: intake.reason || (intake.withFood ? 'Mit Mahlzeit' : 'Optimiert')
    }));
  } else if (supp.manualType === 'together') {
    // All together at one time
    const togetherTime = supp.togetherTime || addMinutesToTime(wakeTime, 30);
    const dosage = supp.dosagePerDay || 1;
    times = [{
      time: togetherTime,
      icon: '⏰',
      note: dosage > 1 ? `${dosage}x zusammen` : 'Alle zusammen'
    }];
  } else if (supp.manualType === 'distributed' && supp.timeSlots) {
    // Distributed across slots - use dynamic times!
    times = supp.timeSlots.map(slot => ({
      time: timeSlotLabels[slot]?.time || addMinutesToTime(wakeTime, 30),
      icon: timeSlotLabels[slot]?.icon || '⏰',
      note: timeSlotLabels[slot]?.note || slot
    }));
  }
  
  if (times.length === 0) {
    container.innerHTML = '<span class="times-empty" data-i18n="supps.noTimeSet">Noch keine Zeit festgelegt</span>';
    return;
  }
  
  // Sort by time
  times.sort((a, b) => a.time.localeCompare(b.time));
  
  // Add shift info badge if not 'off'
  let shiftBadge = '';
  if (shiftType !== 'off' && shiftType !== 'vacation') {
    const shiftNames = { early: 'Frühschicht', day: 'Tagschicht', late: 'Spätschicht', night: 'Nachtschicht' };
    shiftBadge = `<span class="times-shift-badge">Heute: ${shiftNames[shiftType] || shiftType}</span>`;
  }
  
  container.innerHTML = shiftBadge + times.map(t => `
    <div class="time-chip">
      <span>${t.icon}</span>
      <span class="chip-time">${t.time}</span>
      <span class="chip-note">${t.note}</span>
    </div>
  `).join('');
}

// Update the schedule preview in detail sheet
function updateDetailSchedulePreview(supp) {
  const container = document.getElementById('detailScheduleTimes');
  if (!container) return;
  if (!supp) {
    container.innerHTML = '<p style="text-align:center;color:var(--text-muted);font-size:12px;">Keine Daten verfügbar</p>';
    return;
  }
  
  const today = new Date();
  let html = '';
  const dosagePerDay = supp.dosagePerDay || 1;
  
  // Show next 3 days of scheduled intakes
  for (let i = 0; i < 3; i++) {
    const date = new Date(today);
    date.setDate(date.getDate() + i);
    const dateStr = formatDate(date);
    const shiftType = shifts[dateStr];
    
    const dayName = i === 0 ? 'Heute' : i === 1 ? 'Morgen' : dayNamesGetDay[date.getDay()];
    
    const optimal = calculateOptimalTime(supp, shiftType, shiftConfig);
    if (!optimal || !optimal.time) continue;
    
    // Generate times for each dose
    for (let dose = 0; dose < dosagePerDay; dose++) {
      let intakeTime = optimal.time;
      if (dosagePerDay === 2) {
        intakeTime = dose === 0 ? optimal.time : addMinutesToTime(optimal.time, 12 * 60);
      } else if (dosagePerDay === 3) {
        intakeTime = addMinutesToTime(optimal.time, dose * 6 * 60);
      } else if (dosagePerDay >= 4) {
        intakeTime = addMinutesToTime(optimal.time, dose * 4 * 60);
      }
      
      html += `
        <div class="schedule-time-item">
          <span class="time">${intakeTime}</span>
          <span class="info">${optimal.reason || ''}${optimal.withFood ? ' • Mit Mahlzeit' : ''}</span>
          <span class="date">${dayName}</span>
        </div>
      `;
    }
    
    // Show warnings for first day only
    if (i === 0 && optimal.warnings && optimal.warnings.length > 0) {
      optimal.warnings.forEach(warning => {
        html += `<div class="schedule-warning-item">${warning}</div>`;
      });
    }
  }
  
  container.innerHTML = html || '<p style="text-align:center;color:var(--text-muted);font-size:12px;">Keine Schichten eingetragen</p>';
}

function closeSuppDetail() {
  // Save settings when closing
  if (currentSupplementId) {
    const supp = mySupplements.find(s => s.id === currentSupplementId);
    if (supp) {
      saveMySupplements();
      updateAllScheduledIntakes();
      renderMySupplements('all');
    }
  }
  
  document.getElementById('suppDetailOverlay').classList.remove('visible');
  document.getElementById('suppDetailSheet').classList.remove('visible');
  currentSupplementId = null;
  unlockBody();
}

function adjustDosage(delta) {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  const newDosage = Math.max(1, Math.min(10, supp.dosagePerDay + delta));
  supp.dosagePerDay = newDosage;
  document.getElementById('dosageAmount').textContent = newDosage;
  
  // Update days left display
  const daysLeft = Math.floor(supp.stock / newDosage);
  document.getElementById('detailDays').textContent = `~${daysLeft} Tage`;
  
  // Update empty date
  const emptyDate = new Date();
  emptyDate.setDate(emptyDate.getDate() + daysLeft);
  const emptyDateStr = `~${emptyDate.getDate()}. ${monthNames[emptyDate.getMonth()].substring(0, 3)}`;
  document.getElementById('detailEmpty').textContent = emptyDateStr;
  
  // Update schedule preview if Robur is enabled
  if (supp.roburScheduled) {
    updateDetailSchedulePreview(supp);
    updateAllScheduledIntakes();
  }
  
  saveMySupplements();
  renderMySupplements('all');
  updateSupplementStats();
}

function updateStock() {
  const supp = mySupplements.find(s => s.id === currentSupplementId);
  if (!supp) return;
  
  const newStock = parseInt(document.getElementById('newStockAmount').value);
  if (isNaN(newStock) || newStock < 0) {
    showToast('Bitte gültige Zahl eingeben');
    return;
  }
  
  supp.stock = newStock;
  supp.packSize = Math.max(supp.packSize, newStock);
  saveMySupplements();
  
  // Update display
  document.getElementById('detailStock').textContent = `${newStock} Stück`;
  const daysLeft = Math.floor(newStock / supp.dosagePerDay);
  document.getElementById('detailDays').textContent = `~${daysLeft} Tage`;
  
  document.getElementById('newStockAmount').value = '';
  showToast('Vorrat aktualisiert');
  
  renderMySupplements('all');
  updateSupplementStats();
}

function quickReorder(suppId) {
  const supp = mySupplements.find(s => s.id === suppId);
  if (!supp) return;
  
  if (supp.source === 'shop') {
    showToast(`${supp.name} zum Warenkorb hinzugefügt`);
    // In real app, would add to cart
  } else {
    showToast('Im Shop nach Alternativen suchen...');
    switchScreen('productsScreen');
  }
}

function reorderSupplement() {
  try {
    const supp = mySupplements.find(s => s.id === currentSupplementId);
    if (!supp) {
      showToast('Supplement nicht gefunden');
      return;
    }
    
    closeSuppDetail();
    
    if (supp.source === 'shop') {
      // Add to cart (simulated)
      showToast(`${supp.name} zum Warenkorb hinzugefügt 🛒`);
    } else {
      // Search for alternatives in shop
      showToast('Suche im Shop...');
      setTimeout(() => {
        switchScreen('productsScreen');
      }, 500);
    }
  } catch (error) {
    console.error('Error in reorderSupplement:', error);
    showToast('Fehler: ' + error.message);
  }
}

function deleteSupplement() {
  try {
    const supp = mySupplements.find(s => s.id === currentSupplementId);
    if (!supp) {
      showToast('Supplement nicht gefunden');
      return;
    }
    
    
    // Show custom confirm dialog
    document.getElementById('deleteConfirmTitle').textContent = `${supp.name} entfernen?`;
    document.getElementById('deleteConfirmText').textContent = t('supps.confirmDelete') || 'Möchtest du dieses Supplement wirklich aus deiner Liste entfernen?';
    document.getElementById('deleteConfirmOverlay').classList.add('visible');
    document.getElementById('deleteConfirmDialog').classList.add('visible');
    
  } catch (error) {
    console.error('Error in deleteSupplement:', error);
    showToast('Fehler: ' + error.message);
  }
}

function cancelDelete() {
  document.getElementById('deleteConfirmOverlay').classList.remove('visible');
  document.getElementById('deleteConfirmDialog').classList.remove('visible');
}

function confirmDelete() {
  try {
    mySupplements = mySupplements.filter(s => s.id !== currentSupplementId);
    saveMySupplements();
    
    // Close dialog and detail sheet
    cancelDelete();
    closeSuppDetail();
    
    renderMySupplements('all');
    updateSupplementStats();
    showToast('Supplement entfernt ✓');
  } catch (error) {
    console.error('Error in confirmDelete:', error);
    showToast('Fehler beim Löschen');
  }
}

