// SUPPLEMENT SELECTOR
// ===============================
function openSupplementSelector() {
  if (!currentUser) {
    showConfirmDialog('Anmeldung erforderlich', 'Melde dich an, um deine persönlichen Supplements zu importieren.', 'Jetzt anmelden', function() {
      showCustomerAuth();
      setCustomerAuthMode('login');
    });
    return;
  }
  if (mySupplements.length === 0) {
    showToast('Keine Supplements in "Meine Supplements"');
    return;
  }
  
  selectedSupplements = new Set();
  renderSupplementSelector();
  
  document.getElementById('suppSelectorOverlay').classList.add('visible');
  document.getElementById('suppSelectorSheet').classList.add('visible');
}

function closeSupplementSelector() {
  document.getElementById('suppSelectorOverlay').classList.remove('visible');
  document.getElementById('suppSelectorSheet').classList.remove('visible');
}

function renderSupplementSelector() {
  const container = document.getElementById('supplementSelectorList');
  
  container.innerHTML = mySupplements.map(supp => {
    const isAdded = matrixItems.some(m => m.id === supp.id);
    const isSelected = selectedSupplements.has(supp.id);
    
    return `
      <div class="selector-item ${isSelected ? 'selected' : ''} ${isAdded ? 'disabled' : ''}" 
           onclick="${isAdded ? '' : `toggleSupplementSelect('${supp.id}')`}">
        <div class="selector-item-icon">${supp.icon}</div>
        <div class="selector-item-info">
          <h4>${escapeHtml(supp.name)}</h4>
          <p>${escapeHtml(supp.dosage) || ''}${isAdded ? ' • Bereits hinzugefügt' : ''}</p>
        </div>
        <div class="selector-item-check">${isSelected ? '✓' : ''}</div>
      </div>
    `;
  }).join('');
}

function toggleSupplementSelect(id) {
  if (selectedSupplements.has(id)) {
    selectedSupplements.delete(id);
  } else {
    selectedSupplements.add(id);
  }
  renderSupplementSelector();
}

function selectAllSupplements() {
  mySupplements.forEach(supp => {
    if (!matrixItems.some(m => m.id === supp.id)) {
      selectedSupplements.add(supp.id);
    }
  });
  renderSupplementSelector();
}

function deselectAllSupplements() {
  selectedSupplements.clear();
  renderSupplementSelector();
}

function confirmSupplementSelection() {
  let added = 0;
  
  selectedSupplements.forEach(id => {
    if (matrixItems.length >= 15) return;
    const supp = mySupplements.find(s => s.id === id);
    if (!supp) return;
    
    matrixItems.push({
      type: 'supplement',
      id: supp.id,
      name: supp.name,
      icon: supp.icon,
      activeIngredient: supp.name.toLowerCase()
    });
    added++;
  });
  
  closeSupplementSelector();
  renderMatrixItems();
  document.getElementById('matrixResults').style.display = 'none';
  
  if (added > 0) {
    showToast(`${added} Supplement${added > 1 ? 's' : ''} hinzugefügt`);
  }
}

