// ===============================
// SAVED SEARCHES
// ===============================
function loadSavedAnalyses() {
  const saved = localStorage.getItem('suppTreeSavedAnalyses');
  if (saved) {
    savedAnalyses = JSON.parse(saved);
  }
}

function saveSavedAnalyses() {
  localStorage.setItem('suppTreeSavedAnalyses', JSON.stringify(savedAnalyses));
}

function renderSavedSearches() {
  loadSavedAnalyses();
  
  const section = document.getElementById('savedSearchesSection');
  const container = document.getElementById('savedSearchesList');
  
  if (!section || savedAnalyses.length === 0) {
    if (section) section.style.display = 'none';
    return;
  }
  
  section.style.display = 'block';
  
  container.innerHTML = savedAnalyses.map((analysis, idx) => {
    const statusClass = analysis.hasAnyDanger ? 'danger' : analysis.hasAnyWarning ? 'warning' : 'safe';
    const statusIcon = analysis.hasAnyDanger ? '⚠️' : analysis.hasAnyWarning ? '⚡' : '✅';
    
    return `
      <div class="saved-search-item" onclick="loadSavedAnalysis(${idx})">
        <div class="saved-search-icon ${statusClass}">${statusIcon}</div>
        <div class="saved-search-info">
          <h4>${analysis.name}</h4>
          <p>${analysis.items.length} Produkte • ${new Date(analysis.date).toLocaleDateString('de-DE')}</p>
        </div>
        <button class="saved-search-delete" onclick="event.stopPropagation(); deleteSavedAnalysis(${idx})">🗑️</button>
      </div>
    `;
  }).join('');
}

function loadSavedAnalysis(idx) {
  const analysis = savedAnalyses[idx];
  if (!analysis) return;
  
  matrixItems = [...analysis.items];
  renderMatrixItems();
  
  // Re-run analysis
  analyzeInteractions();
}

function deleteSavedAnalysis(idx) {
  showConfirmDialog('Analyse löschen', 'Möchtest du diese gespeicherte Analyse wirklich löschen?', 'Löschen', function() {
    savedAnalyses.splice(idx, 1);
    saveSavedAnalyses();
    renderSavedSearches();
    showToast('Analyse gelöscht');
  }, true);
}

function saveCurrentAnalysis() {
  if (!lastAnalysisResult || matrixItems.length < 2) {
    showToast('Führe zuerst eine Analyse durch');
    return;
  }
  
  const name = prompt('Name für diese Analyse:', `Analyse ${savedAnalyses.length + 1}`);
  if (!name) return;
  
  const analysis = {
    name: name,
    date: new Date().toISOString(),
    items: [...matrixItems],
    hasAnyDanger: lastAnalysisResult.counts.danger > 0,
    hasAnyWarning: lastAnalysisResult.counts.warning > 0,
    counts: lastAnalysisResult.counts
  };
  
  savedAnalyses.unshift(analysis);
  if (savedAnalyses.length > 10) savedAnalyses.pop(); // Max 10 saved
  
  saveSavedAnalyses();
  renderSavedSearches();
  showToast('Analyse gespeichert');
}

function toggleSavedSearches() {
  const list = document.getElementById('savedSearchesList');
  const btn = document.querySelector('.toggle-saved-btn');
  
  if (list.style.display === 'none') {
    list.style.display = 'flex';
    btn.textContent = '▼';
  } else {
    list.style.display = 'none';
    btn.textContent = '▶';
  }
}

