    'ibuprofen': { name: 'Ibuprofen', activeIngredient: 'ibuprofen' },
    'aspirin': { name: 'Aspirin', activeIngredient: 'aspirin' },
    'metformin': { name: 'Metformin', activeIngredient: 'metformin' },
    'omeprazol': { name: 'Omeprazol', activeIngredient: 'omeprazol' },
    'levothyroxin': { name: 'L-Thyroxin', activeIngredient: 'levothyroxin' },
