function closeMatrixInfo() {
  document.getElementById('matrixInfoOverlay')?.classList.remove('visible');
  document.getElementById('matrixInfoSheet')?.classList.remove('visible');
}

function toggleMatrixExamples() {
  const section = document.querySelector('.matrix-examples-section');
  const content = document.getElementById('matrixExamplesContent');
  
  if (section && content) {
    section.classList.toggle('expanded');
    content.style.display = section.classList.contains('expanded') ? 'block' : 'none';
  }
}

// ===============================
// MEDICATIONS FUNCTIONS
// ===============================
let selectedMedForm = 'tablet';

const medFormIcons = {
  'tablet': '💊',
  'capsule': '💊',
  'liquid': '🧪',
  'drops': '💧',
  'spray': '🌬️',
  'injection': '💉',
  'cream': '🧴',
  'other': '📦'
};

const medFormLabels = {
  'tablet': 'Tablette',
  'capsule': 'Kapsel',
  'liquid': 'Flüssig',
  'drops': 'Tropfen',
  'spray': 'Spray',
  'injection': 'Spritze',
  'cream': 'Salbe',
  'other': 'Andere'
};

// Dose units based on form type
const medDoseUnits = {
  'tablet': { unit: 'Tablette(n)', placeholder: '1', step: '0.5' },
  'capsule': { unit: 'Kapsel(n)', placeholder: '1', step: '1' },
  'liquid': { unit: 'ml', placeholder: '5', step: '0.5' },
  'drops': { unit: 'Tropfen', placeholder: '10', step: '1' },
  'spray': { unit: 'Sprühstöße', placeholder: '2', step: '1' },
  'injection': { unit: 'ml / I.E.', placeholder: '1', step: '0.1' },
  'cream': { unit: 'Anwendung(en)', placeholder: '1', step: '1' },
  'other': { unit: 'Einheit(en)', placeholder: '1', step: '1' }
};

const instructionLabels = {
  'any': '',
  'before_meal': 'Vor dem Essen',
  'with_meal': 'Mit dem Essen',
  'after_meal': 'Nach dem Essen',
  'empty_stomach': 'Nüchtern',
  'custom': ''
};

function initMedications() {
  const saved = localStorage.getItem('suppTreeMedications');
  if (saved) {
    myMedications = JSON.parse(saved);
  } else {
    myMedications = [];
  }
  renderMedications();
  
  // Add event listener for custom note toggle
  const instructionSelect = document.getElementById('medInstruction');
  if (instructionSelect) {
    instructionSelect.addEventListener('change', function() {
      const customSection = document.getElementById('customNoteSection');
      if (customSection) {
        customSection.style.display = this.value === 'custom' ? 'block' : 'none';
      }
    });
  }
}

function saveMedications() {
  localStorage.setItem('suppTreeMedications', JSON.stringify(myMedications));
  if (supabase && currentUser) {
    DataStore.set('my_medications', 'suppTreeMedications', myMedications, {
      replaceAll: true,
      transform: (m) => ({
        user_id: currentUser.id,
        name: m.name,
        icon: m.icon || '💊',
        dosage: m.dosage,
        doses_per_day: m.dosePerDay || m.dosagePerDay || 1,
        is_active: m.isActive !== false
      })
    }).catch(e => console.error('Medications sync error:', e));
  }
}

function renderMedications() {
  const container = document.getElementById('medicationsListContainer');
  if (!container) return;
  
  if (myMedications.length === 0) {
    container.innerHTML = `
      <div style="text-align: center; padding: 40px 20px; color: var(--text-muted);">
        <span style="font-size: 48px; display: block; margin-bottom: 12px;">💊</span>
        <p>${t('meds.noneYet') || 'Noch keine Medikamente hinterlegt'}</p>
        <p style="font-size: 12px;">${t('meds.roburNote')}</p>
      </div>
    `;
    return;
  }
  
  const timeLabels = { 
    morning: '🌅 ' + (t('time.morning') || 'Morgens'), 
    noon: '☀️ ' + (t('time.noon') || 'Mittags'), 
    evening: '🌆 ' + (t('time.evening') || 'Abends'), 
    night: '🌙 ' + (t('time.night') || 'Nachts') 
  };
  
  container.innerHTML = myMedications.map((med, idx) => {
    // Calculate remaining days if duration is set
    let durationInfo = '';
    if (med.duration && med.durationType !== 'ongoing') {
      const startDate = new Date(med.startDate || Date.now());
      const totalDays = med.durationType === 'days' ? med.duration : 
                        med.durationType === 'weeks' ? med.duration * 7 : 
                        med.duration * 30;
      const endDate = new Date(startDate);
      endDate.setDate(endDate.getDate() + totalDays);
      const today = new Date();
      const remainingDays = Math.ceil((endDate - today) / (1000 * 60 * 60 * 24));
      
      if (remainingDays > 0) {
        const daysText = t('time.days') || 'Tage';
        const stillText = t('time.still') || 'Noch';
        durationInfo = `<span class="med-duration-badge">📅 ${stillText} ${remainingDays} ${daysText}</span>`;
      } else if (remainingDays === 0) {
        durationInfo = `<span class="med-duration-badge ending">📅 ${t('meds.lastDay') || 'Letzter Tag!'}</span>`;
      } else {
        durationInfo = `<span class="med-duration-badge ended">✓ ${t('meds.completed') || 'Abgeschlossen'}</span>`;
      }
    } else if (med.durationType === 'ongoing') {
      durationInfo = `<span class="med-duration-badge ongoing">∞ ${t('meds.ongoing') || 'Dauerhaft'}</span>`;
    }
    
    const formIcon = medFormIcons[med.formType] || '💊';
    const formLabel = medFormLabels[med.formType] || 'Tablette';
    
    // Format dosage display
    const unitInfo = medDoseUnits[med.formType] || medDoseUnits['tablet'];
    const doseAmount = med.doseAmount || 1;
    const frequency = med.times ? med.times.length : 1;
    
    // Get short unit name
    const shortUnit = unitInfo.unit.replace('(n)', '').replace('(en)', '');
    const doseDisplay = `${doseAmount} ${doseAmount === 1 ? shortUnit : unitInfo.unit}`;
    
    // Get instruction text
    let instructionText = '';
    if (med.instruction === 'custom' && med.customNote) {
      instructionText = med.customNote;
    } else if (med.instruction && med.instruction !== 'any') {
      instructionText = instructionLabels[med.instruction] || '';
    }
    
    const dailyText = t('time.daily') || 'täglich';
    
    return `
      <div class="medication-card ${med.durationType === 'ongoing' ? '' : (durationInfo.includes('ended') ? 'completed' : '')}">
        <div class="med-icon">${formIcon}</div>
        <div class="med-info">
          <div class="med-name">${escapeHtml(med.name)}</div>
          <div class="med-meta">
            <span class="med-form-badge">${formLabel}</span>
            <span>•</span>
            <span>${doseDisplay}</span>
            <span>•</span>
            <span>${frequency}x ${dailyText}</span>
          </div>
          <div class="med-times">
            ${med.times && med.times.length > 0 ? med.times.map(t => `<span class="med-time-badge">${timeLabels[t]}</span>`).join('') : ''}
          </div>
          ${instructionText ? `<div class="med-instruction-note">📝 ${escapeHtml(instructionText)}</div>` : ''}
          ${durationInfo ? `<div class="med-duration">${durationInfo}</div>` : ''}
        </div>
        <div class="med-actions">
          <button class="med-action-btn edit" onclick="editMedication(${idx})">✏️</button>
          <button class="med-action-btn delete" onclick="deleteMedication(${idx})">🗑️</button>
        </div>
      </div>
    `;
  }).join('');
}

function openAddMedication() {
  editingMedIndex = -1; // Reset edit mode

  document.getElementById('medName').value = '';
  const aiField = document.getElementById('medActiveIngredient');
  if (aiField) aiField.value = '';
  document.getElementById('medDuration').value = '';
  document.getElementById('medDurationType').value = 'days';
  document.getElementById('medDoseAmount').value = '1';
  document.getElementById('medInstruction').value = 'any';
  document.getElementById('medCustomNote').value = '';

  // Reset gruppe & form auto-detection
  const gruppeIdField = document.getElementById('medGruppeId');
  if (gruppeIdField) gruppeIdField.value = '';
  const gruppeNameField = document.getElementById('medGruppeName');
  if (gruppeNameField) gruppeNameField.value = '';
  const autoFormField = document.getElementById('medAutoForm');
  if (autoFormField) autoFormField.value = '';

  // Reset gruppe search field
  const gruppeSearch = document.getElementById('medGruppeSearch');
  if (gruppeSearch) { gruppeSearch.value = ''; gruppeSearch.style.display = ''; }

  // Hide gruppe display box
  const gruppeDisplayBox = document.getElementById('medGruppeDisplayBox');
  if (gruppeDisplayBox) gruppeDisplayBox.style.display = 'none';

  // Show form selector, hide auto-display
  const formSelector = document.getElementById('medFormSelector');
  if (formSelector) formSelector.style.display = '';
  const formDisplayBox = document.getElementById('medFormDisplayBox');
  if (formDisplayBox) formDisplayBox.style.display = 'none';

  // Hide both autosuggest dropdowns
  const nameDropdown = document.getElementById('medNameDropdown');
  if (nameDropdown) nameDropdown.style.display = 'none';
  const grpDropdown = document.getElementById('medGruppeDropdown');
  if (grpDropdown) grpDropdown.style.display = 'none';

  selectedMedForm = 'tablet';

  // Reset form type buttons
  document.querySelectorAll('.form-type-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.form === 'tablet');
  });

  // Update dose unit display
  updateDoseUnitDisplay('tablet');

  // Hide custom note section
  const customSection = document.getElementById('customNoteSection');
  if (customSection) customSection.style.display = 'none';

  document.getElementById('medTimeMorning').checked = true;
  document.getElementById('medTimeNoon').checked = false;
  document.getElementById('medTimeEvening').checked = false;
  document.getElementById('medTimeNight').checked = false;
  document.getElementById('medRoburConsider').checked = true;

  // Reset button text
  const saveBtn = document.querySelector('.save-med-btn');
  if (saveBtn) saveBtn.textContent = '💊 Medikament speichern';

  document.getElementById('addMedOverlay').classList.add('visible');
  document.getElementById('addMedSheet').classList.add('visible');
}

function closeAddMedication() {
  document.getElementById('addMedOverlay').classList.remove('visible');
  document.getElementById('addMedSheet').classList.remove('visible');
  setMedSheetScroll(false);
}

function setMedForm(form) {
  selectedMedForm = form;
  document.querySelectorAll('.form-type-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.form === form);
  });
  
  // Update dose unit display
  updateDoseUnitDisplay(form);
}

function updateDoseUnitDisplay(form) {
  const unitInfo = medDoseUnits[form] || medDoseUnits['tablet'];
  const doseInput = document.getElementById('medDoseAmount');
  const unitLabel = document.getElementById('doseUnit');
  const dosageLabel = document.getElementById('dosageLabel');
  
  if (doseInput) {
    doseInput.placeholder = unitInfo.placeholder;
    doseInput.step = unitInfo.step;
    // Set default value based on form type
    if (!doseInput.value || doseInput.value === '1') {
      doseInput.value = unitInfo.placeholder;
    }
  }
  
  if (unitLabel) {
    unitLabel.textContent = unitInfo.unit;
  }
  
  // Update label based on form
  if (dosageLabel) {
    const labelText = {
      'tablet': 'Wie viele Tabletten pro Einnahme?',
      'capsule': 'Wie viele Kapseln pro Einnahme?',
      'liquid': 'Wie viel ml pro Einnahme?',
      'drops': 'Wie viele Tropfen pro Einnahme?',
      'spray': 'Wie viele Sprühstöße pro Einnahme?',
      'injection': 'Wie viel ml/I.E. pro Injektion?',
      'cream': 'Wie oft auftragen pro Anwendung?',
      'other': 'Menge pro Einnahme'
    };
    dosageLabel.textContent = labelText[form] || 'Dosierung pro Einnahme *';
  }
}

function saveMedication() {
  const nameInput = document.getElementById('medName');
  const name = nameInput.value.trim();
  
  if (!name) {
    nameInput.classList.add('input-error');
    showToast('⚠️ Bitte Name eingeben');
    nameInput.focus();
    return;
  }
  
  nameInput.classList.remove('input-error');
  const doseAmount = parseFloat(document.getElementById('medDoseAmount').value) || 1;
  
  const times = [];
  if (document.getElementById('medTimeMorning').checked) times.push('morning');
  if (document.getElementById('medTimeNoon').checked) times.push('noon');
  if (document.getElementById('medTimeEvening').checked) times.push('evening');
  if (document.getElementById('medTimeNight').checked) times.push('night');
  
  if (times.length === 0) {
    showToast('Bitte mindestens eine Einnahmezeit wählen');
    return;
  }
  
  const duration = parseInt(document.getElementById('medDuration').value) || null;
  const durationType = document.getElementById('medDurationType').value;
  const instruction = document.getElementById('medInstruction').value;
  const customNote = document.getElementById('medCustomNote').value.trim();
  
  // Auto-detect medication group for Ampel system
  const gruppeIdField = document.getElementById('medGruppeId');
  const gruppeNameField = document.getElementById('medGruppeName');
  const gruppe_id = (gruppeIdField && gruppeIdField.value) ? gruppeIdField.value : null;
  const gruppe_name = (gruppeNameField && gruppeNameField.value) ? gruppeNameField.value : null;
  const autoGruppe = !gruppe_id ? findMedikamentGruppe(name) : null;

  const medData = {
    name: name,
    activeIngredient: (document.getElementById('medActiveIngredient') && document.getElementById('medActiveIngredient').value.trim()) || name,
    formType: selectedMedForm,
    doseAmount: doseAmount,
    doseUnit: medDoseUnits[selectedMedForm]?.unit || 'Einheit(en)',
    times: times,
    instruction: instruction,
    customNote: instruction === 'custom' ? customNote : '',
    duration: duration,
    durationType: duration ? durationType : 'ongoing',
    roburConsider: document.getElementById('medRoburConsider').checked,
    gruppe_id: gruppe_id || (autoGruppe ? autoGruppe.id : null),
    gruppe_name: gruppe_name || (autoGruppe ? autoGruppe.name : null)
  };

  let isEdit = editingMedIndex >= 0;
  let savedMed;

  if (isEdit && myMedications[editingMedIndex]) {
    // Update existing medication
    savedMed = { ...myMedications[editingMedIndex], ...medData };
    myMedications[editingMedIndex] = savedMed;
  } else {
    // Add new medication
    savedMed = { id: 'med_' + Date.now(), startDate: new Date().toISOString(), ...medData };
    myMedications.push(savedMed);
  }

  saveMedications();
  editingMedIndex = -1;

  // Update scheduled intakes if Robur should consider this
  if (savedMed.roburConsider) {
    updateAllScheduledIntakes();
  }

  // Check for Ampel conflicts after adding/editing medication
  if (ampelDataLoaded && savedMed.gruppe_id) {
    const konflikte = pruefeMedikamentKonflikte(mySupplements || [], [savedMed]);
    if (konflikte.length > 0) {
      const rotKonflikte = konflikte.filter(k => k.ampel === 'rot');
      const gelbKonflikte = konflikte.filter(k => k.ampel === 'gelb');

      setTimeout(() => {
        if (rotKonflikte.length > 0) {
          showAmpelRotSheet(rotKonflikte[0]);
        } else if (gelbKonflikte.length > 0) {
          showAmpelGelbSheet(gelbKonflikte[0]);
        }
      }, 500);
    }
  }

  closeAddMedication();
  renderMedications();

  // Build confirmation message
  const unitInfo = medDoseUnits[selectedMedForm];
  const shortUnit = unitInfo.unit.replace('(n)', '').replace('(en)', '');
  const doseText = `${doseAmount} ${doseAmount === 1 ? shortUnit : unitInfo.unit}`;

  showToast(`${name}: ${doseText}, ${times.length}x täglich ${isEdit ? 'aktualisiert' : 'hinzugefügt'}`);
}

let editingMedIndex = -1; // -1 = neues Medikament, >= 0 = bearbeiten

function editMedication(idx) {
  const med = myMedications[idx];
  if (!med) return;

  editingMedIndex = idx;

  // Fill form fields with existing data
  document.getElementById('medName').value = med.name || '';
  const aiField = document.getElementById('medActiveIngredient');
  if (aiField) aiField.value = med.activeIngredient || '';
  document.getElementById('medDoseAmount').value = med.doseAmount || 1;
  document.getElementById('medDuration').value = med.duration || '';
  document.getElementById('medDurationType').value = med.durationType || 'days';
  document.getElementById('medInstruction').value = med.instruction || 'any';
  document.getElementById('medCustomNote').value = med.customNote || '';

  // Set form type
  selectedMedForm = med.formType || 'tablet';
  document.querySelectorAll('.form-type-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.form === selectedMedForm);
  });
  updateDoseUnitDisplay(selectedMedForm);

  // Custom note section
  const customSection = document.getElementById('customNoteSection');
  if (customSection) customSection.style.display = med.instruction === 'custom' ? 'block' : 'none';

  // Set times
  document.getElementById('medTimeMorning').checked = (med.times || []).includes('morning');
  document.getElementById('medTimeNoon').checked = (med.times || []).includes('noon');
  document.getElementById('medTimeEvening').checked = (med.times || []).includes('evening');
  document.getElementById('medTimeNight').checked = (med.times || []).includes('night');
  document.getElementById('medRoburConsider').checked = med.roburConsider !== false;

  // Set gruppe_id and gruppe_name if available
  const gruppeIdField = document.getElementById('medGruppeId');
  if (gruppeIdField) gruppeIdField.value = med.gruppe_id || '';
  const gruppeNameField = document.getElementById('medGruppeName');
  if (gruppeNameField) gruppeNameField.value = med.gruppe_name || '';

  // Hide both autosuggest dropdowns
  const nameDropdown = document.getElementById('medNameDropdown');
  if (nameDropdown) nameDropdown.style.display = 'none';
  const grpDropdown = document.getElementById('medGruppeDropdown');
  if (grpDropdown) grpDropdown.style.display = 'none';

  // Show gruppe display if group known
  const gruppeSearch = document.getElementById('medGruppeSearch');
  const gruppeDisplayBox = document.getElementById('medGruppeDisplayBox');
  const gruppeDisplayText = document.getElementById('medGruppeDisplayText');
  if (med.gruppe_id || med.gruppe_name) {
    const gruppeName = med.gruppe_name || (function() {
      const grp = MEDIKAMENTE_DB.gruppen.find(g => g.id === med.gruppe_id) || MED_GRUPPEN.find(g => g.id === med.gruppe_id);
      return grp ? grp.name : '';
    })();
    if (gruppeDisplayBox && gruppeDisplayText && gruppeName) {
      gruppeDisplayText.textContent = gruppeName;
      gruppeDisplayBox.style.display = 'flex';
      if (gruppeSearch) gruppeSearch.style.display = 'none';
    }
  } else {
    if (gruppeDisplayBox) gruppeDisplayBox.style.display = 'none';
    if (gruppeSearch) { gruppeSearch.style.display = ''; gruppeSearch.value = ''; }
  }

  // Show form selector (manual), hide auto-display
  const formSelector = document.getElementById('medFormSelector');
  if (formSelector) formSelector.style.display = '';
  const formDisplayBox = document.getElementById('medFormDisplayBox');
  if (formDisplayBox) formDisplayBox.style.display = 'none';

  // Change button text to "Aktualisieren"
  const saveBtn = document.querySelector('.save-med-btn');
  if (saveBtn) saveBtn.textContent = '💊 Medikament aktualisieren';

  // Open sheet
  document.getElementById('addMedOverlay').classList.add('visible');
  document.getElementById('addMedSheet').classList.add('visible');
}

function deleteMedication(idx) {
  var name = myMedications[idx] ? myMedications[idx].name : 'Medikament';
  showConfirmDialog('Medikament entfernen', name + ' wirklich entfernen?', 'Entfernen', function() {
    myMedications.splice(idx, 1);
    saveMedications();
    renderMedications();
    updateAllScheduledIntakes();
    showToast('Medikament entfernt');
  }, true);
}

// Get medications scheduled for a specific date
function getMedicationsForDate(dateStr) {
  const medications = [];
  const checkDate = new Date(dateStr);
  
  // Default times for medication slots
  const timeMappings = {
    morning: '07:00',
    noon: '12:00',
    evening: '18:00',
    night: '22:00'
  };
  
  myMedications.forEach(med => {
    if (!med.roburConsider) return;
    
    // Check if medication is still active (within duration)
    if (med.duration && med.durationType !== 'ongoing') {
      const startDate = new Date(med.startDate);
      const totalDays = med.durationType === 'days' ? med.duration : 
                        med.durationType === 'weeks' ? med.duration * 7 : 
                        med.duration * 30;
      const endDate = new Date(startDate);
      endDate.setDate(endDate.getDate() + totalDays);
      
      if (checkDate > endDate) return; // Medication period ended
    }
    
    const formIcon = medFormIcons[med.formType] || '💊';
    const unitInfo = medDoseUnits[med.formType] || medDoseUnits['tablet'];
    const shortUnit = unitInfo.unit.replace('(n)', '').replace('(en)', '');
    const doseAmount = med.doseAmount || 1;
    const doseText = `${doseAmount} ${doseAmount === 1 ? shortUnit : unitInfo.unit}`;
    
    // Skip if no times set
    if (!med.times || med.times.length === 0) return;
    
    // Get instruction text for timeline
    let instructionText = '';
    if (med.instruction === 'custom' && med.customNote) {
      instructionText = ` • ${med.customNote}`;
    } else if (med.instruction && med.instruction !== 'any') {
      const labels = { before_meal: 'Vor dem Essen', with_meal: 'Mit dem Essen', after_meal: 'Nach dem Essen', empty_stomach: 'Nüchtern' };
      instructionText = ` • ${labels[med.instruction] || ''}`;
    }
    
    // Add each scheduled time
    med.times.forEach((timeSlot, idx) => {
      medications.push({
        time: timeMappings[timeSlot] || '08:00',
        icon: formIcon,
        label: `${med.name} (${doseText})${med.times.length > 1 ? ` ${idx + 1}/${med.times.length}` : ''}${instructionText}`,
        type: 'medication',
        instruction: med.instruction
      });
    });
  });
  
  return medications;
}
