// Load shift config from localStorage
function loadShiftConfig() {
  const saved = localStorage.getItem('suppTreeShiftConfig');
  if (saved) {
    const parsed = JSON.parse(saved);
    // Merge with defaults to ensure all fields exist
    Object.keys(shiftConfig).forEach(key => {
      if (parsed[key]) {
        shiftConfig[key] = { ...shiftConfig[key], ...parsed[key] };
      }
    });
  }
  updateShiftTimeDisplays();
}

// Save shift config to localStorage
function saveShiftConfig() {
  // Early shift
  shiftConfig.early.start = document.getElementById('configEarlyStart')?.value || shiftConfig.early.start;
  shiftConfig.early.end = document.getElementById('configEarlyEnd')?.value || shiftConfig.early.end;
  shiftConfig.early.wake = document.getElementById('configEarlyWake')?.value || shiftConfig.early.wake;
  shiftConfig.early.sleep = document.getElementById('configEarlySleep')?.value || shiftConfig.early.sleep;
  
  // Day shift
  shiftConfig.day.start = document.getElementById('configDayStart')?.value || shiftConfig.day.start;
  shiftConfig.day.end = document.getElementById('configDayEnd')?.value || shiftConfig.day.end;
  shiftConfig.day.wake = document.getElementById('configDayWake')?.value || shiftConfig.day.wake;
  shiftConfig.day.sleep = document.getElementById('configDaySleep')?.value || shiftConfig.day.sleep;
  
  // Late shift
  shiftConfig.late.start = document.getElementById('configLateStart')?.value || shiftConfig.late.start;
  shiftConfig.late.end = document.getElementById('configLateEnd')?.value || shiftConfig.late.end;
  shiftConfig.late.wake = document.getElementById('configLateWake')?.value || shiftConfig.late.wake;
  shiftConfig.late.sleep = document.getElementById('configLateSleep')?.value || shiftConfig.late.sleep;
  
  // Night shift
  shiftConfig.night.start = document.getElementById('configNightStart')?.value || shiftConfig.night.start;
  shiftConfig.night.end = document.getElementById('configNightEnd')?.value || shiftConfig.night.end;
  shiftConfig.night.wake = document.getElementById('configNightWake')?.value || shiftConfig.night.wake;
  shiftConfig.night.sleep = document.getElementById('configNightSleep')?.value || shiftConfig.night.sleep;
  
  // Off/Free day
  shiftConfig.off.wake = document.getElementById('configOffWake')?.value || shiftConfig.off.wake;
  shiftConfig.off.sleep = document.getElementById('configOffSleep')?.value || shiftConfig.off.sleep;
  
  // Save appearance settings (name, colors)
  const shiftTypes = ['early', 'day', 'late', 'night', 'off', 'vacation', 'sick'];
  shiftTypes.forEach(key => {
    const nameInput = document.getElementById(`appearanceName_${key}`);
    const bgInput = document.getElementById(`appearanceBg_${key}`);
    const textInput = document.getElementById(`appearanceText_${key}`);
    
    if (nameInput) shiftConfig[key].name = nameInput.value;
    if (bgInput) shiftConfig[key].bgColor = bgInput.value;
    if (textInput) shiftConfig[key].textColor = textInput.value;
  });
  
  saveShiftConfig(shiftConfig);

  // Recalculate all scheduled intakes with new times
  updateAllScheduledIntakes();
  updateShiftTimeDisplays();
  
  // Update calendar display with new colors
  updateCalendarDisplay();
  updateShiftLegend();
  
  // If in week view, re-render it
  if (currentCalendarView === 'week') {
    renderWeekView();
  }
  
  closeShiftConfig();
  showToast('Einstellungen gespeichert! ✓');
}

function updateShiftTimeDisplays() {
  const displays = {
    early: document.getElementById('earlyTimeDisplay'),
    day: document.getElementById('dayTimeDisplay'),
    late: document.getElementById('lateTimeDisplay'),
    night: document.getElementById('nightTimeDisplay')
  };
  
  Object.entries(displays).forEach(([key, el]) => {
    if (el && shiftConfig[key]) {
      const { start, end } = shiftConfig[key];
      el.textContent = start && end ? `${start} - ${end}` : 'Nicht eingestellt';
    }
  });
}

