// Tab switching
function switchConfigTab(tabName) {
  // Update tab buttons
  document.querySelectorAll('.config-tab').forEach(tab => tab.classList.remove('active'));
  document.getElementById(`configTab${tabName.charAt(0).toUpperCase() + tabName.slice(1)}`).classList.add('active');
  
  // Update tab content
  document.getElementById('configContentTimes').style.display = tabName === 'times' ? 'block' : 'none';
  document.getElementById('configContentMeals').style.display = tabName === 'meals' ? 'block' : 'none';
  document.getElementById('configContentAppearance').style.display = tabName === 'appearance' ? 'block' : 'none';
  
  // Render meals config wenn Tab gewählt
  if (tabName === 'meals') {
    renderMealsConfig();
  }
}

// Render Mahlzeiten-Einstellungen
function renderMealsConfig() {
  const container = document.getElementById('mealsConfigList');
  if (!container) return;
  
  const shiftTypes = ['early', 'day', 'late', 'night', 'off', 'vacation', 'sick'];
  const shiftNames = {
    early: 'Frühschicht',
    day: 'Tagschicht',
    late: 'Spätschicht',
    night: 'Nachtschicht',
    off: 'Frei',
    vacation: 'Urlaub',
    sick: 'Krank'
  };
  const shiftIcons = {
    early: '🌅',
    day: '☀️',
    late: '🌇',
    night: '🌙',
    off: '🏠',
    vacation: '🏖️',
    sick: '🤒'
  };
  const mealNames = {
    breakfast: '🥐 Frühstück',
    lunch: '🍽️ Mittagessen',
    dinner: '🍝 Abendessen',
    snack: '🍎 Snack/Nachtsnack'
  };
  
  let html = '';
  
  shiftTypes.forEach(shift => {
    const config = shiftConfig[shift];
    const meals = config.meals || {
      breakfast: { enabled: true, time: '08:00' },
      lunch: { enabled: true, time: '12:30' },
      dinner: { enabled: true, time: '19:00' },
      snack: { enabled: false, time: null }
    };
    
    html += `
      <div class="meals-shift-item">
        <div class="meals-shift-header" onclick="toggleMealsExpand('${shift}')">
          <span class="meals-shift-icon">${config.icon || shiftIcons[shift]}</span>
          <span class="meals-shift-name">${config.name || shiftNames[shift]}</span>
          <span class="meals-expand-icon" id="mealsExpandIcon${shift}">▼</span>
        </div>
        <div class="meals-shift-details" id="mealsDetails${shift}">
    `;
    
    Object.entries(mealNames).forEach(([mealKey, mealLabel]) => {
      const meal = meals[mealKey] || { enabled: false, time: null };
      html += `
        <div class="meals-row">
          <label class="meals-toggle">
            <input type="checkbox" 
                   id="meal_${shift}_${mealKey}_enabled" 
                   ${meal.enabled ? 'checked' : ''} 
                   onchange="toggleMealEnabled('${shift}', '${mealKey}')">
            <span class="meals-toggle-slider"></span>
          </label>
          <span class="meals-label">${mealLabel}</span>
          <input type="time" 
                 class="meals-time-input" 
                 id="meal_${shift}_${mealKey}_time" 
                 value="${meal.time || ''}"
                 ${!meal.enabled ? 'disabled' : ''}
                 onchange="updateMealTime('${shift}', '${mealKey}', this.value)">
        </div>
      `;
    });
    
    html += `
        </div>
      </div>
    `;
  });
  
  container.innerHTML = html;
}

function toggleMealsExpand(shift) {
  const details = document.getElementById(`mealsDetails${shift}`);
  const icon = document.getElementById(`mealsExpandIcon${shift}`);
  if (details) {
    details.classList.toggle('expanded');
    if (icon) {
      icon.textContent = details.classList.contains('expanded') ? '▲' : '▼';
    }
  }
}

function toggleMealEnabled(shift, mealKey) {
  const checkbox = document.getElementById(`meal_${shift}_${mealKey}_enabled`);
  const timeInput = document.getElementById(`meal_${shift}_${mealKey}_time`);
  
  if (!shiftConfig[shift].meals) {
    shiftConfig[shift].meals = {
      breakfast: { enabled: true, time: '08:00' },
      lunch: { enabled: true, time: '12:30' },
      dinner: { enabled: true, time: '19:00' },
      snack: { enabled: false, time: null }
    };
  }
  
  shiftConfig[shift].meals[mealKey].enabled = checkbox.checked;
  
  if (timeInput) {
    timeInput.disabled = !checkbox.checked;
  }
}

function updateMealTime(shift, mealKey, time) {
  if (!shiftConfig[shift].meals) {
    shiftConfig[shift].meals = {
      breakfast: { enabled: true, time: '08:00' },
      lunch: { enabled: true, time: '12:30' },
      dinner: { enabled: true, time: '19:00' },
      snack: { enabled: false, time: null }
    };
  }
  
  shiftConfig[shift].meals[mealKey].time = time;
}

