let currentIconPickerKey = null;

function openIconPicker(key) {
  currentIconPickerKey = key;
  
  // Create popup if not exists
  let picker = document.getElementById('iconPickerPopup');
  if (!picker) {
    picker = document.createElement('div');
    picker.id = 'iconPickerPopup';
    picker.className = 'icon-picker-popup';
    picker.innerHTML = `
      <div class="icon-picker-header">
        <span>Symbol auswählen</span>
        <button onclick="closeIconPicker()">✕</button>
      </div>
      <div class="icon-picker-grid" id="iconPickerGrid"></div>
    `;
    document.body.appendChild(picker);
  }
  
  // Fill grid
  const grid = document.getElementById('iconPickerGrid');
  grid.innerHTML = shiftIconOptions.map(icon => 
    `<button class="icon-picker-btn" onclick="selectIcon('${icon}')">${icon}</button>`
  ).join('');
  
  // Show popup
  picker.classList.add('visible');
}

function closeIconPicker() {
  const picker = document.getElementById('iconPickerPopup');
  if (picker) picker.classList.remove('visible');
  currentIconPickerKey = null;
}

function selectIcon(icon) {
  if (!currentIconPickerKey) return;
  
  // Update preview
  const previewIcon = document.getElementById(`previewIcon_${currentIconPickerKey}`);
  if (previewIcon) previewIcon.textContent = icon;
  
  // Update shiftConfig
  if (shiftConfig[currentIconPickerKey]) {
    shiftConfig[currentIconPickerKey].icon = icon;
  }
  
  closeIconPicker();
}

// Update preview when colors change
function updateShiftAppearancePreview(key) {
  const preview = document.getElementById(`preview_${key}`);
  const bgInput = document.getElementById(`appearanceBg_${key}`);
  const textInput = document.getElementById(`appearanceText_${key}`);

  if (preview && bgInput && textInput) {
    preview.style.background = bgInput.value;
    preview.style.color = textInput.value;
  }
  // Update swatches
  const swatchBg = document.getElementById(`swatchBg_${key}`);
  const swatchText = document.getElementById(`swatchText_${key}`);
  if (swatchBg && bgInput) swatchBg.style.background = bgInput.value;
  if (swatchText && textInput) swatchText.style.background = textInput.value;
}

