function openPatternApply(patternId) {
  const patterns = {
    '2-2-3': { name: '2-2-3 Muster', shifts: ['early', 'early', 'off', 'off', 'late', 'late', 'late'] },
    '4-4': { name: '4 on / 4 off', shifts: ['day', 'day', 'day', 'day', 'off', 'off', 'off', 'off'] },
    '5-2': { name: '5-2 Standard', shifts: ['day', 'day', 'day', 'day', 'day', 'off', 'off'] },
    'rotating': { name: 'Rotierend', shifts: ['early', 'early', 'late', 'late', 'night', 'night', 'off'] },
    'continental': { name: 'Kontinental', shifts: ['early', 'early', 'late', 'late', 'off', 'off', 'night', 'night', 'off', 'off'] }
  };
  
  const pattern = patterns[patternId];
  if (!pattern) return;
  
  document.getElementById('patternApplyTitle').textContent = pattern.name;
  
  // Render preview
  const preview = document.getElementById('patternPreviewBig');
  preview.innerHTML = pattern.shifts.map((s, i) => {
    const labels = { early: 'F', day: 'T', late: 'S', night: 'N', off: 'X' };
    return `<div class="p-dot ${s}">${labels[s]}</div>`;
  }).join('');
  
  // Set default start date to today
  document.getElementById('patternStartDate').value = formatDate(new Date());
  
  document.getElementById('patternApplyOverlay').classList.add('visible');
  document.getElementById('patternApplySheet').classList.add('visible');
  lockBody();
}

function closePatternApply() {
  document.getElementById('patternApplyOverlay').classList.remove('visible');
  document.getElementById('patternApplySheet').classList.remove('visible');
  unlockBody();
}

function backToPatterns() {
  closePatternApply();
  openPatternSheet();
}

function applyPattern() {
  const patterns = {
    '2-2-3': ['early', 'early', 'off', 'off', 'late', 'late', 'late'],
    '4-4': ['day', 'day', 'day', 'day', 'off', 'off', 'off', 'off'],
    '5-2': ['day', 'day', 'day', 'day', 'day', 'off', 'off'],
    'rotating': ['early', 'early', 'late', 'late', 'night', 'night', 'off'],
    'continental': ['early', 'early', 'late', 'late', 'off', 'off', 'night', 'night', 'off', 'off']
  };
  
  // Check if it's a custom pattern
  let pattern = patterns[selectedPattern];
  
  // If not found in predefined, check if we have customPatternShifts
  if (!pattern && customPatternShifts) {
    pattern = customPatternShifts;
  }
  
  // If still not found, try to load from saved patterns
  if (!pattern && selectedPattern && selectedPattern.startsWith('custom-')) {
    try {
      const saved = localStorage.getItem('suppTreeCustomPatterns');
      if (saved) {
        const savedPatterns = JSON.parse(saved);
        const customPattern = savedPatterns.find(p => p.id === selectedPattern);
        if (customPattern) pattern = customPattern.shifts;
      }
    } catch(e) {}
  }
  
  if (!pattern) {
    showToast('⚠️ Kein Muster ausgewählt');
    return;
  }
  
  const startDateStr = document.getElementById('patternStartDate').value;
  const weeks = parseInt(document.getElementById('patternDuration').value);
  
  const startDate = new Date(startDateStr);
  const totalDays = weeks * 7;
  
  const appliedDates = [];
  for (let i = 0; i < totalDays; i++) {
    const currentDate = new Date(startDate);
    currentDate.setDate(currentDate.getDate() + i);
    const dateKey = formatDate(currentDate);
    const shiftType = pattern[i % pattern.length];
    shifts[dateKey] = shiftType;
    appliedDates.push(dateKey);
  }

  // Track which pattern applied which dates
  if (selectedPattern) {
    const patternMap = JSON.parse(localStorage.getItem('suppTreePatternDateMap') || '{}');
    patternMap[selectedPattern] = appliedDates;
    localStorage.setItem('suppTreePatternDateMap', JSON.stringify(patternMap));
  }

  // Save shifts
  saveShifts(shifts);

  // Update supplement schedules based on new pattern
  updateAllScheduledIntakes();
  
  // Clear custom pattern shifts
  customPatternShifts = null;
  
  // Update alle Anzeigen
  updateCalendarDisplay();
  updateTodayShiftCard();  // Update Home-Screen Schicht-Karte
  renderDayPlanner();  // Update Home-Screen Timeline
  renderWeekPreview();  // Update 7-Tage Vorschau
  updateWeekPreviewBadge();  // Update Badge
  
  closePatternApply();
  showToast(`✅ Muster für ${weeks} Wochen angewendet`);
}

