function initPaintShiftColors() {
  const shiftTypes = ['early', 'day', 'late', 'night', 'off'];
  
  shiftTypes.forEach(key => {
    const config = shiftConfig[key];
    const bgColor = config?.bgColor;
    const textColor = config?.textColor;
    const icon = config?.icon;
    
    // Update CSS variable
    if (bgColor) {
      document.documentElement.style.setProperty(`--shift-${key}`, bgColor);
    }
    
    // Update paint shift button
    const paintBtn = document.querySelector(`.paint-shift-btn[data-shift="${key}"]`);
    if (paintBtn) {
      if (bgColor) paintBtn.style.background = bgColor;
      if (textColor) paintBtn.style.color = textColor;
      
      // Update icon
      if (icon) {
        const iconSpan = paintBtn.querySelector('span:first-child');
        if (iconSpan) iconSpan.textContent = icon;
      }
    }
  });
}

