// Set cycle length and show/hide days
function setCustomCycleLength(days) {
  // Update buttons
  document.querySelectorAll('.cycle-btn').forEach(btn => {
    btn.classList.toggle('active', parseInt(btn.dataset.days) === days);
  });
  
  // Show/hide days in grid
  const grid = document.getElementById('customRhythmGrid');
  
  // Clear existing grid
  grid.innerHTML = '';
  
  // Create days
  for (let i = 1; i <= days; i++) {
    const dayEl = document.createElement('div');
    dayEl.className = 'rhythm-day';
    dayEl.dataset.day = i;
    dayEl.onclick = function() { cycleRhythmDay(this); };
    dayEl.innerHTML = `
      <span class="rhythm-day-num">${i}</span>
      <span class="rhythm-day-shift off">—</span>
    `;
    grid.appendChild(dayEl);
  }
}

// Cycle through shift types on tap
const shiftCycle = ['off', 'early', 'day', 'late', 'night'];
const rhythmShiftLabels = {
  'off': '—',
  'early': 'F',
  'day': 'T',
  'late': 'S',
  'night': 'N'
};

// Paint Mode - Selected shift
let selectedPaintShift = 'early';

function selectPaintShift(shift) {
  selectedPaintShift = shift;
  
  // Update button states
  document.querySelectorAll('.paint-shift-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.shift === shift);
  });
}

function cycleRhythmDay(dayEl) {
  // Paint Mode: Apply selected shift
  const shiftSpan = dayEl.querySelector('.rhythm-day-shift');
  
  // Get shift color from shiftConfig or fallback
  const config = shiftConfig[selectedPaintShift];
  const bgColor = config?.bgColor || getDefaultShiftColor(selectedPaintShift);
  const textColor = config?.textColor || (selectedPaintShift === 'night' ? 'white' : 'inherit');
  
  // Remove all shift classes
  shiftCycle.forEach(s => shiftSpan.classList.remove(s));
  
  // Add new class and label
  shiftSpan.classList.add(selectedPaintShift);
  shiftSpan.textContent = rhythmShiftLabels[selectedPaintShift];
  
  // Apply color to the day element
  dayEl.style.background = bgColor;
  dayEl.style.color = textColor;
  
  // Add tap animation
  dayEl.style.transform = 'scale(0.9)';
  setTimeout(() => {
    dayEl.style.transform = '';
  }, 100);
}

function getDefaultShiftColor(shift) {
  const defaults = {
    early: '#f59e0b',
    day: '#8b5cf6',
    late: '#3b82f6',
    night: '#1e293b',
    off: '#10b981'
  };
  return defaults[shift] || '#94a3b8';
}

// Quick fill all days with same shift
function quickFillRhythm(shiftType) {
  const config = shiftConfig[shiftType];
  const bgColor = config?.bgColor || getDefaultShiftColor(shiftType);
  const textColor = config?.textColor || (shiftType === 'night' ? 'white' : 'inherit');
  
  document.querySelectorAll('.rhythm-day').forEach(dayEl => {
    const shiftSpan = dayEl.querySelector('.rhythm-day-shift');
    
    // Remove all shift classes
    shiftCycle.forEach(s => shiftSpan.classList.remove(s));
    
    // Add new class and label
    shiftSpan.classList.add(shiftType);
    shiftSpan.textContent = rhythmShiftLabels[shiftType];
    
    // Apply background color to the day element (same as manual click)
    dayEl.style.background = bgColor;
    dayEl.style.color = textColor;
  });
}

// Save custom rhythm
function saveCustomRhythm() {
  const nameInput = document.getElementById('customRhythmName');
  
  if (!nameInput) {
    showToast('⚠️ Fehler: Input nicht gefunden');
    return;
  }
  
  const name = nameInput.value ? nameInput.value.trim() : '';
  
  if (!name || name === '') {
    showToast('⚠️ Bitte gib deinem Rhythmus einen Namen');
    // Markiere das Feld rot
    nameInput.classList.add('input-error');
    nameInput.focus();
    return;
  }
  
  // Entferne error-Klasse falls vorhanden
  nameInput.classList.remove('input-error');
  
  // Get the pattern from the grid
  const grid = document.getElementById('customRhythmGrid');
  if (!grid) {
    showToast('⚠️ Fehler: Grid nicht gefunden');
    return;
  }
  
  const days = grid.querySelectorAll('.rhythm-day:not(.hidden)');
  const shiftsArray = [];
  const shiftTypes = ['early', 'day', 'late', 'night', 'off'];
  
  days.forEach(day => {
    const shiftSpan = day.querySelector('.rhythm-day-shift');
    let foundShift = 'off';
    
    shiftTypes.forEach(type => {
      if (shiftSpan && shiftSpan.classList.contains(type)) {
        foundShift = type;
      }
    });
    
    shiftsArray.push(foundShift);
  });
  
  if (shiftsArray.length === 0) {
    showToast('⚠️ Bitte wähle mindestens einen Tag');
    return;
  }
  
  // Load existing patterns
  let savedPatterns = [];
  try {
    const saved = localStorage.getItem('suppTreeCustomPatterns');
    if (saved) savedPatterns = JSON.parse(saved);
  } catch(e) {}
  
  // Create new pattern
  const newPattern = {
    id: 'custom-' + Date.now(),
    name: name,
    shifts: shiftsArray,
    createdAt: new Date().toISOString()
  };
  
  savedPatterns.unshift(newPattern);
  if (savedPatterns.length > 10) savedPatterns.pop();
  
  localStorage.setItem('suppTreeCustomPatterns', JSON.stringify(savedPatterns));
  
  showToast('✅ Rhythmus "' + name + '" gespeichert!');
  
  // Clear the input
  nameInput.value = '';
  
  // Close the sheet after a short delay
  setTimeout(() => {
    closeCustomRhythm();
  }, 500);
}

// Render saved custom patterns in the pattern sheet
function renderSavedCustomPatterns() {
  const container = document.getElementById('savedPatternsContainer');
  if (!container) {
    return;
  }
  
  let savedPatterns = [];
  try {
    const saved = localStorage.getItem('suppTreeCustomPatterns');
    if (saved) {
      savedPatterns = JSON.parse(saved);
    }
  } catch(e) {
    // Fehler beim Laden ignorieren
  }
  
  if (!savedPatterns || savedPatterns.length === 0) {
    container.innerHTML = '';
    container.style.display = 'none';
    return;
  }
  
  container.style.display = 'block';
  
  const shiftLabels = { early: 'F', day: 'T', late: 'S', night: 'N', off: 'X' };
  
  container.innerHTML = `
    <div class="saved-patterns-header">
      <h4>📁 Meine Vorlagen (${savedPatterns.length})</h4>
    </div>
    <div class="saved-patterns-list">
      ${savedPatterns.map(pattern => `
        <div class="pattern-card saved" onclick="selectSavedPattern('${pattern.id}')">
          <div class="pattern-preview">
            ${(pattern.shifts || []).slice(0, 7).map(s => `<span class="p-dot ${s}">${shiftLabels[s] || '?'}</span>`).join('')}
          </div>
          <div class="pattern-info">
            <h4>${pattern.name || 'Unbenannt'}</h4>
            <p>${(pattern.shifts || []).length} Tage Rhythmus</p>
          </div>
          <button class="pattern-delete-btn" onclick="event.stopPropagation(); deleteCustomPattern('${pattern.id}')">🗑️</button>
        </div>
      `).join('')}
    </div>
  `;
}

// Select a saved custom pattern
function selectSavedPattern(patternId) {
  let savedPatterns = [];
  try {
    const saved = localStorage.getItem('suppTreeCustomPatterns');
    if (saved) savedPatterns = JSON.parse(saved);
  } catch(e) {}
  
  const pattern = savedPatterns.find(p => p.id === patternId);
  if (!pattern) return;
  
  closePatternSheet();
  
  // Open apply sheet with this pattern
  document.getElementById('patternApplyTitle').textContent = pattern.name;
  
  const shiftLabels = { early: 'F', day: 'T', late: 'S', night: 'N', off: 'X' };
  const preview = document.getElementById('patternPreviewBig');
  preview.innerHTML = pattern.shifts.map(s => `<div class="p-dot ${s}">${shiftLabels[s] || '?'}</div>`).join('');
  
  // Store for applying
  selectedPattern = patternId;
  customPatternShifts = pattern.shifts;
  
  document.getElementById('patternStartDate').valueAsDate = new Date();
  document.getElementById('patternApplyOverlay').classList.add('visible');
  document.getElementById('patternApplySheet').classList.add('visible');
  lockBody();
}

// Delete a custom pattern
function deleteCustomPattern(patternId) {
  showConfirmDialog('Vorlage löschen', 'Vorlage und alle zugehörigen Schichten im Kalender löschen?', 'Löschen', function() {
    // Remove applied shifts from calendar
    try {
      const patternMap = JSON.parse(localStorage.getItem('suppTreePatternDateMap') || '{}');
      const appliedDates = patternMap[patternId];
      if (appliedDates && appliedDates.length > 0) {
        appliedDates.forEach(function(dateKey) {
          delete shifts[dateKey];
        });
        saveShifts(shifts);
      }
      delete patternMap[patternId];
      localStorage.setItem('suppTreePatternDateMap', JSON.stringify(patternMap));
    } catch(e) {}

    // Remove pattern template
    let savedPatterns = [];
    try {
      const saved = localStorage.getItem('suppTreeCustomPatterns');
      if (saved) savedPatterns = JSON.parse(saved);
    } catch(e) {}

    savedPatterns = savedPatterns.filter(p => p.id !== patternId);
    localStorage.setItem('suppTreeCustomPatterns', JSON.stringify(savedPatterns));

    // Update all displays
    updateCalendarDisplay();
    updateTodayShiftCard();
    renderDayPlanner();
    renderWeekPreview();
    updateWeekPreviewBadge();

    showToast('🗑️ Vorlage & Schichten gelöscht');
    renderSavedCustomPatterns();
  }, true);
}

