function updateShiftLegend() {
  const legendItems = document.querySelectorAll('.shift-legend .legend-item');
  legendItems.forEach(item => {
    const shiftKey = item.dataset.shift;
    if (shiftKey && shiftConfig[shiftKey]) {
      const dot = item.querySelector('.legend-dot');
      const label = item.querySelector('span:not(.legend-dot)');
      
      if (dot) {
        dot.style.background = shiftConfig[shiftKey].bgColor;
        // Show icon inside dot if available
        if (shiftConfig[shiftKey].icon) {
          dot.textContent = shiftConfig[shiftKey].icon;
          dot.style.fontSize = '10px';
          dot.style.display = 'flex';
          dot.style.alignItems = 'center';
          dot.style.justifyContent = 'center';
        }
      }
      if (label) {
        label.textContent = shiftLabels[shiftKey] || shiftConfig[shiftKey].name || shiftKey;
      }
    }
  });
}

