let currentCalendarView = 'month';
let currentWeekOffset = 0;

function setCalendarView(view) {
  currentCalendarView = view;
  currentWeekOffset = 0;
  
  // Update button states - alle Tab-Varianten
  document.querySelectorAll('.cal-action-btn').forEach(btn => btn.classList.remove('active'));
  document.querySelector(`.cal-action-btn[onclick="setCalendarView('${view}')"]`)?.classList.add('active');
  
  document.querySelectorAll('.view-pill').forEach(btn => btn.classList.remove('active'));
  document.querySelector(`.view-pill[data-view="${view}"]`)?.classList.add('active');
  
  document.querySelectorAll('.planer-tab').forEach(btn => btn.classList.remove('active'));
  document.querySelector(`.planer-tab[data-view="${view}"]`)?.classList.add('active');
  
  const planerContainer = document.getElementById('planerContainer');
  const weekdaysFixed = document.querySelector('.planer-weekdays-fixed');
  
  if (view === 'week') {
    // Wochenansicht
    if (weekdaysFixed) weekdaysFixed.style.display = 'none';
    renderWeekView();
  } else {
    // Monatsansicht
    if (weekdaysFixed) weekdaysFixed.style.display = 'grid';
    renderMonthCalendar();
  }
}

function renderMonthCalendar() {
  const container = document.getElementById('planerContainer');
  if (!container) return;
  
  const today = new Date();
  let html = '';
  
  // Generate 12 months (current + 11 future)
  for (let i = 0; i < 12; i++) {
    const date = new Date(today.getFullYear(), today.getMonth() + i, 1);
    html += renderMonth(date);
  }
  
  container.innerHTML = html;
  
  // Re-setup touch events
  setupMultiSelectEvents();
  
  // Update display with saved shifts
  updateCalendarDisplay();
}

function renderWeekView() {
  const container = document.getElementById('planerContainer');
  if (!container) return;
  
  // Berechne die aktuelle Woche
  const today = new Date();
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - today.getDay() + 1 + (currentWeekOffset * 7)); // Montag der Woche
  
  const weekDays = [];
  for (let i = 0; i < 7; i++) {
    const day = new Date(startOfWeek);
    day.setDate(startOfWeek.getDate() + i);
    weekDays.push(day);
  }
  
  // Wochen-Header
  const weekStart = weekDays[0];
  const weekEnd = weekDays[6];
  const monthNames = ['Januar', 'Februar', 'März', 'April', 'Mai', 'Juni', 'Juli', 'August', 'September', 'Oktober', 'November', 'Dezember'];
  const weekLabel = `${weekStart.getDate()}. ${monthNames[weekStart.getMonth()]} - ${weekEnd.getDate()}. ${monthNames[weekEnd.getMonth()]} ${weekEnd.getFullYear()}`;
  
  let html = `
    <div class="week-view-container">
      <div class="week-view-header">
        <button class="week-nav-btn" onclick="changeWeek(-1)">‹</button>
        <h3 class="week-view-title">${weekLabel}</h3>
        <button class="week-nav-btn" onclick="changeWeek(1)">›</button>
      </div>
      <div class="week-view-days">
  `;
  
  const dayNames = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So'];
  const todayStr = formatDate(today);
  
  weekDays.forEach((day, index) => {
    const dateStr = formatDate(day);
    const shiftType = shifts[dateStr] || '';
    const config = shiftConfig[shiftType] || null;
    const isToday = dateStr === todayStr;
    const isPast = day < new Date().setHours(0,0,0,0);
    
    const shiftName = config ? config.name : '';
    const shiftIcon = config?.icon || '';
    const shiftTime = config && config.start && config.end ? `${config.start} - ${config.end}` : '';
    const bgColor = config?.bgColor || '#F3F4F6';
    const textColor = config?.textColor || '#6B7280';
    
    html += `
      <div class="week-day-card ${isToday ? 'today' : ''} ${isPast ? 'past' : ''}" onclick="openShiftEditForDate('${dateStr}')">
        <div class="week-day-header">
          <span class="week-day-name">${dayNames[index]}</span>
          <span class="week-day-date ${isToday ? 'today-badge' : ''}">${day.getDate()}</span>
        </div>
        <div class="week-day-content">
          ${shiftType && config ? `
            <div class="week-day-shift" style="background: ${bgColor}; color: ${textColor}; padding: 6px 10px; border-radius: 7px;">
              ${shiftIcon ? `<span class="shift-icon">${shiftIcon}</span>` : ''}
              <span class="shift-name">${shiftName}</span>
            </div>
            ${shiftTime ? `<span class="shift-time">${shiftTime}</span>` : ''}
          ` : `
            <div class="week-day-empty">
              <span>+ Hinzufügen</span>
            </div>
          `}
        </div>
      </div>
    `;
  });
  
  html += `
      </div>
      <button class="week-today-btn" onclick="goToCurrentWeek()">📍 Aktuelle Woche</button>
    </div>
  `;
  
  container.innerHTML = html;
}

function changeWeek(delta) {
  currentWeekOffset += delta;
  renderWeekView();
}

function goToCurrentWeek() {
  currentWeekOffset = 0;
  renderWeekView();
}

function openShiftEditForDate(dateStr) {
  selectedDate = dateStr;
  openShiftEdit(dateStr);
}

function scrollToToday() {
  const today = formatDate(new Date());
  const todayEl = document.querySelector(`.planer-day[data-date="${today}"]`);
  if (todayEl) {
    todayEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }
}

function showToast(message) {
  // Create toast element
  const toast = document.createElement('div');
  toast.className = 'toast';
  toast.textContent = message;
  toast.style.cssText = `
    position: fixed;
    bottom: 120px;
    left: 50%;
    transform: translateX(-50%);
    background: #1e293b;
    color: white;
    padding: 12px 24px;
    border-radius: 7px;
    font-size: 14px;
    font-weight: 500;
    z-index: 300000;
    animation: toastIn 0.3s ease;
  `;
  document.body.appendChild(toast);
  
  setTimeout(() => {
    toast.style.animation = 'toastOut 0.3s ease forwards';
    setTimeout(() => toast.remove(), 300);
  }, 2000);
}

// Add toast animations to head
const toastStyles = document.createElement('style');
toastStyles.textContent = `
  @keyframes toastIn {
    from { opacity: 0; transform: translateX(-50%) translateY(20px); }
    to { opacity: 1; transform: translateX(-50%) translateY(0); }
  }
  @keyframes toastOut {
    from { opacity: 1; transform: translateX(-50%) translateY(0); }
    to { opacity: 0; transform: translateX(-50%) translateY(-20px); }
  }
`;
document.head.appendChild(toastStyles);

