function toggleIntake(card) {
  const check = card.querySelector('.intake-check');
  const isChecked = check.classList.contains('checked');
  
  if (isChecked) {
    check.classList.remove('checked');
    check.textContent = '○';
    card.classList.remove('completed');
  } else {
    check.classList.add('checked');
    check.textContent = '✓';
    card.classList.add('completed');
    
    // Celebration animation
    check.style.transform = 'scale(1.3)';
    setTimeout(() => {
      check.style.transform = 'scale(1)';
    }, 200);
    
    // Update stats
    updateDailyProgress();
  }
}

function updateDailyProgress() {
  const total = document.querySelectorAll('.intake-card').length;
  const completed = document.querySelectorAll('.intake-card.completed').length;
  const statCards = document.querySelectorAll('.mein-stat-card');
  
  if (statCards[2]) {
    statCards[2].querySelector('.stat-ring-value').textContent = `${completed}/${total}`;
    const percentage = (completed / total) * 100;
    statCards[2].querySelector('.stat-ring-fill').setAttribute('stroke-dasharray', `${percentage}, 100`);
  }
  
  // Update week day for today
  const todayDot = document.querySelector('.week-day.today .day-count');
  if (todayDot) {
    todayDot.textContent = `${completed}/${total}`;
  }
}

function markAllDone() {
  const cards = document.querySelectorAll('.intake-card:not(.completed)');
  cards.forEach((card, index) => {
    setTimeout(() => {
      toggleIntake(card);
    }, index * 150);
  });
}

function dismissAlert() {
  const alert = document.getElementById('smartAlert');
  alert.style.transform = 'translateX(100%)';
  alert.style.opacity = '0';
  setTimeout(() => {
    alert.style.display = 'none';
  }, 300);
}

