// Update greeting based on time
function updateGreeting() {
  const now = new Date();
  const hour = now.getHours();
  const greetingEl = document.querySelector('.greeting-time');
  const homeGreetingEl = document.getElementById('homeGreetingTime');
  
  // Greeting Text
  let greetingText = 'Guten Tag,';
  if (hour < 12) {
    greetingText = t('greeting.morning') || 'Guten Morgen,';
  } else if (hour < 17) {
    greetingText = t('greeting.day') || 'Guten Tag,';
  } else {
    greetingText = t('greeting.evening') || 'Guten Abend,';
  }
  
  if (greetingEl) greetingEl.textContent = greetingText;
  if (homeGreetingEl) homeGreetingEl.textContent = greetingText;
  
  // Datum
  const dateEl = document.getElementById('homeDateDisplay');
  if (dateEl) {
    const days = ['Sonntag', 'Montag', 'Dienstag', 'Mittwoch', 'Donnerstag', 'Freitag', 'Samstag'];
    const months = ['Januar', 'Februar', 'März', 'April', 'Mai', 'Juni', 'Juli', 'August', 'September', 'Oktober', 'November', 'Dezember'];
    dateEl.textContent = `${days[now.getDay()]}, ${now.getDate()}. ${months[now.getMonth()]}`;
  }
  
  // Uhrzeit
  const timeEl = document.getElementById('homeTimeDisplay');
  if (timeEl) {
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    timeEl.textContent = `${hours}:${minutes}`;
  }

  // App-Mode Badge aktualisieren
  const modeBadge = document.getElementById('appModeBadge');
  if (modeBadge) {
    const isLive = supabase && currentUser;
    modeBadge.textContent = isLive ? 'LIVE' : 'LOCAL';
    modeBadge.style.background = isLive ? 'rgba(0,200,120,0.25)' : 'rgba(255,255,255,0.15)';
    modeBadge.style.color = isLive ? '#00ff88' : 'rgba(255,255,255,0.6)';
  }
}

// Update time every minute
setInterval(updateGreeting, 60000);

