function openAlleKuren() {
  lockBody();
  document.getElementById('alleKurenOverlay').classList.add('visible');
  document.getElementById('alleKurenSheet').classList.add('visible');
}

function closeAlleKuren() {
  document.getElementById('alleKurenOverlay').classList.remove('visible');
  document.getElementById('alleKurenSheet').classList.remove('visible');
  unlockBody();
}

