let currentKurKategorie = null;
let cameFromAlleKuren = false;

// Direkt zu Produkten (von Mein-Screen Chips)
function openKurProdukteDirekt(kategorie) {
  cameFromAlleKuren = false;
  openKurProdukteInternal(kategorie);
}

// Über Alle Kuren zu Produkten
function openKurProdukte(kategorie) {
  cameFromAlleKuren = true;
  openKurProdukteInternal(kategorie);
}

function openKurProdukteInternal(kategorie) {
  const kur = kurKatalog[kategorie];
  const pakete = kurPakete[kategorie];
  
  if (!kur || !pakete) return;
  
  currentKurKategorie = kategorie;
  
  // Header
  document.getElementById('kurProdukteTitle').textContent = `${kur.icon} ${kur.name}`;
  document.getElementById('kurProdukteIntro').textContent = kur.description;
  
  // Pakete rendern
  renderKurPakete(pakete);
  
  // Sheet öffnen
  document.getElementById('kurProdukteOverlay').classList.add('visible');
  document.getElementById('kurProdukteSheet').classList.add('visible');
}

function renderKurPakete(pakete) {
  const container = document.getElementById('kurPaketeList');
  
  container.innerHTML = pakete.map(paket => {
    const badgeHtml = paket.badge ? `<div class="kur-paket-badge ${paket.badge}">${paket.badge === 'bestseller' ? '⭐ Bestseller' : paket.badge === 'premium' ? '👑 Premium' : '🆕 Neu'}</div>` : '';
    
    const starsHtml = '★'.repeat(Math.floor(paket.rating)) + (paket.rating % 1 >= 0.5 ? '½' : '');
    
    return `
      <div class="kur-paket-card ${paket.badge || ''}">
        ${badgeHtml}
        <div class="kur-paket-content">
          <div class="kur-paket-header">
            <div class="kur-paket-image">${paket.icon}</div>
            <div class="kur-paket-info">
              <span class="kur-paket-partner">von ${paket.partner}</span>
              <span class="kur-paket-name">${paket.name}</span>
              <div class="kur-paket-meta">
                <span>⏱️ ${paket.duration}</span>
                <span>💊 ${paket.products.length} Produkte</span>
              </div>
              <div class="kur-paket-rating">
                <span class="kur-paket-stars">${starsHtml}</span>
                <span class="kur-paket-rating-text">${paket.rating} (${paket.reviews})</span>
              </div>
            </div>
          </div>
          
          <p class="kur-paket-desc">${paket.desc}</p>
          
          <div class="kur-paket-products">
            ${paket.products.map(p => `<span class="kur-paket-product-chip">✓ ${p}</span>`).join('')}
          </div>
          
          <div class="kur-paket-footer">
            <div class="kur-paket-pricing">
              ${paket.oldPrice ? `<span class="kur-paket-old-price">${paket.oldPrice.toFixed(2).replace('.', ',')} €</span>` : ''}
              <span class="kur-paket-price">${paket.price.toFixed(2).replace('.', ',')} €</span>
              <span class="kur-paket-price-info">inkl. MwSt., zzgl. Versand</span>
            </div>
            <button class="kur-paket-btn" onclick="addKurPaketToCart('${paket.id}')">
              In den Warenkorb
            </button>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

function closeKurProdukte() {
  document.getElementById('kurProdukteOverlay').classList.remove('visible');
  document.getElementById('kurProdukteSheet').classList.remove('visible');
  // Schließe auch Alle Kuren nur wenn direkt geöffnet
  if (!cameFromAlleKuren) {
    closeAlleKuren();
  }
}

function backToAlleKuren() {
  // Nur Produkte-Sheet schließen
  document.getElementById('kurProdukteOverlay').classList.remove('visible');
  document.getElementById('kurProdukteSheet').classList.remove('visible');
  
  // Wenn direkt geöffnet (nicht über Alle Kuren), dann komplett schließen
  if (!cameFromAlleKuren) {
    // Nichts weiter - einfach schließen
  }
  // Wenn über Alle Kuren geöffnet, bleibt Alle Kuren offen (ist bereits offen)
}

function addKurPaketToCart(paketId) {
  // Finde das Paket
  let paket = null;
  for (const kategorie in kurPakete) {
    const found = kurPakete[kategorie].find(p => p.id === paketId);
    if (found) {
      paket = found;
      break;
    }
  }
  
  if (!paket) return;
  
  // Zum Warenkorb hinzufügen
  let cart = JSON.parse(localStorage.getItem('supptree_cart') || '[]');
  
  const existingIndex = cart.findIndex(item => item.id === paket.id);
  if (existingIndex >= 0) {
    cart[existingIndex].quantity += 1;
  } else {
    cart.push({
      id: paket.id,
      name: paket.name,
      price: paket.price,
      oldPrice: paket.oldPrice,
      quantity: 1,
      type: 'kur-paket',
      partner: paket.partner,
      image: paket.icon,
      products: paket.products
    });
  }
  
  localStorage.setItem('supptree_cart', JSON.stringify(cart));
  updateCartBadge();
  
  showToast(`${paket.name} hinzugefügt! 🛒`, 'success');
}

