function renderPlanerWeekPreview() {
  const container = document.getElementById('planerWeekPreview');
  if (!container) return;
  
  const days = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So'];
  const today = new Date().getDay();
  const todayIdx = today === 0 ? 6 : today - 1; // Montag = 0
  
  // Demo Schichten
  const shifts = JSON.parse(localStorage.getItem('suppTreeShifts') || '{}');
  const shiftIcons = { 'F': '🌅', 'S': '☀️', 'N': '🌙', 'frei': '🏠', '': '➖' };
  
  container.innerHTML = days.map((day, idx) => {
    const isToday = idx === todayIdx;
    // Demo-Daten
    const shift = idx < 5 ? (idx % 3 === 0 ? 'F' : idx % 3 === 1 ? 'S' : 'N') : 'frei';
    return `
      <div class="week-day-preview ${isToday ? 'today' : ''}">
        <span class="wdp-label">${day}</span>
        <span class="wdp-shift">${shiftIcons[shift] || '➖'}</span>
      </div>
    `;
  }).join('');
}

function renderMeinActivePlaner() {
  const container = document.getElementById('meinActivePlaner');
  if (!container) return;

  const dayLabels = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So'];
  const today = new Date();
  const todayDayOfWeek = today.getDay();
  const todayIdx = todayDayOfWeek === 0 ? 6 : todayDayOfWeek - 1;

  const shiftIcons = {
    early: '🌅',
    day: '☀️',
    late: '🌆',
    night: '🌙',
    off: '🏠',
    vacation: '🏖️',
    sick: '🤒'
  };

  const shiftNames = {
    early: 'Frühschicht',
    day: 'Tagschicht',
    late: 'Spätschicht',
    night: 'Nachtschicht',
    off: 'Frei',
    vacation: 'Urlaub',
    sick: 'Krank'
  };

  // Berechne Montag dieser Woche
  const monday = new Date(today);
  monday.setDate(today.getDate() - todayIdx);

  // Hole Schichten für diese Woche
  const weekShifts = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    const dateStr = formatDate(d);
    const shift = shifts[dateStr] || 'off';
    weekShifts.push(shift);
  }

  // Heutige Schicht aus echten Daten
  const todayStr = formatDate(today);
  const currentShift = shifts[todayStr] || 'off';
  const currentShiftInfo = shiftConfig[currentShift] || {};
  const displayName = currentShiftInfo.name || shiftNames[currentShift] || 'Frei';
  const displayIcon = shiftIcons[currentShift] || '🏠';

  // Zähle geplante Supplements für heute
  const suppsCount = (mySupplements || []).length;
  const suppsText = suppsCount === 1 ? '1 Supplement geplant' : `${suppsCount} Supplements geplant`;

  container.innerHTML = `
    <div class="active-planer-card" onclick="switchScreen('calendarScreen')">
      <div class="active-kur-header-large">
        <div class="active-kur-icon-large" style="background: rgba(255,255,255,0.6);">📅</div>
        <div class="active-kur-info-large">
          <span class="active-kur-label" style="color:#1e40af;">Heute</span>
          <span class="active-kur-name-large" style="color:#1e40af;">${displayIcon} ${displayName}</span>
          <span class="active-kur-dates" style="color:#3b82f6;">${suppsText}</span>
        </div>
      </div>
      <div class="planer-week-mini">
        ${dayLabels.map((day, idx) => {
          const shift = weekShifts[idx];
          const icon = shiftIcons[shift] || '🏠';
          const isToday = idx === todayIdx;
          return `<div class="planer-day-mini" ${isToday ? 'style="background:rgba(59,130,246,0.3);"' : ''}>
            <span class="day-label">${day}</span>
            <span class="day-shift">${icon}</span>
          </div>`;
        }).join('')}
      </div>
    </div>
  `;
}

