function openTerminKategorie(kategorie) {
  document.body.style.overflow = 'hidden';
  
  // Zeige das Alle-Termine Sheet aber filtere nach Kategorie
  const subKategorien = kategorieMapping[kategorie] || [];
  
  // Rendere gefilterte Kategorien
  renderKategorieTermine(kategorie, subKategorien);
  
  document.getElementById('alleTermineOverlay').classList.add('visible');
  document.getElementById('alleTermineSheet').classList.add('visible');
}

function renderKategorieTermine(kategorie, subKategorien) {
  const container = document.querySelector('#alleTermineSheet .termine-options-grid');
  if (!container) return;
  
  // Setze Titel
  const titleEl = document.querySelector('#alleTermineSheet h2');
  if (titleEl) {
    titleEl.textContent = kategorieTitles[kategorie] || '🗓️ Termine buchen';
  }
  
  // Zeige nur relevante Kategorien
  const allCards = container.querySelectorAll('.termine-option-card');
  allCards.forEach(card => {
    const cardKat = card.getAttribute('onclick')?.match(/'([^']+)'/)?.[1];
    if (subKategorien.length === 0 || subKategorien.includes(cardKat)) {
      card.style.display = 'flex';
    } else {
      card.style.display = 'none';
    }
  });
}

function openAlleTermine() {
  lockBody();
  renderMeineTermineListe();
  
  // Setze Titel zurück
  const titleEl = document.querySelector('#alleTermineSheet h2');
  if (titleEl) {
    titleEl.textContent = '🗓️ Termine buchen';
  }
  
  // Zeige alle Kategorien
  const allCards = document.querySelectorAll('#alleTermineSheet .termine-option-card');
  allCards.forEach(card => card.style.display = 'flex');
  
  document.getElementById('alleTermineOverlay').classList.add('visible');
  document.getElementById('alleTermineSheet').classList.add('visible');
}

