function regenerateErnPlan() {
  showToast('Plan wird neu generiert...', 'success');
  setTimeout(renderGeneratedErnPlan, 500);
}

function saveErnaehrungPlan() {
  const plan = {
    id: 'ernplan_' + Date.now(),
    goal: selectedErnaehrungGoal,
    config: { ...ernaehrungConfig },
    createdAt: new Date().toISOString(),
    status: 'active'
  };
  
  let plans = JSON.parse(localStorage.getItem('suppTreeErnaehrungPlans') || '[]');
  plans.push(plan);
  saveErnaehrungPlans(plans);

  showToast('Ernährungsplan gespeichert! 🥗', 'success');
  document.getElementById('ernaehrungBuilderOverlay').classList.remove('visible');
  document.getElementById('ernaehrungBuilderSheet').classList.remove('visible');
  closeAlleErnaehrung();
  document.body.style.overflow = '';
  renderMeinActiveErnaehrung();
}

// Fertige Pläne
function openFertigePlaene() {
  document.body.style.overflow = 'hidden';
  cameFromAlleErnaehrung = document.getElementById('alleErnaehrungSheet')?.classList.contains('visible') || false;
  renderFertigePlaene();
  document.getElementById('fertigePlaeneOverlay').classList.add('visible');
  document.getElementById('fertigePlaeneSheet').classList.add('visible');
}

function closeFertigePlaene() {
  document.getElementById('fertigePlaeneOverlay').classList.remove('visible');
  document.getElementById('fertigePlaeneSheet').classList.remove('visible');
  if (!cameFromAlleErnaehrung) {
    closeAlleErnaehrung();
  }
  document.body.style.overflow = '';
}

function backFromFertigePlaene() {
  document.getElementById('fertigePlaeneOverlay').classList.remove('visible');
  document.getElementById('fertigePlaeneSheet').classList.remove('visible');
}

function filterFertigePlaene(category) {
  document.querySelectorAll('.fp-filter').forEach(f => f.classList.remove('active'));
  event.currentTarget.classList.add('active');
  renderFertigePlaene(category);
}

function renderFertigePlaene(filter = 'all') {
  const container = document.getElementById('fertigePlaeneList');
  const filtered = filter === 'all' ? fertigePlaene : fertigePlaene.filter(p => p.category === filter);
  
  container.innerHTML = filtered.map(plan => {
    const badgeHtml = plan.badge ? `<div class="fertig-plan-badge ${plan.badge}">${plan.badge === 'bestseller' ? '⭐ Bestseller' : plan.badge === 'premium' ? '👑 Premium' : '🆕 Neu'}</div>` : '';
    const starsHtml = '★'.repeat(Math.floor(plan.rating));
    
    return `
      <div class="fertig-plan-card ${plan.badge || ''}">
        ${badgeHtml}
        <div class="fertig-plan-content">
          <div class="fertig-plan-header">
            <div class="fertig-plan-image">${plan.icon}</div>
            <div class="fertig-plan-info">
              <span class="fertig-plan-partner">von ${plan.partner}</span>
              <span class="fertig-plan-name">${plan.name}</span>
              <div class="fertig-plan-meta">
                <span>⏱️ ${plan.duration}</span>
                <span>🔥 ${plan.kcal} kcal</span>
              </div>
              <div class="fertig-plan-rating">
                <span class="fertig-plan-stars">${starsHtml}</span>
                <span class="fertig-plan-rating-text">${plan.rating} (${plan.reviews})</span>
              </div>
            </div>
          </div>
          
          <p class="fertig-plan-desc">${plan.desc}</p>
          
          <div class="fertig-plan-features">
            ${plan.features.map(f => `<span class="fertig-plan-feature">✓ ${f}</span>`).join('')}
          </div>
          
          <div class="fertig-plan-footer">
            <div class="fertig-plan-pricing">
              <span class="fertig-plan-price">${plan.price.toFixed(2).replace('.', ',')} €</span>
              <span class="fertig-plan-price-info">einmalig</span>
            </div>
            <button class="fertig-plan-btn" onclick="buyFertigPlan('${plan.id}')">
              Kaufen
            </button>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

function buyFertigPlan(planId) {
  const plan = fertigePlaene.find(p => p.id === planId);
  if (plan) {
    showToast(`${plan.name} wird zum Warenkorb hinzugefügt...`, 'success');
  }
}

// Render Active Ernährung on Mein Screen
function renderMeinActiveErnaehrung() {
  const container = document.getElementById('meinActiveErnaehrung');
  if (!container) return;
  
  const plans = JSON.parse(localStorage.getItem('suppTreeErnaehrungPlans') || '[]');
  const activePlan = plans.find(p => p.status === 'active');
  
  if (!activePlan) {
    container.innerHTML = `
      <div class="ernaehrung-empty-state">
        <span class="ernaehrung-empty-icon">🥗</span>
        <p class="ernaehrung-empty-title">Kein aktiver Ernährungsplan</p>
        <p class="ernaehrung-empty-text">Erstelle einen Plan oder finde einen Ernährungsberater</p>
      </div>
    `;
    return;
  }
  
  const goalIcons = { abnehmen: '🔥', muskel: '💪', gesund: '❤️', energie: '⚡', vegan: '🌱', darm: '🦠' };
  const goalNames = { abnehmen: 'Abnehm-Plan', muskel: 'Muskelaufbau', gesund: 'Gesund & Fit', energie: 'Energie-Plan', vegan: 'Veganer Plan', darm: 'Darmgesundheit' };
  
  container.innerHTML = `
    <div class="active-ernaehrung-card">
      <div class="active-kur-header-large">
        <div class="active-kur-icon-large" style="background: rgba(255,255,255,0.6);">${goalIcons[activePlan.goal] || '🥗'}</div>
        <div class="active-kur-info-large">
          <span class="active-kur-label" style="color:#166534;">Aktiver Ernährungsplan</span>
          <span class="active-kur-name-large" style="color:#166534;">${goalNames[activePlan.goal] || 'Ernährungsplan'}</span>
          <span class="active-kur-dates" style="color:#22c55e;">${activePlan.config.meals} Mahlzeiten/Tag</span>
        </div>
      </div>
    </div>
  `;
}

