// Training Builder
function openTrainingBuilder() {
  window.savedScrollY = window.scrollY;
  document.body.style.overflow = 'hidden';
  document.body.classList.add('sheet-open');
  cameFromAlleTraining = document.getElementById('alleTrainingSheet')?.classList.contains('visible') || false;
  resetTrainingBuilder();
  const overlay = document.getElementById('trainingBuilderOverlay');
  overlay.classList.add('visible');
  overlay.addEventListener('touchmove', preventScroll, { passive: false });
  document.getElementById('trainingBuilderSheet').classList.add('visible');
}

function closeTrainingBuilder() {
  const overlay = document.getElementById('trainingBuilderOverlay');
  overlay.classList.remove('visible');
  overlay.removeEventListener('touchmove', preventScroll);
  document.getElementById('trainingBuilderSheet').classList.remove('visible');
  if (!cameFromAlleTraining) {
    closeAlleTraining();
  }
  document.body.style.overflow = '';
  document.body.classList.remove('sheet-open');
  if (window.savedScrollY !== undefined) {
    window.scrollTo(0, window.savedScrollY);
  }
}

function backFromTrainingBuilder() {
  const overlay = document.getElementById('trainingBuilderOverlay');
  overlay.classList.remove('visible');
  overlay.removeEventListener('touchmove', preventScroll);
  document.getElementById('trainingBuilderSheet').classList.remove('visible');
  // Alle Training Sheet ist noch offen
}

function resetTrainingBuilder() {
  selectedTrainingGoal = null;
  selectedMuscleGroups = [];
  
  // Zeige Auswahl-Screen
  document.getElementById('builderContent0').style.display = 'block';
  document.getElementById('builderContentTemplates').style.display = 'none';
  document.getElementById('builderContentTemplateDetail').style.display = 'none';
  document.getElementById('builderContentCustom').style.display = 'none';
  document.getElementById('builderContent1').style.display = 'none';
  document.getElementById('builderContent1b').style.display = 'none';
  document.getElementById('builderContent2').style.display = 'none';
  document.getElementById('builderContent3').style.display = 'none';
  
  // Reset step indicators
  const steps = ['builderStep1', 'builderStep1b', 'builderStep2', 'builderStep3'];
  steps.forEach(s => {
    const el = document.getElementById(s);
    if (el) {
      el.classList.remove('active', 'done');
    }
  });
  document.getElementById('builderStep1')?.classList.add('active');
  document.querySelectorAll('.builder-goal-card, .custom-goal-card').forEach(c => c.classList.remove('selected'));
  
  // Reset muscle group UI
  document.querySelectorAll('.muscle-chip').forEach(c => c.classList.remove('selected'));
  document.querySelectorAll('.body-part-btn').forEach(p => p.classList.remove('selected'));
}

// Vorlagen zeigen
function showTemplates() {
  document.getElementById('builderContent0').style.display = 'none';
  document.getElementById('builderContentTemplates').style.display = 'block';
  filterTemplates('all');
}

// Custom Builder zeigen
function showCustomBuilder() {
  document.getElementById('builderContent0').style.display = 'none';
  document.getElementById('builderContentCustom').style.display = 'block';
  document.getElementById('builderContent1').style.display = 'block';
}

function backToBuilderChoice() {
  document.getElementById('builderContentTemplates').style.display = 'none';
  document.getElementById('builderContentCustom').style.display = 'none';
  document.getElementById('builderContent1').style.display = 'none';
  document.getElementById('builderContent0').style.display = 'block';
}

function backToTemplates() {
  document.getElementById('builderContentTemplateDetail').style.display = 'none';
  document.getElementById('builderContentTemplates').style.display = 'block';
}

// Template Filter
function filterTemplates(category) {
  document.querySelectorAll('.template-filter').forEach(f => f.classList.remove('active'));
  event.currentTarget.classList.add('active');
  
  document.querySelectorAll('.template-card').forEach(card => {
    if (category === 'all' || card.dataset.category === category) {
      card.classList.remove('hidden');
    } else {
      card.classList.add('hidden');
    }
  });
}

