let selectedTemplateId = null;
let selectedTemplateDays = [0, 2, 4]; // Default: Mo, Mi, Fr
let customSelectedDays = [0, 2, 4]; // Für Custom Builder
let selectedMuscleGroups = []; // Für Muskelgruppen-Auswahl

// Toggle Muscle Group Selection
function toggleMuscleGroup(muscle) {
  // Ganzkörper ist exklusiv
  if (muscle === 'ganzkoerper') {
    if (selectedMuscleGroups.includes('ganzkoerper')) {
      selectedMuscleGroups = [];
    } else {
      selectedMuscleGroups = ['ganzkoerper'];
    }
  } else {
    // Entferne Ganzkörper wenn einzelne Muskeln gewählt werden
    const gkIdx = selectedMuscleGroups.indexOf('ganzkoerper');
    if (gkIdx > -1) {
      selectedMuscleGroups.splice(gkIdx, 1);
    }
    
    const idx = selectedMuscleGroups.indexOf(muscle);
    if (idx > -1) {
      selectedMuscleGroups.splice(idx, 1);
    } else {
      selectedMuscleGroups.push(muscle);
    }
  }
  
  updateMuscleGroupUI();
}

function updateMuscleGroupUI() {
  // Update Chips
  document.querySelectorAll('.muscle-chip').forEach(chip => {
    const muscle = chip.dataset.muscle;
    chip.classList.toggle('selected', selectedMuscleGroups.includes(muscle));
  });
  
  // Update Body SVG
  document.querySelectorAll('.body-part-btn').forEach(part => {
    const muscle = part.dataset.part;
    part.classList.toggle('selected', selectedMuscleGroups.includes(muscle) || selectedMuscleGroups.includes('ganzkoerper'));
  });
  
  // Update Hint
  const hint = document.getElementById('muscleSelectionHint');
  const btn = document.getElementById('toStep2Btn');
  
  if (selectedMuscleGroups.length === 0) {
    hint.textContent = 'Wähle mindestens eine Muskelgruppe';
    hint.classList.remove('has-selection');
    btn.disabled = true;
  } else if (selectedMuscleGroups.includes('ganzkoerper')) {
    hint.textContent = '✓ Ganzkörper-Training ausgewählt';
    hint.classList.add('has-selection');
    btn.disabled = false;
  } else {
    const names = {
      brust: 'Brust', ruecken: 'Rücken', schultern: 'Schultern',
      arme: 'Arme', bauch: 'Bauch', beine: 'Beine', po: 'Po'
    };
    const selected = selectedMuscleGroups.map(m => names[m]).join(', ');
    hint.textContent = `✓ ${selected}`;
    hint.classList.add('has-selection');
    btn.disabled = false;
  }
}

function goToStep2() {
  if (selectedMuscleGroups.length === 0) return;
  
  document.getElementById('builderContent1b').style.display = 'none';
  document.getElementById('builderContent2').style.display = 'block';
  document.getElementById('builderStep1b').classList.remove('active');
  document.getElementById('builderStep1b').classList.add('done');
  document.getElementById('builderStep2').classList.add('active');
}

// Toggle Custom Day Selection
function toggleCustomDay(dayIndex) {
  const idx = customSelectedDays.indexOf(dayIndex);
  if (idx > -1) {
    if (customSelectedDays.length > 1) {
      customSelectedDays.splice(idx, 1);
    }
  } else {
    customSelectedDays.push(dayIndex);
    customSelectedDays.sort((a, b) => a - b);
  }
  
  // Update trainingConfig frequency
  trainingConfig.frequency = customSelectedDays.length;
  
  // Update UI
  document.querySelectorAll('.custom-day-btn').forEach((btn, i) => {
    btn.classList.toggle('selected', customSelectedDays.includes(i));
  });
  
  // Update hint
  document.getElementById('dayCountHint').textContent = `${customSelectedDays.length} ${customSelectedDays.length === 1 ? 'Tag' : 'Tage'} ausgewählt`;
}

// Duration Slider Update
function updateDuration(value) {
  trainingConfig.duration = parseInt(value);
  document.getElementById('durationValue').textContent = value;
  
  // Update preset buttons
  document.querySelectorAll('.duration-preset').forEach(btn => {
    btn.classList.remove('active');
  });
}

function setDuration(value) {
  trainingConfig.duration = value;
  document.getElementById('durationSlider').value = value;
  document.getElementById('durationValue').textContent = value;
  
  document.querySelectorAll('.duration-preset').forEach(btn => {
    btn.classList.toggle('active', parseInt(btn.textContent) === value);
  });
}

// Go Back to Step 2
function goBackToStep2() {
  document.getElementById('builderContent3').style.display = 'none';
  document.getElementById('builderContent2').style.display = 'block';
  document.getElementById('builderStep3').classList.remove('active');
  document.getElementById('builderStep2').classList.remove('done');
  document.getElementById('builderStep2').classList.add('active');
}

