function renderMeinActiveKur() {
  const container = document.getElementById('meinActiveKurLarge');
  if (!container) return;
  
  const kuren = JSON.parse(localStorage.getItem('suppTreeKuren') || '[]');
  const today = new Date().toISOString().split('T')[0];
  
  const activeKur = kuren.find(k => k.status === 'active' && k.startDate <= today && k.endDate >= today);
  
  if (!activeKur) {
    // Empty State
    container.innerHTML = `
      <div class="kur-empty-state">
        <span class="kur-empty-icon">🌿</span>
        <p class="kur-empty-title">Keine aktive Kur</p>
        <p class="kur-empty-text">Starte eine Kur für optimierte Supplement-Pläne und tägliche Erinnerungen</p>
      </div>
    `;
    return;
  }
  
  // Fortschritt berechnen
  const start = new Date(activeKur.startDate);
  const end = new Date(activeKur.endDate);
  const now = new Date();
  const total = Math.ceil((end - start) / (1000 * 60 * 60 * 24));
  const elapsed = Math.ceil((now - start) / (1000 * 60 * 60 * 24));
  const progress = Math.min(100, Math.round((elapsed / total) * 100));
  
  // Aktuelle Phase bestimmen
  let currentPhase = '';
  if (activeKur.phases && activeKur.phases.length > 0) {
    const phaseIdx = Math.min(Math.floor(elapsed / (total / activeKur.phases.length)), activeKur.phases.length - 1);
    currentPhase = activeKur.phases[phaseIdx]?.title || '';
  }
  
  // Datum formatieren
  const startStr = new Date(activeKur.startDate).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
  const endStr = new Date(activeKur.endDate).toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
  
  container.innerHTML = `
    <div class="active-kur-large-card" onclick="openKurKatalogDetail('${activeKur.kurType}')">
      <div class="active-kur-header-large">
        <div class="active-kur-icon-large">${activeKur.icon}</div>
        <div class="active-kur-info-large">
          <span class="active-kur-label">Aktive Kur</span>
          <span class="active-kur-name-large">${activeKur.name}</span>
          <span class="active-kur-dates">${startStr} – ${endStr}</span>
        </div>
      </div>
      <div class="active-kur-progress-section">
        <div class="active-kur-progress-header">
          <span class="active-kur-day">Tag ${elapsed} von ${total}</span>
          <span class="active-kur-percent">${progress}%</span>
        </div>
        <div class="active-kur-progress-large">
          <div class="active-kur-progress-bar-large" style="width: ${progress}%"></div>
        </div>
        ${currentPhase ? `<div class="active-kur-phase"><strong>Aktuelle Phase:</strong> ${currentPhase}</div>` : ''}
      </div>
    </div>
  `;
}

function updateMeinMatrix() {
  try {
    const suppsEl = document.getElementById('meinMatrixSupps');
    const medsEl = document.getElementById('meinMatrixMeds');
    
    // Load data
    if (!mySupplements) {
      const saved = localStorage.getItem('suppTreeMySupplements');
      if (saved) mySupplements = JSON.parse(saved);
    }
    if (!myMedications) {
      const saved = localStorage.getItem('suppTreeMedications');
      if (saved) myMedications = JSON.parse(saved);
    }
    
    const supps = mySupplements || [];
    const meds = (myMedications || []).filter(m => m && m.roburConsider);
    
    if (suppsEl) suppsEl.textContent = supps.length;
    if (medsEl) medsEl.textContent = meds.length;
  } catch (e) {
    console.error('updateMeinMatrix error:', e);
  }
}

