// ===============================
// COMBINED TIMELINE (Supplements + Medications)
// ===============================
function renderCombinedTimeline() {
  const container = document.getElementById('combinedIntakeList');
  const dateDisplay = document.getElementById('todayDateDisplay');
  if (!container) return;
  
  // Set today's date
  const today = new Date();
  const dayNames = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
  const monthNames = ['Jan', 'Feb', 'Mär', 'Apr', 'Mai', 'Jun', 'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dez'];
  const dateStr = `${dayNames[today.getDay()]}, ${today.getDate()}. ${monthNames[today.getMonth()]}`;
  if (dateDisplay) dateDisplay.textContent = dateStr;
  
  const todayFormatted = formatDate(today);
  const now = today.getHours() * 60 + today.getMinutes();
  
  // Collect all intakes
  let allIntakes = [];
  
  // Get shift info for wake/sleep times
  const shiftType = shifts[todayFormatted] || 'off';
  const shift = shiftConfig[shiftType] || shiftConfig.off;
  const wakeTime = shift.wake || '08:00';
  const sleepTime = shift.sleep || '23:00';
  
  // Add wake up entry
  let wakeInstruction = 'Freier Tag';
  if (shift.name && shift.start && shift.end) {
    wakeInstruction = `${shift.name} (${shift.start} - ${shift.end})`;
  } else if (shift.name) {
    wakeInstruction = shift.name;
  }
  
  allIntakes.push({
    id: 'wake-up',
    name: 'Aufstehen',
    icon: '🌅',
    time: wakeTime,
    type: 'info',
    instruction: wakeInstruction,
    taken: false
  });
  
  // 1. Get supplements - ALWAYS recalculate to ensure shift times are correct
  const dayIntakes = scheduleSupplementsForDate(todayFormatted);
  dayIntakes.forEach(intake => {
    allIntakes.push({
      id: intake.suppId,
      name: intake.name,
      icon: intake.icon,
      time: intake.time,
      type: 'supplement',
      instruction: intake.withFood ? ((intake.warnings || []).some(w => w.toLowerCase().includes('fetthaltig')) ? 'Mit fetthaltiger Mahlzeit' : 'Mit dem Essen') : '',
      taken: intake.taken || false,
      capsules: intake.capsules || 1,
      form: intake.form || 'capsule',
      doseUnit: intake.doseUnit || null,
      coffeeRestriction: intake.coffeeRestriction
    });
  });
  
  // 2. Add coffee restriction warning ONCE based on sleep time
  const hasSleepSupp = dayIntakes.some(i => i.coffeeRestriction);
  if (hasSleepSupp) {
    const stopTime = addMinutesToTime(sleepTime, -8 * 60);
    allIntakes.push({
      id: 'coffee-stop',
      name: 'Koffein-Stopp',
      icon: '☕',
      time: stopTime,
      type: 'warning',
      instruction: `Für Schlaf um ${sleepTime}`,
      taken: false
    });
  }
  
  // Add sleep entry
  allIntakes.push({
    id: 'sleep',
    name: 'Schlafen gehen',
    icon: '😴',
    time: sleepTime,
    type: 'info',
    instruction: 'Gute Nacht! 🌙',
    taken: false
  });
  
  // 3. Get medications
  if (!myMedications || myMedications.length === 0) {
    const saved = localStorage.getItem('suppTreeMedications');
    if (saved) {
      myMedications = JSON.parse(saved);
    } else {
      myMedications = [];
    }
  }
  
  const timeLabels = { morning: '07:00', noon: '12:00', evening: '18:00', night: '22:00' };
  
  const todayMeds = myMedications.filter(med => {
    if (!med.roburConsider) return false;
    
    if (med.duration && med.durationType !== 'ongoing') {
      const startDate = new Date(med.startDate);
      const totalDays = med.durationType === 'days' ? med.duration : 
                        med.durationType === 'weeks' ? med.duration * 7 : 
                        med.duration * 30;
      const endDate = new Date(startDate);
      endDate.setDate(endDate.getDate() + totalDays);
      
      if (today > endDate) return false;
    }
    return true;
  });
  
  todayMeds.forEach(med => {
    const formIcon = medFormIcons[med.formType] || '💊';
    const unitInfo = medDoseUnits[med.formType] || medDoseUnits['tablet'];
    const shortUnit = unitInfo.unit.replace('(n)', '').replace('(en)', '');
    const doseAmount = med.doseAmount || 1;
    const doseText = `${doseAmount} ${doseAmount === 1 ? shortUnit : unitInfo.unit}`;
    
    let instructionText = '';
    if (med.instruction === 'custom' && med.customNote) {
      instructionText = med.customNote;
    } else if (med.instruction && med.instruction !== 'any') {
      const labels = { before_meal: 'Vor dem Essen', with_meal: 'Mit dem Essen', after_meal: 'Nach dem Essen', empty_stomach: 'Nüchtern' };
      instructionText = labels[med.instruction] || '';
    }
    
    (med.times || []).forEach(timeSlot => {
      allIntakes.push({
        id: med.id,
        name: med.name,
        icon: formIcon,
        time: timeLabels[timeSlot] || '08:00',
        type: 'medication',
        instruction: instructionText,
        dose: doseText,
        taken: false
      });
    });
  });
  
  // Sort by time - considering shift wake time as start of day
  // For night shift, times after midnight should come AFTER times before midnight
  const wakeMinutes = timeToMinutes(wakeTime);
  
  allIntakes.sort((a, b) => {
    let aMin = timeToMinutes(a.time);
    let bMin = timeToMinutes(b.time);
    
    // Adjust times relative to wake time
    // If a time is before wake time, it's "later" in the day (add 24h)
    if (aMin < wakeMinutes) aMin += 24 * 60;
    if (bMin < wakeMinutes) bMin += 24 * 60;
    
    return aMin - bMin;
  });
  
  // Render
  if (allIntakes.length === 0) {
    container.innerHTML = `
      <div class="empty-timeline">
        <div class="empty-icon">📋</div>
        <p>Keine Einnahmen für heute geplant</p>
        <button class="add-intake-btn" onclick="openSTFeature('supplements')">+ Supplements hinzufügen</button>
      </div>
    `;
    return;
  }
  
  // Remove duplicate coffee warnings
  const seen = new Set();
  allIntakes = allIntakes.filter(intake => {
    if (intake.type === 'warning') {
      const key = intake.time + intake.name;
      if (seen.has(key)) return false;
      seen.add(key);
    }
    return true;
  });
  
  container.innerHTML = allIntakes.map((intake, idx) => {
    const [hours, mins] = intake.time.split(':').map(Number);
    const intakeMinutes = hours * 60 + mins;
    
    // Info type (Aufstehen, Schlafen gehen)
    if (intake.type === 'info') {
      const isPast = intakeMinutes <= now;
      const cardClass = intake.id === 'wake-up' ? 'wake-up' : (intake.id === 'sleep' ? 'sleep' : '');
      return `
        <div class="intake-card info ${cardClass} ${isPast ? 'past' : ''}" data-idx="${idx}">
          <div class="intake-time-badge info">${intake.time}</div>
          <div class="intake-main">
            <div class="intake-icon-big">${intake.icon}</div>
            <div class="intake-details">
              <h4>${intake.name}</h4>
              <p>${intake.instruction || ''}</p>
            </div>
          </div>
        </div>
      `;
    }
    
    // Warning type (Koffein-Stopp etc.)
    if (intake.type === 'warning') {
      const isPast = intakeMinutes <= now;
      return `
        <div class="intake-card warning ${isPast ? 'past' : ''}" data-idx="${idx}">
          <div class="intake-time-badge warning">${intake.time}</div>
          <div class="intake-main">
            <div class="intake-icon-big">${intake.icon}</div>
            <div class="intake-details">
              <h4>${intake.name}</h4>
              <p>${intake.instruction || ''}</p>
            </div>
          </div>
        </div>
      `;
    }
    
    let statusClass = 'future';
    let badgeClass = '';
    let checkContent = '○';
    let countdown = '';
    
    if (intake.taken) {
      statusClass = 'completed';
      checkContent = '✓';
    } else if (intakeMinutes <= now) {
      statusClass = 'completed'; // Past time, show as done-able
    } else if (intakeMinutes - now <= 120) {
      statusClass = 'upcoming';
      badgeClass = 'soon';
      const diff = intakeMinutes - now;
      const h = Math.floor(diff / 60);
      const m = diff % 60;
      countdown = h > 0 ? `in ${h}h ${m}min` : `in ${m}min`;
    }
    
    const typeLabel = intake.type === 'medication' ? '<span class="intake-type-badge med">💊</span>' : '';
    
    // Build dose info - intelligent formatting based on form
    let doseInfo = '';
    if (intake.type === 'medication') {
      doseInfo = intake.dose || '';
    } else if (intake.type === 'supplement') {
      // Custom dose unit takes priority
      if (intake.doseUnit) {
        doseInfo = intake.doseUnit;
      } else {
        const count = parseInt(intake.capsules) || 1;
        let form = intake.form || 'capsule';
        
        // Auto-detect form from name if not set
        if (!intake.form) {
          const name = (intake.name || '').toLowerCase();
          if (name.includes('tropfen') || name.includes('drops') || name.includes('öl')) {
            form = 'drops';
          } else if (name.includes('spray')) {
            form = 'spray';
          } else if (name.includes('pulver') || name.includes('powder') || name.includes('kreatin') || name.includes('creatine')) {
            form = 'powder';
          } else if (name.includes('softgel') || name.includes('fischöl') || name.includes('fish oil') || name.includes('omega')) {
            form = 'softgel';
          } else if (name.includes('gummi') || name.includes('gummy')) {
            form = 'gummy';
          } else if (name.includes('lutsch') || name.includes('lozenge')) {
            form = 'lozenge';
          } else if (name.includes('tablette') || name.includes('tablet')) {
            form = 'tablet';
          }
        }
        
        // German form labels with singular/plural
        const formLabels = {
          'capsule': { s: 'Kapsel', p: 'Kapseln' },
          'tablet': { s: 'Tablette', p: 'Tabletten' },
          'softgel': { s: 'Softgel', p: 'Softgels' },
          'drops': { s: 'Tropfen', p: 'Tropfen' },
          'spray': { s: 'Sprühstoß', p: 'Sprühstöße' },
          'powder': { s: 'Portion', p: 'Portionen' },
          'liquid': { s: 'ml', p: 'ml' },
          'gummy': { s: 'Gummibärchen', p: 'Gummibärchen' },
          'lozenge': { s: 'Lutschtablette', p: 'Lutschtabletten' }
        };
        
        const label = formLabels[form] || formLabels['capsule'];
        doseInfo = `${count} ${count === 1 ? label.s : label.p}`;
      }
    }
    
    return `
      <div class="intake-card ${statusClass}" data-idx="${idx}" onclick="toggleIntakeCard(this, ${idx})">
        <div class="intake-time-badge ${badgeClass}">${intake.time}</div>
        <div class="intake-main">
          <div class="intake-icon-big">${intake.icon}</div>
          <div class="intake-details">
            <h4>${intake.name} ${typeLabel}</h4>
            <p>${doseInfo}${doseInfo && intake.instruction ? ' • ' : ''}${intake.instruction || ''}</p>
          </div>
        </div>
        <div class="intake-check ${intake.taken ? 'checked' : ''}">${checkContent}</div>
        ${countdown ? `<div class="intake-countdown">${countdown}</div>` : ''}
      </div>
    `;
  }).join('');
}

// Toggle intake card (combined)
function toggleIntakeCard(card, idx) {
  const check = card.querySelector('.intake-check');
  const isChecked = check.classList.contains('checked');
  
  if (isChecked) {
    check.classList.remove('checked');
    check.textContent = '○';
    card.classList.remove('completed');
    card.classList.add('future');
  } else {
    check.classList.add('checked');
    check.textContent = '✓';
    card.classList.remove('upcoming', 'future');
    card.classList.add('completed');
    
    // Animation
    check.style.transform = 'scale(1.3)';
    setTimeout(() => check.style.transform = 'scale(1)', 200);
  }
}

function toggleMedCheck(el) {
  const isChecked = el.classList.contains('checked');
  if (isChecked) {
    el.classList.remove('checked');
    el.textContent = '○';
  } else {
    el.classList.add('checked');
    el.textContent = '✓';
    el.style.transform = 'scale(1.2)';
    setTimeout(() => el.style.transform = 'scale(1)', 200);
  }
}

// ===============================
// BODY SCROLL LOCK & OVERLAY MANAGEMENT
// ===============================
let bodyScrollPosition = 0;

function closeAllOverlays() {
  // Speichere aktuelle Scroll-Position bevor wir irgendetwas machen
  const savedScrollPosition = bodyScrollPosition || window.scrollY;
  
  // Close all overlays
  document.querySelectorAll('.overlay').forEach(o => o.classList.remove('active', 'visible'));
  document.querySelectorAll('.bottom-sheet').forEach(s => s.classList.remove('active', 'visible'));
  document.querySelectorAll('.cartfav-sheet').forEach(s => s.classList.remove('visible'));
  document.querySelectorAll('.share-modal').forEach(s => s.classList.remove('visible'));
  document.querySelectorAll('.product-search-container').forEach(s => s.classList.remove('visible'));
  document.querySelectorAll('.entry-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.kur-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.activate-kur-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.kur-detail-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.sleep-time-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.abo-detail-sheet').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.co-fullscreen').forEach(s => s.classList.remove('visible'));
  
  // Close icon picker if open
  const iconPicker = document.getElementById('entryIconPicker');
  if (iconPicker) iconPicker.classList.remove('show');
  
  // Reset any fixed positioning und restore scroll
  document.body.style.overflow = '';
  document.body.style.position = '';
  document.body.style.width = '';
  document.body.style.top = '';
  document.body.classList.remove('no-scroll');
  
  // Scroll zurück zur gespeicherten Position
  if (savedScrollPosition > 0) {
    window.scrollTo(0, savedScrollPosition);
  }
}

function lockBody() {
  bodyScrollPosition = window.scrollY;
  document.body.style.overflow = 'hidden';
  document.body.style.position = 'fixed';
  document.body.style.width = '100%';
  document.body.style.top = `-${bodyScrollPosition}px`;
}

function unlockBody() {
  const savedPos = bodyScrollPosition || 0;
  document.body.style.overflow = '';
  document.body.style.position = '';
  document.body.style.width = '';
  document.body.style.top = '';
  document.body.classList.remove('sheet-open');
  document.body.classList.remove('body-locked');
  // Scroll nach Reflow wiederherstellen
  window.scrollTo(0, savedPos);
  requestAnimationFrame(() => window.scrollTo(0, savedPos));
}

// Notfall-Reset falls UI hängt - kann in Console aufgerufen werden
function emergencyUnlock() {
  document.body.style.overflow = '';
  document.body.style.position = '';
  document.body.style.width = '';
  document.body.style.top = '';
  document.body.classList.remove('sheet-open');
  document.body.classList.remove('body-locked');
  
  // Schließe alle offenen Overlays und Sheets
  document.querySelectorAll('.overlay.visible').forEach(el => el.classList.remove('visible'));
  document.querySelectorAll('.bottom-sheet.visible').forEach(el => el.classList.remove('visible'));
  document.querySelectorAll('.info-sheet.visible').forEach(el => el.classList.remove('visible'));
  
  console.log('Emergency unlock completed');
}

// ===============================
// PRODUCT SEARCH FUNCTIONS
// ===============================
let recentSearches = [];

function openProductSearch() {
  document.getElementById('productSearchContainer').classList.add('visible');
  document.getElementById('productSearchInput').focus();
  
  lockBody();
  
  // Load recent searches
  const saved = localStorage.getItem('suppTreeRecentSearches');
  if (saved) {
    recentSearches = JSON.parse(saved);
  }
  renderRecentSearches();
  
  // Reset view - show recent searches or empty state
  document.getElementById('searchProductList').style.display = 'none';
  const hasRecent = recentSearches.length > 0;
  document.getElementById('searchRecent').style.display = hasRecent ? 'block' : 'none';
  const emptyState = document.getElementById('searchEmptyState');
  if (emptyState) emptyState.style.display = hasRecent ? 'none' : 'flex';
}

function closeProductSearch() {
  document.getElementById('productSearchContainer').classList.remove('visible');
  document.getElementById('productSearchInput').value = '';
  const autocomplete = document.getElementById('searchAutocomplete');
  if (autocomplete) autocomplete.style.display = 'none';
  
  unlockBody();
}

// Handle click on container background to close
function handleSearchContainerClick(event) {
  // Only close if clicking directly on the container background or results area
  if (event.target.classList.contains('product-search-container') || 
      event.target.classList.contains('product-search-results') ||
      event.target.classList.contains('search-empty-state')) {
    closeProductSearch();
  }
}

function clearProductSearch() {
  document.getElementById('productSearchInput').value = '';
  document.querySelector('.search-clear-btn').style.display = 'none';
  document.getElementById('searchProductList').style.display = 'none';
  const autocomplete = document.getElementById('searchAutocomplete');
  if (autocomplete) autocomplete.style.display = 'none';
  const hasRecent = recentSearches.length > 0;
  document.getElementById('searchRecent').style.display = hasRecent ? 'block' : 'none';
  const emptyState = document.getElementById('searchEmptyState');
  if (emptyState) emptyState.style.display = hasRecent ? 'none' : 'flex';
}

// Debounce Timer für Autocomplete
let searchDebounceTimer = null;

function handleSearchInput() {
  const query = document.getElementById('productSearchInput').value.trim();
  const autocomplete = document.getElementById('searchAutocomplete');
  
  // Clear previous timer
  clearTimeout(searchDebounceTimer);
  
  // Show/hide clear button
  const clearBtn = document.querySelector('.search-clear-btn');
  if (clearBtn) clearBtn.style.display = query.length > 0 ? 'block' : 'none';

  // Zeige Autocomplete bei 2+ Zeichen (KEINE Produktergebnisse während Tippen)
  if (query.length >= 2) {
    searchDebounceTimer = setTimeout(() => {
      showAutocomplete(query);
    }, 100);
    // Verstecke alles andere während Autocomplete aktiv
    document.getElementById('productSearchResults').style.display = 'none';
  } else {
    autocomplete.style.display = 'none';
    document.getElementById('productSearchResults').style.display = '';
    // Bei leerem Input: zeige letzte Suchen oder Empty State
    if (query.length === 0) {
      document.getElementById('searchProductList').style.display = 'none';
      const hasRecent = recentSearches.length > 0;
      document.getElementById('searchRecent').style.display = hasRecent ? 'block' : 'none';
      const emptyState = document.getElementById('searchEmptyState');
      if (emptyState) emptyState.style.display = hasRecent ? 'none' : 'flex';
    }
  }
}

function handleSearchKeydown(event) {
  if (event.key === 'Enter') {
    event.preventDefault();
    const query = document.getElementById('productSearchInput').value.trim();
    
    if (query.length > 0) {
      // Save to recent searches
      if (!recentSearches.includes(query)) {
        recentSearches.unshift(query);
        if (recentSearches.length > 5) recentSearches.pop();
        localStorage.setItem('suppTreeRecentSearches', JSON.stringify(recentSearches));
      }
      
      // Set active search query for marketplace
      activeSearchQuery = query;
      
      // Close search overlay
      closeProductSearch();
      
      // Switch to products screen and render with search filter
      switchScreen('productsScreen');
      updateActiveFiltersBar();
      renderProductsGridNew();
      
      // Show toast
      showToast(`🔍 Suche: "${query}"`);
    }
  }
}

function showAutocomplete(query) {
  const autocomplete = document.getElementById('searchAutocomplete');
  const queryLower = query.toLowerCase();
  
  // Sammle Vorschläge
  const suggestions = [];
  const seenNames = new Set();
  
  // 1. Produkte die mit dem Query beginnen (höchste Priorität)
  products.forEach(p => {
    const nameLower = p.name.toLowerCase();
    if (nameLower.startsWith(queryLower) && !seenNames.has(p.name)) {
      suggestions.push({
        type: 'product',
        name: p.name,
        category: p.category,
        brand: p.brand,
        id: p.id,
        priority: 1
      });
      seenNames.add(p.name);
    }
  });
  
  // 2. Produkte die den Query enthalten
  products.forEach(p => {
    const nameLower = p.name.toLowerCase();
    if (nameLower.includes(queryLower) && !seenNames.has(p.name)) {
      suggestions.push({
        type: 'product',
        name: p.name,
        category: p.category,
        brand: p.brand,
        id: p.id,
        priority: 2
      });
      seenNames.add(p.name);
    }
  });
  
  // 3. Marken die matchen
  products.forEach(p => {
    const brandLower = p.brand.toLowerCase();
    if (brandLower.includes(queryLower) && !seenNames.has('brand:' + p.brand)) {
      suggestions.push({
        type: 'brand',
        name: p.brand,
        category: p.category,
        priority: 3
      });
      seenNames.add('brand:' + p.brand);
    }
  });
  
  // Sortiere nach Priorität und limitiere auf 8
  suggestions.sort((a, b) => a.priority - b.priority);
  const topSuggestions = suggestions.slice(0, 8);

  if (topSuggestions.length === 0) {
    autocomplete.style.display = 'none';
    return;
  }

  // Verstecke andere Sektionen während Autocomplete aktiv
  document.getElementById('searchProductList').style.display = 'none';
  document.getElementById('searchRecent').style.display = 'none';
  const es = document.getElementById('searchEmptyState');
  if (es) es.style.display = 'none';
  
  // Rendere Autocomplete als vertikale Liste
  let html = '';

  topSuggestions.forEach(s => {
    const icon = s.type === 'brand' ? '🏷️' : '💊';
    const typeClass = s.type === 'brand' ? 'brand' : 'product';
    const sub = s.type === 'brand' ? 'Marke' : (s.brand ? s.brand : (s.category || ''));
    const highlighted = highlightAutocomplete(s.name, query);

    html += `<div class="ac-row" onclick="selectAutocomplete('${s.name.replace(/'/g, "\\'")}', '${s.type}', '${s.id || ''}')">
      <div class="ac-row-icon ${typeClass}">${icon}</div>
      <div class="ac-row-text">
        <div class="ac-row-name">${highlighted}</div>
        ${sub ? `<div class="ac-row-sub">${sub}</div>` : ''}
      </div>
      <div class="ac-row-arrow">→</div>
    </div>`;
  });
  
  autocomplete.innerHTML = html;
  autocomplete.style.display = 'block';
}

function highlightAutocomplete(text, query) {
  if (!query) return text;
  const regex = new RegExp(`(${query})`, 'gi');
  return text.replace(regex, '<mark>$1</mark>');
}

function selectAutocomplete(term, type, productId) {
  const input = document.getElementById('productSearchInput');
  const autocomplete = document.getElementById('searchAutocomplete');
  
  // Verstecke Autocomplete, zeige Results wieder
  autocomplete.style.display = 'none';
  document.getElementById('productSearchResults').style.display = '';

  if (type === 'product' && productId) {
    // Direkt zum Produkt gehen
    closeProductSearch();
    openProductDetail(productId);
    
    // Speichere in Recent Searches
    if (!recentSearches.includes(term)) {
      recentSearches.unshift(term);
      if (recentSearches.length > 5) recentSearches.pop();
      localStorage.setItem('suppTreeRecentSearches', JSON.stringify(recentSearches));
    }
  } else {
    // Suche nach dem Begriff
    input.value = term;
    filterProductSearch();
    
    // Speichere in Recent Searches
    if (!recentSearches.includes(term)) {
      recentSearches.unshift(term);
      if (recentSearches.length > 5) recentSearches.pop();
      localStorage.setItem('suppTreeRecentSearches', JSON.stringify(recentSearches));
    }
  }
}

// Schließe Autocomplete bei Klick außerhalb
document.addEventListener('click', function(e) {
  const autocomplete = document.getElementById('searchAutocomplete');
  const searchInput = document.getElementById('productSearchInput');
  if (autocomplete && !autocomplete.contains(e.target) && e.target !== searchInput) {
    autocomplete.style.display = 'none';
  }
});

function filterProductSearch() {
  const query = document.getElementById('productSearchInput').value.toLowerCase().trim();
  const clearBtn = document.querySelector('.search-clear-btn');
  const emptyState = document.getElementById('searchEmptyState');
  
  if (query.length === 0) {
    clearBtn.style.display = 'none';
    document.getElementById('searchProductList').style.display = 'none';
    const hasRecent = recentSearches.length > 0;
    document.getElementById('searchRecent').style.display = hasRecent ? 'block' : 'none';
    if (emptyState) emptyState.style.display = hasRecent ? 'none' : 'flex';
    return;
  }
  
  clearBtn.style.display = 'block';
  document.getElementById('searchRecent').style.display = 'none';
  if (emptyState) emptyState.style.display = 'none';
  
  const filtered = products.filter(p => 
    p.name.toLowerCase().includes(query) || 
    p.brand.toLowerCase().includes(query) ||
    (p.category && p.category.toLowerCase().includes(query)) ||
    p.icon.includes(query)
  );
  
  renderSearchResults(filtered, query);
}

function quickSearch(term) {
  document.getElementById('productSearchInput').value = term;
  filterProductSearch();
  
  // Save to recent
  if (!recentSearches.includes(term)) {
    recentSearches.unshift(term);
    if (recentSearches.length > 5) recentSearches.pop();
    localStorage.setItem('suppTreeRecentSearches', JSON.stringify(recentSearches));
  }
}

function searchByBrand(brandId) {
  const filtered = products.filter(p => p.brandId === brandId);
  const brandName = brands[brandId]?.name || brandId;
  
  document.getElementById('productSearchInput').value = brandName;
  document.querySelectorAll('.search-section').forEach(s => s.style.display = 'none');
  document.querySelector('.search-clear-btn').style.display = 'block';
  
  renderSearchResults(filtered, brandName);
}

function renderSearchResults(results, query) {
  const container = document.getElementById('searchProductList');
  container.style.display = 'block';
  
  if (results.length === 0) {
    container.innerHTML = `
      <div class="search-no-results">
        <span>🔍</span>
        <p>Keine Produkte gefunden für "${query}"</p>
        <button class="robur-suggest-btn" onclick="askRoburAbout('${query}')">
          🤖 Robur nach "${query}" fragen
        </button>
      </div>
    `;
    return;
  }
  
  container.innerHTML = `
    <div class="search-results-header">
      <span>${results.length} Ergebnisse für "${query}"</span>
    </div>
    ${results.map(p => `
    <button class="search-product-item" onclick="selectSearchProduct('${p.id}', '${query}')">
      <div class="search-product-icon">${p.icon}</div>
      <div class="search-product-info">
        <strong>${highlightMatch(p.name, query)}</strong>
        <span>${p.brand} • ${getCategoryName(p.category)}</span>
      </div>
      <div class="search-product-right">
        <span class="search-product-price">€${p.price}</span>
        <span class="search-product-rating">★ ${p.rating}</span>
      </div>
    </button>
  `).join('')}`;
}

function highlightMatch(text, query) {
  if (!query) return text;
  const regex = new RegExp(`(${query})`, 'gi');
  return text.replace(regex, '<mark>$1</mark>');
}

function getCategoryName(cat) {
  const names = {
    'vitamine': 'Vitamine',
    'mineralien': 'Mineralien',
    'omega': 'Omega',
    'sport': 'Sport',
    'kraeuter': 'Kräuter',
    'schlaf': 'Schlaf',
    'verdauung': 'Verdauung',
    'beauty': 'Beauty'
  };
  return names[cat] || cat;
}

function selectSearchProduct(productId, query) {
  // Save to recent searches
  if (query && query.length > 2 && !recentSearches.includes(query)) {
    recentSearches.unshift(query);
    if (recentSearches.length > 5) recentSearches.pop();
    localStorage.setItem('suppTreeRecentSearches', JSON.stringify(recentSearches));
  }
  
  closeProductSearch();
  openProductDetail(productId);
}

function searchByCategory(category) {
  // Filter by category directly
  const filtered = products.filter(p => p.category === category);
  const categoryNames = {
    'vitamine': 'Vitamine',
    'mineralien': 'Mineralien',
    'omega': 'Omega',
    'sport': 'Sport',
    'kraeuter': 'Kräuter',
    'schlaf': 'Schlaf',
    'verdauung': 'Verdauung',
    'beauty': 'Beauty'
  };
  
  const displayName = categoryNames[category] || category;
  document.getElementById('productSearchInput').value = displayName;
  document.querySelectorAll('.search-section').forEach(s => s.style.display = 'none');
  document.querySelector('.search-clear-btn').style.display = 'block';
  
  renderSearchResultsWithViewAll(filtered, category, displayName);
}

function renderSearchResultsWithViewAll(results, category, displayName) {
  const container = document.getElementById('searchProductList');
  container.style.display = 'block';
  
  container.innerHTML = `
    <div class="search-results-header">
      <span>${results.length} Produkte in "${displayName}"</span>
    </div>
    <button class="search-view-all-btn" onclick="viewAllInCategory('${category}')">
      🛒 Alle ${displayName} im Shop anzeigen →
    </button>
    ${results.slice(0, 6).map(p => `
    <button class="search-product-item" onclick="selectSearchProduct('${p.id}', '${displayName}')">
      <div class="search-product-icon">${p.icon}</div>
      <div class="search-product-info">
        <strong>${p.name}</strong>
        <span>${p.brand} • €${p.price}</span>
      </div>
      <div class="search-product-right">
        <span class="search-product-rating">★ ${p.rating}</span>
      </div>
    </button>
  `).join('')}
  ${results.length > 6 ? `
    <button class="search-view-all-btn secondary" onclick="viewAllInCategory('${category}')">
      + ${results.length - 6} weitere Produkte anzeigen
    </button>
  ` : ''}`;
}

function viewAllInCategory(category) {
  closeProductSearch();
  activeCategory = category;
  activeFilter = 'all';
  switchScreen('productsScreen');
  setTimeout(() => {
    renderProductsGridNew();
  }, 100);
}

function renderRecentSearches() {
  const container = document.getElementById('recentSearches');
  if (!container) return;
  
  if (recentSearches.length === 0) {
    container.innerHTML = `<p style="font-size: 12px; color: var(--text-muted);">${t('search.noRecent') || 'Keine kürzlichen Suchen'}</p>`;
    return;
  }
  
  container.innerHTML = recentSearches.map(term => `
    <button class="recent-search-item" onclick="applyRecentSearch('${term}')">
      <span>🕒</span>
      <span>${term}</span>
    </button>
  `).join('');
}

function applyRecentSearch(term) {
  document.getElementById('productSearchInput').value = term;
  filterProductSearch();
}

function askRoburAbout(query) {
  closeProductSearch();
  openRoburChat();
  // Pre-fill Robur with the query
  setTimeout(() => {
    const input = document.getElementById('roburInput');
    if (input) {
      input.value = `Ich suche nach ${query}`;
    }
  }, 300);
}

// ===============================
// ROBUR CHAT FUNCTIONS
// ===============================
function openRoburChat() {
  document.getElementById('roburChatOverlay').classList.add('visible');
  document.getElementById('roburChatSheet').classList.add('visible');
  lockBody();
}

function closeRoburChat() {
  document.getElementById('roburChatOverlay').classList.remove('visible');
  document.getElementById('roburChatSheet').classList.remove('visible');
  unlockBody();
}

function sendSuggestion(text) {
  addUserMessage(text);
  setTimeout(() => {
    addBotResponse(text);
  }, 1000);
}

function sendQuickReply(text) {
  addUserMessage(text);
  setTimeout(() => {
    addBotResponse(text);
  }, 1000);
}

function sendRoburMessage() {
  const input = document.getElementById('roburInput');
  const text = input.value.trim();
  if (text) {
    addUserMessage(text);
    input.value = '';
    setTimeout(() => {
      addBotResponse(text);
    }, 1000);
  }
}

function handleRoburInput(event) {
  if (event.key === 'Enter') {
    sendRoburMessage();
  }
}

function addUserMessage(text) {
  const messages = document.getElementById('roburMessages');
  
  // Remove quick replies and suggestions
  const quickReplies = messages.querySelector('.robur-quick-replies');
  if (quickReplies) quickReplies.remove();
  const suggestions = messages.querySelector('.robur-suggestions');
  if (suggestions) suggestions.remove();
  
  const messageHtml = `
    <div class="robur-message user">
      <div class="message-avatar">👤</div>
      <div class="message-bubble">
        <p>${text}</p>
      </div>
    </div>
  `;
  messages.insertAdjacentHTML('beforeend', messageHtml);
  messages.scrollTop = messages.scrollHeight;
}

