// Update all filter UI elements
function updateFilterUI() {
  // Update filter cards
  document.querySelectorAll('.filter-card[data-filter]').forEach(card => {
    const filter = card.dataset.filter;
    card.classList.toggle('active', activeFilters.has(filter));
  });
  
  // Update quick filter chips (legacy)
  document.querySelectorAll('.filter-chip-new[data-filter]').forEach(chip => {
    const filter = chip.dataset.filter;
    chip.classList.toggle('active', activeFilters.has(filter));
  });
  
  // Update checkboxes in sheet (legacy)
  document.querySelectorAll('.filter-checkbox[data-filter]').forEach(checkbox => {
    const filter = checkbox.dataset.filter;
    const input = checkbox.querySelector('input');
    if (input) input.checked = activeFilters.has(filter);
    checkbox.classList.toggle('active', activeFilters.has(filter));
  });
  
  // Update active filters pills
  updateActiveFiltersPills();
  
  // Update clear button visibility
  const clearBtn = document.getElementById('filterClearBtn');
  if (clearBtn) {
    clearBtn.style.display = activeFilters.size > 0 ? 'block' : 'none';
  }
  
  // Update apply button count
  updateFilterApplyCount();
}

