function updateActiveFiltersPills() {
  const pills = document.getElementById('activeFiltersPills');
  
  if (!pills) return;
  
  if (activeFilters.size === 0) {
    pills.style.display = 'none';
    return;
  }
  
  pills.style.display = 'flex';
  
  let html = '';
  activeFilters.forEach(filter => {
    const label = filterLabels[filter] || filter;
    html += `
      <div class="filter-pill">
        <span>${label}</span>
        <span class="remove-pill" onclick="removeFilter('${filter}')">✕</span>
      </div>
    `;
  });
  
  pills.innerHTML = html;
}

