// Initialize home page
// ================================
// HOME TAGESPLANER FUNKTIONEN
// ================================

let currentPlannerDate = new Date();

function renderDayPlanner() {
  const timeline = document.getElementById('dayPlannerTimeline');
  const dateLabel = document.getElementById('plannerDateLabel');
  if (!timeline) return;
  
  const realNow = new Date();
  const isViewingOtherDay = currentPlannerDate && formatDate(currentPlannerDate) !== formatDate(realNow);
  const now = isViewingOtherDay ? new Date(currentPlannerDate) : new Date();

  // Zeitfenster definieren
  let pastStart, pastEnd, currentStart, currentEnd;
  if (isViewingOtherDay) {
    // Bei anderem Tag: ganzen Tag anzeigen (00:00 - 23:59)
    pastStart = new Date(now);
    pastStart.setHours(0, 0, 0, 0);
    pastEnd = pastStart; // Keine Vergangenheit bei anderem Tag
    currentStart = new Date(now);
    currentStart.setHours(0, 0, 0, 0);
    currentEnd = new Date(now);
    currentEnd.setHours(23, 59, 59, 999);
  } else {
    pastStart = new Date(now.getTime() - 24 * 60 * 60 * 1000);  // 24h zurück
    pastEnd = new Date(now.getTime() - 2 * 60 * 60 * 1000);     // 2h zurück
    currentStart = new Date(now.getTime() - 2 * 60 * 60 * 1000); // 2h zurück
    currentEnd = new Date(now.getTime() + 24 * 60 * 60 * 1000);  // 24h voraus
  }

  // Update date label
  if (dateLabel) {
    if (isViewingOtherDay) {
      const dayNames = ['Sonntag', 'Montag', 'Dienstag', 'Mittwoch', 'Donnerstag', 'Freitag', 'Samstag'];
      dateLabel.textContent = dayNames[now.getDay()] + ', ' + now.toLocaleDateString('de-DE', {day: '2-digit', month: '2-digit', year: 'numeric'});
    } else {
      dateLabel.textContent = 'Deine Timeline';
    }
  }

  // "Heute" Button ein/ausblenden
  const todayBtn = document.getElementById('plannerTodayBtn');
  if (todayBtn) todayBtn.style.display = isViewingOtherDay ? '' : 'none';

  // Update Schicht-Block für den angezeigten Tag
  const todayStr = formatDate(now);
  const todayShift = shifts[todayStr] || 'off';
  const todayShiftInfo = shiftConfig[todayShift] || {};
  renderShiftBlock(todayShift, todayShiftInfo);

  // Sammle alle Items
  const allItems = [];
  const processedDates = new Set();

  // Gehe durch relevante Tage
  const datesToProcess = [];
  if (isViewingOtherDay) {
    datesToProcess.push(new Date(now));
  } else {
    const tempDate = new Date(pastStart);
    for (let i = 0; i < 3; i++) {
      datesToProcess.push(new Date(tempDate));
      tempDate.setDate(tempDate.getDate() + 1);
    }
  }
  
  datesToProcess.forEach(d => {
    const dateStr = formatDate(d);
    if (processedDates.has(dateStr)) return;
    processedDates.add(dateStr);
    
    const shift = shifts[dateStr] || 'off';
    const items = getItemsForDay(dateStr, shift);
    
    // Caffeine stop hinzufügen - auch bei Frei, mit Pause/Aus Option
    const caffeineSettings = JSON.parse(localStorage.getItem('suppTreeCaffeineSettings') || '{}');
    const caffeineEnabled = caffeineSettings.enabled !== false; // Standard: an
    const caffeinePausedUntil = caffeineSettings.pausedUntil || null;
    const isPaused = caffeinePausedUntil && new Date(caffeinePausedUntil) > new Date();
    
    if (caffeineEnabled && !isPaused) {
      const shiftInfo = shiftConfig[shift] || shiftConfig['off'] || {};
      const customSleepTimes = JSON.parse(localStorage.getItem('suppTreeCustomSleepTimes') || '{}');
      const sleepTime = customSleepTimes[dateStr] || shiftInfo.sleep || '23:00';
      const [sleepH, sleepM] = sleepTime.split(':').map(Number);
      let stopH = sleepH - 8;
      if (stopH < 0) stopH += 24;
      const stopTime = `${String(stopH).padStart(2, '0')}:${String(sleepM).padStart(2, '0')}`;
      
      items.push({
        name: 'Koffein-Stopp',
        time: stopTime,
        icon: '☕',
        type: 'caffeine-stop',
        dose: `Für Schlaf um ${sleepTime}`,
        isWarning: true
      });
    }
    
    // Notes hinzufügen
    const notesKey = `suppTree_notes_${dateStr}`;
    const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');
    notes.forEach((note, idx) => {
      items.push({
        name: note.text,
        time: note.time || '––:––',
        icon: note.icon || '📝',
        type: 'note',
        noteIndex: idx
      });
    });
    
    // Füge Datum und eindeutige ID zu jedem Item hinzu
    let itemCounter = 0;
    items.forEach(item => {
      if (!item.time || item.time === '––:––') return;
      
      const [h, m] = item.time.split(':').map(Number);
      const itemDate = new Date(d);
      itemDate.setHours(h, m, 0, 0);
      
      // Eindeutige ID: datum_zeit_name_counter
      const uniqueId = `${dateStr}_${item.time}_${item.name.replace(/[^a-zA-Z0-9]/g, '')}_${itemCounter}`;
      itemCounter++;
      
      // Nur Items im gesamten Fenster (24h zurück bis 24h voraus)
      if (itemDate >= pastStart && itemDate <= currentEnd) {
        allItems.push({
          ...item,
          uniqueId: uniqueId,
          dateStr: dateStr,
          timestamp: itemDate.getTime(),
          itemDate: itemDate
        });
      }
    });
  });
  
  // Nach Timestamp sortieren
  allItems.sort((a, b) => a.timestamp - b.timestamp);

  // Ampel-Overlay anwenden (additiv — nur Labels und Klassen hinzufügen)
  if (ampelDataLoaded) {
    const overlayedItems = applyInteractionOverlay(allItems.filter(i => i.type === 'supplement'));
    overlayedItems.forEach(oi => {
      const idx = allItems.findIndex(a => a.uniqueId === oi.uniqueId);
      if (idx >= 0) {
        allItems[idx] = { ...allItems[idx], ...oi };
      }
    });
  }

  // Aufteilen in Vergangenheit (2-24h her) und Aktuell (letzte 2h + nächste 24h)
  const pastItems = allItems.filter(item => item.itemDate >= pastStart && item.itemDate < pastEnd);
  const currentItems = allItems.filter(item => item.itemDate >= currentStart && item.itemDate <= currentEnd);
  
  // Get completion status
  const completedKey = `suppTree_completed_${todayStr}`;
  const completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
  
  let html = '';
  
  // === VERGANGENE EINNAHMEN (aufklappbar) ===
  if (pastItems.length > 0) {
    const pastDoneCount = pastItems.filter(i => 
      completed.includes(i.name) || i.done || 
      i.type === 'caffeine-stop' || i.type === 'info-wake' || i.type === 'info-sleep'
    ).length;
    
    html += `
      <div class="timeline-past-section" id="timelinePastSection">
        <div class="timeline-past-header" onclick="togglePastTimeline()">
          <div class="past-header-info">
            <span class="past-header-icon">🕐</span>
            <span class="past-header-title">Vergangene Einnahmen</span>
            <span class="past-header-count">${pastDoneCount}/${pastItems.length}</span>
          </div>
          <span class="past-header-arrow" id="pastArrow">›</span>
        </div>
        <div class="timeline-past-content" id="timelinePastContent">
    `;
    
    // Gruppiere vergangene Items
    const pastGroups = groupItemsByTime(pastItems);
    html += renderTimelineGroups(pastGroups, completed, now, true);
    
    html += `
        </div>
      </div>
    `;
  }
  
  // === AKTUELLE TIMELINE ===
  if (currentItems.length === 0) {
    html += `
      <div class="timeline-empty">
        <div class="timeline-empty-icon">📋</div>
        <p>Keine Einträge in den nächsten 24 Stunden</p>
        <button onclick="openAddTimelineEntry()">+ Eintrag hinzufügen</button>
      </div>
    `;
  } else {
    const currentGroups = groupItemsByTime(currentItems);
    html += renderTimelineGroups(currentGroups, completed, now, false);
  }
  
  timeline.innerHTML = html;
  
  // Update progress (nur aktuelle Items)
  const trackableItems = currentItems.filter(i => 
    i.type !== 'note' && i.type !== 'info-wake' && i.type !== 'info-sleep' && i.type !== 'caffeine-stop'
  );
  const doneCount = trackableItems.filter(item => completed.includes(item.name) || item.done).length;
  updatePlannerProgress(doneCount, trackableItems.length);
}

// Hilfsfunktion: Items nach Zeit gruppieren
function groupItemsByTime(items) {
  const timeGroups = {};
  items.forEach(item => {
    const timeKey = `${item.dateStr}_${item.time}`;
    if (!timeGroups[timeKey]) {
      timeGroups[timeKey] = {
        time: item.time,
        dateStr: item.dateStr,
        timestamp: item.timestamp,
        items: []
      };
    }
    timeGroups[timeKey].items.push(item);
  });
  return Object.values(timeGroups).sort((a, b) => a.timestamp - b.timestamp);
}

// Hilfsfunktion: Timeline-Gruppen rendern
function renderTimelineGroups(groups, completed, now, isPast) {
  let html = '';
  let foundCurrent = false;
  let lastDateStr = null;
  const todayStr = formatDate(now);
  const tomorrowDate = new Date(now);
  tomorrowDate.setDate(tomorrowDate.getDate() + 1);
  const tomorrowStr = formatDate(tomorrowDate);
  const yesterdayDate = new Date(now);
  yesterdayDate.setDate(yesterdayDate.getDate() - 1);
  const yesterdayStr = formatDate(yesterdayDate);
  
  const dayNames = ['Sonntag', 'Montag', 'Dienstag', 'Mittwoch', 'Donnerstag', 'Freitag', 'Samstag'];
  const monthNames = ['Jan', 'Feb', 'Mär', 'Apr', 'Mai', 'Jun', 'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dez'];
  
  groups.forEach(group => {
    // Prüfe ob neuer Tag beginnt
    if (lastDateStr !== null && group.dateStr !== lastDateStr) {
      // Neuer Tag - Trennlinie einfügen
      const groupDate = new Date(group.dateStr + 'T12:00:00');
      let dayLabel = '';
      
      if (group.dateStr === todayStr) {
        dayLabel = 'Heute';
      } else if (group.dateStr === tomorrowStr) {
        dayLabel = 'Morgen';
      } else if (group.dateStr === yesterdayStr) {
        dayLabel = 'Gestern';
      } else {
        const dayName = dayNames[groupDate.getDay()];
        const day = groupDate.getDate();
        const month = monthNames[groupDate.getMonth()];
        dayLabel = `${dayName}, ${day}. ${month}`;
      }
      
      html += `
        <div class="timeline-day-separator">
          <div class="day-separator-line"></div>
          <span class="day-separator-label">${dayLabel}</span>
          <div class="day-separator-line"></div>
        </div>
      `;
    }
    lastDateStr = group.dateStr;
    
    const diffMinutes = (group.timestamp - now.getTime()) / 60000;
    
    let groupStatus = 'upcoming';
    if (isPast || diffMinutes < -30) {
      groupStatus = 'past';
    } else if (diffMinutes <= 30 && !foundCurrent) {
      groupStatus = 'current';
      foundCurrent = true;
    }
    
    const allDone = group.items.every(item => 
      completed.includes(item.uniqueId || item.name) || item.done || 
      item.type === 'caffeine-stop' || item.type === 'info-wake' || item.type === 'info-sleep'
    );
    
    // Gruppiere Items nach "reason" (Mahlzeit) - aber konsolidiere ähnliche Zeiten
    const itemsByReason = {};
    const otherItems = [];
    
    // Funktion um reason zu normalisieren (ähnliche zusammenfassen)
    function normalizeReason(reason) {
      if (!reason) return null;
      const r = reason.toLowerCase();
      
      // Abend/Nacht zusammenfassen
      if (r.includes('abends') || r.includes('nachts') || r.includes('vor dem schlafen') || r.includes('vor dem schlaf')) {
        return 'Abends';
      }
      // Morgen zusammenfassen
      if (r.includes('morgens') || r.includes('nach dem aufstehen') || r.includes('vor dem frühstück') || r.includes('mit dem frühstück') || r.includes('nüchtern')) {
        return 'Morgens';
      }
      // Mittag zusammenfassen
      if (r.includes('mittag') || r.includes('vor dem mittagessen') || r.includes('mit dem mittagessen')) {
        return 'Mittags';
      }
      // Sport zusammenfassen
      if (r.includes('sport') || r.includes('training')) {
        return 'Sport';
      }
      return reason; // Original zurückgeben wenn nichts passt
    }
    
    group.items.forEach(item => {
      if (item.reason && item.type === 'supplement') {
        const normalizedReason = normalizeReason(item.reason);
        if (!itemsByReason[normalizedReason]) {
          itemsByReason[normalizedReason] = [];
        }
        itemsByReason[normalizedReason].push(item);
      } else {
        otherItems.push(item);
      }
    });
    
    html += `
      <div class="timeline-group ${groupStatus} ${allDone ? 'all-done' : ''}">
        <div class="timeline-group-time">
          <span class="group-time-label">${group.time}</span>
          <div class="group-time-line"></div>
        </div>
        <div class="timeline-group-items">
    `;
    
    // Rendere andere Items zuerst (Wake, Sleep, Caffeine etc.)
    otherItems.forEach((item, idx) => {
      html += renderTimelineItem(item, idx, completed);
    });
    
    // Sortiere Mahlzeit-Gruppen in logischer Reihenfolge
    const reasonOrder = getReasonSortOrder();
    const sortedReasons = Object.keys(itemsByReason).sort((a, b) => {
      const orderA = reasonOrder[a.toLowerCase()] ?? 999;
      const orderB = reasonOrder[b.toLowerCase()] ?? 999;
      return orderA - orderB;
    });
    
    // Rendere Supplement-Gruppen nach sortierter Reihenfolge
    sortedReasons.forEach(reason => {
      const reasonItems = itemsByReason[reason];
      const reasonAllDone = reasonItems.every(item => completed.includes(item.uniqueId || item.name));
      
      html += `
        <div class="timeline-meal-group ${reasonAllDone ? 'all-done' : ''}">
          <div class="meal-group-header">
            <span class="meal-group-title">${reason}</span>
          </div>
          <div class="meal-group-items">
      `;
      
      reasonItems.forEach((item, idx) => {
        html += renderTimelineItem(item, idx, completed, true);
      });
      
      html += `
          </div>
        </div>
      `;
    });
    
    html += `
        </div>
      </div>
    `;
  });
  
  return html;
}

// Hilfsfunktion für Mahlzeit-Icons
function getMealIcon(reason) {
  const lower = reason.toLowerCase();
  if (lower.includes('frühstück')) return '🍳';
  if (lower.includes('mittag')) return '🍽️';
  if (lower.includes('abend')) return '🌙';
  if (lower.includes('snack')) return '🍎';
  if (lower.includes('training') || lower.includes('sport') || lower.includes('workout')) return '💪';
  if (lower.includes('schlaf') || lower.includes('bett')) return '😴';
  if (lower.includes('aufstehen') || lower.includes('aufwachen')) return '🌅';
  if (lower.includes('nüchtern')) return '💧';
  return '⏰';
}

// Logische Sortierung für Mahlzeit-Gruppen
function getReasonSortOrder() {
  return {
    // Morgens
    'nach dem aufstehen': 1,
    'nach dem aufwachen': 2,
    'morgens (nüchtern)': 3,
    'nüchtern': 4,
    'vor dem frühstück': 5,
    'mit dem frühstück': 6,
    'nach dem frühstück': 7,
    
    // Vormittag
    'vormittags': 10,
    'am vormittag': 11,
    
    // Sport/Training (Vormittag/Mittag)
    'vor dem training': 15,
    'vor dem sport': 16,
    'vor dem workout': 17,
    'während dem training': 18,
    'beim training': 19,
    'nach dem training': 20,
    'nach dem sport': 21,
    'nach dem workout': 22,
    
    // Mittag
    'vor dem mittagessen': 25,
    'mit dem mittagessen': 26,
    'nach dem mittagessen': 27,
    'zur mittagszeit': 28,
    'mittags': 29,
    
    // Nachmittag
    'nachmittags': 35,
    'am nachmittag': 36,
    
    // Abend
    'am abend': 40,
    'abends': 41,
    'vor dem abendessen': 45,
    'mit dem abendessen': 46,
    'nach dem abendessen': 47,
    
    // Nacht
    'vor dem schlafen': 50,
    'vor dem schlafengehen': 51,
    'abends (1/2)': 52,
    'abends (2/2)': 53,
    
    // Verteilte Dosen
    'morgens (1/2)': 5,
    'morgens (1/3)': 5,
    'mittags (1/2)': 26,
    'mittags (2/2)': 27,
    'mittags (2/3)': 27,
    'abends (3/3)': 48
  };
}

// Einzelnes Timeline-Item rendern
function renderTimelineItem(item, idx, completed, hideReason = false) {
  const isDone = completed.includes(item.uniqueId || item.name) || item.done;
  const typeClass = item.type || 'custom';
  const isNote = item.type === 'note';
  const isCaffeineStop = item.type === 'caffeine-stop';
  const isInfoEntry = item.type === 'info-wake' || item.type === 'info-sleep';
  const isMeal = item.type === 'meal';
  const isSupp = item.type === 'supplement';
  const canCheck = !isCaffeineStop && !isInfoEntry && !isMeal;
  
  // Nutze uniqueId für Checkbox wenn vorhanden
  const checkId = item.uniqueId || item.name;
  
  const isTrainingEntry = item.type === 'custom' && item.entryId && item.entryId.startsWith('plan_');

  const contentClickHandler = isCaffeineStop ? `onclick="openCaffeineSettings()"` :
    item.type === 'info-wake' ? `onclick="openWakeTimeEdit()"` :
    item.type === 'info-sleep' ? `onclick="openSleepTimeEdit()"` :
    isMeal ? '' :
    isNote ? `onclick="editNote(${item.noteIndex})"` :
    isSupp ? `onclick="openSupplementInfoSheet('${item.suppId || ''}', '${item.name.replace(/'/g, "\\'")}', '${item.time || ''}', '${(item.dose || '').replace(/'/g, "\\'")}', '${(item.reason || '').replace(/'/g, "\\'")}', '${item.icon || '💊'}', '${checkId.replace(/'/g, "\\'")}')"` :
    isTrainingEntry ? `onclick="openCalendarEntry('${item.entryId}')"` :
    (item.type === 'custom' && item.entryId) ? `onclick="openCalendarEntry('${item.entryId}')"` :
    `onclick="togglePlannerEntry(${idx}, '${item.name.replace(/'/g, "\\'")}')"`;
  
  const checkboxHTML = canCheck ? `
    <button class="entry-checkbox" onclick="event.stopPropagation(); togglePlannerEntryById('${checkId.replace(/'/g, "\\'")}')">
      <span class="check-icon">✓</span>
    </button>
  ` : '';
  
  // Mahlzeit Info-Badge
  const mealBadge = isMeal ? `<span class="item-detail">Spontane Mahlzeit</span>` : '';
  
  // Zeige reason nur wenn nicht in einer Gruppe
  const showReason = !hideReason && item.reason && isSupp;
  
  const trainingStyle = isTrainingEntry ? 'background:#dbeafe;border:1.5px solid #93c5fd;border-radius:7px;cursor:pointer;' : '';

  // Ampel classes
  const ampelClass = item.ampel === 'gelb' ? 'ampel-gelb' : item.ampel === 'rot' ? (item.ampelOverridden ? 'ampel-rot' : 'ampel-rot intake-blocked') : (item.foerderndLabels && item.foerderndLabels.length ? 'foerdernd' : '');

  return `
    <div class="timeline-item ${typeClass} ${ampelClass} ${isDone && !isCaffeineStop && !isInfoEntry && !isMeal ? 'done' : ''}"
         ${contentClickHandler}
         style="${trainingStyle}"
         data-id="${checkId}"
         data-name="${item.name}">
      <div class="item-icon ${typeClass}">${item.icon || '💊'}</div>
      <div class="item-info">
        <span class="item-name" ${isTrainingEntry ? 'style="color:#1e40af;font-weight:700"' : ''}>${item.name}</span>
        ${item.kurName ? `<span class="item-kur-badge">${item.kurName}</span>` : ''}
        ${item.dose ? `<span class="item-detail">${item.dose}</span>` : ''}
        ${item.trainingNote ? `<span class="item-detail" style="font-size:10px;color:#1e40af;font-weight:600">🏋️ ${item.trainingNote}</span>` : ''}
        ${item.entryNote && isTrainingEntry ? `<span class="item-detail" style="font-size:10px;color:#3b82f6">${item.entryNote}</span>` : ''}
        ${item.entryNote && !isTrainingEntry ? `<span class="item-detail" style="font-size:10px;color:var(--text-muted)">${item.entryNote}</span>` : ''}
        ${mealBadge}
        ${showReason ? `<span class="item-reason">${item.reason}</span>` : ''}
        ${item.ampel === 'gelb' && !item.ampelOverridden ? `<span class="ampel-label gelb">&#9888;&#65039; Wechselwirkung — manuell einplanen</span>` : ''}
        ${item.ampel === 'gelb' && item.ampelOverridden ? `<span class="ampel-label gelb">&#9888;&#65039; Manuell eingeplant</span>` : ''}
        ${item.ampel === 'rot' && !item.ampelOverridden ? `<span class="ampel-label rot">&#128308; Gesperrt — Wechselwirkung</span>` : ''}
        ${item.ampel === 'rot' && item.ampelOverridden ? `<span class="ampel-label rot">&#128308; Nach Disclaimer eingeplant</span>` : ''}
        ${(item.foerderndLabels || []).map(f => `<span class="interaction-hint" style="color:#16a34a;">&#10003; ${f.text}</span>`).join('')}
        ${(item.hemmendLabels || []).map(h => `<span class="interaction-hint" style="color:#f59e0b;">&#9888; ${h.text}</span>`).join('')}
      </div>
      ${isTrainingEntry ? `<span style="color:#3b82f6;font-size:16px;margin-left:auto">›</span>` : ''}
      ${isNote ? `<button class="item-delete" onclick="event.stopPropagation(); deleteNote(${item.noteIndex})">🗑️</button>` : ''}
      ${!isTrainingEntry ? checkboxHTML : ''}
    </div>
  `;
}

// Toggle für vergangene Einnahmen
function togglePastTimeline() {
  const section = document.getElementById('timelinePastSection');
  const arrow = document.getElementById('pastArrow');
  if (section) {
    section.classList.toggle('expanded');
  }
}

// Neue Funktion für Abhaken nach eindeutiger ID
function togglePlannerEntryById(id) {
  const todayStr = formatDate(new Date());
  const completedKey = `suppTree_completed_${todayStr}`;
  let completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
  
  if (completed.includes(id)) {
    completed = completed.filter(n => n !== id);
  } else {
    completed.push(id);
  }
  
  localStorage.setItem(completedKey, JSON.stringify(completed));
  renderDayPlanner();
  showToast(completed.includes(id) ? '✓ Erledigt!' : 'Rückgängig');
}

// Legacy Funktion für Abhaken nach Name (Fallback)
function togglePlannerEntryByName(name) {
  togglePlannerEntryById(name);
}

// ===============================
// KOFFEIN-STOP EINSTELLUNGEN
// ===============================
function openCaffeineSettings() {
  const settings = JSON.parse(localStorage.getItem('suppTreeCaffeineSettings') || '{}');
  const enabled = settings.enabled !== false;
  const pausedUntil = settings.pausedUntil || null;
  const isPaused = pausedUntil && new Date(pausedUntil) > new Date();
  
  let statusText = '';
  if (!enabled) {
    statusText = '<span class="caffeine-status off">🔴 Ausgeschaltet</span>';
  } else if (isPaused) {
    const pauseDate = new Date(pausedUntil);
    const formattedDate = pauseDate.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
    statusText = `<span class="caffeine-status paused">⏸️ Pausiert bis ${formattedDate}</span>`;
  } else {
    statusText = '<span class="caffeine-status on">🟢 Aktiv</span>';
  }
  
  const sheet = document.getElementById('caffeineSettingsSheet');
  const overlay = document.getElementById('caffeineSettingsOverlay');
  
  if (!sheet) {
    // Sheet existiert nicht, erstelle es
    createCaffeineSettingsSheet();
    return openCaffeineSettings();
  }
  
  // Update Status
  document.getElementById('caffeineCurrentStatus').innerHTML = statusText;
  document.getElementById('caffeineToggle').checked = enabled;
  
  overlay.classList.add('visible');
  sheet.classList.add('visible');
  lockBody();
}

function closeCaffeineSettings() {
  const sheet = document.getElementById('caffeineSettingsSheet');
  const overlay = document.getElementById('caffeineSettingsOverlay');
  if (sheet) sheet.classList.remove('visible');
  if (overlay) overlay.classList.remove('visible');
  unlockBody();
}

function toggleCaffeineEnabled() {
  const toggle = document.getElementById('caffeineToggle');
  const settings = JSON.parse(localStorage.getItem('suppTreeCaffeineSettings') || '{}');
  settings.enabled = toggle.checked;
  if (toggle.checked) {
    settings.pausedUntil = null; // Pause aufheben wenn aktiviert
  }
  localStorage.setItem('suppTreeCaffeineSettings', JSON.stringify(settings));
  renderDayPlanner();
  openCaffeineSettings(); // Refresh
  showToast(toggle.checked ? '☕ Koffein-Stopp aktiviert' : '☕ Koffein-Stopp deaktiviert');
}

function pauseCaffeineFor(days) {
  const settings = JSON.parse(localStorage.getItem('suppTreeCaffeineSettings') || '{}');
  const pauseUntil = new Date();
  pauseUntil.setDate(pauseUntil.getDate() + days);
  settings.pausedUntil = pauseUntil.toISOString();
  settings.enabled = true; // Sicherstellen dass es aktiviert ist
  localStorage.setItem('suppTreeCaffeineSettings', JSON.stringify(settings));
  renderDayPlanner();
  closeCaffeineSettings();
  showToast(`☕ Koffein-Stopp für ${days} Tag${days > 1 ? 'e' : ''} pausiert`);
}

function resumeCaffeine() {
  const settings = JSON.parse(localStorage.getItem('suppTreeCaffeineSettings') || '{}');
  settings.pausedUntil = null;
  settings.enabled = true;
  localStorage.setItem('suppTreeCaffeineSettings', JSON.stringify(settings));
  renderDayPlanner();
  openCaffeineSettings(); // Refresh
  showToast('☕ Koffein-Stopp wieder aktiv');
}

function createCaffeineSettingsSheet() {
  // Overlay
  const overlay = document.createElement('div');
  overlay.className = 'overlay';
  overlay.id = 'caffeineSettingsOverlay';
  overlay.onclick = closeCaffeineSettings;
  document.body.appendChild(overlay);
  
  // Sheet
  const sheet = document.createElement('div');
  sheet.className = 'bottom-sheet caffeine-settings-sheet';
  sheet.id = 'caffeineSettingsSheet';
  sheet.innerHTML = `
    <div class="sheet-header">
      <h2>☕ Koffein-Stopp Einstellungen</h2>
      <button class="sheet-close" onclick="closeCaffeineSettings()">✕</button>
    </div>
    <div class="sheet-content">
      <div class="caffeine-status-box" id="caffeineCurrentStatus">
        <!-- Status wird dynamisch gesetzt -->
      </div>
      
      <div class="caffeine-info-box">
        <p>Der Koffein-Stopp erinnert dich, 8 Stunden vor dem Schlafengehen kein Koffein mehr zu konsumieren.</p>
      </div>
      
      <div class="caffeine-toggle-row">
        <span>Koffein-Stopp anzeigen</span>
        <label class="toggle-switch">
          <input type="checkbox" id="caffeineToggle" onchange="toggleCaffeineEnabled()">
          <span class="toggle-slider"></span>
        </label>
      </div>
      
      <div class="caffeine-pause-section">
        <h4>⏸️ Temporär pausieren</h4>
        <div class="caffeine-pause-buttons">
          <button class="pause-btn" onclick="pauseCaffeineFor(1)">1 Tag</button>
          <button class="pause-btn" onclick="pauseCaffeineFor(3)">3 Tage</button>
          <button class="pause-btn" onclick="pauseCaffeineFor(7)">1 Woche</button>
        </div>
        <button class="resume-btn" onclick="resumeCaffeine()">▶️ Pause aufheben</button>
      </div>
    </div>
  `;
  document.body.appendChild(sheet);
}

function renderShiftBlock(shift, shiftInfo) {
  const iconEl = document.getElementById('shiftBlockIcon');
  const nameEl = document.getElementById('shiftBlockName');
  const timesEl = document.getElementById('shiftBlockTimes');
  const blockEl = document.getElementById('plannerShiftBlock');
  
  // Für 24h-Ansicht: Zeige aktuelle Schicht
  const now = new Date();
  const todayStr = formatDate(now);
  const todayShift = shifts[todayStr] || 'off';
  const todayShiftInfo = shiftConfig[todayShift] || {};
  
  const shiftIcons = {
    early: '🌅', day: '☀️', late: '🌆', night: '🌙',
    off: '🏠', vacation: '🏖️', sick: '🤒'
  };
  
  const shiftNames = {
    early: 'Frühschicht', day: 'Tagschicht', late: 'Spätschicht', night: 'Nachtschicht',
    off: 'Frei', vacation: 'Urlaub', sick: 'Krank'
  };
  
  if (iconEl) iconEl.textContent = shiftIcons[todayShift] || '📅';
  if (nameEl) nameEl.textContent = todayShiftInfo.name || shiftNames[todayShift] || 'Frei';
  
  if (timesEl) {
    if (todayShiftInfo.start && todayShiftInfo.end) {
      timesEl.textContent = `${todayShiftInfo.start} - ${todayShiftInfo.end}`;
    } else if (todayShift === 'off') {
      timesEl.textContent = 'Kein Dienst';
    } else {
      timesEl.textContent = '–';
    }
  }
  
  // Hintergrundfarbe basierend auf Schicht
  if (blockEl) {
    const colors = {
      early: '#fef3c7',
      day: '#ede9fe',
      late: '#dbeafe',
      night: '#1e293b',
      off: '#d1fae5',
      vacation: '#fce7f3',
      sick: '#fee2e2'
    };
    blockEl.style.background = colors[todayShift] || '#f3f4f6';
    if (todayShift === 'night') {
      blockEl.style.color = 'white';
    } else {
      blockEl.style.color = 'inherit';
    }
  }
}

function renderPlannerWarnings(shift, shiftInfo, dateStr) {
  const container = document.getElementById('plannerWarnings');
  if (!container) return;
  
  let warnings = [];
  
  // Koffein-Stopp basierend auf Schlafzeit (immer wenn Schlafzeit vorhanden)
  const sleepTime = shiftInfo.sleep || '22:00';
  const [sleepH, sleepM] = sleepTime.split(':').map(Number);
  let stopH = sleepH - 8;
  if (stopH < 0) stopH += 24;
  const stopTime = `${String(stopH).padStart(2, '0')}:${String(sleepM).padStart(2, '0')}`;
  
  // Prüfe aktuelle Zeit
  const now = new Date();
  const currentMinutes = now.getHours() * 60 + now.getMinutes();
  const stopMinutes = stopH * 60 + sleepM;
  const isToday = dateStr === formatDate(now);
  
  // Zeige Warnung für heute wenn noch relevant
  if (shift !== 'off' && shift !== 'vacation') {
    // Prüfe ob Melatonin/Schlaf-Supplement vorhanden
    const savedSupps = JSON.parse(localStorage.getItem('suppTreeSupplements') || '[]');
    const sleepSupps = savedSupps.filter(s => 
      s.name?.toLowerCase().includes('melatonin') || 
      s.name?.toLowerCase().includes('schlaf') ||
      s.name?.toLowerCase().includes('sleep') ||
      s.name?.toLowerCase().includes('magnesium')
    );
    
    const reason = sleepSupps.length > 0 
      ? `Wegen ${sleepSupps[0].name} um ${sleepSupps[0].time || sleepTime}`
      : `Für besseren Schlaf um ${sleepTime}`;
    
    warnings.push({
      type: 'caffeine',
      icon: '☕',
      title: `Koffein-Stopp ab ${stopTime}`,
      subtitle: reason,
      urgent: isToday && currentMinutes >= stopMinutes
    });
  }
  
  // Interaktions-Warnung
  const meds = JSON.parse(localStorage.getItem('suppTreeMedications') || '[]');
  const savedSupps = JSON.parse(localStorage.getItem('suppTreeSupplements') || '[]');
  if (meds.length > 0 && savedSupps.length > 0) {
    const hasMagnesium = savedSupps.some(s => s.name?.toLowerCase().includes('magnesium'));
    const hasAntibiotics = meds.some(m => m.name?.toLowerCase().includes('antibio'));
    
    if (hasMagnesium && hasAntibiotics) {
      warnings.push({
        type: 'interaction',
        icon: '⚠️',
        title: 'Wechselwirkung beachten',
        subtitle: 'Magnesium 2h vor/nach Antibiotika'
      });
    }
  }
  
  if (warnings.length === 0) {
    container.innerHTML = '';
    return;
  }
  
  container.innerHTML = warnings.map(w => `
    <div class="planner-warning ${w.type} ${w.urgent ? 'urgent' : ''}">
      <div class="warning-icon-wrap">
        <span class="warning-icon">${w.icon}</span>
      </div>
      <div class="warning-content">
        <span class="warning-title">${w.title}</span>
        <span class="warning-subtitle">${w.subtitle}</span>
      </div>
    </div>
  `).join('');
}

function renderPlannerNotes(dateStr) {
  const container = document.getElementById('plannerNotes');
  if (!container) return;
  
  const notesKey = `suppTree_notes_${dateStr}`;
  const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');
  
  if (notes.length === 0) {
    container.innerHTML = '';
    return;
  }
  
  container.innerHTML = notes.map((note, idx) => `
    <div class="planner-note">
      <span class="note-icon">📝</span>
      <div class="note-content">
        <div class="note-text">${escapeHtml(note.text)}</div>
        ${note.time ? `<div class="note-time">${escapeHtml(note.time)}</div>` : ''}
      </div>
      <div class="note-actions">
        <button class="note-action-btn" onclick="editNote(${idx})">✏️</button>
        <button class="note-action-btn" onclick="deleteNote(${idx})">🗑️</button>
      </div>
    </div>
  `).join('');
}

function togglePlannerEntry(index, name) {
  const dateStr = formatDate(currentPlannerDate);
  const completedKey = `suppTree_completed_${dateStr}`;
  let completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
  
  if (completed.includes(name)) {
    completed = completed.filter(n => n !== name);
  } else {
    completed.push(name);
  }
  
  localStorage.setItem(completedKey, JSON.stringify(completed));
  renderDayPlanner();
  renderWeekOverview();
}

function updatePlannerProgress(done, total) {
  const fill = document.getElementById('plannerProgressFill');
  const text = document.getElementById('plannerProgressText');
  
  const percent = total > 0 ? Math.round((done / total) * 100) : 0;
  
  if (fill) fill.style.width = percent + '%';
  if (text) text.textContent = `${done}/${total} erledigt`;
}

function changePlannerDay(delta) {
  currentPlannerDate.setDate(currentPlannerDate.getDate() + delta);
  renderDayPlanner();
  
  // Also update shift card if going back to today
  const isToday = formatDate(currentPlannerDate) === formatDate(new Date());
  if (isToday) {
    updateTodayShiftCard();
  }
}

function renderWeekOverview() {
  const grid = document.getElementById('weekOverviewGrid');
  const scoreEl = document.getElementById('weekScoreDisplay');
  if (!grid) return;
  
  const today = new Date();
  const dayOfWeek = today.getDay(); // 0 = Sunday
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1)); // Monday
  
  const dayNames = ['Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa', 'So'];
  let html = '';
  let totalItems = 0;
  let totalDone = 0;
  
  for (let i = 0; i < 7; i++) {
    const date = new Date(startOfWeek);
    date.setDate(startOfWeek.getDate() + i);
    const dateStr = formatDate(date);
    const isToday = dateStr === formatDate(today);
    const isPast = date < today && !isToday;
    
    const shift = shifts[dateStr] || 'off';
    const items = getItemsForDay(dateStr, shift);
    const completedKey = `suppTree_completed_${dateStr}`;
    const completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
    const doneCount = items.filter(item => completed.includes(item.name) || item.done).length;
    
    totalItems += items.length;
    totalDone += doneCount;
    
    const allDone = items.length > 0 && doneCount === items.length;
    const partial = items.length > 0 && doneCount > 0 && doneCount < items.length;
    
    let statusClass = '';
    if (isToday) statusClass = 'today';
    else if (allDone && isPast) statusClass = 'done';
    else if (partial && isPast) statusClass = 'partial';
    
    html += `
      <div class="week-day-item ${statusClass}" onclick="jumpToPlannerDay(${i})">
        <span class="week-day-label">${dayNames[i]}</span>
        <div class="week-day-dot">${allDone ? '✓' : partial ? '!' : isToday ? '◐' : '○'}</div>
        <span class="week-day-count">${doneCount}/${items.length}</span>
      </div>
    `;
  }
  
  grid.innerHTML = html;
  
  // Update score
  const percent = totalItems > 0 ? Math.round((totalDone / totalItems) * 100) : 0;
  if (scoreEl) scoreEl.textContent = percent + '% ✓';
}

function jumpToPlannerDay(dayIndex) {
  const today = new Date();
  const dayOfWeek = today.getDay();
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
  
  currentPlannerDate = new Date(startOfWeek);
  currentPlannerDate.setDate(startOfWeek.getDate() + dayIndex);
  
  renderDayPlanner();
  
  // Scroll to planner
  document.getElementById('homeDayPlanner')?.scrollIntoView({ behavior: 'smooth' });
}

