function initWeek7Preview() {
  const header = document.getElementById('week7Header');
  if (header) {
    header.onclick = function() {
      toggleWeek7Preview();
    };
  }
  
  // Badge sofort aktualisieren
  updateWeek7Badge();
}

function updateWeek7Badge() {
  const badge = document.getElementById('week7Badge');
  if (!badge) return;
  
  const today = new Date();
  let totalItems = 0;
  
  for (let i = 1; i <= 7; i++) {
    const date = new Date(today);
    date.setDate(today.getDate() + i);
    const dateStr = formatDate(date);
    const shift = shifts[dateStr] || 'off';
    const items = getItemsForDay(dateStr, shift);
    totalItems += items.length;
  }
  
  badge.textContent = `${totalItems} Einträge`;
}

function toggleWeek7Preview() {
  const preview = document.getElementById('week7Preview');
  if (!preview) return;
  
  const isOpen = preview.classList.contains('open');
  
  if (isOpen) {
    preview.classList.remove('open');
  } else {
    preview.classList.add('open');
    renderWeek7Days();
  }
}

function renderWeek7Days() {
  const content = document.getElementById('week7Content');
  const badge = document.getElementById('week7Badge');
  if (!content) return;
  
  const today = new Date();
  const dayNames = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
  const shiftColors = {
    early: '#f59e0b', day: '#8b5cf6', late: '#3b82f6', night: '#1e293b',
    off: '#10b981', vacation: '#ec4899', sick: '#ef4444'
  };
  const shiftLabels = {
    early: 'F', day: 'T', late: 'S', night: 'N',
    off: '–', vacation: 'U', sick: 'K'
  };
  
  let html = '';
  let totalItems = 0;
  
  for (let i = 1; i <= 7; i++) {
    const date = new Date(today);
    date.setDate(today.getDate() + i);
    const dateStr = formatDate(date);
    const shift = shifts[dateStr] || 'off';
    const shiftInfo = shiftConfig[shift] || {};
    const items = getItemsForDay(dateStr, shift);
    
    totalItems += items.length;
    
    const dayName = dayNames[date.getDay()];
    const shiftName = shiftInfo.name || (shift === 'off' ? 'Frei' : shift);
    
    html += `
      <div class="week7-day" data-date="${dateStr}" data-index="${i}">
        <div class="week7-day-date">
          <span class="week7-day-name">${dayName}</span>
          <span class="week7-day-num">${date.getDate()}</span>
        </div>
        <div class="week7-day-info">
          <div class="week7-day-shift">${shiftName}</div>
          <div class="week7-day-count">${items.length} Einträge</div>
        </div>
        <div class="week7-day-badge" style="background: ${shiftColors[shift] || '#6b7280'}">
          ${shiftLabels[shift] || '–'}
        </div>
        <span class="week7-day-arrow">›</span>
      </div>
      <div class="week7-day-detail" id="week7Detail${i}">
        ${items.length > 0 ? items.map(item => {
          const isTraining = item.entryId && item.entryId.startsWith('plan_');
          const isSupp = item.type === 'supplement';
          const isCustom = item.type === 'custom' && item.entryId;
          const isInfo = item.type === 'info-wake' || item.type === 'info-sleep';
          if (isTraining) {
            return `
            <div class="week7-item" data-entry-id="${item.entryId}" style="background:#dbeafe;border:1.5px solid #93c5fd;border-radius:7px;cursor:pointer;padding:8px 10px">
              <span class="week7-item-icon">${item.icon || '💊'}</span>
              <div style="flex:1">
                <span class="week7-item-name" style="color:#1e40af;font-weight:700">${item.name}</span>
                ${item.entryNote ? `<div style="font-size:9px;color:#3b82f6;margin-top:1px">${item.entryNote}</div>` : ''}
              </div>
              <span style="color:#3b82f6;font-size:14px">›</span>
            </div>`;
          }
          if (isSupp) {
            return `
            <div class="week7-item" data-supp-name="${(item.name||'').replace(/"/g,'&quot;')}" data-supp-id="${item.suppId||''}" data-supp-icon="${item.icon||'💊'}" data-supp-dose="${(item.dose||'').replace(/"/g,'&quot;')}" data-date="${dateStr}" style="cursor:pointer">
              <span class="week7-item-icon">${item.icon || '💊'}</span>
              <div style="flex:1;min-width:0">
                <span class="week7-item-name">${item.name}</span>
                ${item.trainingNote ? `<div style="font-size:9px;color:#1e40af;font-weight:600">🏋️ ${item.trainingNote}</div>` : ''}
              </div>
              <span class="week7-item-time">${item.time || '–'}</span>
            </div>`;
          }
          if (isCustom) {
            return `
            <div class="week7-item" data-entry-id="${item.entryId}" style="cursor:pointer">
              <span class="week7-item-icon">${item.icon || '📝'}</span>
              <span class="week7-item-name">${item.name}</span>
              <span class="week7-item-time">${item.time || '–'}</span>
            </div>`;
          }
          return `
          <div class="week7-item"${isInfo ? '' : ' style="cursor:pointer"'}>
            <span class="week7-item-icon">${item.icon || '💊'}</span>
            <span class="week7-item-name">${item.name}</span>
            <span class="week7-item-time">${item.time || '–'}</span>
          </div>`;
        }).join('') : '<div class="week7-item">Keine Einträge</div>'}
      </div>
    `;
  }
  
  content.innerHTML = html;
  
  // Update badge
  if (badge) {
    badge.textContent = `${totalItems} Einträge`;
  }
  
  // Add click handlers to each day
  content.querySelectorAll('.week7-day').forEach(day => {
    day.onclick = function() {
      const index = this.dataset.index;
      toggleWeek7Day(index);
    };
  });

  // Add click handlers to training/custom entry items
  content.querySelectorAll('[data-entry-id]').forEach(el => {
    el.onclick = function(e) {
      e.stopPropagation();
      const eid = this.getAttribute('data-entry-id');
      if (eid) openCalendarEntry(eid);
    };
  });

  // Add click handlers to supplement items
  content.querySelectorAll('[data-supp-name]').forEach(el => {
    el.onclick = function(e) {
      e.stopPropagation();
      const name = this.getAttribute('data-supp-name');
      const suppId = this.getAttribute('data-supp-id');
      const icon = this.getAttribute('data-supp-icon');
      const dose = this.getAttribute('data-supp-dose');
      const dateStr = this.getAttribute('data-date');
      // Temporär currentPlannerDate auf den Zukunfts-Tag setzen
      const savedDate = new Date(currentPlannerDate);
      if (dateStr) {
        const [y, m, d] = dateStr.split('-').map(Number);
        currentPlannerDate = new Date(y, m - 1, d);
      }
      if (typeof openSupplementInfoSheet === 'function') {
        openSupplementInfoSheet(suppId, name, '', dose, '', icon, name);
      }
      // currentPlannerDate bleibt auf dem Zukunfts-Tag damit der Button richtig angezeigt wird
    };
  });
}

function toggleWeek7Day(index) {
  const day = document.querySelector(`.week7-day[data-index="${index}"]`);
  const detail = document.getElementById(`week7Detail${index}`);

  if (!day || !detail) return;

  const wasExpanded = day.classList.contains('expanded');

  // Close all days
  document.querySelectorAll('.week7-day.expanded').forEach(d => {
    d.classList.remove('expanded');
  });

  // Toggle this day (open if was closed)
  if (!wasExpanded) {
    day.classList.add('expanded');
  }
}

function addNoteForDay(dateStr) {
  // Setze das Datum für den neuen Eintrag
  const [year, month, day] = dateStr.split('-').map(Number);
  currentPlannerDate = new Date(year, month - 1, day);
  
  // Öffne das Eintrag-Sheet
  openAddTimelineEntry();
}

function jumpToDay(dateStr) {
  const [year, month, day] = dateStr.split('-').map(Number);
  currentPlannerDate = new Date(year, month - 1, day);
  renderDayPlanner();
  
  // Scroll to planner
  document.getElementById('homeDayPlanner')?.scrollIntoView({ behavior: 'smooth' });
  
  // Close week7 preview
  const preview = document.getElementById('week7Preview');
  if (preview) preview.classList.remove('open');
}

