function openAddNote() {
  const dateStr = formatDate(currentPlannerDate);
  
  // Get saved templates
  const templates = JSON.parse(localStorage.getItem('suppTree_noteTemplates') || '[]');
  
  let templatesHtml = '';
  if (templates.length > 0) {
    templatesHtml = `
      <div class="note-templates-section">
        <h4>📋 Vorlagen</h4>
        <div class="note-templates-list">
          ${templates.map((t, i) => `
            <button class="note-template-btn" onclick="useNoteTemplate(${i})">
              ${t.icon || '📝'} ${t.name}
            </button>
          `).join('')}
        </div>
      </div>
    `;
  }
  
  const sheetHTML = `
    <div class="bottom-sheet-overlay" onclick="closeNoteSheet()"></div>
    <div class="bottom-sheet note-sheet">
      <div class="sheet-handle"></div>
      <div class="sheet-header">
        <h3>📝 Notiz hinzufügen</h3>
        <button class="sheet-close" onclick="closeNoteSheet()">✕</button>
      </div>
      <div class="sheet-content">
        ${templatesHtml}
        
        <div class="note-form">
          <div class="form-group">
            <label>Notiz</label>
            <textarea id="noteTextInput" rows="3" placeholder="Deine Notiz..."></textarea>
          </div>
          
          <div class="form-group">
            <label>Uhrzeit (optional)</label>
            <input type="time" id="noteTimeInput">
          </div>
          
          <div class="form-group">
            <label>Icon</label>
            <div class="icon-picker" id="noteIconPicker">
              <button class="icon-option selected" data-icon="📝" onclick="selectNoteIcon('📝')">📝</button>
              <button class="icon-option" data-icon="💡" onclick="selectNoteIcon('💡')">💡</button>
              <button class="icon-option" data-icon="⚠️" onclick="selectNoteIcon('⚠️')">⚠️</button>
              <button class="icon-option" data-icon="✨" onclick="selectNoteIcon('✨')">✨</button>
              <button class="icon-option" data-icon="🎯" onclick="selectNoteIcon('🎯')">🎯</button>
              <button class="icon-option" data-icon="💪" onclick="selectNoteIcon('💪')">💪</button>
              <button class="icon-option" data-icon="🏃" onclick="selectNoteIcon('🏃')">🏃</button>
              <button class="icon-option" data-icon="🍎" onclick="selectNoteIcon('🍎')">🍎</button>
            </div>
          </div>
          
          <div class="form-group template-save-option">
            <label class="checkbox-label">
              <input type="checkbox" id="saveAsTemplateCheck">
              <span>Als Vorlage speichern</span>
            </label>
            <input type="text" id="templateNameInput" placeholder="Vorlagen-Name" style="display: none; margin-top: 8px;">
          </div>
        </div>
        
        <div class="sheet-actions">
          <button class="btn-secondary" onclick="closeNoteSheet()">Abbrechen</button>
          <button class="btn-primary" onclick="saveNote()">Speichern</button>
        </div>
      </div>
    </div>
  `;
  
  // Add to body
  const container = document.createElement('div');
  container.id = 'noteSheetContainer';
  container.innerHTML = sheetHTML;
  document.body.appendChild(container);
  
  // Add event listener for template checkbox
  setTimeout(() => {
    const checkbox = document.getElementById('saveAsTemplateCheck');
    const nameInput = document.getElementById('templateNameInput');
    if (checkbox && nameInput) {
      checkbox.addEventListener('change', () => {
        nameInput.style.display = checkbox.checked ? 'block' : 'none';
      });
    }
  }, 100);
}

let selectedNoteIcon = '📝';

function selectNoteIcon(icon) {
  selectedNoteIcon = icon;
  document.querySelectorAll('#noteIconPicker .icon-option').forEach(btn => {
    btn.classList.toggle('selected', btn.dataset.icon === icon);
  });
}

function useNoteTemplate(templateIndex) {
  const templates = JSON.parse(localStorage.getItem('suppTree_noteTemplates') || '[]');
  const template = templates[templateIndex];
  if (!template) return;
  
  const textInput = document.getElementById('noteTextInput');
  const timeInput = document.getElementById('noteTimeInput');
  
  if (textInput) textInput.value = template.text || '';
  if (timeInput && template.time) timeInput.value = template.time;
  if (template.icon) selectNoteIcon(template.icon);
}

function saveNote() {
  const textInput = document.getElementById('noteTextInput');
  const timeInput = document.getElementById('noteTimeInput');
  const saveAsTemplate = document.getElementById('saveAsTemplateCheck');
  const templateName = document.getElementById('templateNameInput');
  
  const text = textInput?.value?.trim();
  if (!text) {
    alert('Bitte gib eine Notiz ein.');
    return;
  }
  
  const dateStr = formatDate(currentPlannerDate);
  const notesKey = `suppTree_notes_${dateStr}`;
  const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');
  
  const newNote = {
    text: text,
    time: timeInput?.value || null,
    icon: selectedNoteIcon,
    created: new Date().toISOString()
  };
  
  notes.push(newNote);
  localStorage.setItem(notesKey, JSON.stringify(notes));
  
  // Save as template if checked
  if (saveAsTemplate?.checked && templateName?.value?.trim()) {
    const templates = JSON.parse(localStorage.getItem('suppTree_noteTemplates') || '[]');
    templates.push({
      name: templateName.value.trim(),
      text: text,
      time: timeInput?.value || null,
      icon: selectedNoteIcon
    });
    localStorage.setItem('suppTree_noteTemplates', JSON.stringify(templates));
  }
  
  closeNoteSheet();
  renderDayPlanner();
}

function deleteNote(noteIndex) {
  showConfirmDialog('Notiz löschen', 'Möchtest du diese Notiz wirklich löschen?', 'Löschen', function() {
    const dateStr = formatDate(currentPlannerDate);
    const notesKey = `suppTree_notes_${dateStr}`;
    const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');

    notes.splice(noteIndex, 1);
    localStorage.setItem(notesKey, JSON.stringify(notes));

    renderDayPlanner();
  }, true);
}

function editNote(noteIndex) {
  const dateStr = formatDate(currentPlannerDate);
  const notesKey = `suppTree_notes_${dateStr}`;
  const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');
  const note = notes[noteIndex];
  
  if (!note) return;
  
  openAddNote();
  
  // Fill in existing values after sheet is open
  setTimeout(() => {
    const textInput = document.getElementById('noteTextInput');
    const timeInput = document.getElementById('noteTimeInput');
    
    if (textInput) textInput.value = note.text || '';
    if (timeInput && note.time) timeInput.value = note.time;
    if (note.icon) selectNoteIcon(note.icon);
    
    // Change save button to update
    const saveBtn = document.querySelector('.note-sheet .btn-primary');
    if (saveBtn) {
      saveBtn.textContent = 'Aktualisieren';
      saveBtn.onclick = () => updateNote(noteIndex);
    }
  }, 100);
}

function updateNote(noteIndex) {
  const textInput = document.getElementById('noteTextInput');
  const timeInput = document.getElementById('noteTimeInput');
  
  const text = textInput?.value?.trim();
  if (!text) {
    alert('Bitte gib eine Notiz ein.');
    return;
  }
  
  const dateStr = formatDate(currentPlannerDate);
  const notesKey = `suppTree_notes_${dateStr}`;
  const notes = JSON.parse(localStorage.getItem(notesKey) || '[]');
  
  notes[noteIndex] = {
    ...notes[noteIndex],
    text: text,
    time: timeInput?.value || null,
    icon: selectedNoteIcon,
    updated: new Date().toISOString()
  };
  
  localStorage.setItem(notesKey, JSON.stringify(notes));
  
  closeNoteSheet();
  renderDayPlanner();
}

function closeNoteSheet() {
  const container = document.getElementById('noteSheetContainer');
  if (container) container.remove();
  selectedNoteIcon = '📝';
}

