function renderCalendarReminders() {
  const section = document.getElementById('planerRemindersSection');
  const list = document.getElementById('planerRemindersList');
  if (!section || !list) return;
  
  const reminders = [];
  
  // Get current shift and sleep time
  const todayStr = formatDate(new Date());
  const shift = shifts[todayStr] || 'day';
  const shiftInfo = shiftConfig[shift] || { sleep: '23:00' };
  const sleepTime = shiftInfo.sleep || '23:00';
  
  // Get supplements that need caffeine stop
  const savedSupps = JSON.parse(localStorage.getItem('suppTreeSupplements') || '[]');
  const caffeineConflicts = savedSupps.filter(s => 
    s.name?.toLowerCase().includes('melatonin') || 
    s.name?.toLowerCase().includes('schlaf') ||
    s.name?.toLowerCase().includes('magnesium')
  );
  
  if (caffeineConflicts.length > 0) {
    // Calculate caffeine stop time (8 hours before sleep)
    const [sleepH, sleepM] = sleepTime.split(':').map(Number);
    let stopH = sleepH - 8;
    if (stopH < 0) stopH += 24;
    const stopTime = `${String(stopH).padStart(2, '0')}:${String(sleepM).padStart(2, '0')}`;
    
    const suppNames = caffeineConflicts.map(s => s.name).join(', ');
    
    reminders.push({
      type: 'caffeine',
      icon: '☕',
      title: `Koffein-Stopp ab ${stopTime}`,
      subtitle: `Wegen ${suppNames} um ${sleepTime}`,
      time: stopTime
    });
  }
  
  // Show/hide section based on reminders
  if (reminders.length > 0) {
    section.style.display = 'block';
    list.innerHTML = reminders.map(r => `
      <div class="reminder-card ${r.type}">
        <div class="reminder-icon">${r.icon}</div>
        <div class="reminder-content">
          <div class="reminder-title">${r.title}</div>
          <div class="reminder-subtitle">${r.subtitle}</div>
        </div>
        <div class="reminder-time">ab ${r.time}</div>
      </div>
    `).join('');
  } else {
    section.style.display = 'none';
  }
}

// Legacy function - now redirects to planer
function updateCaffeineWarning() {
  const warningSection = document.getElementById('homeCaffeineWarning');
  if (!warningSection) return;
  
  // Check if dismissed today
  const dismissedDate = localStorage.getItem('caffeineDismissed');
  const today = new Date().toDateString();
  if (dismissedDate === today) {
    warningSection.style.display = 'none';
    return;
  }
  
  // Get current shift and sleep time
  const todayStr = formatDate(new Date());
  const shift = shifts[todayStr] || 'day';
  const shiftInfo = shiftConfig[shift] || { sleep: '23:00' };
  const sleepTime = shiftInfo.sleep || '23:00';
  
  // Check if user has supplements that conflict with caffeine
  const savedSupps = JSON.parse(localStorage.getItem('suppTreeSupplements') || '[]');
  const caffeineConflicts = savedSupps.filter(s => 
    s.name?.toLowerCase().includes('melatonin') || 
    s.name?.toLowerCase().includes('schlaf')
  );
  
  if (caffeineConflicts.length === 0) {
    warningSection.style.display = 'none';
    return;
  }
  
  // Calculate caffeine stop time (8 hours before sleep)
  const [sleepH, sleepM] = sleepTime.split(':').map(Number);
  let stopH = sleepH - 8;
  if (stopH < 0) stopH += 24;
  const stopTime = `${String(stopH).padStart(2, '0')}:${String(sleepM).padStart(2, '0')}`;
  
  // Update the display
  const stopTimeEl = document.getElementById('caffeineStopTime');
  const reasonEl = document.getElementById('caffeineStopReason');
  if (stopTimeEl) stopTimeEl.textContent = stopTime;
  if (reasonEl) {
    const suppName = caffeineConflicts[0].name;
    reasonEl.textContent = `Du nimmst um ${sleepTime} ${suppName} – Koffein würde die Wirkung stören`;
  }
  
  // Check if current time is before stop time
  const now = new Date();
  const currentMinutes = now.getHours() * 60 + now.getMinutes();
  const stopMinutes = stopH * 60 + sleepM;
  
  if (currentMinutes < stopMinutes) {
    warningSection.style.display = 'block';
  } else {
    warningSection.style.display = 'none';
  }
}

function dismissCaffeineWarning() {
  const warningSection = document.getElementById('homeCaffeineWarning');
  if (warningSection) {
    warningSection.style.display = 'none';
    localStorage.setItem('caffeineDismissed', new Date().toDateString());
  }
}

