function getShiftColor(shift) {
  const colors = {
    early: '#f59e0b',
    day: '#8b5cf6',
    late: '#3b82f6',
    night: '#1e293b',
    off: '#10b981',
    vacation: '#ec4899',
    sick: '#ef4444'
  };
  return colors[shift] || '#6b7280';
}

function renderHomeWeekPreview() {
  const content = document.getElementById('homeWeekPreviewContent');
  if (!content) return;
  
  const today = new Date();
  let html = '<div class="week-preview-days">';
  
  for (let i = 1; i <= 7; i++) {
    const date = new Date(today);
    date.setDate(today.getDate() + i);
    const dateStr = formatDate(date);
    const shift = shifts[dateStr];
    const shiftInfo = shift ? shiftConfig[shift] : null;
    
    const dayNames = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
    const dayName = dayNames[date.getDay()];
    
    const items = getItemsForDay(dateStr, shift);
    
    html += `
      <div class="week-day-row" onclick="alert('Klick auf ${dateStr}'); jumpToDay('${dateStr}')">
        <div class="week-day-info">
          <span class="week-day-name">${dayName}</span>
          <span class="week-day-date">${date.getDate()}.${date.getMonth() + 1}.</span>
        </div>
        <div class="week-day-shift" style="background: ${shiftInfo?.color || getShiftColor(shift)};">
          ${shiftInfo?.name || (shift ? shift.charAt(0).toUpperCase() : '–')}
        </div>
        <div class="week-day-count">
          ${items.length > 0 ? `${items.length} Einträge` : '–'}
        </div>
        <span class="week-day-arrow">›</span>
      </div>
    `;
  }
  
  html += '</div>';
  content.innerHTML = html;
}

function toggleFilterSection(titleEl) {
  const content = titleEl.nextElementSibling;
  const arrow = titleEl.querySelector('.filter-section-arrow');
  if (!content) return;
  const isOpen = content.style.display !== 'none';
  const hasFilterOptions = content.classList.contains('filter-options');
  content.style.display = isOpen ? 'none' : (hasFilterOptions ? 'flex' : 'block');
  if (arrow) arrow.textContent = isOpen ? '+' : '−';
}

function openFilterSheet() {
  // Copy current filters to temp
  tempFilters = new Set(activeFilters);
  
  // Update UI to show current filters
  document.querySelectorAll('#filterSheet .filter-option').forEach(opt => {
    const isActive = tempFilters.has(opt.dataset.filter);
    opt.classList.toggle('selected', isActive);
    opt.classList.toggle('active', isActive);
    // Sektion mit aktiven Filtern automatisch aufklappen
    if (isActive) {
      const collapsible = opt.closest('.filter-collapsible');
      if (collapsible) {
        collapsible.style.display = 'flex';
        const arrow = collapsible.previousElementSibling?.querySelector('.filter-section-arrow');
        if (arrow) arrow.textContent = '−';
      }
    }
  });

  document.getElementById('filterOverlay').classList.add('active');
  document.getElementById('filterSheet').classList.add('visible');
  lockBody();
}

function closeFilterSheet() {
  document.getElementById('filterOverlay').classList.remove('active');
  document.getElementById('filterSheet').classList.remove('visible');
  unlockBody();
}

function toggleSheetFilter(filter, btn) {
  if (tempFilters.has(filter)) {
    tempFilters.delete(filter);
    btn.classList.remove('selected');
  } else {
    tempFilters.add(filter);
    btn.classList.add('selected');
  }
}

function resetFiltersInSheet() {
  tempFilters.clear();
  document.querySelectorAll('#filterSheet .filter-option').forEach(opt => {
    opt.classList.remove('selected');
    opt.classList.remove('active');
  });
  // Clear price inputs
  const priceMin = document.getElementById('priceMin');
  const priceMax = document.getElementById('priceMax');
  if (priceMin) priceMin.value = '';
  if (priceMax) priceMax.value = '';
}

