function openSubcategory(category) {
  const data = subcategories[category];
  if (!data) {
    goToCategory(category);
    return;
  }
  
  document.getElementById('subcategoryTitle').textContent = data.title;
  
  const grid = document.getElementById('subcategoryGrid');
  grid.innerHTML = data.items.map(item => `
    <div class="subcategory-item" onclick="selectSubcategory('${item.id}', '${item.name}')">
      <div class="subcategory-icon">${item.icon}</div>
      <div class="subcategory-info">
        <h4>${item.name}</h4>
        <span>${item.count} Produkte</span>
      </div>
    </div>
  `).join('') + `
    <button class="subcategory-all-btn" onclick="goToCategory('${category}'); closeSubcategory();">
      Alle ${data.title.split(' ').slice(1).join(' ')} anzeigen →
    </button>
  `;
  
  document.getElementById('subcategoryOverlay').classList.add('visible');
  document.getElementById('subcategorySheet').classList.add('visible');
  lockBody();
}

function closeSubcategory() {
  document.getElementById('subcategoryOverlay').classList.remove('visible');
  document.getElementById('subcategorySheet').classList.remove('visible');
  unlockBody();
}

function selectSubcategory(subcategoryId, subcategoryName) {
  closeSubcategory();
  
  // Set the filter to the subcategory
  activeCategory = subcategoryId;
  activeFilter = 'all';
  
  switchScreen('productsScreen');
  
  setTimeout(() => {
    renderProductsGridNew();
    showToast(`${subcategoryName} wird angezeigt`);
  }, 100);
}

function goToAllProducts() {
  activeCategory = 'all';
  activeFilter = 'all';
  switchScreen('productsScreen');
  setTimeout(() => {
    renderProductsGridNew();
  }, 100);
}

function setCategory(category) {
  activeCategory = category;
  renderProductsGridNew();
}

function toggleProductFav(productId, btn) {
  if (favorites.has(productId)) {
    favorites.delete(productId);
    favCount--;
    btn.classList.remove('active');
    btn.textContent = '🤍';
  } else {
    favorites.add(productId);
    favCount++;
    btn.classList.add('active');
    btn.textContent = '❤️';
    createFlyingItem(btn, 'heart');
  }
  saveFavorites();
  updateAllBadges();
}

function addToCartFromGrid(productId, btn) {
  const currentQty = cart.get(productId) || 0;
  cart.set(productId, currentQty + 1);
  cartCount++;
  saveCart();
  createFlyingCartItem(btn);

  // Guided Shop: Produkt-Hinzufügung tracken + Provision verknüpfen
  if (guidedShopActive) {
    guidedShopItemAdded = true;
    if (guidedShopResults[guidedShopIndex]) {
      guidedShopResults[guidedShopIndex].status = 'added';
    }

    // Provisions-Referral speichern: Berater bekommt Provision für dieses Produkt
    if (guidedShopBeraterId) {
      const berater = mbGetBerater().find(b => b.id === guidedShopBeraterId);
      const supp = guidedShopSupplements[guidedShopIndex];
      cartReferrals.set(productId, {
        beraterId: guidedShopBeraterId,
        beraterName: berater ? berater.name : 'Berater',
        planId: guidedShopPlanId,
        supplementName: supp ? supp.name : '',
        addedAt: new Date().toISOString()
      });
      saveCartReferrals();
    }

    // Guided-Bar aktualisieren
    const bar = document.getElementById('guidedShopBar');
    if (bar) {
      bar.outerHTML = renderGuidedShopBar();
    }
    showToast('✅ Hinzugefügt! Klicke "Weiter" für die nächste Empfehlung');
  } else {
    showToast('Zum Warenkorb hinzugefügt');
  }
}

