function checkRoburVisibility() {
  const roburFloating = document.getElementById('roburFloating');
  const currentScreen = document.querySelector('.screen.active');
  
  if (currentScreen && (currentScreen.id === 'productsScreen' || currentScreen.id === 'homeScreen')) {
    const scrollY = window.scrollY;
    if (scrollY > 300) {
      roburFloating.classList.add('visible');
    } else {
      roburFloating.classList.remove('visible');
    }
  } else {
    roburFloating.classList.remove('visible');
  }
}

window.addEventListener('scroll', checkRoburVisibility);

// Check on screen switch
