// ===============================
function openSTFeature(feature) {
  const screenMap = {
    'planer': 'calendarScreen',
    'mysupplements': 'mysupplementsScreen',
    'matrix': 'matrixScreen',
    'medications': 'medicationsScreen',
    'quiz': 'quizScreen',
    'knowledge': 'knowledgeScreen',
    'symptoms': 'symptomsScreen',
    'practitioner': 'practitionerScreen',
    'robur': 'roburScreen',
    'bloodtest': 'bloodTestScreen'
  };
  
  const screenId = screenMap[feature];
  if (screenId && document.getElementById(screenId)) {
    document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
    document.getElementById(screenId).classList.add('active');
    screenHistory.push(screenId);
    window.scrollTo(0, 0);
    updateFloatingButtonsVisibility(screenId);
    
    // Init planer when opening
    if (screenId === 'calendarScreen') {
      initCalendar();
    }
    // Init my supplements when opening
    if (screenId === 'mysupplementsScreen') {
      initMySupplements();
      renderAboManagement();
    }
    // Init matrix when opening
    if (screenId === 'matrixScreen') {
      initMatrix();
    }
    // Init medications when opening
    if (screenId === 'medicationsScreen') {
      initMedications();
    }
    // Init quiz stats when opening
    if (screenId === 'quizScreen') {
      updateQuizScreenStats();
    }
  }
}

