// ===============================
// CENTRAL POINTS SYSTEM
// ===============================

let pointsState = {
  shop: 0,    // Points from purchases
  spent: 0    // Total points spent on rewards
};

// ===============================
// PUNKTESYSTEM (nur Shop-Punkte)
// ===============================
// Sammeln: 5 Punkte pro €1 Einkauf
// Einlösen: 100 Punkte = 1€ Guthaben

const POINTS_CONFIG = {
  normalRate: 5,      // 5 Punkte pro €1 bei normalem Kauf (5%)
  aboRate: 5,         // 5 Punkte pro €1 bei Abo-Kauf (5%)
  redemptionRate: 100 // 100 Punkte = 1€
};

// Load points from localStorage
function loadPointsData() {
  const saved = localStorage.getItem('suppTreeShopPoints');
  if (saved) {
    const data = JSON.parse(saved);
    pointsState.shop = data.shop || 0;
    pointsState.spent = data.spent || 0;
  }
}

// Save points to localStorage
function savePointsData() {
  localStorage.setItem('suppTreeShopPoints', JSON.stringify({
    shop: pointsState.shop,
    spent: pointsState.spent
  }));
  if (supabase && currentUser) {
    DataStore.set('points_transactions', 'suppTreeShopPoints', {
      shop: pointsState.shop,
      spent: pointsState.spent
    }, {
      upsert: true,
      transform: (p) => ({
        user_id: currentUser.id,
        type: 'earn',
        amount: p.shop - p.spent,
        source: 'sync',
        description: `Points sync: ${p.shop} earned, ${p.spent} spent`
      })
    }).catch(e => console.error('Points sync error:', e));
  }
}

// Get total available points
function getTotalPoints() {
  return Math.max(0, pointsState.shop - pointsState.spent);
}

// Get points value in Euro
function getPointsValueInEuro() {
  const points = getTotalPoints();
  return Math.floor(points / POINTS_CONFIG.redemptionRate * 100) / 100; // 2 Dezimalstellen
}

// Add points after purchase
function addShopPoints(euroAmount, isAbo = false) {
  loadPointsData();
  const rate = isAbo ? POINTS_CONFIG.aboRate : POINTS_CONFIG.normalRate;
  const points = Math.floor(euroAmount * rate);
  pointsState.shop += points;
  savePointsData();
  
  if (points > 0) {
    const euroValue = (points / POINTS_CONFIG.redemptionRate).toFixed(2);
    showToast(`🎉 +${points} Punkte gesammelt! (${euroValue}€ Guthaben)`);
  }
}

// Spend points as Euro discount
function spendPointsAsEuro(euroAmount) {
  loadPointsData();
  const pointsNeeded = Math.ceil(euroAmount * POINTS_CONFIG.redemptionRate);
  
  if (getTotalPoints() >= pointsNeeded) {
    pointsState.spent += pointsNeeded;
    savePointsData();
    return true;
  }
  return false;
}

// Spend exact points amount
function spendPoints(pointsAmount) {
  loadPointsData();
  if (getTotalPoints() >= pointsAmount) {
    pointsState.spent += pointsAmount;
    savePointsData();
    return true;
  }
  return false;
}

// Calculate points for a purchase preview
function calculatePointsPreview(euroAmount, isAbo = false) {
  const rate = isAbo ? POINTS_CONFIG.aboRate : POINTS_CONFIG.normalRate;
  const points = Math.floor(euroAmount * rate);
  const euroValue = (points / POINTS_CONFIG.redemptionRate).toFixed(2);
  return { points, euroValue };
}

// Open points info sheet
function openPointsDetail() {
  const points = getTotalPoints();
  const euroValue = getPointsValueInEuro().toFixed(2).replace('.', ',');
  
  const content = `
    <div style="text-align: center; padding: 20px;">
      <div style="font-size: 48px; margin-bottom: 10px;">🏆</div>
      <div style="font-size: 32px; font-weight: 700; color: var(--primary);">${points.toLocaleString('de-DE')}</div>
      <div style="font-size: 14px; color: var(--text-muted); margin-bottom: 20px;">Punkte</div>
      
      <div style="background: linear-gradient(135deg, #dcfce7, #bbf7d0); padding: 16px; border-radius: 7px; margin-bottom: 20px;">
        <div style="font-size: 24px; font-weight: 700; color: #16a34a;">${euroValue}€</div>
        <div style="font-size: 13px; color: #15803d;">Guthaben zum Einlösen</div>
      </div>
      
      <div style="background: var(--cream); padding: 16px; border-radius: 7px; text-align: left;">
        <div style="font-weight: 600; margin-bottom: 12px;">So sammelst du Punkte:</div>
        <div style="display: flex; justify-content: space-between; margin-bottom: 8px;">
          <span>Einkauf</span>
          <span style="font-weight: 600;">5 Punkte pro €1</span>
        </div>
        <div style="display: flex; justify-content: space-between; margin-bottom: 12px;">
          <span>Abo-Bestellung</span>
          <span style="font-weight: 600; color: var(--primary);">8 Punkte pro €1</span>
        </div>
        <div style="border-top: 1px solid var(--cream-dark); padding-top: 12px; font-size: 13px; color: var(--text-muted);">
          100 Punkte = 1€ Guthaben<br>
          Beim Checkout direkt einlösbar!
        </div>
      </div>
    </div>
  `;
  
  // Show as toast/modal or simple alert for now
  showInfoModal('Meine Punkte', content);
}

// Show info modal
function showInfoModal(title, content) {
  // Check if modal exists, create if not
  let modal = document.getElementById('infoModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'infoModal';
    modal.className = 'overlay';
    modal.innerHTML = `
      <div class="info-modal-content">
        <div class="info-modal-header">
          <h3 id="infoModalTitle"></h3>
          <button class="sheet-close" onclick="closeInfoModal()">✕</button>
        </div>
        <div class="info-modal-body" id="infoModalBody"></div>
      </div>
    `;
    modal.onclick = (e) => { if (e.target === modal) closeInfoModal(); };
    document.body.appendChild(modal);
  }
  
  document.getElementById('infoModalTitle').textContent = title;
  document.getElementById('infoModalBody').innerHTML = content;
  modal.classList.add('visible');
  lockBody();
}

function closeInfoModal() {
  const modal = document.getElementById('infoModal');
  if (modal) {
    modal.classList.remove('visible');
    unlockBody();
  }
}

// Award points for shop purchase (called when purchase is made)
function awardShopPoints(euroAmount, isAbo = false) {
  addShopPoints(euroAmount, isAbo);
}

