// Quiz State
let quizState = {
  currentQuestion: 0,
  selectedAnswer: null,
  answered: false,
  correctCount: 0,
  questions: [],
  answeredQuestions: [], // Store answered questions with user answers
  startTime: null,
  completedToday: false,
  streak: 0,
  totalQuizzes: 0,
  totalCorrect: 0,
  totalQuestions: 0,
  points: 0,
  lastQuizDate: null,
  history: [],
  // Properties for two modes
  mode: 'daily', // 'daily' or 'practice'
  practiceCategory: 'Alle',
  practiceQuestions: [], // Shuffled questions for endless practice
  practiceIndex: 0 // Current index in practice questions
};

// Load quiz data from localStorage
function loadQuizData() {
  const saved = localStorage.getItem('suppTreeQuizData');
  if (saved) {
    const data = JSON.parse(saved);
    quizState.streak = data.streak || 0;
    quizState.totalQuizzes = data.totalQuizzes || 0;
    quizState.totalCorrect = data.totalCorrect || 0;
    quizState.totalQuestions = data.totalQuestions || 0;
    quizState.points = data.points || 0;
    quizState.lastQuizDate = data.lastQuizDate || null;
    quizState.history = data.history || [];
    
    // Check if already completed today
    const today = new Date().toDateString();
    quizState.completedToday = quizState.lastQuizDate === today;
  }
}

// Save quiz data to localStorage
function saveQuizData() {
  const data = {
    streak: quizState.streak,
    totalQuizzes: quizState.totalQuizzes,
    totalCorrect: quizState.totalCorrect,
    totalQuestions: quizState.totalQuestions,
    points: quizState.points,
    lastQuizDate: quizState.lastQuizDate,
    history: quizState.history.slice(-10) // Keep last 10 quizzes
  };
  localStorage.setItem('suppTreeQuizData', JSON.stringify(data));
}

// Update ST+ screen stats
function updateSTPlusStats() {
  loadQuizData();
  
  // ========== UPDATE SUPPLEMENTS STATS ==========
  // Load supplements if not loaded
  if (!mySupplements || mySupplements.length === 0) {
    const saved = localStorage.getItem('suppTreeMySupplements');
    if (saved) {
      mySupplements = JSON.parse(saved);
    }
  }
  
  const supplementsCount = document.getElementById('stplusSupplementsCount');
  const supplementsWarning = document.getElementById('stplusSupplementsWarning');
  
  if (supplementsCount) {
    const total = mySupplements ? mySupplements.length : 0;
    const productWord = total === 1 ? (t('misc.product') || 'Produkt') : (t('misc.products') || 'Produkte');
    supplementsCount.textContent = `${total} ${productWord}`;
  }
  
  if (supplementsWarning) {
    // Count low stock supplements (14 days or less)
    const lowStock = mySupplements ? mySupplements.filter(s => {
      const stock = s.stock || 0;
      const dosagePerDay = s.dosagePerDay || 1;
      return (stock / dosagePerDay) <= 14;
    }).length : 0;
    
    if (lowStock > 0) {
      supplementsWarning.textContent = `• ${lowStock} ${t('supps.soonEmpty') || 'bald leer'}`;
      supplementsWarning.style.display = 'inline';
    } else {
      supplementsWarning.style.display = 'none';
    }
  }
  
  // ========== UPDATE LOW STOCK SECTION ON HOME ==========
  const lowStockSection = document.getElementById('homeLowStockSection');
  if (lowStockSection) {
    // Finde das Supplement mit niedrigstem Bestand
    let lowestSupp = null;
    let lowestDays = Infinity;
    
    if (mySupplements && mySupplements.length > 0) {
      mySupplements.forEach(s => {
        const stock = s.stock || 0;
        const dosagePerDay = s.dosagePerDay || 1;
        const daysLeft = Math.floor(stock / dosagePerDay);
        if (daysLeft <= 14 && daysLeft < lowestDays) {
          lowestDays = daysLeft;
          lowestSupp = s;
        }
      });
    }
    
    if (lowestSupp) {
      lowStockSection.style.display = 'block';
      const titleEl = document.getElementById('lowStockTitle');
      const subEl = document.getElementById('lowStockSub');
      if (titleEl) titleEl.textContent = `Bald leer: ${lowestSupp.name}`;
      if (subEl) subEl.textContent = `Noch ca. ${lowestDays} ${lowestDays === 1 ? 'Tag' : 'Tage'}`;
    } else {
      lowStockSection.style.display = 'none';
    }
  }
  
  // ========== UPDATE MEDICATIONS STATS ==========
  if (!myMedications || myMedications.length === 0) {
    const saved = localStorage.getItem('suppTreeMedications');
    if (saved) {
      myMedications = JSON.parse(saved);
    }
  }
  
  const medsCard = document.querySelector('.medications-card .status-dot');
  const medsStatus = document.querySelector('.medications-card .feature-card-status span:last-child');
  
  if (medsCard && medsStatus && myMedications) {
    const activeMeds = myMedications.filter(m => m.roburConsider).length;
    if (activeMeds > 0) {
      medsCard.classList.add('active');
      const activeText = t('meds.active') || 'aktiv';
      const considersText = t('robur.considers') || 'Robur berücksichtigt';
      medsStatus.textContent = `${activeMeds} ${activeText} • ${considersText}`;
    } else {
      medsCard.classList.remove('active');
      medsStatus.textContent = t('meds.noneStored') || 'Keine hinterlegt';
    }
  }
  
  // ========== UPDATE QUIZ STATS ==========
  // Update daily quiz banner
  const quizBanner = document.getElementById('dailyQuizHint');
  const quizTitle = document.getElementById('quizHintText');
  const quizSubtitle = quizBanner?.querySelector('.quiz-banner-subtitle');
  const quizPoints = quizBanner?.querySelector('.quiz-banner-points');
  
  if (quizBanner && quizTitle) {
    if (quizState.completedToday) {
      // Get today's result
      const todayResult = quizState.history.find(h => {
        const histDate = new Date(h.date).toDateString();
        return histDate === new Date().toDateString();
      });
      
      quizBanner.classList.add('completed');
      if (todayResult) {
        quizTitle.textContent = `Quiz erledigt! ${todayResult.correct}/${todayResult.total} ✓`;
        if (quizSubtitle) quizSubtitle.textContent = `+${todayResult.points} Punkte verdient`;
        if (quizPoints) quizPoints.textContent = '✓';
      } else {
        quizTitle.textContent = 'Quiz erledigt! ✓';
        if (quizSubtitle) quizSubtitle.textContent = t('quiz.tomorrowAgain') || 'Morgen wieder verfügbar';
        if (quizPoints) quizPoints.textContent = '✓';
      }
    } else {
      quizBanner.classList.remove('completed');
      quizTitle.textContent = t('quiz.daily');
      if (quizSubtitle) quizSubtitle.textContent = t('quiz.collectDaily') || 'Sammle täglich Punkte!';
      
      // Calculate potential points
      const potentialPoints = 25 + (quizState.streak >= 7 ? 10 : quizState.streak >= 3 ? 5 : 0);
      if (quizPoints) quizPoints.textContent = `+${potentialPoints}`;
    }
  }
}

// Update Mein screen quiz stats
function updateMeinQuizStats() {
  loadQuizData();
  
  const percentage = quizState.totalQuestions > 0 
    ? Math.round((quizState.totalCorrect / quizState.totalQuestions) * 100) 
    : 0;
  
  // Update stats
  const quizCount = document.getElementById('meinQuizCount');
  const quizPercent = document.getElementById('meinQuizPercent');
  const quizStreak = document.getElementById('meinQuizStreak');
  
  if (quizCount) quizCount.textContent = quizState.totalQuizzes;
  if (quizPercent) quizPercent.textContent = percentage + '%';
  if (quizStreak) quizStreak.textContent = quizState.streak;
  
  // Update quiz card state
  const quizCard = document.querySelector('.mein-quiz-card');
  const quizTitle = document.getElementById('meinQuizTitle');
  const quizSubtitle = document.getElementById('meinQuizSubtitle');
  
  if (quizCard && quizTitle && quizSubtitle) {
    if (quizState.completedToday) {
      const todayResult = quizState.history.find(h => {
        const histDate = new Date(h.date).toDateString();
        return histDate === new Date().toDateString();
      });
      
      quizCard.classList.remove('available');
      quizCard.classList.add('completed');
      
      if (todayResult) {
        quizTitle.textContent = `Quiz erledigt! ${todayResult.correct}/${todayResult.total}`;
        quizSubtitle.textContent = `+${todayResult.points} Punkte ✓`;
      } else {
        quizTitle.textContent = t('quiz.completed') || 'Quiz erledigt!';
        quizSubtitle.textContent = t('quiz.tomorrowShort') || 'Morgen wieder';
      }
    } else {
      quizCard.classList.remove('completed');
      quizCard.classList.add('available');
      quizTitle.textContent = t('quiz.daily');
      
      const potentialPoints = 25 + (quizState.streak >= 7 ? 10 : quizState.streak >= 3 ? 5 : 0);
      quizSubtitle.textContent = `+${potentialPoints} Punkte sammeln`;
    }
  }
}

// Update quiz screen stats
function updateQuizScreenStats() {
  loadQuizData();
  
  const percentage = quizState.totalQuestions > 0 
    ? Math.round((quizState.totalCorrect / quizState.totalQuestions) * 100) 
    : 0;
  
  // Update stat values
  const statsValues = document.querySelectorAll('#quizScreen .quiz-stat-value');
  if (statsValues.length >= 3) {
    statsValues[0].textContent = quizState.totalQuizzes;
    statsValues[1].textContent = percentage + '%';
    statsValues[2].textContent = quizState.streak;
  }
  
  // Update points display
  const pointsDisplay = document.getElementById('quizTotalPoints');
  if (pointsDisplay) {
    pointsDisplay.textContent = quizState.points.toLocaleString('de-DE');
  }
  
  // Update daily quiz card
  const dailyCard = document.getElementById('dailyQuizCard');
  const dailyBtn = document.getElementById('dailyQuizBtn');
  
  if (dailyCard && dailyBtn) {
    if (quizState.completedToday) {
      dailyCard.classList.add('completed');
      dailyCard.querySelector('.daily-quiz-icon').textContent = '✅';
      dailyCard.querySelector('h3').textContent = 'Heute abgeschlossen!';
      dailyCard.querySelector('p').textContent = 'Komm morgen wieder für neue Punkte';
      dailyBtn.textContent = t('quiz.done') || '✓ Erledigt';
      dailyBtn.disabled = true;
    } else {
      dailyCard.classList.remove('completed');
      dailyCard.querySelector('.daily-quiz-icon').textContent = '🎯';
      dailyCard.querySelector('h3').textContent = t('quiz.getPoints');
      dailyCard.querySelector('p').textContent = t('quiz.questions');
      dailyBtn.textContent = t('quiz.playNow') || '🎮 Jetzt spielen →';
      dailyBtn.disabled = false;
    }
  }
  
  // Update history
  renderQuizHistory();
}

function renderQuizHistory() {
  const container = document.getElementById('quizHistoryList');
  if (!container) return;
  
  if (quizState.history.length === 0) {
    container.innerHTML = `<p class="no-history">${t('quiz.noHistory') || 'Noch keine Quizze gespielt'}</p>`;
    return;
  }
  
  const historyHTML = quizState.history.slice().reverse().slice(0, 10).map(quiz => {
    const date = new Date(quiz.date);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    
    let dateStr;
    if (date.toDateString() === today.toDateString()) {
      dateStr = 'Heute';
    } else if (date.toDateString() === yesterday.toDateString()) {
      dateStr = 'Gestern';
    } else {
      dateStr = date.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
    }
    
    const typeLabel = quiz.type === 'practice' ? '📚' : '⭐';
    const pointsDisplay = quiz.points > 0 ? `<span class="past-quiz-points">+${quiz.points}</span>` : '<span class="past-quiz-points practice">Übung</span>';
    
    // Only make clickable if quiz has questions saved
    const clickHandler = quiz.id && quiz.questions ? `onclick="openQuizReview('${quiz.id}')"` : '';
    const clickableClass = quiz.id && quiz.questions ? 'clickable' : '';
    
    return `
      <div class="past-quiz-item ${clickableClass}" ${clickHandler}>
        <div class="past-quiz-info">
          <span class="past-quiz-date">${typeLabel} ${dateStr}</span>
          <span class="past-quiz-score">${quiz.correct}/${quiz.total} richtig</span>
        </div>
        ${pointsDisplay}
        ${quiz.id && quiz.questions ? '<span class="past-quiz-arrow">›</span>' : ''}
      </div>
    `;
  }).join('');
  
  container.innerHTML = historyHTML;
}

// Practice mode category selection
function selectPracticeCategory(category) {
  quizState.practiceCategory = category;
  
  // Update UI
  const chips = document.querySelectorAll('#practiceCategoryChips .category-chip');
  chips.forEach(chip => {
    chip.classList.remove('active');
    if (chip.textContent.includes(category)) {
      chip.classList.add('active');
    }
  });
  
  // Count available questions
  let availableCount;
  if (category === 'Alle') {
    availableCount = quizQuestions.length;
  } else {
    availableCount = quizQuestions.filter(q => q.category === category).length;
  }
  
  // Update info text
  const infoEl = document.getElementById('practiceCategoryInfo');
  if (infoEl) {
    infoEl.textContent = `${availableCount} Fragen verfügbar`;
  }
  
  // Update question count if needed
  if (quizState.practiceQuestionCount > availableCount && quizState.practiceQuestionCount !== 0) {
    selectQuestionCount(Math.min(5, availableCount));
  }
}

// Question count selection for practice mode
// Start Daily Quiz (with points)
function startDailyQuiz() {
  loadQuizData();
  
  // Check if already completed today
  if (quizState.completedToday) {
    showToast('Du hast dein tägliches Quiz bereits gemacht!');
    return;
  }
  
  // Check if there's a paused quiz
  if (hasPausedQuiz()) {
    const resume = confirm('Du hast ein pausiertes Quiz!\n\n✅ OK = Fortsetzen\n❌ Abbrechen = Neu starten');
    
    if (resume) {
      resumePausedQuiz();
      return;
    } else {
      clearPausedQuiz();
    }
  }
  
  // Set mode to daily
  quizState.mode = 'daily';
  
  // Reset state for new quiz
  quizState.currentQuestion = 0;
  quizState.selectedAnswer = null;
  quizState.answered = false;
  quizState.correctCount = 0;
  quizState.answeredQuestions = []; // Reset answered questions
  quizState.startTime = Date.now();
  
  // Select 5 random questions from all categories
  const shuffled = [...quizQuestions].sort(() => Math.random() - 0.5);
  quizState.questions = shuffled.slice(0, 5);
  
  // Update header for daily mode
  document.querySelector('.quiz-header-info h2').textContent = 'Tägliches Quiz';
  document.getElementById('quizTimer').style.display = 'block';
  
  // Open quiz sheet
  document.getElementById('quizOverlay').classList.add('visible');
  document.getElementById('quizSheet').classList.add('visible');
  lockBody();
  
  // Render first question
  renderQuizQuestion();
}

// Start Practice Quiz (endless mode)
function startPracticeQuiz() {
  // Set mode to practice
  quizState.mode = 'practice';
  
  // Reset state for new quiz
  quizState.currentQuestion = 0;
  quizState.selectedAnswer = null;
  quizState.answered = false;
  quizState.correctCount = 0;
  quizState.answeredQuestions = []; // Reset answered questions
  quizState.startTime = Date.now();
  
  // Filter questions by category and shuffle
  let availableQuestions = [...quizQuestions];
  if (quizState.practiceCategory !== 'Alle') {
    availableQuestions = quizQuestions.filter(q => q.category === quizState.practiceCategory);
  }
  
  // Shuffle and store all available questions for endless mode
  quizState.practiceQuestions = availableQuestions.sort(() => Math.random() - 0.5);
  quizState.practiceIndex = 0;
  
  // Start with first question
  quizState.questions = [quizState.practiceQuestions[0]];
  
  // Update header for practice mode
  document.querySelector('.quiz-header-info h2').textContent = 'Übungsquiz';
  document.getElementById('quizTimer').style.display = 'none'; // Hide timer for practice
  
  // Open quiz sheet
  document.getElementById('quizOverlay').classList.add('visible');
  document.getElementById('quizSheet').classList.add('visible');
  lockBody();
  
  // Render first question
  renderQuizQuestion();
}

function showQuizCompletedToday() {
  document.getElementById('quizOverlay').classList.add('visible');
  document.getElementById('quizSheet').classList.add('visible');
  lockBody();
  
  const midnight = new Date();
  midnight.setHours(24, 0, 0, 0);
  const now = new Date();
  const hoursLeft = Math.ceil((midnight - now) / (1000 * 60 * 60));
  
  document.getElementById('quizBody').innerHTML = `
    <div class="quiz-completed-today">
      <div class="quiz-completed-icon">✅</div>
      <h3>Heute schon absolviert!</h3>
      <p>Du hast dein tägliches Quiz bereits gemacht. Komm morgen wieder für neue Fragen!</p>
      <div class="quiz-next-available">
        ⏰ Nächstes Quiz in ca. ${hoursLeft} Stunde${hoursLeft === 1 ? '' : 'n'}
      </div>
    </div>
  `;
  
  document.getElementById('quizNextBtn').textContent = 'Schließen';
  document.getElementById('quizNextBtn').disabled = false;
  document.getElementById('quizNextBtn').onclick = closeQuizSheet;
  document.getElementById('quizProgressFill').style.width = '100%';
  document.getElementById('quizProgressText').textContent = 'Abgeschlossen';
}

function renderQuizQuestion() {
  const q = quizState.questions[quizState.currentQuestion];
  const questionNum = quizState.currentQuestion + 1;
  
  // Update header based on mode
  if (quizState.mode === 'practice') {
    // Endless mode - no total
    document.getElementById('quizProgressText').textContent = `Frage ${questionNum}`;
    document.getElementById('quizProgressFill').style.width = '100%'; // Always full for practice
  } else {
    // Daily mode - fixed total
    const total = quizState.questions.length;
    document.getElementById('quizProgressText').textContent = `Frage ${questionNum} von ${total}`;
    document.getElementById('quizProgressFill').style.width = `${(questionNum / total) * 100}%`;
    
    // Calculate elapsed time (only for daily)
    const elapsed = Math.floor((Date.now() - quizState.startTime) / 1000);
    const minutes = Math.floor(elapsed / 60);
    const seconds = elapsed % 60;
    document.getElementById('quizTimer').textContent = `⏱️ ${minutes}:${seconds.toString().padStart(2, '0')}`;
  }
  
  // Build answers HTML
  const letters = ['A', 'B', 'C', 'D'];
  const answersHTML = q.answers.map((answer, index) => `
    <button class="quiz-answer-btn" onclick="selectQuizAnswer(${index})" data-index="${index}">
      <span class="quiz-answer-letter">${letters[index]}</span>
      <span class="quiz-answer-text">${answer}</span>
      <span class="quiz-answer-icon"></span>
    </button>
  `).join('');
  
  document.getElementById('quizBody').innerHTML = `
    <div class="quiz-question-card">
      <span class="quiz-category-badge">${q.category}</span>
      <h3 class="quiz-question-text">${q.question}</h3>
      <div class="quiz-answers">
        ${answersHTML}
      </div>
      <div class="quiz-explanation" id="quizExplanation">
        <h4>💡 Erklärung</h4>
        <p>${q.explanation}</p>
      </div>
    </div>
  `;
  
  // Reset state
  quizState.selectedAnswer = null;
  quizState.answered = false;
  
  // Update button based on mode
  const nextBtn = document.getElementById('quizNextBtn');
  nextBtn.disabled = true;
  
  if (quizState.mode === 'practice') {
    nextBtn.textContent = 'Nächste Frage →';
  } else {
    const total = quizState.questions.length;
    nextBtn.textContent = questionNum === total ? 'Ergebnis anzeigen' : 'Weiter →';
  }
  nextBtn.onclick = nextQuizQuestion;
}

function selectQuizAnswer(index) {
  if (quizState.answered) return;
  
  quizState.selectedAnswer = index;
  quizState.answered = true;
  
  const q = quizState.questions[quizState.currentQuestion];
  const isCorrect = index === q.correct;
  
  if (isCorrect) {
    quizState.correctCount++;
  }
  
  // Save answered question with user's answer
  quizState.answeredQuestions.push({
    question: q.question,
    category: q.category,
    answers: q.answers,
    correctIndex: q.correct,
    userAnswer: index,
    isCorrect: isCorrect,
    explanation: q.explanation
  });
  
  // Update button states
  const buttons = document.querySelectorAll('.quiz-answer-btn');
  buttons.forEach((btn, i) => {
    btn.classList.add('disabled');
    if (i === index) {
      btn.classList.add(isCorrect ? 'correct' : 'wrong');
      btn.querySelector('.quiz-answer-icon').textContent = isCorrect ? '✓' : '✗';
    }
    if (i === q.correct && !isCorrect) {
      btn.classList.add('correct');
      btn.querySelector('.quiz-answer-icon').textContent = '✓';
    }
  });
  
  // Show explanation
  document.getElementById('quizExplanation').classList.add('visible');
  
  // Enable next button
  document.getElementById('quizNextBtn').disabled = false;
  
  // Vibrate on wrong answer
  if (!isCorrect && navigator.vibrate) {
    navigator.vibrate([100, 50, 100]);
  }
}

function nextQuizQuestion() {
  // For practice mode - endless questions
  if (quizState.mode === 'practice') {
    quizState.practiceIndex++;
    
    // If we've used all questions, reshuffle
    if (quizState.practiceIndex >= quizState.practiceQuestions.length) {
      quizState.practiceQuestions = quizState.practiceQuestions.sort(() => Math.random() - 0.5);
      quizState.practiceIndex = 0;
    }
    
    // Add next question to current questions
    quizState.questions.push(quizState.practiceQuestions[quizState.practiceIndex]);
    quizState.currentQuestion++;
    renderQuizQuestion();
  } else {
    // Daily mode - fixed 5 questions
    if (quizState.currentQuestion < quizState.questions.length - 1) {
      quizState.currentQuestion++;
      renderQuizQuestion();
    } else {
      showQuizResults();
    }
  }
}

function showQuizResults() {
  const total = quizState.answeredQuestions.length;
  const correct = quizState.correctCount;
  const percentage = total > 0 ? Math.round((correct / total) * 100) : 0;
  
  // Determine result message
  let resultIcon, resultTitle;
  if (percentage === 100) {
    resultIcon = '🏆';
    resultTitle = 'Perfekt!';
  } else if (percentage >= 80) {
    resultIcon = '🌟';
    resultTitle = 'Hervorragend!';
  } else if (percentage >= 60) {
    resultIcon = '👍';
    resultTitle = 'Gut gemacht!';
  } else if (percentage >= 40) {
    resultIcon = '📚';
    resultTitle = 'Weiter üben!';
  } else {
    resultIcon = '💪';
    resultTitle = 'Nicht aufgeben!';
  }
  
  // Generate unique ID for this quiz
  const quizId = Date.now().toString();
  
  // Different handling for daily vs practice mode
  if (quizState.mode === 'daily') {
    // Calculate points (5 per correct answer)
    let earnedPoints = correct * 5;
    
    // Streak bonus
    const today = new Date().toDateString();
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    
    // Check streak
    if (quizState.lastQuizDate === yesterday.toDateString()) {
      quizState.streak++;
    } else if (quizState.lastQuizDate !== today) {
      quizState.streak = 1;
    }
    
    // Streak bonus points
    let streakBonus = 0;
    // No points for quiz anymore - just learning
    earnedPoints = 0;
    streakBonus = 0;
    
    // Update stats
    quizState.totalQuizzes++;
    quizState.totalCorrect += correct;
    quizState.totalQuestions += total;
    quizState.lastQuizDate = today;
    quizState.completedToday = true;
    
    // Add to history WITH questions
    quizState.history.push({
      id: quizId,
      date: new Date().toISOString(),
      correct: correct,
      total: total,
      points: 0,
      type: 'daily',
      questions: [...quizState.answeredQuestions] // Save all questions with answers
    });
    
    // Save
    saveQuizData();
    
    // Render daily results without points
    document.getElementById('quizBody').innerHTML = `
      <div class="quiz-results">
        <div class="quiz-results-icon">${resultIcon}</div>
        <h2>${resultTitle}</h2>
        <p class="quiz-results-subtitle">Du hast ${correct} von ${total} Fragen richtig beantwortet</p>
        
        <div class="quiz-results-stats">
          <div class="quiz-result-stat">
            <span class="quiz-result-stat-value">${percentage}%</span>
            <span class="quiz-result-stat-label">${t("quiz.correct")}</span>
          </div>
          <div class="quiz-result-stat">
            <span class="quiz-result-stat-value">${quizState.streak}</span>
            <span class="quiz-result-stat-label">${t("quiz.streak")}</span>
          </div>
        </div>
        
        <div class="quiz-results-actions">
          <button class="quiz-done-btn" onclick="closeQuizSheet(); updateQuizScreenStats();">
            Fertig
          </button>
          <button class="quiz-share-btn" onclick="closeQuizSheet(); openQuizReview('${quizId}');">
            📋 Antworten ansehen
          </button>
        </div>
      </div>
    `;
  } else {
    // Practice mode - no points, just learning
    // Add to history WITH questions
    quizState.history.push({
      id: quizId,
      date: new Date().toISOString(),
      correct: correct,
      total: total,
      points: 0,
      type: 'practice',
      category: quizState.practiceCategory,
      questions: [...quizState.answeredQuestions] // Save all questions with answers
    });
    
    // Save
    saveQuizData();
    
    // Render practice results without points
    document.getElementById('quizBody').innerHTML = `
      <div class="quiz-results">
        <div class="quiz-results-icon">${resultIcon}</div>
        <h2>${resultTitle}</h2>
        <p class="quiz-results-subtitle">Du hast ${correct} von ${total} Fragen richtig beantwortet</p>
        
        <div class="quiz-results-stats">
          <div class="quiz-result-stat">
            <span class="quiz-result-stat-value">${percentage}%</span>
            <span class="quiz-result-stat-label">${t("quiz.correct")}</span>
          </div>
          <div class="quiz-result-stat">
            <span class="quiz-result-stat-value">${total}</span>
            <span class="quiz-result-stat-label">${t("quiz.questions")}</span>
          </div>
        </div>
        
        <div class="quiz-practice-badge">
          <span>📚 Übungsmodus</span>
          <p>Keine Punkte - nur zum Lernen!</p>
        </div>
        
        <div class="quiz-results-actions">
          <button class="quiz-done-btn" onclick="closeQuizSheet(); updateQuizScreenStats();">
            Fertig
          </button>
          <button class="quiz-share-btn" onclick="closeQuizSheet(); openQuizReview('${quizId}');">
            📋 Antworten ansehen
          </button>
        </div>
      </div>
    `;
  }
  
  // Update header
  document.getElementById('quizProgressText').textContent = 'Ergebnis';
  document.getElementById('quizProgressFill').style.width = '100%';
  
  // Hide buttons
  document.getElementById('quizNextBtn').style.display = 'none';
  document.getElementById('quizPauseBtn').style.display = 'none';
}

function closeQuizSheet() {
  document.getElementById('quizOverlay').classList.remove('visible');
  document.getElementById('quizSheet').classList.remove('visible');
  unlockBody();
  
  // Reset buttons
  const nextBtn = document.getElementById('quizNextBtn');
  nextBtn.style.display = 'block';
  nextBtn.onclick = nextQuizQuestion;
  
  document.getElementById('quizPauseBtn').style.display = 'block';
  
  // Update quiz screen stats
  updateQuizScreenStats();
}

// Pause quiz and save progress for later
function pauseQuiz() {
  if (quizState.mode !== 'daily') {
    closeQuizSheet();
    return;
  }
  
  // Save current progress
  const pausedQuiz = {
    currentQuestion: quizState.currentQuestion,
    correctCount: quizState.correctCount,
    questions: quizState.questions,
    answeredQuestions: quizState.answeredQuestions,
    startTime: quizState.startTime,
    pausedAt: Date.now()
  };
  
  localStorage.setItem('suppTreePausedQuiz', JSON.stringify(pausedQuiz));
  
  closeQuizSheet();
  showToast('⏸️ Quiz pausiert - du kannst später weitermachen!');
}

// Check if there's a paused quiz
function hasPausedQuiz() {
  const paused = localStorage.getItem('suppTreePausedQuiz');
  if (!paused) return false;
  
  const data = JSON.parse(paused);
  // Check if paused today (same day)
  const pausedDate = new Date(data.pausedAt).toDateString();
  const today = new Date().toDateString();
  
  return pausedDate === today;
}

// Resume paused quiz
function resumePausedQuiz() {
  const paused = localStorage.getItem('suppTreePausedQuiz');
  if (!paused) return false;
  
  const data = JSON.parse(paused);
  
  // Restore quiz state
  quizState.mode = 'daily';
  quizState.currentQuestion = data.currentQuestion;
  quizState.correctCount = data.correctCount;
  quizState.questions = data.questions;
  quizState.answeredQuestions = data.answeredQuestions;
  quizState.startTime = data.startTime;
  quizState.selectedAnswer = null;
  quizState.answered = false;
  
  // Clear paused quiz
  localStorage.removeItem('suppTreePausedQuiz');
  
  // Update header for daily mode
  document.querySelector('.quiz-header-info h2').textContent = 'Tägliches Quiz';
  document.getElementById('quizTimer').style.display = 'block';
  
  // Open quiz sheet
  document.getElementById('quizOverlay').classList.add('visible');
  document.getElementById('quizSheet').classList.add('visible');
  lockBody();
  
  // Render current question
  renderQuizQuestion();
  
  showToast('▶️ Quiz wird fortgesetzt!');
  return true;
}

// Clear paused quiz
function clearPausedQuiz() {
  localStorage.removeItem('suppTreePausedQuiz');
}

// Confirm close quiz - now with pause option for daily quiz
function confirmCloseQuiz() {
  // For practice mode - just show results or close
  if (quizState.mode === 'practice') {
    if (quizState.answeredQuestions.length > 0) {
      showQuizResults();
    } else {
      closeQuizSheet();
    }
    return;
  }
  
  // For daily mode - offer pause option
  if (quizState.answeredQuestions.length > 0 && quizState.currentQuestion < quizState.questions.length) {
    // Quiz is in progress - ask what to do
    const choice = confirm('Quiz pausieren?\n\n✅ OK = Pausieren (später fortsetzen)\n❌ Abbrechen = Weitermachen');
    
    if (choice) {
      pauseQuiz();
    }
    // If cancelled, just continue (do nothing)
  } else if (quizState.answeredQuestions.length > 0) {
    // All questions answered - show results
    showQuizResults();
  } else {
    // No questions answered - just close
    closeQuizSheet();
  }
}

// Open quiz review
function openQuizReview(quizId) {
  loadQuizData();
  
  // Find the quiz in history
  const quiz = quizState.history.find(q => q.id === quizId);
  if (!quiz || !quiz.questions) {
    showToast('Quiz nicht gefunden');
    return;
  }
  
  // Store current review quiz for retry
  window.currentReviewQuiz = quiz;
  
  // Format date
  const date = new Date(quiz.date);
  const dateStr = date.toLocaleDateString('de-DE', { 
    day: '2-digit', 
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
  
  // Update header
  document.getElementById('reviewTitle').textContent = quiz.type === 'daily' ? 'Tägliches Quiz' : 'Übungsquiz';
  document.getElementById('reviewDate').textContent = dateStr;
  document.getElementById('reviewScore').textContent = `${quiz.correct}/${quiz.total}`;
  
  // Determine result icon
  const percentage = Math.round((quiz.correct / quiz.total) * 100);
  let resultIcon;
  if (percentage === 100) resultIcon = '🏆';
  else if (percentage >= 80) resultIcon = '🌟';
  else if (percentage >= 60) resultIcon = '👍';
  else if (percentage >= 40) resultIcon = '📚';
  else resultIcon = '💪';
  
  // Count wrong answers
  const wrongQuestions = quiz.questions.filter(q => !q.isCorrect);
  const wrongCount = wrongQuestions.length;
  
  // Build review content
  const questionsHTML = quiz.questions.map((q, index) => {
    const letters = ['A', 'B', 'C', 'D'];
    
    let answersHTML = '';
    if (!q.isCorrect) {
      // Show user's wrong answer
      answersHTML += `
        <div class="review-answer user-answer">
          <span class="review-answer-icon">✗</span>
          <span>${letters[q.userAnswer]}: ${q.answers[q.userAnswer]}</span>
        </div>
      `;
    }
    // Show correct answer
    answersHTML += `
      <div class="review-answer correct-answer">
        <span class="review-answer-icon">✓</span>
        <span>${letters[q.correctIndex]}: ${q.answers[q.correctIndex]}</span>
      </div>
    `;
    
    return `
      <div class="review-question-card ${q.isCorrect ? '' : 'wrong'}">
        <div class="review-question-header">
          <span class="review-question-num">Frage ${index + 1}</span>
          <span class="review-question-status ${q.isCorrect ? 'correct' : 'wrong'}">
            ${q.isCorrect ? (t("quiz.correctAnswer")) : (t("quiz.wrongAnswer"))}
          </span>
        </div>
        <p class="review-question-text">${q.question}</p>
        ${answersHTML}
        <div class="review-explanation">
          <strong>💡 Erklärung:</strong> ${q.explanation}
        </div>
      </div>
    `;
  }).join('');
  
  // Build retry buttons HTML
  let retryButtonsHTML = '';
  if (wrongCount > 0) {
    retryButtonsHTML = `
      <div class="review-retry-section">
        <h4>🔄 Nochmal versuchen</h4>
        <div class="review-retry-buttons">
          <button class="retry-btn retry-wrong" onclick="retryQuizQuestions('wrong')">
            <span class="retry-btn-icon">❌</span>
            <span class="retry-btn-text">Falsche Fragen (${wrongCount})</span>
          </button>
          <button class="retry-btn retry-all" onclick="retryQuizQuestions('all')">
            <span class="retry-btn-icon">🔁</span>
            <span class="retry-btn-text">Alle Fragen (${quiz.total})</span>
          </button>
        </div>
      </div>
    `;
  } else {
    retryButtonsHTML = `
      <div class="review-retry-section perfect">
        <div class="perfect-score-badge">🎉 Alles richtig!</div>
        <button class="retry-btn retry-all" onclick="retryQuizQuestions('all')">
          <span class="retry-btn-icon">🔁</span>
          <span class="retry-btn-text" data-i18n="quiz.retryAnyway">Trotzdem nochmal üben</span>
        </button>
      </div>
    `;
  }
  
  document.getElementById('quizReviewBody').innerHTML = `
    <div class="review-summary">
      <div class="review-summary-icon">${resultIcon}</div>
      <h3>${quiz.correct} von ${quiz.total} richtig</h3>
      <div class="review-summary-stats">
        <div class="review-summary-stat">
          <span class="review-summary-stat-value">${percentage}%</span>
          <span class="review-summary-stat-label">${t("quiz.correct")}</span>
        </div>
        ${quiz.points > 0 ? `
          <div class="review-summary-stat">
            <span class="review-summary-stat-value">+${quiz.points}</span>
            <span class="review-summary-stat-label">${t("misc.points")}</span>
          </div>
        ` : ''}
      </div>
    </div>
    ${retryButtonsHTML}
    <div class="review-questions-list">
      ${questionsHTML}
    </div>
  `;
  
  // Show review overlay
  document.getElementById('quizReviewOverlay').classList.add('visible');
  document.getElementById('quizReviewSheet').classList.add('visible');
}

// Retry quiz questions from review
function retryQuizQuestions(type) {
  const quiz = window.currentReviewQuiz;
  if (!quiz || !quiz.questions) {
    showToast('Quiz nicht gefunden');
    return;
  }
  
  // Close review
  closeQuizReview();
  
  // Set mode to practice (no points for retry)
  quizState.mode = 'practice';
  
  // Reset state
  quizState.currentQuestion = 0;
  quizState.selectedAnswer = null;
  quizState.answered = false;
  quizState.correctCount = 0;
  quizState.answeredQuestions = [];
  quizState.startTime = Date.now();
  
  // Get questions based on type
  let questionsToRetry;
  if (type === 'wrong') {
    questionsToRetry = quiz.questions.filter(q => !q.isCorrect);
  } else {
    questionsToRetry = quiz.questions;
  }
  
  // Convert back to quiz format and shuffle
  quizState.questions = questionsToRetry.map(q => ({
    question: q.question,
    category: q.category,
    answers: q.answers,
    correct: q.correctIndex,
    explanation: q.explanation
  })).sort(() => Math.random() - 0.5);
  
  // Store for endless mode
  quizState.practiceQuestions = [...quizState.questions];
  quizState.practiceIndex = 0;
  
  // Update header
  document.querySelector('.quiz-header-info h2').textContent = type === 'wrong' ? 'Falsche Fragen üben' : 'Quiz wiederholen';
  document.getElementById('quizTimer').style.display = 'none';
  
  // Open quiz sheet
  document.getElementById('quizOverlay').classList.add('visible');
  document.getElementById('quizSheet').classList.add('visible');
  lockBody();
  
  // Render first question
  renderQuizQuestion();
}

// Close quiz review
function closeQuizReview() {
  document.getElementById('quizReviewOverlay').classList.remove('visible');
  document.getElementById('quizReviewSheet').classList.remove('visible');
  unlockBody();
}

// Moved to initApp()

// ===============================
// SCREEN NAVIGATION
// ===============================
let _restoreScroll = null;
function switchScreen(screenId) {
  // Zurück-Banner verstecken wenn man den Marktplatz normal (nicht via Artikel) betritt
  if (screenId === 'productsScreen' && !_kwReturnArticleId) {
    var banner = document.getElementById('productsBackBanner');
    if (banner) banner.style.display = 'none';
  }
  // Banner auch verstecken wenn man den Marktplatz verlässt
  if (screenId !== 'productsScreen' && !_kwReturnArticleId) {
    var banner = document.getElementById('productsBackBanner');
    if (banner) banner.style.display = 'none';
  }

  // Redirect old profileScreen to new menuScreen
  if (screenId === 'profileScreen') {
    screenId = 'menuScreen';
  }

  // Persönliche Screens: Login-Hinweis einblenden wenn nicht eingeloggt
  if (!currentUser && (screenId === 'meinScreen' || screenId === 'menuScreen')) {
    showMeinLoginHint(screenId);
  } else {
    hideMeinLoginHint();
  }

  // Einkauf-Screen: Abo-Sektion vergrauen wenn nicht eingeloggt
  if (screenId === 'einkaufScreen') {
    setTimeout(function() { toggleEinkaufAboLock(); }, 50);
  }
  
  // Get current active screen before switching
  const currentScreen = document.querySelector('.screen.active');
  const currentScreenId = currentScreen ? currentScreen.id : null;
  
  // Reset products screen when leaving it
  if (currentScreenId === 'productsScreen' && screenId !== 'productsScreen' && screenId !== 'productDetailScreen') {
    try { resetProductsScreen(); } catch(e) { }
  }
  
  // Safety: unlock body and close any open overlays
  try { unlockBody(); } catch(e) { }
  try { closeAllOverlays(); } catch(e) { }
  
  const targetScreen = document.getElementById(screenId);
  
  // Sicherheitscheck: Wenn der Screen nicht existiert, gehe zu homeScreen
  if (!targetScreen) {
    console.warn('Screen nicht gefunden:', screenId, '- gehe zu homeScreen');
    if (screenId !== 'homeScreen') {
      switchScreen('homeScreen');
      return;
    }
    return;
  }
  
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  targetScreen.classList.add('active');
  // Scroll-Bar-Reset bei Screen-Wechsel
  _mpLastScroll = 0;
  _kwLastScroll = 0;
  if (screenId !== 'productsScreen') {
    const _tsa = document.querySelector('.top-search-area');
    if (_tsa) _tsa.classList.remove('scroll-visible');
  }
  if (screenId !== 'knowledgeScreen') {
    const _kwTsa = document.getElementById('kwTopSearchArea');
    if (_kwTsa) _kwTsa.classList.remove('scroll-visible');
  }
  // Cleanup knowledge search page when leaving
  if (screenId === 'knowledgeScreen') {
    var _sp = document.querySelector('.kw-search-page');
    if (_sp) _sp.remove();
    var _km = document.getElementById('knowledgeMain');
    if (_km) _km.style.display = 'block';
  }

  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  // Entdecken-Screens gehören zu "Mein"
  const navScreenMap = {entdeckenCatScreen:'meinScreen',entdeckenMapScreen:'meinScreen',anbieterProfilScreen:'meinScreen'};
  const navTarget = navScreenMap[screenId] || screenId;
  document.querySelector(`.nav-item[data-screen="${navTarget}"]`)?.classList.add('active');
  
  if (typeof screenHistory !== 'undefined' && screenId !== screenHistory[screenHistory.length - 1]) {
    screenHistory.push(screenId);
  }
  
  // Immer nach oben scrollen bei Screen-Wechsel
  window.scrollTo(0, 0);
  try { updateRoburOnScreenChange(); } catch(e) { }
  try { updateFloatingButtonsVisibility(screenId); } catch(e) { }
  
  // Init planer when opening
  if (screenId === 'calendarScreen') {
    initCalendar();
  }
  
  // Render medications on Mein screen
  if (screenId === 'meinScreen') {
    try { updateMeinGreeting(); } catch(e) { }
    try { renderMeinSuppsOverview(); } catch(e) { }
    try { renderMeinMedsOverview(); } catch(e) { }
    try { renderMeinActiveKur(); } catch(e) { }
    try { renderMeinActivePlaner(); } catch(e) { }
    try { renderMeinActiveTermine(); } catch(e) { }
    try { updateMeinMatrix(); } catch(e) { }
    try { renderMeinBloodPreview(); } catch(e) { }
    try { renderDashEntdecken(); } catch(e) { }
    try { renderEkMeineAnfragen(); } catch(e) { }
    try { renderMeineBerater(); } catch(e) { }
  }

  // Entdecken Screens
  if (screenId === 'entdeckenCatScreen') {
    try { renderEntdeckenCat(); } catch(e) { }
  }
  if (screenId === 'entdeckenMapScreen') {
    try { renderEntdeckenMap(); } catch(e) { }
  }
  if (screenId === 'anbieterProfilScreen') {
    try { renderAnbieterProfil(); } catch(e) { }
  }
  
  // Render Einkauf screen
  if (screenId === 'einkaufScreen') {
    renderEinkaufScreen();
  }
  
  // Update supplements screen
  if (screenId === 'mysupplementsScreen') {
    renderAboManagement();
  }
  
  
  // Update menu screen (formerly profile)
  if (screenId === 'menuScreen') {
    updateMainProfileSummary();
    loadProfileAvatar();
    loadProfileDisplayName();
  }
  
  // Update Home Screen
  if (screenId === 'homeScreen') {
    try { updateDailyStock(); } catch(e) { }
    try { updateTodayShiftCard(); } catch(e) { }
    try { renderDayPlanner(); } catch(e) { }
    try { renderWeekPreview(); } catch(e) { }
    try { updateWeekPreviewBadge(); } catch(e) { }
    try { updateHomeGreeting(); } catch(e) { }
    try { renderHomeNewEmpfehlungen(); } catch(e) { }
    try { renderHomePendingDeliveries(); } catch(e) { }
    try { renderLowStockNotices(); } catch(e) { }
  }

  // Scroll-Position NACH allen Renders wiederherstellen
  if(_restoreScroll!==null){
    setTimeout(()=>{window.scrollTo(0,_restoreScroll);},50);
  }
}

// Reset products screen to default state (no filters, no category, no search)
function resetProductsScreen() {
  // Guided Shop beenden wenn aktiv
  if (guidedShopActive) {
    guidedShopActive = false;
    guidedShopSupplements = [];
    guidedShopIndex = 0;
    guidedShopResults = [];
  }

  // Reset search query
  activeSearchQuery = '';

  // Reset category to 'all'
  activeCategory = 'all';

  // Clear all filters
  activeFilters.clear();
  
  // Reset sort
  currentSort = 'relevance';
  const sortLabel = document.getElementById('currentSortLabel');
  if (sortLabel) sortLabel.textContent = 'Sortieren';
  
  // Reset sort option UI
  document.querySelectorAll('.sort-option').forEach(opt => {
    opt.classList.remove('active');
    if (opt.dataset.sort === 'relevance') opt.classList.add('active');
  });
  
  // Reset search
  const searchInput = document.getElementById('productSearchInput');
  if (searchInput) searchInput.value = '';
  
  // Reset UI elements
  document.querySelectorAll('#productsScreen .category-chip').forEach(c => c.classList.remove('active'));
  const allChip = document.querySelector('#productsScreen .category-chip[data-category="all"]');
  if (allChip) allChip.classList.add('active');
  
  // Hide active category badge
  const badge = document.getElementById('activeCategoryBadge');
  if (badge) badge.style.display = 'none';
  
  // Update filter UI
  updateFilterUI();
  updateFilterBadge();
  updateActiveFiltersBar();
  
  // Re-render products grid
  renderProductsGridNew();
}

// Show/hide floating buttons based on screen
function updateFloatingButtonsVisibility(screenId) {
  const floatingButtons = document.querySelector('.floating-buttons');
  if (!floatingButtons) return;
  
  // Only show on Home, Products, and Detail screens
  const showOnScreens = ['homeScreen', 'productsScreen', 'productDetailScreen', 'kurDetailScreen'];
  
  if (showOnScreens.includes(screenId)) {
    floatingButtons.style.display = 'flex';
  } else {
    floatingButtons.style.display = 'none';
  }
}

function goBack() {
  screenHistory.pop();
  const prevScreen = screenHistory[screenHistory.length - 1] || 'homeScreen';
  switchScreen(prevScreen);
}

// Android Back Button Handler
function handleAndroidBack() {
  // 1. Prüfe ob ein Confirm Dialog offen ist
  const confirmDialog = document.querySelector('.confirm-dialog.visible');
  if (confirmDialog) {
    try { closeConfirmDialog(); } catch(e) {}
    return true;
  }
  
  // 2. Prüfe ob Supplement Info Sheet offen ist
  const suppInfoSheet = document.querySelector('.supp-info-sheet.active');
  if (suppInfoSheet) {
    try { closeSupplementInfoSheet(); } catch(e) {}
    return true;
  }
  
  // 3. Prüfe ob Koffein-Settings offen ist
  const caffeineSheet = document.querySelector('#caffeineSettingsSheet.visible');
  if (caffeineSheet) {
    try { closeCaffeineSettings(); } catch(e) {}
    return true;
  }
  
  // 4. Prüfe ob ein Sheet/Overlay offen ist
  const visibleOverlay = document.querySelector('.overlay.visible, .overlay.active, .supp-info-overlay.active');
  const visibleSheet = document.querySelector('.bottom-sheet.visible, .bottom-sheet.active');
  
  if (visibleOverlay || visibleSheet) {
    try { closeAllOverlays(); } catch(e) {}
    try { unlockBody(); } catch(e) {}
    return true;
  }
  
  // 5. Prüfe ob Robur Chat offen ist
  const roburChat = document.querySelector('.robur-chat-overlay.visible, .robur-chat-overlay.active');
  if (roburChat) {
    try { closeRoburChat(); } catch(e) {}
    return true;
  }
  
  // 6. Prüfe ob Produkt-Detail offen ist
  const productDetail = document.querySelector('.product-detail-view.visible');
  if (productDetail) {
    try { closeProductDetail(); } catch(e) {}
    return true;
  }
  
  // 7. Prüfe ob Menu offen ist
  const menuScreen = document.getElementById('menuScreen');
  if (menuScreen && menuScreen.classList.contains('active')) {
    switchScreen('homeScreen');
    return true;
  }
  
  // 8. Zurück zur vorherigen Seite aus der History
  if (typeof screenHistory !== 'undefined' && screenHistory.length > 1) {
    goBack();
    return true;
  }
  
  // 9. Wenn auf Home Screen → App minimieren (return false)
  const currentScreen = document.querySelector('.screen.active');
  const currentScreenId = currentScreen ? currentScreen.id : 'homeScreen';
  
  if (currentScreenId === 'homeScreen') {
    return false;
  }
  
  // 10. Fallback: Zurück zu Home
  switchScreen('homeScreen');
  return true;
}

// Swipe Vorwärts - navigiert zum nächsten Haupt-Tab
function handleSwipeForward() {
  const mainScreens = ['homeScreen', 'productsScreen', 'meinScreen', 'einkaufScreen'];
  const currentScreen = document.querySelector('.screen.active');
  const currentScreenId = currentScreen ? currentScreen.id : 'homeScreen';
  const currentIndex = mainScreens.indexOf(currentScreenId);
  
  // Prüfe ob ein Overlay offen ist
  const hasOpenOverlay = document.querySelector('.overlay.visible, .overlay.active, .bottom-sheet.visible, .bottom-sheet.active');
  if (hasOpenOverlay) return;
  
  // Wenn auf einem Haupt-Tab und nicht auf dem letzten, gehe zum nächsten
  if (currentIndex !== -1 && currentIndex < mainScreens.length - 1) {
    switchScreen(mainScreens[currentIndex + 1]);
  }
}

