          slogan: bp.slogan || brand?.slogan || '',
          description: bp.description || brand?.description || '',
          highlights: bp.highlights || brand?.highlights || [],
          story: bp.story || brand?.story || '',
          certifications: bp.certifications || brand?.certifications || [],
          contact: bp.contact?.email || brand?.contact || '',
          mission: bp.mission || '',
          values: bp.values || [],
          specialties: bp.specialties || [],
