function saveAddresses(addresses) {
  localStorage.setItem('suppTreeAddresses', JSON.stringify(addresses));
  if (supabase && currentUser) {
    DataStore.set('addresses', 'suppTreeAddresses', addresses, {
      replaceAll: true,
      transform: (a) => ({
        user_id: currentUser.id,
        label: a.label,
        first_name: a.firstName,
        last_name: a.lastName,
        street: a.street,
        extra: a.extra,
        zip: a.zip,
        city: a.city,
        country: a.country || 'DE',
        is_default: a.isDefault || false
      })
    }).catch(e => console.error('Addresses sync error:', e));
  }
}

function loadAddresses() {
  const saved = localStorage.getItem('suppTreeAddresses');
  const addresses = saved ? JSON.parse(saved) : [
    { id: 1, label: 'Zuhause', firstName: 'Max', lastName: 'Mustermann', street: 'Musterstraße 123', extra: '', zip: '12345', city: 'Musterstadt', country: 'DE', isDefault: true },
    { id: 2, label: 'Arbeit', firstName: 'Max', lastName: 'Mustermann', street: 'Firmenweg 456', extra: '3. Etage', zip: '12345', city: 'Musterstadt', country: 'DE', isDefault: false }
  ];
  renderAddressesList(addresses);
}

function renderAddressesList(addresses) {
  const container = document.getElementById('addressesList');
  if (!container) return;
  
  const icons = { 'Zuhause': '🏠', 'Arbeit': '🏢', 'Familie': '👨‍👩‍👧', 'Freunde': '👥' };
  
  container.innerHTML = addresses.map((addr, idx) => `
    <div class="address-item ${addr.isDefault ? 'default' : ''}">
      <div class="address-icon">${icons[addr.label] || '📍'}</div>
      <div class="address-info">
        <span class="address-name">${escapeHtml(addr.label) || 'Adresse ' + (idx + 1)}</span>
        <span class="address-detail">${escapeHtml(addr.firstName)} ${escapeHtml(addr.lastName)}</span>
        <span class="address-detail">${escapeHtml(addr.street)}${addr.extra ? ', ' + escapeHtml(addr.extra) : ''}</span>
        <span class="address-detail">${escapeHtml(addr.zip)} ${escapeHtml(addr.city)}</span>
      </div>
      <div class="address-actions">
        ${addr.isDefault ? '<span class="address-badge">Standard</span>' : `<button class="address-default-btn" onclick="setDefaultAddress(${idx})">Als Standard</button>`}
        <button class="address-edit-btn" onclick="editAddress(${idx})">✏️</button>
      </div>
    </div>
  `).join('');
}

function openAddAddress() {
  document.getElementById('addressForm').style.display = 'block';
  document.getElementById('addressFormTitle').textContent = 'Neue Adresse';
  clearAddressForm();
  document.getElementById('addressForm').dataset.editIndex = '';
}

function editAddress(index) {
  const saved = localStorage.getItem('suppTreeAddresses');
  const addresses = saved ? JSON.parse(saved) : [];
  const addr = addresses[index];
  if (!addr) return;
  
  document.getElementById('addressForm').style.display = 'block';
  document.getElementById('addressFormTitle').textContent = 'Adresse bearbeiten';
  document.getElementById('addressLabel').value = addr.label || '';
  document.getElementById('addressFirstName').value = addr.firstName || '';
  document.getElementById('addressLastName').value = addr.lastName || '';
  document.getElementById('addressStreet').value = addr.street || '';
  document.getElementById('addressExtra').value = addr.extra || '';
  document.getElementById('addressZip').value = addr.zip || '';
  document.getElementById('addressCity').value = addr.city || '';
  document.getElementById('addressCountry').value = addr.country || 'DE';
  document.getElementById('addressDefault').checked = addr.isDefault || false;
  document.getElementById('addressForm').dataset.editIndex = index;
}

function clearAddressForm() {
  document.getElementById('addressLabel').value = '';
  document.getElementById('addressFirstName').value = '';
  document.getElementById('addressLastName').value = '';
  document.getElementById('addressStreet').value = '';
  document.getElementById('addressExtra').value = '';
  document.getElementById('addressZip').value = '';
  document.getElementById('addressCity').value = '';
  document.getElementById('addressCountry').value = 'DE';
  document.getElementById('addressDefault').checked = false;
}

function cancelAddressForm() {
  document.getElementById('addressForm').style.display = 'none';
  clearAddressForm();
}

function saveAddress() {
  const firstNameInput = document.getElementById('addressFirstName');
  const lastNameInput = document.getElementById('addressLastName');
  const streetInput = document.getElementById('addressStreet');
  const zipInput = document.getElementById('addressZip');
  const cityInput = document.getElementById('addressCity');
  
  const firstName = firstNameInput.value.trim();
  const lastName = lastNameInput.value.trim();
  const street = streetInput.value.trim();
  const zip = zipInput.value.trim();
  const city = cityInput.value.trim();
  
  let hasError = false;
  
  if (!firstName) {
    firstNameInput.classList.add('input-error');
    hasError = true;
  }
  if (!lastName) {
    lastNameInput.classList.add('input-error');
    hasError = true;
  }
  if (!street) {
    streetInput.classList.add('input-error');
    hasError = true;
  }
  if (!zip) {
    zipInput.classList.add('input-error');
    hasError = true;
  }
  if (!city) {
    cityInput.classList.add('input-error');
    hasError = true;
  }
  
  if (hasError) {
    showToast('⚠️ Bitte alle Pflichtfelder ausfüllen');
    return;
  }
  
  if (!/^\d{5}$/.test(zip)) {
    zipInput.classList.add('input-error');
    showToast('⚠️ Bitte gültige PLZ eingeben (5 Ziffern)');
    return;
  }
  
  const saved = localStorage.getItem('suppTreeAddresses');
  let addresses = saved ? JSON.parse(saved) : [];
  
  const newAddr = {
    id: Date.now(),
    label: document.getElementById('addressLabel').value.trim() || 'Adresse',
    firstName,
    lastName,
    street,
    extra: document.getElementById('addressExtra').value.trim(),
    zip,
    city,
    country: document.getElementById('addressCountry').value,
    isDefault: document.getElementById('addressDefault').checked
  };
  
  if (newAddr.isDefault) {
    addresses = addresses.map(a => ({ ...a, isDefault: false }));
  }
  
  const editIndex = document.getElementById('addressForm').dataset.editIndex;
  if (editIndex !== '') {
    addresses[parseInt(editIndex)] = { ...addresses[parseInt(editIndex)], ...newAddr };
  } else {
    addresses.push(newAddr);
  }
  
  if (addresses.length === 1) {
    addresses[0].isDefault = true;
  }
  
  saveAddresses(addresses);
  renderAddressesList(addresses);
  cancelAddressForm();
  showToast('✅ Adresse gespeichert');
}

function setDefaultAddress(index) {
  const saved = localStorage.getItem('suppTreeAddresses');
  let addresses = saved ? JSON.parse(saved) : [];
  addresses = addresses.map((a, i) => ({ ...a, isDefault: i === index }));
  saveAddresses(addresses);
  renderAddressesList(addresses);
  showToast('✅ Standardadresse geändert');
}

