// Berechne echte Uhrzeit aus relativem Timing basierend auf Schicht
function calculateKurTime(timing, shift, shiftInfo) {
  const config = shiftInfo || shiftConfig[shift] || shiftConfig['off'];
  
  // Extrahiere Basis-Zeiten aus der Schicht
  const wakeTime = config.start || '07:00';
  const sleepTime = config.sleep || '22:00';
  
  // Parse Zeiten
  const [wakeH, wakeM] = wakeTime.split(':').map(Number);
  const [sleepH, sleepM] = sleepTime.split(':').map(Number);
  
  // Berechne Mahlzeiten-Zeiten basierend auf Wach-/Schlafzeit
  const wakeMinutes = wakeH * 60 + wakeM;
  const sleepMinutes = sleepH * 60 + sleepM + (sleepH < wakeH ? 24 * 60 : 0);
  const awakeDuration = sleepMinutes - wakeMinutes;
  
  // Mahlzeiten verteilt über die Wachzeit
  const meal1Minutes = wakeMinutes + 60; // 1h nach Aufwachen
  const meal2Minutes = wakeMinutes + Math.floor(awakeDuration * 0.5); // Mitte der Wachzeit
  const meal3Minutes = sleepMinutes - 180; // 3h vor Schlafen
  
  let resultMinutes;
  
  if (timing.startsWith('wake')) {
    const offset = parseInt(timing.replace('wake', '').replace('+', '')) || 0;
    resultMinutes = wakeMinutes + offset;
  } else if (timing.startsWith('sleep')) {
    const offset = parseInt(timing.replace('sleep', '')) || 0;
    resultMinutes = sleepMinutes + offset; // offset ist negativ
  } else if (timing === 'meal1') {
    resultMinutes = meal1Minutes;
  } else if (timing === 'meal2') {
    resultMinutes = meal2Minutes;
  } else if (timing === 'meal3') {
    resultMinutes = meal3Minutes;
  } else {
    // Fallback: Direkte Zeit
    return timing;
  }
  
  // Normalisiere auf 24h
  if (resultMinutes >= 24 * 60) resultMinutes -= 24 * 60;
  if (resultMinutes < 0) resultMinutes += 24 * 60;
  
  const hours = Math.floor(resultMinutes / 60);
  const mins = resultMinutes % 60;
  
  return `${String(hours).padStart(2, '0')}:${String(mins).padStart(2, '0')}`;
}

