function addPurchasedKur(templateId, orderId) {
  const purchased = JSON.parse(localStorage.getItem('suppTreePurchasedKuren') || '[]');
  
  purchased.push({
    id: 'purchase-' + Date.now(),
    templateId: templateId,
    purchaseDate: new Date().toISOString(),
    orderId: orderId,
    activated: false
  });
  
  localStorage.setItem('suppTreePurchasedKuren', JSON.stringify(purchased));
  renderPurchasedKuren();
}

