function renderEinkaufAutoReplen() {
  const content = document.getElementById('einkaufAutoContent');
  if (!content) return;
  
  if (typeof autoReplenItems === 'undefined' || autoReplenItems.size === 0) {
    content.innerHTML = `
      <div class="einkauf-empty">
        <div class="einkauf-empty-icon">🤖</div>
        <div class="einkauf-empty-text">Robur bestellt automatisch nach, bevor deine Supplements leer sind</div>
        <button class="einkauf-empty-btn" onclick="switchScreen('productsScreen')">Supplement hinzufügen</button>
      </div>
    `;
    return;
  }
  
  let html = `
    <div class="auto-replen-hint">
      <span>💡</span> Robur bestellt automatisch nach wenn der Füllstand unter den Schwellenwert fällt
    </div>
  `;
  
  autoReplenItems.forEach((item, productId) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    const levelClass = item.remaining > 50 ? 'high' : item.remaining > 25 ? 'medium' : 'low';
    const willOrder = item.enabled && item.remaining <= item.threshold;
    
    html += `
      <div class="einkauf-auto-item">
        <div class="einkauf-item-icon" onclick="openProductDetail('${productId}')">${product.icon}</div>
        <div class="einkauf-auto-item-info" onclick="openProductDetail('${productId}')">
          <div class="einkauf-auto-item-name">${product.name}</div>
          <div class="einkauf-auto-item-stock">
            <div class="einkauf-auto-bar">
              <div class="einkauf-auto-bar-fill ${levelClass}" style="width: ${item.remaining}%"></div>
            </div>
            <span class="einkauf-auto-percent ${levelClass}">${item.remaining}%</span>
          </div>
          ${willOrder ? '<div class="einkauf-auto-alert">⚡ Wird bald nachbestellt</div>' : ''}
        </div>
        <div class="einkauf-auto-toggle-wrap">
          <div class="einkauf-auto-toggle ${item.enabled ? 'active' : ''}" 
               onclick="event.stopPropagation(); toggleAutoReplenEinkauf('${productId}')"></div>
          <span class="einkauf-auto-label">${item.enabled ? 'An' : 'Aus'}</span>
        </div>
      </div>
    `;
  });
  
  html += `
    <button class="einkauf-auto-add-btn" onclick="switchScreen('productsScreen')">
      ➕ Weiteres Supplement hinzufügen
    </button>
  `;
  
  content.innerHTML = html;
}

function toggleAutoReplenEinkauf(productId) {
  toggleAutoReplen(productId);
  renderEinkaufAutoReplen();
  renderEinkaufAbos();
}

