// ===============================
// ABO-VERWALTUNG IN MEINE SUPPLEMENTS
// ===============================

function renderAboManagement() {
  const container = document.getElementById('aboManagementContainer');
  const countEl = document.getElementById('aboManagementCount');
  if (!container) return;
  
  // Count all active/paused abos (including waiting ones)
  let activeCount = 0;
  subscriptions.forEach((sub, productId) => {
    if (sub.status === 'active' || sub.status === 'paused') {
      activeCount++;
    }
  });
  
  if (countEl) countEl.textContent = activeCount;
  
  if (activeCount === 0) {
    container.innerHTML = `
      <div class="abo-management-empty">
        <div class="abo-management-empty-icon">📦</div>
        <p>Du hast noch keine aktiven Abos.<br>Spare 8% mit regelmäßigen Lieferungen!</p>
        <button class="abo-management-empty-btn" onclick="switchScreen('productsScreen')" data-i18n="btn.discover">Produkte entdecken</button>
      </div>
    `;
    return;
  }
  
  let html = '';
  
  subscriptions.forEach((sub, productId) => {
    // Skip pending abos (they're in cart)
    if (sub.status === 'pending') return;
    
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    // Get supplement data for this abo
    const supp = mySupplements.find(s => s.id === productId);
    
    // Check if waiting for delivery
    const isWaiting = supp?.status === 'waiting';
    
    const dosagePerDay = supp?.dosagePerDay || sub.dosePerDay || 1;
    const stock = supp?.stock || 60;
    const packSize = supp?.packSize || 60;
    const daysLeft = Math.floor(stock / dosagePerDay);
    const stockPercent = Math.min((stock / packSize) * 100, 100);
    const levelClass = stockPercent > 50 ? 'high' : stockPercent > 25 ? 'medium' : 'low';
    
    // Dynamic interval text
    let intervalText = 'Monatlich';
    if (sub.intervalMonths === 2) intervalText = 'Alle 2 Monate';
    else if (sub.intervalMonths === 3) intervalText = 'Alle 3 Monate';
    else if (sub.interval === 'dynamic' && sub.daysSupply) {
      const weeks = Math.round(sub.daysSupply / 7);
      intervalText = `Alle ~${weeks} Wochen`;
    }
    
    const isPaused = sub.status === 'paused';
    const letter = product.name.charAt(0).toUpperCase();
    const qtyText = sub.quantity > 1 ? `${sub.quantity}× ` : '';
    
    html += `
      <div class="abo-manage-item ${isPaused ? 'paused' : ''} ${isWaiting ? 'waiting' : ''}">
        <div class="abo-manage-top">
          <div class="abo-manage-icon">
            <div class="abo-icon-css ${product.category}">${letter}</div>
          </div>
          <div class="abo-manage-info">
            <div class="abo-manage-name">${qtyText}${product.name}</div>
            <div class="abo-manage-details">
              <span>🔄 ${intervalText}</span>
              <span>📅 ${sub.nextDelivery}</span>
            </div>
          </div>
          <div class="abo-manage-price">
            <div class="abo-manage-price-value">€${sub.price.toFixed(2)}</div>
            <div class="abo-manage-price-info">-8% Rabatt</div>
          </div>
        </div>
        
        ${isWaiting ? `
          <div class="abo-waiting-banner">
            <span>📦 Warte auf erste Lieferung</span>
            <button class="abo-arrived-btn" onclick="event.stopPropagation(); markAboArrived('${productId}')">
              ✅ Ist angekommen
            </button>
          </div>
        ` : `
          <div class="abo-manage-progress">
            <div class="abo-manage-bar">
              <div class="abo-manage-bar-fill ${levelClass}" style="width: ${stockPercent}%"></div>
            </div>
            <span class="abo-manage-days ${levelClass}">~${daysLeft} Tage</span>
          </div>
        `}
        
        <!-- Einstellungen direkt in der Card -->
        <div class="abo-quick-settings">
          <div class="abo-setting-row">
            <span class="abo-setting-label">💊 Dosierung</span>
            <div class="abo-dosage-control">
              <button class="dosage-btn" onclick="event.stopPropagation(); changeAboDosage('${productId}', -1)">−</button>
              <span class="dosage-value">${dosagePerDay}× täglich</span>
              <button class="dosage-btn" onclick="event.stopPropagation(); changeAboDosage('${productId}', 1)">+</button>
            </div>
          </div>
          <div class="abo-setting-row">
            <span class="abo-setting-label">⏰ Einnahme</span>
            <span class="abo-setting-value">${supp?.roburScheduled ? '🤖 Robur optimiert' : '✏️ Manuell'}</span>
          </div>
        </div>
        
        <div class="abo-manage-actions">
          <button class="abo-manage-btn pause ${isPaused ? 'resume' : ''}" onclick="event.stopPropagation(); ${isPaused ? `resumeAbo('${productId}')` : `pauseAbo('${productId}')`}">
            ${isPaused ? '▶️ Fortsetzen' : '⏸️ Pausieren'}
          </button>
          <button class="abo-manage-btn edit" onclick="event.stopPropagation(); goToAboDetail('${productId}')">
            ⚙️ Verwalten
          </button>
        </div>
      </div>
    `;
  });
  
  container.innerHTML = html;
  
  // Aktualisiere Menü-Count
  if (typeof updateMenuAboCount === 'function') updateMenuAboCount();
}

// Navigiert zur Abo-Detail-Seite
function goToAboDetail(productId) {
  // Speichere welches Abo geöffnet werden soll
  localStorage.setItem('suppTreeOpenAboDetail', productId);
  
  // Navigiere zum Einkauf-Screen
  switchScreen('einkaufScreen');
  
  // Warte kurz und öffne dann das Detail-Sheet
  setTimeout(() => {
    openAboDetailSheet(productId);
  }, 300);
}

// Abo-Dosierung ändern
function changeAboDosage(productId, delta) {
  // Finde das Supplement
  const suppIndex = mySupplements.findIndex(s => s.id === productId);
  if (suppIndex === -1) return;
  
  const supp = mySupplements[suppIndex];
  const currentDosage = supp.dosagePerDay || 1;
  const newDosage = Math.max(1, Math.min(6, currentDosage + delta));
  
  if (newDosage === currentDosage) return;
  
  // Update supplement
  mySupplements[suppIndex].dosagePerDay = newDosage;
  saveMySupplements();
  
  // Update subscription
  const sub = subscriptions.get(productId);
  if (sub) {
    sub.dosePerDay = newDosage;
    saveSubscriptions();
  }
  
  // Refresh calendar
  try { updateAllScheduledIntakes(); } catch(e) {}
  
  // Re-render
  renderAboManagement();
  showToast(`Dosierung auf ${newDosage}× täglich geändert`);
}

// Abo als angekommen markieren
function markAboArrived(productId) {
  const suppIndex = mySupplements.findIndex(s => s.id === productId);
  const product = products.find(p => p.id === productId);
  const sub = subscriptions.get(productId);
  
  // Ensure supplement exists in mySupplements
  if (suppIndex === -1 && product && sub) {
    // Create supplement entry first
    mySupplements.push({
      id: productId,
      name: product.name,
      icon: product.icon,
      brand: product.brand,
      dosagePerDay: sub.dosePerDay || 1,
      stock: 60,
      packSize: 60,
      source: 'shop',
      time: 'auto',
      autoAbo: true,
      roburScheduled: true,
      hasAbo: true,
      status: 'waiting'
    });
    saveMySupplements();
  }
  
  // Now open the same arrival dialog as normal products
  openSuppArrivedDialog(productId);
}

// Abo Detail Sheet öffnen
function openAboDetailSheet(productId) {
  const sub = subscriptions.get(productId);
  const product = products.find(p => p.id === productId);
  if (!sub || !product) return;
  
  const isPaused = sub.status === 'paused';
  
  // Berechne verbleibende Tage
  const remaining = sub.remaining || 50;
  const daysLeft = sub.dosePerDay ? Math.floor((remaining / 100) * sub.packSize / sub.dosePerDay) : '?';
  
  // Intervall Text
  let intervalText = 'Monatlich';
  if (sub.interval === 'dynamic' && sub.daysSupply) {
    const weeks = Math.round(sub.daysSupply / 7);
    intervalText = `Alle ~${weeks} Wochen`;
  }
  
  const letter = product.name.charAt(0).toUpperCase();
  
  const html = `
    <div class="sheet-header">
      <h2>Abo verwalten</h2>
      <button class="sheet-close" onclick="closeAboDetailSheet()">✕</button>
    </div>
    <div class="sheet-content">
      <div class="abo-detail-product">
        <div class="abo-detail-icon">
          <div class="abo-detail-icon-css ${product.category}">${letter}</div>
        </div>
        <div class="abo-detail-info">
          <h3>${product.name}</h3>
          <span class="abo-detail-brand">${product.brand}</span>
        </div>
        ${isPaused ? '<span class="abo-detail-paused-badge">⏸️ Pausiert</span>' : ''}
      </div>
      
      <div class="abo-detail-stats">
        <div class="abo-detail-stat">
          <span class="stat-label">Preis</span>
          <span class="stat-value">€${sub.price.toFixed(2)}</span>
          <span class="stat-discount">-8% Rabatt</span>
        </div>
        <div class="abo-detail-stat">
          <span class="stat-label">Nächste Lieferung</span>
          <span class="stat-value">${sub.nextDelivery}</span>
        </div>
        <div class="abo-detail-stat">
          <span class="stat-label">Intervall</span>
          <span class="stat-value">${intervalText}</span>
        </div>
        <div class="abo-detail-stat">
          <span class="stat-label">Vorrat</span>
          <span class="stat-value">~${daysLeft} Tage</span>
        </div>
      </div>
      
      <div class="abo-detail-actions">
        <button class="abo-detail-btn delivery" onclick="markDeliveryReceived('${productId}')">
          📦 Lieferung erhalten
        </button>
        <button class="abo-detail-btn edit" onclick="closeAboDetailSheet(); editAbo('${productId}')">
          ✏️ Abo anpassen
        </button>
        ${isPaused ? `
          <button class="abo-detail-btn resume" onclick="closeAboDetailSheet(); resumeAbo('${productId}')">
            ▶️ Abo fortsetzen
          </button>
        ` : `
          <button class="abo-detail-btn pause" onclick="closeAboDetailSheet(); pauseAbo('${productId}')">
            ⏸️ Abo pausieren
          </button>
        `}
        <button class="abo-detail-btn skip" onclick="closeAboDetailSheet(); skipNextDelivery('${productId}')">
          ⏭️ Nächste Lieferung überspringen
        </button>
      </div>
      
      <div class="abo-detail-danger">
        <button class="abo-detail-btn cancel" onclick="confirmCancelAbo('${productId}')">
          ❌ Abo kündigen
        </button>
        <p class="abo-detail-cancel-hint">Die Kündigung wird sofort wirksam. Offene Lieferungen werden noch zugestellt.</p>
      </div>
    </div>
  `;
  
  // Erstelle oder aktualisiere das Sheet
  let sheet = document.getElementById('aboDetailSheet');
  let overlay = document.getElementById('aboDetailOverlay');
  
  if (!sheet) {
    overlay = document.createElement('div');
    overlay.id = 'aboDetailOverlay';
    overlay.className = 'overlay';
    overlay.onclick = closeAboDetailSheet;
    document.body.appendChild(overlay);
    
    sheet = document.createElement('div');
    sheet.id = 'aboDetailSheet';
    sheet.className = 'bottom-sheet abo-detail-sheet';
    document.body.appendChild(sheet);
  }
  
  sheet.innerHTML = html;
  
  // Öffne Sheet
  document.body.classList.add('no-scroll');
  setTimeout(() => {
    overlay.classList.add('active');
    sheet.classList.add('active');
  }, 10);
}

function closeAboDetailSheet() {
  const sheet = document.getElementById('aboDetailSheet');
  const overlay = document.getElementById('aboDetailOverlay');
  if (sheet) sheet.classList.remove('active');
  if (overlay) overlay.classList.remove('active');
  document.body.classList.remove('no-scroll');
}

