// Aktualisiere Abo-Anzahl im Menü
function updateMenuAboCount() {
  const countEl = document.getElementById('menuAboCount');
  if (countEl) {
    const activeCount = Array.from(subscriptions.values()).filter(s => s.status === 'active').length;
    countEl.textContent = activeCount > 0 ? `${activeCount} aktiv` : 'Keine';
  }
}

function confirmCancelAbo(productId) {
  const product = products.find(p => p.id === productId);
  if (!product) return;
  
  showConfirmDialog(
    '❌ Abo kündigen',
    `Möchtest du das Abo für "${product.name}" wirklich kündigen?\n\nDu verlierst den 8% Abo-Rabatt. Eine erneute Aktivierung ist jederzeit möglich.`,
    'Ja, kündigen',
    () => {
      closeAboDetailSheet();
      cancelAbo(productId);
    },
    true
  );
}

function markDeliveryReceived(productId) {
  const sub = subscriptions.get(productId);
  const product = products.find(p => p.id === productId);
  if (!sub || !product) return;
  
  // Vorrat auf 100% setzen
  sub.remaining = 100;
  
  // Berechne nächste Lieferung basierend auf Intervall
  const intervalMonths = sub.intervalMonths || sub.interval || 1;
  const nextDate = new Date();
  nextDate.setMonth(nextDate.getMonth() + intervalMonths);
  
  const formatDate = (date) => {
    return `${date.getDate().toString().padStart(2, '0')}.${(date.getMonth() + 1).toString().padStart(2, '0')}.${date.getFullYear()}`;
  };
  sub.nextDelivery = formatDate(nextDate);
  
  // Auch in autoReplenItems aktualisieren
  if (autoReplenItems.has(productId)) {
    autoReplenItems.get(productId).remaining = 100;
    saveAutoReplenItems();
  }

  saveSubscriptions();
  
  // Prüfe ob bereits in Meine Supps
  if (!mySupplements) mySupplements = [];
  const isInSupps = mySupplements.some(s => s.id === productId);
  
  if (isInSupps) {
    // Nur Vorrat auffüllen
    closeAboDetailSheet();
    showToast('📦 Lieferung erhalten! Vorrat aufgefüllt.');
    renderAboManagement();
    renderEinkaufAbos();
  } else {
    // Fragen ob zu Meine Supps hinzufügen
    closeAboDetailSheet();
    
    const modal = document.createElement('div');
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:100001;display:flex;align-items:center;justify-content:center;padding:20px;';
    modal.innerHTML = `
      <div style="background:white;border-radius:14px;max-width:340px;width:100%;padding:32px 24px;text-align:center;box-shadow:0 20px 60px rgba(0,0,0,0.3);">
        <div style="font-size:48px;margin-bottom:12px;">📦</div>
        <h3 style="font-size:20px;font-weight:700;margin:0 0 8px;">Lieferung erhalten!</h3>
        <p style="margin-bottom: 16px;">Dein Vorrat wurde auf 100% aufgefüllt.</p>
        <p style="font-size: 14px; color: var(--text-muted); margin-bottom: 20px;">
          Möchtest du <strong>${product.name}</strong> zu deinem Einnahme-Planer hinzufügen?
        </p>
        <div style="display: flex; flex-direction: column; gap: 10px;">
          <button id="addToSuppsBtn" style="padding: 14px; background: linear-gradient(135deg, var(--green-accent), #34d399); color: white; border: none; border-radius: 7px; font-weight: 600; cursor: pointer;">
            ✅ Ja, zum Planer hinzufügen
          </button>
          <button id="laterBtn" style="padding: 14px; background: var(--cream); color: var(--text-dark); border: none; border-radius: 7px; font-weight: 500; cursor: pointer;">
            Später
          </button>
        </div>
      </div>
    `;
    document.body.appendChild(modal);
    
    // Event Listeners hinzufügen
    document.getElementById('addToSuppsBtn').onclick = function() {
      addAboToSupps(productId);
      modal.remove();
    };
    document.getElementById('laterBtn').onclick = function() {
      modal.remove();
    };
  }
}

function addAboToSupps(productId) {
  const sub = subscriptions.get(productId);
  const product = products.find(p => p.id === productId);
  if (!product) {
    showToast('Produkt nicht gefunden');
    return;
  }
  
  // Always load fresh from localStorage
  const saved = localStorage.getItem('suppTreeMySupplements');
  if (saved) {
    mySupplements = JSON.parse(saved);
  } else if (!mySupplements) {
    mySupplements = [];
  }
  
  // Prüfen ob bereits vorhanden
  const exists = mySupplements.some(s => s.id === productId);
  if (exists) {
    showToast('Bereits im Planer vorhanden');
    return;
  }
  
  // Use consistent structure with demo supplements
  const packSize = sub?.packSize || parseInt(product.packSize) || 60;
  const dosagePerDay = sub?.dosePerDay || 1;
  
  mySupplements.push({
    id: product.id,
    name: product.name,
    icon: product.icon,
    brand: product.brand,
    dosagePerDay: dosagePerDay,
    stock: packSize,
    packSize: packSize,
    source: 'shop',
    time: 'auto',
    autoAbo: true,
    roburScheduled: true,
    hasAbo: true,
    notes: 'Abo-Produkt'
  });
  
  saveMySupplements();
  
  // Update calendar with new supplement
  try { updateAllScheduledIntakes(); } catch(e) {}
  
  showToast(`✅ ${product.name} zum Planer hinzugefügt!`);
  
  // Aktualisiere alle relevanten Views
  try { renderMySupplements(); } catch(e) {}
  try { renderMeinSuppsOverview(); } catch(e) {}
}

function skipNextDelivery(productId) {
  const sub = subscriptions.get(productId);
  if (!sub) return;
  
  // Berechne neues Lieferdatum (2 Wochen später)
  const [day, month, year] = sub.nextDelivery.split('.').map(Number);
  const nextDate = new Date(year, month - 1, day);
  nextDate.setDate(nextDate.getDate() + 14);
  
  const formatDate = (date) => {
    return `${date.getDate().toString().padStart(2, '0')}.${(date.getMonth() + 1).toString().padStart(2, '0')}.${date.getFullYear()}`;
  };
  
  sub.nextDelivery = formatDate(nextDate);
  saveSubscriptions();
  
  showToast('⏭️ Nächste Lieferung übersprungen');
  renderAboManagement();
}

function editAbo(productId) {
  const sub = subscriptions.get(productId);
  const product = products.find(p => p.id === productId);
  if (!sub || !product) return;
  
  // Set currentAboProduct and open sheet in edit mode
  currentAboProduct = product;
  aboDosePerDay = sub.dosePerDay || 1;
  aboPackSize = sub.packSize || 60;
  
  // Fill product preview
  const preview = document.getElementById('aboProductPreview');
  preview.innerHTML = `
    <div class="abo-product-icon">${product.icon}</div>
    <div class="abo-product-info">
      <div class="abo-product-name">${product.name}</div>
      <div class="abo-product-brand">${product.brand}</div>
    </div>
  `;
  
  // Set values
  document.getElementById('aboDoseValue').textContent = aboDosePerDay;
  document.getElementById('aboPackSize').value = aboPackSize;
  
  // Auto-toggle based on autoReplenItems
  const autoItem = autoReplenItems.get(productId);
  aboAutoEnabled = autoItem ? autoItem.enabled : true;
  document.getElementById('aboAutoToggle').classList.toggle('active', aboAutoEnabled);
  
  // Update calculations
  updateAboCalculation();
  updateAboSummary();
  
  // Change button to "Speichern"
  const confirmBtn = document.querySelector('.abo-confirm-btn');
  confirmBtn.textContent = 'Änderungen speichern';
  confirmBtn.onclick = () => saveAboChanges(productId);
  
  // Show sheet
  document.getElementById('aboOverlay').classList.add('visible');
  document.getElementById('aboSheet').classList.add('visible');
  lockBody();
  
  // Listen for pack size changes
  document.getElementById('aboPackSize').onchange = function() {
    aboPackSize = parseInt(this.value);
    updateAboCalculation();
    updateAboSummary();
  };
}

function saveAboChanges(productId) {
  const sub = subscriptions.get(productId);
  if (!sub) return;

  const price = parseFloat(products.find(p => p.id === productId)?.price || 0);
  const discount = 0.08;
  const finalPrice = price * (1 - discount);

  const daysSupply = Math.floor(aboPackSize / aboDosePerDay);

  const orderAfterDays = Math.floor(daysSupply * 0.8);
  const nextDelivery = new Date();
  nextDelivery.setDate(nextDelivery.getDate() + orderAfterDays);
  const formatDate = (date) => {
    return `${date.getDate().toString().padStart(2, '0')}.${(date.getMonth() + 1).toString().padStart(2, '0')}.${date.getFullYear()}`;
  };

  sub.daysSupply = daysSupply;
  sub.dosePerDay = aboDosePerDay;
  sub.packSize = aboPackSize;
  sub.nextDelivery = formatDate(nextDelivery);
  sub.price = finalPrice;
  saveSubscriptions();

  if (autoReplenItems.has(productId)) {
    const autoItem = autoReplenItems.get(productId);
    autoItem.enabled = aboAutoEnabled;
    autoItem.dosePerDay = aboDosePerDay;
    autoItem.packSize = aboPackSize;
    saveAutoReplenItems();
  }

  closeAboSheet();

  const confirmBtn = document.querySelector('.abo-confirm-btn');
  if (confirmBtn) {
    confirmBtn.textContent = 'Abo starten';
    confirmBtn.onclick = confirmAboToCart;
  }

  showToast('✅ Abo aktualisiert');
  renderAboManagement();
  try { renderEinkaufAbos(); } catch(e) {}
}

function pauseAbo(productId) {
  const sub = subscriptions.get(productId);
  if (!sub) return;

  sub.status = 'paused';
  saveSubscriptions();

  if (autoReplenItems.has(productId)) {
    autoReplenItems.get(productId).enabled = false;
    saveAutoReplenItems();
  }

  showToast('⏸️ Abo pausiert');
  renderAboManagement();
  try { renderEinkaufAbos(); } catch(e) {}
}

function resumeAbo(productId) {
  const sub = subscriptions.get(productId);
  if (!sub) return;

  sub.status = 'active';
  saveSubscriptions();

  if (autoReplenItems.has(productId)) {
    autoReplenItems.get(productId).enabled = true;
    saveAutoReplenItems();
  }

  showToast('▶️ Abo fortgesetzt');
  renderAboManagement();
  try { renderEinkaufAbos(); } catch(e) {}
}

function cancelAbo(productId) {
  const product = products.find(p => p.id === productId);
  if (!product) return;

  subscriptions.delete(productId);
  saveSubscriptions();

  autoReplenItems.delete(productId);
  saveAutoReplenItems();

  showToast('❌ Abo gekündigt');
  renderAboManagement();
  try { renderEinkaufAbos(); } catch(e) {}
  updateNavEinkaufBadge();
}

function toggleAutoReplenSupps(productId) {
  toggleAutoReplen(productId);
  renderAutoReplenSupps();
  
  // Update stats
  updateAutoReplenStats();
}

function updateAutoReplenStats() {
  // Update the "Auto-Abo" count in stats
  let activeCount = 0;
  if (typeof autoReplenItems !== 'undefined') {
    autoReplenItems.forEach(item => {
      if (item.enabled) activeCount++;
    });
  }
  
  const statCard = document.querySelector('.my-supps-stats .supp-stat-card:nth-child(3) .supp-stat-value');
  if (statCard) {
    statCard.textContent = activeCount;
  }
}

// ===============================
// ABO SHEET
// ===============================

let currentAboProduct = null;
let aboAutoEnabled = true;
let aboDosePerDay = 1;
let aboPackSize = 60;
let aboSelectedInterval = 2; // Default: alle 2 Monate
let aboQuantity = 1; // Packungen pro Lieferung

function openAboSheet() {
  if (!currentProduct) {
    showToast('Kein Produkt ausgewählt');
    return;
  }
  
  currentAboProduct = currentProduct;
  aboDosePerDay = 1;
  aboPackSize = parseInt(currentProduct.packSize) || 60;
  aboQuantity = 1;
  
  // Reset UI
  document.getElementById('aboDoseValue').textContent = '1';
  
  // Reset quantity selection
  document.querySelectorAll('.abo-qty-option').forEach(btn => {
    btn.classList.remove('selected');
    if (btn.dataset.qty === '1') btn.classList.add('selected');
  });
  
  // Update product preview
  const preview = document.getElementById('aboProductPreview');
  if (preview) {
    preview.innerHTML = `
      <div class="abo-product-icon">${currentProduct.icon}</div>
      <div class="abo-product-info">
        <div class="abo-product-name">${currentProduct.name}</div>
        <div class="abo-product-brand">${currentProduct.brand} · ${aboPackSize} Stück</div>
      </div>
    `;
  }
  
  // Update quantity prices
  updateAboQuantityPrices();
  
  // Calculate and show Robur recommendation
  updateAboRoburRecommendation();
  
  // Update price display
  updateAboSummary();
  
  // Show sheet
  document.getElementById('aboOverlay').classList.add('visible');
  document.getElementById('aboSheet').classList.add('visible');
  lockBody();
}

function updateAboQuantityPrices() {
  if (!currentAboProduct) return;
  
  const price = parseFloat(currentAboProduct.price);
  const aboPrice = price * 0.92; // 8% Rabatt
  
  [1, 2, 3].forEach(qty => {
    const priceEl = document.getElementById(`aboQtyPrice${qty}`);
    if (priceEl) {
      priceEl.textContent = `€${(aboPrice * qty).toFixed(2)}`;
    }
  });
}

function selectAboQuantity(qty) {
  aboQuantity = qty;
  
  // Update UI
  document.querySelectorAll('.abo-qty-option').forEach(btn => {
    btn.classList.toggle('selected', parseInt(btn.dataset.qty) === qty);
  });
  
  // Update summary and reichweite
  updateAboSummary();
  
  // Update Reichweite info based on new quantity
  const daysPerPack = Math.floor(aboPackSize / aboDosePerDay);
  const totalDaysSupply = daysPerPack * qty;
  const reichweiteInfo = document.getElementById('aboReichweiteInfo');
  if (reichweiteInfo) {
    reichweiteInfo.textContent = `${totalDaysSupply} Tage`;
  }
}

function updateAboIntervalRecommendation() {
  // Berechne Reichweite mit aktueller Menge
  const daysPerPack = Math.floor(aboPackSize / aboDosePerDay);
  const totalDaysSupply = daysPerPack * aboQuantity;
  
  // Bestimme empfohlenes Intervall basierend auf Gesamtreichweite
  let recommendedInterval;
  if (totalDaysSupply <= 35) {
    recommendedInterval = 1;
  } else if (totalDaysSupply <= 70) {
    recommendedInterval = 2;
  } else {
    recommendedInterval = 3;
  }
  
  // Update Robur text
  const roburText = document.getElementById('aboRoburText');
  if (roburText) {
    const intervalText = recommendedInterval === 1 ? 'monatliche Lieferung' : 
                         recommendedInterval === 2 ? 'Lieferung alle 2 Monate' : 'Lieferung alle 3 Monate';
    roburText.innerHTML = `Mit <strong>${aboQuantity} Packung${aboQuantity > 1 ? 'en' : ''}</strong> hast du ~${totalDaysSupply} Tage Vorrat. Ich empfehle eine <strong>${intervalText}</strong>.`;
  }
  
  // Update Reichweite info
  const reichweiteInfo = document.getElementById('aboReichweiteInfo');
  if (reichweiteInfo) {
    reichweiteInfo.textContent = `${totalDaysSupply} Tage`;
  }
  
  // Update interval options - mark recommended
  [1, 2, 3].forEach(interval => {
    const option = document.getElementById(`aboInterval${interval}`);
    if (option) {
      option.classList.toggle('recommended', interval === recommendedInterval);
      const badge = option.querySelector('.interval-badge');
      if (interval === recommendedInterval) {
        if (!badge) {
          const badgeEl = document.createElement('span');
          badgeEl.className = 'interval-badge';
          badgeEl.textContent = 'empfohlen';
          option.appendChild(badgeEl);
        }
      } else if (badge) {
        badge.remove();
      }
    }
  });
  
  // Auto-select recommended interval
  selectAboInterval(recommendedInterval);
  const radioBtn = document.querySelector(`input[name="aboInterval"][value="${recommendedInterval}"]`);
  if (radioBtn) radioBtn.checked = true;
}

function addAboToCart(product) {
  // This is called when user clicks "Abo starten" button on product detail
  // It now opens the configuration sheet instead of adding directly
  currentProduct = product;
  openAboSheet();
}

function closeAboSheet() {
  document.getElementById('aboOverlay').classList.remove('visible');
  document.getElementById('aboSheet').classList.remove('visible');
  unlockBody();
}

function adjustAboDose(change) {
  aboDosePerDay = Math.max(1, Math.min(10, aboDosePerDay + change));
  document.getElementById('aboDoseValue').textContent = aboDosePerDay;
  updateAboRoburRecommendation();
  updateAboSummary();
}

function updateAboRoburRecommendation() {
  // Berechne Reichweite pro Packung
  const daysPerPack = Math.floor(aboPackSize / aboDosePerDay);
  
  // Bestimme empfohlene Menge und Intervall
  let recommendedQty = 1;
  let recommendedInterval = 2;
  let roburMessage = '';
  
  if (daysPerPack < 28) {
    // Eine Packung reicht weniger als 1 Monat
    if (daysPerPack * 2 >= 28 && daysPerPack * 2 <= 45) {
      recommendedQty = 2;
      recommendedInterval = 1;
      roburMessage = `Bei ${aboDosePerDay}× täglich reicht eine Packung (${aboPackSize} Stk) nur ~${daysPerPack} Tage. Ich empfehle **2 Packungen pro Lieferung** für ~${daysPerPack * 2} Tage Reichweite – dann passt eine monatliche Lieferung perfekt! 📦📦`;
    } else if (daysPerPack * 3 >= 28) {
      recommendedQty = 3;
      recommendedInterval = 1;
      roburMessage = `Bei ${aboDosePerDay}× täglich reicht eine Packung nur ~${daysPerPack} Tage. Mit **3 Packungen** hast du ~${daysPerPack * 3} Tage Vorrat – ideal für monatliche Lieferung!`;
    } else {
      recommendedQty = 2;
      recommendedInterval = 1;
      roburMessage = `Bei ${aboDosePerDay}× täglich brauchst du mehr als eine Packung pro Monat. Ich empfehle **2 Packungen pro Lieferung** für bessere Versorgung.`;
    }
  } else if (daysPerPack <= 45) {
    // ~1 Monat Reichweite
    recommendedQty = 1;
    recommendedInterval = 1;
    roburMessage = `Bei ${aboDosePerDay}× täglich reicht deine Packung (${aboPackSize} Stk) für ~${daysPerPack} Tage. Eine **monatliche Lieferung** passt perfekt!`;
  } else if (daysPerPack <= 75) {
    // ~2 Monate Reichweite
    recommendedQty = 1;
    recommendedInterval = 2;
    roburMessage = `Bei ${aboDosePerDay}× täglich reicht deine Packung (${aboPackSize} Stk) für ~${daysPerPack} Tage. Ich empfehle eine **Lieferung alle 2 Monate**.`;
  } else {
    // >2.5 Monate Reichweite
    recommendedQty = 1;
    recommendedInterval = 3;
    roburMessage = `Bei ${aboDosePerDay}× täglich reicht deine Packung für ~${daysPerPack} Tage. Eine **Lieferung alle 3 Monate** ist ideal!`;
  }
  
  // Update Robur text (remove markdown ** for display)
  const roburText = document.getElementById('aboRoburText');
  if (roburText) {
    roburText.innerHTML = roburMessage.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  }
  
  // Set aboQuantity to recommended
  aboQuantity = recommendedQty;
  
  // Update quantity UI directly
  document.querySelectorAll('.abo-qty-option').forEach(btn => {
    btn.classList.toggle('selected', parseInt(btn.dataset.qty) === recommendedQty);
  });
  
  // Update Reichweite info
  const totalDaysSupply = daysPerPack * recommendedQty;
  const reichweiteInfo = document.getElementById('aboReichweiteInfo');
  if (reichweiteInfo) {
    reichweiteInfo.textContent = `${totalDaysSupply} Tage`;
  }
  
  // Show/hide quantity badge
  [1, 2, 3].forEach(qty => {
    const badge = document.getElementById(`aboQtyBadge${qty}`);
    if (badge) {
      badge.style.display = qty === recommendedQty ? 'block' : 'none';
    }
    const option = document.querySelector(`.abo-qty-option[data-qty="${qty}"]`);
    if (option) {
      option.classList.toggle('recommended', qty === recommendedQty);
    }
  });
  
  // Update interval options - mark recommended
  [1, 2, 3].forEach(interval => {
    const option = document.getElementById(`aboInterval${interval}`);
    if (option) {
      option.classList.toggle('recommended', interval === recommendedInterval);
      const badge = option.querySelector('.interval-badge');
      if (interval === recommendedInterval) {
        if (!badge) {
          const badgeEl = document.createElement('span');
          badgeEl.className = 'interval-badge';
          badgeEl.textContent = 'empfohlen';
          option.appendChild(badgeEl);
        }
      } else if (badge) {
        badge.remove();
      }
    }
  });
  
  // Set interval
  aboSelectedInterval = recommendedInterval;
  const intervalSpan = document.getElementById('aboSelectedInterval');
  if (intervalSpan) intervalSpan.textContent = recommendedInterval;
  
  // Check radio button
  const radioBtn = document.querySelector(`input[name="aboInterval"][value="${recommendedInterval}"]`);
  if (radioBtn) radioBtn.checked = true;
}

function selectAboInterval(months) {
  aboSelectedInterval = months;
  
  // Update selected interval display
  const intervalSpan = document.getElementById('aboSelectedInterval');
  if (intervalSpan) intervalSpan.textContent = months;
  
  // Update summary
  updateAboSummary();
}

function updateAboSummary() {
  if (!currentAboProduct) return;
  
  const price = parseFloat(currentAboProduct.price);
  const totalPrice = price * aboQuantity;
  const discount = 0.08; // 8%
  const discountAmount = totalPrice * discount;
  const finalPrice = totalPrice - discountAmount;
  
  // Update UI elements
  const oldPriceEl = document.getElementById('aboOldPrice');
  const newPriceEl = document.getElementById('aboNewPrice');
  const finalPriceEl = document.getElementById('aboFinalPrice');
  const savingsEl = document.getElementById('aboSavings');
  const intervalSpan = document.getElementById('aboSelectedInterval');
  
  if (oldPriceEl) oldPriceEl.textContent = `€${totalPrice.toFixed(2)}`;
  if (newPriceEl) newPriceEl.textContent = `€${finalPrice.toFixed(2)}`;
  if (finalPriceEl) finalPriceEl.textContent = finalPrice.toFixed(2);
  if (savingsEl) savingsEl.textContent = `sparst €${discountAmount.toFixed(2)}`;
  if (intervalSpan) intervalSpan.textContent = aboSelectedInterval;
  
  // Update Reichweite info
  const daysPerPack = Math.floor(aboPackSize / aboDosePerDay);
  const totalDays = daysPerPack * aboQuantity;
  const reichweiteInfo = document.getElementById('aboReichweiteInfo');
  if (reichweiteInfo) {
    reichweiteInfo.textContent = `${totalDays} Tage`;
  }
}

function confirmAboToCart() {
  if (!currentAboProduct) return;
  
  const productId = currentAboProduct.id;
  const price = parseFloat(currentAboProduct.price);
  const totalPrice = price * aboQuantity;
  const aboPrice = totalPrice * 0.92; // 8% Rabatt
  
  // Check if already pending
  if (subscriptions.has(productId) && subscriptions.get(productId).status === 'pending') {
    showToast('Dieses Abo ist bereits im Warenkorb');
    closeAboSheet();
    return;
  }
  
  // Calculate days supply based on dose and quantity
  const daysPerPack = Math.floor(aboPackSize / aboDosePerDay);
  const totalDaysSupply = daysPerPack * aboQuantity;
  
  // Frequency text based on selected interval
  const frequencyText = aboSelectedInterval === 1 ? 'Monatlich' : 
                        aboSelectedInterval === 2 ? 'Alle 2 Monate' : 'Alle 3 Monate';
  
  // Add to subscriptions (pending status until checkout complete)
  subscriptions.set(productId, {
    interval: aboSelectedInterval,
    intervalMonths: aboSelectedInterval,
    daysSupply: totalDaysSupply,
    dosePerDay: aboDosePerDay,
    packSize: aboPackSize,
    quantity: aboQuantity,
    nextDelivery: 'Nach Kauf',
    status: 'pending',
    price: aboPrice,
    frequency: frequencyText,
    remaining: 100
  });
  saveSubscriptions();
  
  // Close sheet
  closeAboSheet();
  
  // Show success with quantity info
  const qtyText = aboQuantity > 1 ? ` (${aboQuantity}× Packung)` : '';
  showToast(`🔄 ${currentAboProduct.name}${qtyText} Abo im Warenkorb!`);
  
  // Update all displays
  updateAllBadges();
  updateEinkaufCheckoutBar();
  renderEinkaufCart();
  renderEinkaufAbos();
  updateSubscribeButtonState();
  
  // Animate
  const btn = document.querySelector('.subscribe-btn');
  if (btn && !btn.classList.contains('in-cart')) {
    createFlyingItem(btn, 'cart');
  }
}

function toggleAboAuto() {
  aboAutoEnabled = !aboAutoEnabled;
  document.getElementById('aboAutoToggle').classList.toggle('active', aboAutoEnabled);
}

function updateAboCalculation() {
  const daysSupply = Math.floor(aboPackSize / aboDosePerDay);
  const weeksSupply = Math.round(daysSupply / 7);
  
  // Update UI elements
  const reichweiteEl = document.getElementById('aboReichweite');
  const intervallEl = document.getElementById('aboIntervall');
  
  if (reichweiteEl) reichweiteEl.textContent = `${daysSupply} Tage`;
  if (intervallEl) intervallEl.textContent = `alle ${weeksSupply} Wochen`;
}

