// E-Mail Einstellungen
function openEmailSettings() {
  document.getElementById('emailSettingsOverlay').classList.add('visible');
  document.getElementById('emailSettingsSheet').classList.add('visible');
  loadEmailSettings();
  lockBody();
}

function closeEmailSettings() {
  document.getElementById('emailSettingsOverlay').classList.remove('visible');
  document.getElementById('emailSettingsSheet').classList.remove('visible');
  unlockBody();
}

function loadEmailSettings() {
  const saved = localStorage.getItem('suppTreeEmailSettings');
  const settings = saved ? JSON.parse(saved) : {
    email: 'flo@example.com',
    verified: true,
    newProducts: true,
    recommendations: true,
    discounts: true,
    healthTips: false,
    orderConfirm: true,
    shipping: true,
    aboReminder: true
  };
  
  document.getElementById('currentEmailDisplay').textContent = settings.email;
  document.getElementById('emailNewProducts').checked = settings.newProducts;
  document.getElementById('emailRecommendations').checked = settings.recommendations;
  document.getElementById('emailDiscounts').checked = settings.discounts;
  document.getElementById('emailHealthTips').checked = settings.healthTips;
  document.getElementById('emailShipping').checked = settings.shipping;
  document.getElementById('emailAboReminder').checked = settings.aboReminder;
}

function toggleEmailChange() {
  const form = document.getElementById('emailChangeForm');
  form.style.display = form.style.display === 'none' ? 'block' : 'none';
}

function cancelEmailChange() {
  document.getElementById('emailChangeForm').style.display = 'none';
  document.getElementById('newEmailInput').value = '';
  document.getElementById('emailConfirmPassword').value = '';
}

function saveEmailChange() {
  const newEmail = document.getElementById('newEmailInput').value.trim();
  const password = document.getElementById('emailConfirmPassword').value;
  
  if (!newEmail || !password) {
    showToast('⚠️ Bitte alle Felder ausfüllen');
    return;
  }
  
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(newEmail)) {
    showToast('⚠️ Bitte gültige E-Mail eingeben');
    return;
  }
  
  // Simulate verification email
  showToast('📧 Bestätigungsmail gesendet an ' + newEmail);
  cancelEmailChange();
}

function saveEmailSettings() {
  const settings = {
    email: document.getElementById('currentEmailDisplay').textContent,
    verified: true,
    newProducts: document.getElementById('emailNewProducts').checked,
    recommendations: document.getElementById('emailRecommendations').checked,
    discounts: document.getElementById('emailDiscounts').checked,
    healthTips: document.getElementById('emailHealthTips').checked,
    orderConfirm: true,
    shipping: document.getElementById('emailShipping').checked,
    aboReminder: document.getElementById('emailAboReminder').checked
  };
  
  localStorage.setItem('suppTreeEmailSettings', JSON.stringify(settings));
  closeEmailSettings();
  showToast('✅ E-Mail Einstellungen gespeichert');
}

