// Passwort ändern
function openPasswordChange() {
  document.getElementById('passwordChangeOverlay').classList.add('visible');
  document.getElementById('passwordChangeSheet').classList.add('visible');
  clearPasswordForm();
  lockBody();
}

function closePasswordChange() {
  document.getElementById('passwordChangeOverlay').classList.remove('visible');
  document.getElementById('passwordChangeSheet').classList.remove('visible');
  clearPasswordForm();
  unlockBody();
}

function clearPasswordForm() {
  document.getElementById('currentPassword').value = '';
  document.getElementById('newPassword').value = '';
  document.getElementById('confirmPassword').value = '';
  document.getElementById('strengthFill').className = 'strength-fill';
  document.getElementById('strengthFill').style.width = '0';
  document.getElementById('strengthText').textContent = 'Passwortstärke';
  document.getElementById('passwordMatchHint').textContent = '';
  document.querySelectorAll('.requirements-list li').forEach(li => li.classList.remove('met'));
}

function togglePasswordVisibility(inputId, btn) {
  const input = document.getElementById(inputId);
  if (input.type === 'password') {
    input.type = 'text';
    btn.textContent = '🙈';
  } else {
    input.type = 'password';
    btn.textContent = '👁️';
  }
}

function checkPasswordStrength() {
  const password = document.getElementById('newPassword').value;
  const fill = document.getElementById('strengthFill');
  const text = document.getElementById('strengthText');
  
  // Check requirements
  const hasLength = password.length >= 8;
  const hasUpper = /[A-Z]/.test(password);
  const hasLower = /[a-z]/.test(password);
  const hasNumber = /[0-9]/.test(password);
  
  document.getElementById('reqLength').classList.toggle('met', hasLength);
  document.getElementById('reqUpper').classList.toggle('met', hasUpper);
  document.getElementById('reqLower').classList.toggle('met', hasLower);
  document.getElementById('reqNumber').classList.toggle('met', hasNumber);
  
  // Update requirement icons
  document.querySelectorAll('.requirements-list li').forEach(li => {
    const icon = li.querySelector('.req-icon');
    icon.textContent = li.classList.contains('met') ? '✓' : '○';
  });
  
  // Calculate strength
  let strength = 0;
  if (hasLength) strength++;
  if (hasUpper) strength++;
  if (hasLower) strength++;
  if (hasNumber) strength++;
  if (password.length >= 12) strength++;
  if (/[^A-Za-z0-9]/.test(password)) strength++;
  
  fill.className = 'strength-fill';
  if (password.length === 0) {
    fill.style.width = '0';
    text.textContent = 'Passwortstärke';
  } else if (strength <= 2) {
    fill.classList.add('weak');
    text.textContent = 'Schwach';
  } else if (strength <= 3) {
    fill.classList.add('fair');
    text.textContent = 'Mittel';
  } else if (strength <= 4) {
    fill.classList.add('good');
    text.textContent = 'Gut';
  } else {
    fill.classList.add('strong');
    text.textContent = 'Stark 💪';
  }
  
  checkPasswordMatch();
}

function checkPasswordMatch() {
  const newPw = document.getElementById('newPassword').value;
  const confirm = document.getElementById('confirmPassword').value;
  const hint = document.getElementById('passwordMatchHint');
  
  if (confirm.length === 0) {
    hint.textContent = '';
    hint.className = 'password-match-hint';
  } else if (newPw === confirm) {
    hint.textContent = '✓ Passwörter stimmen überein';
    hint.className = 'password-match-hint match';
  } else {
    hint.textContent = '✗ Passwörter stimmen nicht überein';
    hint.className = 'password-match-hint no-match';
  }
}

function savePasswordChange() {
  const current = document.getElementById('currentPassword').value;
  const newPw = document.getElementById('newPassword').value;
  const confirm = document.getElementById('confirmPassword').value;
  
  if (!current || !newPw || !confirm) {
    showToast('⚠️ Bitte alle Felder ausfüllen');
    return;
  }
  
  const hasLength = newPw.length >= 8;
  const hasUpper = /[A-Z]/.test(newPw);
  const hasLower = /[a-z]/.test(newPw);
  const hasNumber = /[0-9]/.test(newPw);
  
  if (!hasLength || !hasUpper || !hasLower || !hasNumber) {
    showToast('⚠️ Passwort erfüllt nicht alle Anforderungen');
    return;
  }
  
  if (newPw !== confirm) {
    showToast('⚠️ Passwörter stimmen nicht überein');
    return;
  }
  
  closePasswordChange();
  showToast('✅ Passwort erfolgreich geändert');
}

