function savePaymentMethods(methods) {
  localStorage.setItem('suppTreePaymentMethods', JSON.stringify(methods));
  if (supabase && currentUser) {
    DataStore.set('payment_methods', 'suppTreePaymentMethods', methods, {
      replaceAll: true,
      transform: (m) => ({
        user_id: currentUser.id,
        type: m.type,
        display_name: m.detail || m.name,
        brand: m.name,
        is_default: m.isDefault || false
      })
    }).catch(e => console.error('PaymentMethods sync error:', e));
  }
}

function loadPaymentMethods() {
  const saved = localStorage.getItem('suppTreePaymentMethods');
  const methods = saved ? JSON.parse(saved) : [
    { id: 1, type: 'paypal', name: 'PayPal', detail: 'flo@example.com', isDefault: true },
    { id: 2, type: 'sepa', name: 'SEPA-Lastschrift', detail: 'DE89 •••• •••• 1234', isDefault: false }
  ];
  renderPaymentMethods(methods);
}

function renderPaymentMethods(methods) {
  const container = document.getElementById('paymentMethodsList');
  if (!container) return;
  
  const icons = { 
    paypal: '💳', 
    sepa: '🏦', 
    card: '💳', 
    klarna: '🛒', 
    rechnung: '📄' 
  };
  
  container.innerHTML = methods.map((method, idx) => `
    <div class="payment-method-item ${method.isDefault ? 'default' : ''}">
      <div class="payment-method-icon">${icons[method.type] || '💳'}</div>
      <div class="payment-method-info">
        <span class="payment-method-name">${method.name}</span>
        <span class="payment-method-detail">${method.detail}</span>
      </div>
      ${method.isDefault ? 
        '<span class="payment-method-badge">Standard</span>' : 
        `<button class="payment-method-action" onclick="setDefaultPayment(${idx})">Als Standard</button>`
      }
    </div>
  `).join('');
}

function openAddPaymentMethod() {
  const options = document.getElementById('paymentAddOptions');
  options.style.display = options.style.display === 'none' ? 'block' : 'none';
}

function addPaymentMethod(type) {
  const typeNames = {
    paypal: 'PayPal',
    sepa: 'SEPA-Lastschrift',
    card: 'Kreditkarte',
    klarna: 'Klarna',
    rechnung: 'Kauf auf Rechnung'
  };
  
  // In production this would open a proper form/integration
  showToast(`💳 ${typeNames[type]} wird hinzugefügt...`);
  document.getElementById('paymentAddOptions').style.display = 'none';
  
  // Demo: Add to list
  const saved = localStorage.getItem('suppTreePaymentMethods');
  let methods = saved ? JSON.parse(saved) : [];
  methods.push({
    id: Date.now(),
    type: type,
    name: typeNames[type],
    detail: type === 'paypal' ? 'neu@example.com' : 'Neu hinzugefügt',
    isDefault: methods.length === 0
  });
  savePaymentMethods(methods);
  renderPaymentMethods(methods);
  showToast(`✅ ${typeNames[type]} hinzugefügt`);
}

function setDefaultPayment(index) {
  const saved = localStorage.getItem('suppTreePaymentMethods');
  let methods = saved ? JSON.parse(saved) : [];
  methods = methods.map((m, i) => ({ ...m, isDefault: i === index }));
  savePaymentMethods(methods);
  renderPaymentMethods(methods);
  showToast('✅ Standard-Zahlungsmethode geändert');
}

