async function openMyProfile() {
  document.getElementById('myProfileOverlay').classList.add('visible');
  document.getElementById('myProfileSheet').classList.add('visible');
  await loadMyProfile();
  lockBody();
}

function closeMyProfile() {
  document.getElementById('myProfileOverlay').classList.remove('visible');
  document.getElementById('myProfileSheet').classList.remove('visible');
  unlockBody();
}

async function loadMyProfile() {
  const saved = localStorage.getItem('suppTreeProfile');
  const profile = saved ? JSON.parse(saved) : {};

  // Supabase-Profil laden falls nicht vorhanden
  if (!userProfile && currentUser && supabase) {
    try { await loadUserProfile(); } catch(e) { console.warn('Profile load:', e); }
  }

  // Supabase personal_data hat Priorität über leere localStorage-Felder
  if (userProfile && userProfile.personal_data) {
    var pd = userProfile.personal_data;
    if (!profile.firstName && pd.firstName) profile.firstName = pd.firstName;
    if (!profile.lastName && pd.lastName) profile.lastName = pd.lastName;
    if (!profile.anrede && pd.anrede) profile.anrede = pd.anrede;
    if (!profile.titel && pd.titel) profile.titel = pd.titel;
    if (!profile.birthdate && pd.birthdate) profile.birthdate = pd.birthdate;
    if (!profile.gender && pd.gender) profile.gender = pd.gender;
    if (!profile.height && pd.height) profile.height = pd.height;
    if (!profile.weight && pd.weight) profile.weight = pd.weight;
    if (!profile.phone && pd.phone) profile.phone = pd.phone;
  }
  // Name aus profiles.name splitten falls immer noch leer
  if (!profile.firstName && userProfile && userProfile.name) {
    var parts = userProfile.name.trim().split(/\s+/);
    profile.firstName = parts[0] || '';
    profile.lastName = parts.slice(1).join(' ') || '';
  }
  // Letzter Fallback: Name aus Auth user_metadata
  if (!profile.firstName && currentUser) {
    var metaName = (currentUser.user_metadata && currentUser.user_metadata.name) || '';
    if (metaName) {
      var parts2 = metaName.trim().split(/\s+/);
      profile.firstName = parts2[0] || '';
      profile.lastName = parts2.slice(1).join(' ') || '';
    }
  }
  // E-Mail aus Auth
  if (!profile.email && currentUser && currentUser.email) {
    profile.email = currentUser.email;
  }

  document.getElementById('profileAnrede').value = profile.anrede || '';
  document.getElementById('profileTitel').value = profile.titel || '';
  document.getElementById('profileFirstName').value = profile.firstName || '';
  document.getElementById('profileLastName').value = profile.lastName || '';
  document.getElementById('profileBirthdate').value = profile.birthdate || '';
  document.getElementById('profileGender').value = profile.gender || '';
  document.getElementById('profileHeight').value = profile.height || '';
  document.getElementById('profileWeight').value = profile.weight || '';
  document.getElementById('profileEmail').value = profile.email || '';
  document.getElementById('profilePhone').value = profile.phone || '';
  
  // Load avatar or photo
  const avatarEmoji = document.getElementById('profileAvatarEmoji');
  const avatarImage = document.getElementById('profileAvatarImage');
  const removeBtn = document.getElementById('removePhotoBtn');
  
  // Check for saved photo first
  const photoData = localStorage.getItem('suppTreeProfilePhoto');
  if (photoData && profile.hasPhoto) {
    avatarEmoji.style.display = 'none';
    avatarImage.src = photoData;
    avatarImage.style.display = 'block';
    if (removeBtn) removeBtn.style.display = 'block';
    // Deselect all avatars
    document.querySelectorAll('.avatar-option').forEach(btn => btn.classList.remove('selected'));
  } else {
    // Show emoji avatar
    avatarEmoji.textContent = profile.avatar || '👤';
    avatarEmoji.style.display = 'flex';
    avatarImage.style.display = 'none';
    if (removeBtn) removeBtn.style.display = 'none';
    // Highlight selected avatar
    document.querySelectorAll('.avatar-option').forEach(btn => {
      btn.classList.toggle('selected', btn.textContent === (profile.avatar || '👤'));
    });
  }
  
  // Calculate BMI if height and weight exist
  if (profile.height && profile.weight) {
    calculateBMI();
  }
  
  // Add event listeners for BMI calculation
  document.getElementById('profileHeight').addEventListener('input', calculateBMI);
  document.getElementById('profileWeight').addEventListener('input', calculateBMI);
}

function selectAvatar(emoji) {
  // Hide photo, show emoji
  const avatarEmoji = document.getElementById('profileAvatarEmoji');
  const avatarImage = document.getElementById('profileAvatarImage');
  
  avatarEmoji.textContent = emoji;
  avatarEmoji.style.display = 'flex';
  avatarImage.style.display = 'none';
  
  // Clear photo data
  localStorage.removeItem('suppTreeProfilePhoto');
  document.getElementById('removePhotoBtn').style.display = 'none';
  
  // Mark selected
  document.querySelectorAll('.avatar-option').forEach(btn => {
    btn.classList.toggle('selected', btn.textContent === emoji);
  });
}

function triggerPhotoUpload() {
  document.getElementById('profilePhotoInput').click();
}

function handleProfilePhoto(event) {
  const file = event.target.files[0];
  if (!file) return;
  
  // Validate file type
  if (!file.type.startsWith('image/')) {
    showToast('❌ Bitte wähle ein Bild aus');
    return;
  }
  
  // Validate file size (max 5MB)
  if (file.size > 5 * 1024 * 1024) {
    showToast('❌ Bild zu groß (max. 5 MB)');
    return;
  }
  
  const reader = new FileReader();
  reader.onload = function(e) {
    const imageData = e.target.result;
    
    // Resize image to save space
    resizeImage(imageData, 200, 200, function(resizedData) {
      // Update avatar display
      const avatarEmoji = document.getElementById('profileAvatarEmoji');
      const avatarImage = document.getElementById('profileAvatarImage');
      
      avatarEmoji.style.display = 'none';
      avatarImage.src = resizedData;
      avatarImage.style.display = 'block';
      
      // Save to localStorage
      localStorage.setItem('suppTreeProfilePhoto', resizedData);
      
      // Show remove button
      document.getElementById('removePhotoBtn').style.display = 'block';
      
      // Deselect avatars
      document.querySelectorAll('.avatar-option').forEach(btn => btn.classList.remove('selected'));
      
      showToast('✅ Foto hochgeladen');
    });
  };
  reader.readAsDataURL(file);
}

function resizeImage(dataUrl, maxWidth, maxHeight, callback) {
  const img = new Image();
  img.onload = function() {
    const canvas = document.createElement('canvas');
    let width = img.width;
    let height = img.height;
    
    // Calculate new dimensions
    if (width > height) {
      if (width > maxWidth) {
        height *= maxWidth / width;
        width = maxWidth;
      }
    } else {
      if (height > maxHeight) {
        width *= maxHeight / height;
        height = maxHeight;
      }
    }
    
    // Make it square (crop center)
    const size = Math.min(width, height);
    canvas.width = size;
    canvas.height = size;
    
    const ctx = canvas.getContext('2d');
    const sx = (img.width - img.width * size / width) / 2;
    const sy = (img.height - img.height * size / height) / 2;
    
    ctx.drawImage(img, 0, 0, img.width, img.height, 0, 0, size, size);
    
    callback(canvas.toDataURL('image/jpeg', 0.8));
  };
  img.src = dataUrl;
}

function removeProfilePhoto() {
  showConfirmDialog('Foto entfernen', 'Möchtest du dein Profilfoto wirklich entfernen?', 'Entfernen', function() {
    const avatarEmoji = document.getElementById('profileAvatarEmoji');
    const avatarImage = document.getElementById('profileAvatarImage');

    avatarEmoji.textContent = '👤';
    avatarEmoji.style.display = 'flex';
    avatarImage.style.display = 'none';
    avatarImage.src = '';

    localStorage.removeItem('suppTreeProfilePhoto');
    document.getElementById('removePhotoBtn').style.display = 'none';
    document.getElementById('profilePhotoInput').value = '';

    showToast('Foto entfernt');
  }, true);
}

function loadProfilePhoto() {
  const photoData = localStorage.getItem('suppTreeProfilePhoto');
  if (photoData) {
    const avatarEmoji = document.getElementById('profileAvatarEmoji');
    const avatarImage = document.getElementById('profileAvatarImage');
    const removeBtn = document.getElementById('removePhotoBtn');
    
    if (avatarEmoji && avatarImage) {
      avatarEmoji.style.display = 'none';
      avatarImage.src = photoData;
      avatarImage.style.display = 'block';
      if (removeBtn) removeBtn.style.display = 'block';
    }
  }
}

function calculateBMI() {
  const height = parseFloat(document.getElementById('profileHeight').value);
  const weight = parseFloat(document.getElementById('profileWeight').value);
  const display = document.getElementById('profileBmiDisplay');
  const valueEl = document.getElementById('profileBmiValue');
  const catEl = document.getElementById('profileBmiCategory');
  
  if (height && weight && height > 0) {
    const heightM = height / 100;
    const bmi = weight / (heightM * heightM);
    
    display.style.display = 'flex';
    valueEl.textContent = bmi.toFixed(1);
    
    if (bmi < 18.5) {
      catEl.textContent = 'Untergewicht';
      catEl.style.background = '#fef3c7';
      catEl.style.color = '#b45309';
    } else if (bmi < 25) {
      catEl.textContent = 'Normalgewicht';
      catEl.style.background = '#ECFDF5';
      catEl.style.color = '#059669';
    } else if (bmi < 30) {
      catEl.textContent = 'Übergewicht';
      catEl.style.background = '#fed7aa';
      catEl.style.color = '#c2410c';
    } else {
      catEl.textContent = 'Adipositas';
      catEl.style.background = '#fee2e2';
      catEl.style.color = '#b91c1c';
    }
  } else {
    display.style.display = 'none';
  }
}

function saveMyProfile() {
  const avatarEmoji = document.getElementById('profileAvatarEmoji');
  const avatarImage = document.getElementById('profileAvatarImage');
  
  const profile = {
    anrede: document.getElementById('profileAnrede').value,
    titel: document.getElementById('profileTitel').value,
    firstName: document.getElementById('profileFirstName').value.trim(),
    lastName: document.getElementById('profileLastName').value.trim(),
    birthdate: document.getElementById('profileBirthdate').value,
    gender: document.getElementById('profileGender').value,
    height: document.getElementById('profileHeight').value,
    weight: document.getElementById('profileWeight').value,
    email: document.getElementById('profileEmail').value.trim(),
    phone: document.getElementById('profilePhone').value.trim(),
    avatar: avatarImage.style.display !== 'none' ? 'photo' : avatarEmoji.textContent,
    hasPhoto: avatarImage.style.display !== 'none'
  };

  localStorage.setItem('suppTreeProfile', JSON.stringify(profile));

  // Supabase-Profil synchronisieren
  if (currentUser && supabase) {
    var fullName = [profile.firstName, profile.lastName].filter(Boolean).join(' ');
    updateProfile({ name: fullName, personal_data: { anrede: profile.anrede, titel: profile.titel, firstName: profile.firstName, lastName: profile.lastName, birthdate: profile.birthdate, gender: profile.gender, height: profile.height, weight: profile.weight, phone: profile.phone } }).catch(function(e) { console.warn('Profile sync:', e); });
  }

  // Update greeting name if set
  if (profile.firstName) {
    const greetingName = document.getElementById('homeGreetingName');
    if (greetingName) {
      greetingName.textContent = profile.firstName + '! 👋';
    }
  }

  closeMyProfile();
  if (!currentUser || !supabase) showToast('✅ Profil gespeichert');
}

