function selectTestKit(kitId) {
  // Zeige Details oder füge direkt zum Warenkorb hinzu
  const kit = testKitProducts[kitId];
  if (!kit) return;
  
  // Highlight-Effekt
  const cards = document.querySelectorAll('.testkit-card');
  cards.forEach(card => card.style.borderColor = '');
  event.currentTarget.style.borderColor = 'var(--green-accent)';
}

function addTestKitToCart(kitId) {
  const kit = testKitProducts[kitId];
  if (!kit) return;
  
  // Zum Warenkorb hinzufügen
  let cart = JSON.parse(localStorage.getItem('supptree_cart') || '[]');
  
  // Prüfe ob schon im Warenkorb
  const existingIndex = cart.findIndex(item => item.id === kit.id);
  if (existingIndex >= 0) {
    cart[existingIndex].quantity += 1;
  } else {
    cart.push({
      id: kit.id,
      name: kit.name,
      price: kit.price,
      originalPrice: kit.originalPrice,
      quantity: 1,
      type: 'testkit',
      image: '📦'
    });
  }
  
  localStorage.setItem('supptree_cart', JSON.stringify(cart));
  
  // Update Cart Badge
  updateCartBadge();
  
  showToast(`${kit.name} zum Warenkorb hinzugefügt! 🛒`, 'success');
  
  // Optional: Zum Warenkorb navigieren
  setTimeout(() => {
    closeTestKitShop();
    closeBloodValues();
    // showScreen('cart'); // Falls du direkt zum Warenkorb willst
  }, 1000);
}

function updateCartBadge() {
  const cart = JSON.parse(localStorage.getItem('supptree_cart') || '[]');
  const totalItems = cart.reduce((sum, item) => sum + (item.quantity || 1), 0);
  
  const badges = document.querySelectorAll('.cart-badge');
  badges.forEach(badge => {
    if (totalItems > 0) {
      badge.textContent = totalItems;
      badge.style.display = 'flex';
    } else {
      badge.style.display = 'none';
    }
  });
}

