// Ausgewählter Heilpraktiker und Buchungsdaten
let selectedHeilpraktiker = null;
let selectedTestForBooking = null;
let selectedBookingDate = null;
let selectedBookingTime = null;

function openHeilpraktikerSearch() {
  // Aktuellen Testtyp übernehmen falls ausgewählt
  if (activeBloodTestType) {
    selectedTestForBooking = activeBloodTestType;
    const testInfo = bloodTestNames[activeBloodTestType];
    if (testInfo) {
      document.getElementById('hpSelectedTest').style.display = 'flex';
      document.getElementById('hpSelectedTestName').textContent = testInfo.name;
    }
  } else {
    document.getElementById('hpSelectedTest').style.display = 'none';
    selectedTestForBooking = 'grosses-blutbild'; // Default
  }
  
  // User PLZ aus Profil laden falls vorhanden
  const savedProfile = localStorage.getItem('supptree_health_profile');
  if (savedProfile) {
    try {
      const profile = JSON.parse(savedProfile);
      if (profile.plz) {
        document.getElementById('hpSearchPlz').value = profile.plz;
      }
    } catch(e) {}
  }
  
  document.getElementById('hpSearchOverlay').classList.add('visible');
  document.getElementById('hpSearchSheet').classList.add('visible');
  
  // Initial-Suche starten
  searchHeilpraktiker();
}

function closeHeilpraktikerSearch() {
  document.getElementById('hpSearchOverlay').classList.remove('visible');
  document.getElementById('hpSearchSheet').classList.remove('visible');
}

function updateRadiusDisplay() {
  const radius = document.getElementById('hpSearchRadius').value;
  document.getElementById('hpRadiusValue').textContent = radius;
}

function useCurrentLocation() {
  const btn = document.querySelector('.hp-location-btn');
  btn.innerHTML = '<span class="loading-spinner-small"></span>';
  
  if (navigator.geolocation) {
    navigator.geolocation.getCurrentPosition(
      (position) => {
        // Simuliere PLZ-Lookup basierend auf Koordinaten
        document.getElementById('hpSearchPlz').value = 'Karlsruhe (Standort erkannt)';
        btn.innerHTML = '<span>✓</span>';
        setTimeout(() => { btn.innerHTML = '<span>📍</span>'; }, 2000);
        searchHeilpraktiker();
      },
      (error) => {
        btn.innerHTML = '<span>📍</span>';
        showToast('Standort konnte nicht ermittelt werden', 'error');
      }
    );
  } else {
    btn.innerHTML = '<span>📍</span>';
    showToast('Standortdienste nicht verfügbar', 'error');
  }
}

function searchHeilpraktiker() {
  const plz = document.getElementById('hpSearchPlz').value;
  const radius = parseInt(document.getElementById('hpSearchRadius').value);
  
  // Filter Heilpraktiker nach Radius (simuliert)
  const filtered = heilpraktikerData.filter(hp => hp.distance <= radius);
  
  // Nach Entfernung sortieren
  filtered.sort((a, b) => a.distance - b.distance);
  
  renderHeilpraktikerList(filtered);
}

function renderHeilpraktikerList(heilpraktiker) {
  const container = document.getElementById('hpResultsList');
  const noResults = document.getElementById('hpNoResults');
  
  if (heilpraktiker.length === 0) {
    container.innerHTML = '';
    noResults.style.display = 'block';
    return;
  }
  
  noResults.style.display = 'none';
  
  container.innerHTML = heilpraktiker.map(hp => {
    const stars = '⭐'.repeat(hp.rating);
    const testPrice = bloodTestPrices[selectedTestForBooking] || 25;
    const totalPrice = (hp.basePrice + testPrice).toFixed(2).replace('.', ',');
    
    return `
      <div class="hp-result-card" onclick="selectHeilpraktiker('${hp.id}')">
        <div class="hp-result-header">
          <div class="hp-avatar">${hp.avatar}</div>
          <div class="hp-info">
            <h5>${hp.name}</h5>
            <div class="hp-rating">
              <span class="stars">${stars}</span>
              <span class="rating-count">(${hp.reviews} Bewertungen)</span>
            </div>
            <p class="hp-address">${hp.address}</p>
          </div>
          <div class="hp-distance">${hp.distance.toFixed(1).replace('.', ',')} km</div>
        </div>
        <div class="hp-details">
          <div class="hp-tags">
            ${hp.tags.map(tag => `<span class="hp-tag">✓ ${tag}</span>`).join('')}
          </div>
          <div class="hp-next-slot">
            <span class="slot-label">Nächster Termin:</span>
            <span class="slot-time">${hp.nextSlot}</span>
          </div>
        </div>
        <div class="hp-prices">
          <span class="price-label">Blutabnahme + Labor:</span>
          <span class="price-value">ab ${totalPrice} €</span>
        </div>
      </div>
    `;
  }).join('');
}

function expandSearchRadius() {
  const slider = document.getElementById('hpSearchRadius');
  const currentRadius = parseInt(slider.value);
  const newRadius = Math.min(currentRadius + 25, 100);
  slider.value = newRadius;
  updateRadiusDisplay();
  searchHeilpraktiker();
}

