function selectBloodTestType(type) {
  // Toggle selection
  const btn = document.querySelector(`.test-type-btn[data-type="${type}"]`);
  const wasSelected = btn.classList.contains('selected');
  
  // Deselect all
  document.querySelectorAll('.test-type-btn').forEach(b => b.classList.remove('selected'));
  
  // Hide all value sections
  document.querySelectorAll('.blood-test-values').forEach(section => {
    section.style.display = 'none';
  });
  
  if (wasSelected) {
    // Deselect
    activeBloodTestType = null;
    document.getElementById('bloodTestDateSection').style.display = 'none';
    document.getElementById('bloodInfoBox').style.display = 'none';
    document.getElementById('saveBloodBtn').style.display = 'none';
  } else {
    // Select new type
    btn.classList.add('selected');
    activeBloodTestType = type;
    
    // Show date section
    document.getElementById('bloodTestDateSection').style.display = 'block';
    
    // Show relevant value sections
    const sectionsToShow = bloodTestTypeMap[type] || [];
    sectionsToShow.forEach(sectionType => {
      const section = document.getElementById(`values-${sectionType}`);
      if (section) {
        section.style.display = 'block';
      }
    });
    
    // Show info and save button
    document.getElementById('bloodInfoBox').style.display = 'flex';
    document.getElementById('saveBloodBtn').style.display = 'block';
    
    // Scroll to date section
    setTimeout(() => {
      document.getElementById('bloodTestDateSection').scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  }
}

function toggleBloodCategory(catId) {
  const cat = document.querySelector(`.blood-category:has(#cat-${catId})`);
  if (!cat) {
    // Fallback for browsers without :has()
    document.querySelectorAll('.blood-category').forEach(c => {
      if (c.querySelector(`#cat-${catId}`)) {
        c.classList.toggle('expanded');
      }
    });
    return;
  }
  cat.classList.toggle('expanded');
}

function loadBloodValues() {
  const saved = localStorage.getItem('suppTreeBloodValues');
  const data = saved ? JSON.parse(saved) : {};
  
  // Set date
  const dateInput = document.getElementById('bloodTestDate');
  if (dateInput) {
    if (data.testDate) {
      dateInput.value = data.testDate;
    } else {
      dateInput.value = new Date().toISOString().split('T')[0];
    }
  }
  
  // All blood value fields (numeric inputs)
  const fields = [
    // Kleines Blutbild
    'hemoglobin', 'hematocrit', 'rbc', 'wbc', 'platelets', 'mcv', 'mch', 'mchc',
    // Großes Blutbild / Differentialblutbild
    'neutrophils', 'lymphocytes', 'monocytes', 'eosinophils', 'basophils',
    // Stoffwechsel
    'glucose', 'hba1c', 'cholesterol', 'ldl', 'hdl', 'triglycerides',
    // Leberwerte
    'got', 'gpt', 'ggt', 'ap', 'bilirubin', 'albumin',
    // Nierenwerte
    'creatinine', 'gfr', 'urea', 'uricacid',
    // Schilddrüse
    'tsh', 'ft3', 'ft4',
    // Vitamine & Mineralien
    'vitamind', 'b12', 'folate', 'ferritin', 'iron', 'magnesium', 'zinc', 'selenium',
    // Entzündungswerte
    'crp', 'bsg',
    // Hormone
    'testosterone', 'estradiol', 'cortisol', 'dheas',
    // Elektrolyte
    'sodium', 'potassium', 'calcium', 'chloride', 'phosphate',
    // Gerinnung
    'quick', 'inr', 'ptt', 'fibrinogen', 'ddimer',
    // Herz-Marker
    'troponin', 'bnp', 'ntprobnp', 'ck', 'ckmb', 'ldh', 'homocysteine',
    // Bauchspeicheldrüse
    'lipase', 'amylase',
    // Eisen erweitert
    'iron2', 'ferritin2', 'transferrin', 'transferrinsat', 'reticulocytes',
    // Infektionen (numerisch)
    'antihbs',
    // Rheuma
    'rheumafactor', 'anticcp', 'antidsdna',
    // Tumormarker
    'psa', 'cea', 'afp', 'ca125', 'ca199', 'ca153'
  ];
  
  // Select fields (qualitative)
  const selectFields = ['hbsag', 'antihcv', 'hiv'];
  
  // Text fields
  const textFields = ['ana'];
  
  fields.forEach(field => {
    const input = document.getElementById(`bv-${field}`);
    if (input && data[field] !== undefined) {
      input.value = data[field];
    }
  });
  
  selectFields.forEach(field => {
    const select = document.getElementById(`bv-${field}`);
    if (select && data[field] !== undefined) {
      select.value = data[field];
    }
  });
  
  textFields.forEach(field => {
    const input = document.getElementById(`bv-${field}`);
    if (input && data[field] !== undefined) {
      input.value = data[field];
    }
  });
  
  // Show history if exists
  const historyDiv = document.getElementById('bloodHistory');
  if (data.history && data.history.length > 0 && historyDiv) {
    historyDiv.style.display = 'block';
    renderBloodHistory(data.history);
  }
  
  // Also show history preview in main sheet
  loadBloodHistoryPreview();
}

function loadBloodHistoryPreview() {
  const previewDiv = document.getElementById('bloodHistoryPreview');
  const previewList = document.getElementById('bloodHistoryPreviewList');
  if (!previewDiv || !previewList) return;
  
  // Get blood history from localStorage
  const bloodHistory = JSON.parse(localStorage.getItem('supptree_blood_values') || '[]');
  const oldData = JSON.parse(localStorage.getItem('suppTreeBloodValues') || '{}');
  
  // Combine old and new format
  let allHistory = [...bloodHistory];
  if (oldData.history) {
    allHistory = [...allHistory, ...oldData.history];
  }
  
  if (allHistory.length === 0) {
    previewDiv.style.display = 'none';
    return;
  }
  
  // Sort by date descending
  allHistory.sort((a, b) => new Date(b.date || b.createdAt) - new Date(a.date || a.createdAt));
  
  // Show only last 3
  const recentHistory = allHistory.slice(0, 3);
  
  previewDiv.style.display = 'block';
  previewList.innerHTML = recentHistory.map(entry => {
    const date = new Date(entry.date || entry.createdAt);
    const dateStr = date.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });
    
    // Count values
    const valueCount = entry.values ? Object.keys(entry.values).filter(k => entry.values[k]).length : 0;
    
    // Determine source icon
    let sourceIcon = '📊';
    if (entry.source === 'upload' || entry.uploadMethod) sourceIcon = '📄';
    else if (entry.source === 'heilpraktiker') sourceIcon = '🩺';
    else if (entry.source === 'testkit') sourceIcon = '📦';
    
    const testName = entry.testType ? (bloodTestNames[entry.testType]?.name || entry.testType) : 'Bluttest';
    
    return `
      <div class="history-preview-item" onclick="showBloodHistoryDetail('${entry.id}')">
        <span class="history-icon">${sourceIcon}</span>
        <div class="history-info">
          <span class="history-date">${dateStr}</span>
          <span class="history-type">${testName}</span>
        </div>
        <span class="history-values">${valueCount} Werte</span>
        <span class="history-arrow">→</span>
      </div>
    `;
  }).join('');
}

