function saveBloodValues() {
  // All blood value fields (numeric inputs)
  const fields = [
    // Kleines Blutbild
    'hemoglobin', 'hematocrit', 'rbc', 'wbc', 'platelets', 'mcv', 'mch', 'mchc',
    // Großes Blutbild / Differentialblutbild
    'neutrophils', 'lymphocytes', 'monocytes', 'eosinophils', 'basophils',
    // Stoffwechsel
    'glucose', 'hba1c', 'cholesterol', 'ldl', 'hdl', 'triglycerides',
    // Leberwerte
    'got', 'gpt', 'ggt', 'ap', 'bilirubin', 'albumin',
    // Nierenwerte
    'creatinine', 'gfr', 'urea', 'uricacid',
    // Schilddrüse
    'tsh', 'ft3', 'ft4',
    // Vitamine & Mineralien
    'vitamind', 'b12', 'folate', 'ferritin', 'iron', 'magnesium', 'zinc', 'selenium',
    // Entzündungswerte
    'crp', 'bsg',
    // Hormone
    'testosterone', 'estradiol', 'cortisol', 'dheas',
    // Elektrolyte
    'sodium', 'potassium', 'calcium', 'chloride', 'phosphate',
    // Gerinnung
    'quick', 'inr', 'ptt', 'fibrinogen', 'ddimer',
    // Herz-Marker
    'troponin', 'bnp', 'ntprobnp', 'ck', 'ckmb', 'ldh', 'homocysteine',
    // Bauchspeicheldrüse
    'lipase', 'amylase',
    // Eisen erweitert
    'iron2', 'ferritin2', 'transferrin', 'transferrinsat', 'reticulocytes',
    // Infektionen (numerisch)
    'antihbs',
    // Rheuma
    'rheumafactor', 'anticcp', 'antidsdna',
    // Tumormarker
    'psa', 'cea', 'afp', 'ca125', 'ca199', 'ca153'
  ];
  
  // Select fields (qualitative)
  const selectFields = ['hbsag', 'antihcv', 'hiv'];
  
  // Text fields
  const textFields = ['ana'];
  
  const saved = localStorage.getItem('suppTreeBloodValues');
  const existingData = saved ? JSON.parse(saved) : { history: [] };
  
  const newData = {
    testDate: document.getElementById('bloodTestDate').value,
    testType: activeBloodTestType || 'komplett',
    savedAt: new Date().toISOString(),
    history: existingData.history || []
  };
  
  // Collect all numeric values
  let hasValues = false;
  fields.forEach(field => {
    const input = document.getElementById(`bv-${field}`);
    if (input && input.value) {
      newData[field] = parseFloat(input.value);
      hasValues = true;
    }
  });
  
  // Collect select values
  selectFields.forEach(field => {
    const select = document.getElementById(`bv-${field}`);
    if (select && select.value) {
      newData[field] = select.value;
      hasValues = true;
    }
  });
  
  // Collect text values
  textFields.forEach(field => {
    const input = document.getElementById(`bv-${field}`);
    if (input && input.value) {
      newData[field] = input.value;
      hasValues = true;
    }
  });
  
  if (!hasValues) {
    showToast('⚠️ Bitte mindestens einen Wert eingeben');
    return;
  }
  
  // Add to history (keep last 10)
  const historyEntry = { ...newData };
  delete historyEntry.history;
  newData.history.unshift(historyEntry);
  if (newData.history.length > 10) {
    newData.history = newData.history.slice(0, 10);
  }
  
  localStorage.setItem('suppTreeBloodValues', JSON.stringify(newData));
  
  // Check for critical values and show recommendations
  checkBloodValueAlerts(newData);
  
  closeBloodValues();
  showToast('✅ Blutwerte gespeichert');
}

function checkBloodValueAlerts(data) {
  const alerts = [];
  
  // Vitamin D check
  if (data.vitamind && data.vitamind < 50) {
    alerts.push('⚠️ Vitamin D ist niedrig - Supplementierung empfohlen');
  }
  
  // B12 check
  if (data.b12 && data.b12 < 200) {
    alerts.push('⚠️ Vitamin B12 ist niedrig');
  }
  
  // Ferritin check
  if (data.ferritin && data.ferritin < 30) {
    alerts.push('⚠️ Ferritin (Eisenspeicher) ist niedrig');
  }
  
  // Magnesium check
  if (data.magnesium && data.magnesium < 0.75) {
    alerts.push('⚠️ Magnesium ist am unteren Rand');
  }
  
  if (alerts.length > 0) {
    setTimeout(() => {
      showToast(alerts[0]);
    }, 2000);
  }
}

function renderBloodHistory(history) {
  const container = document.getElementById('bloodHistory');
  const list = document.getElementById('bloodHistoryList');
  
  if (!container || !list || history.length === 0) return;
  
  container.style.display = 'block';
  
  list.innerHTML = history.slice(0, 5).map(entry => `
    <div class="blood-history-entry">
      <span class="history-date">${new Date(entry.testDate).toLocaleDateString('de-DE')}</span>
      <span class="history-values">${Object.keys(entry).filter(k => !['testDate', 'savedAt'].includes(k)).length} Werte</span>
    </div>
  `).join('');
}

// Dark Mode
function toggleDarkMode(event) {
  if (event) {
    event.stopPropagation();
    event.preventDefault();
  }
  
  const toggle = document.getElementById('darkModeToggle');
  const isDark = document.body.classList.contains('dark-mode');
  
  if (isDark) {
    document.body.classList.remove('dark-mode');
    toggle.checked = false;
    localStorage.setItem('darkMode', 'false');
    showToast('☀️ Light Mode aktiviert');
  } else {
    document.body.classList.add('dark-mode');
    toggle.checked = true;
    localStorage.setItem('darkMode', 'true');
    showToast('🌙 Dark Mode aktiviert');
  }
}

// Check dark mode on load
function initDarkMode() {
  const savedMode = localStorage.getItem('darkMode');
  const toggle = document.getElementById('darkModeToggle');
  if (savedMode === 'true') {
    document.body.classList.add('dark-mode');
    if (toggle) toggle.checked = true;
  }
}

