function openLanguageSettings() {
  document.getElementById('languageSettingsOverlay').classList.add('visible');
  document.getElementById('languageSettingsSheet').classList.add('visible');
  lockBody();
}

function closeLanguageSettings() {
  document.getElementById('languageSettingsOverlay').classList.remove('visible');
  document.getElementById('languageSettingsSheet').classList.remove('visible');
  unlockBody();
}

function selectLanguage(element, lang) {
  if (element.classList.contains('disabled')) return;
  
  // Update both old and new UI elements
  document.querySelectorAll('.language-option, .language-item').forEach(opt => {
    opt.classList.remove('selected');
    opt.classList.remove('active');
  });
  element.classList.add('selected');
  element.classList.add('active');
  
  // Save language - use consistent key
  localStorage.setItem('supptree-language', lang);
  currentLang = lang;
  
  // Apply NEW i18n system
  applyI18n();
  
  // Apply OLD translations (for backward compatibility)
  applyTranslations(lang);
  
  // Update language display in profile/menu
  const langDisplay = document.querySelector('.profile-menu-item .menu-value');
  if (langDisplay) {
    langDisplay.textContent = translations[lang]._name;
  }
  const menuLangHint = document.getElementById('menuCurrentLang');
  if (menuLangHint) {
    menuLangHint.textContent = translations[lang]._name;
  }
  
  closeLanguageSettings();
  showToast(`🌐 ${translations[lang]._name}`);
}

