  // Walk through all text nodes and replace
  function replaceTextInElement(element) {
    if (element.nodeType === Node.TEXT_NODE) {
      let text = element.textContent;
      let changed = false;
      
      // Sort by length descending to replace longer strings first
      const sortedEntries = Object.entries(textMap).sort((a, b) => b[0].length - a[0].length);
      
      for (const [search, replace] of sortedEntries) {
        if (text.includes(search) && search !== replace) {
          text = text.split(search).join(replace);
          changed = true;
        }
      }
      if (changed) element.textContent = text;
    } else if (element.nodeType === Node.ELEMENT_NODE && 
               !['SCRIPT', 'STYLE', 'TEXTAREA'].includes(element.tagName)) {
      // Also handle input placeholders
      if (element.tagName === 'INPUT' && element.placeholder) {
        for (const [search, replace] of Object.entries(textMap)) {
          if (element.placeholder.includes(search)) {
            element.placeholder = element.placeholder.split(search).join(replace);
          }
        }
      }
      for (const child of element.childNodes) {
        replaceTextInElement(child);
      }
    }
  }
  
  // Apply to entire body
  replaceTextInElement(document.body);
  
  // ===== SPECIFIC ELEMENTS =====
  
  // Navigation (5 items: Home, Marktplatz, Mein, Fav & Korb, Menü)
  const navLabels = document.querySelectorAll('.nav-label');
  const navTexts = [t.nav_home, t.nav_products, t.nav_mein, t.nav_favkorb || 'Fav & Korb', t.nav_menu || 'Menü'];
  navLabels.forEach((label, i) => {
    if (navTexts[i]) label.textContent = navTexts[i];
  });
  
