function renderEinkaufCart() {
  const content = document.getElementById('einkaufCartContent');
  const countEl = document.getElementById('einkaufCartCount');
  const summaryEl = document.getElementById('einkaufCartSummary');
  
  // Count pending abos
  let pendingAboCount = 0;
  subscriptions.forEach(sub => {
    if (sub.status === 'pending') pendingAboCount++;
  });
  
  let totalItems = 0;
  cart.forEach(qty => totalItems += qty);
  cartKuren.forEach(item => totalItems += item.qty);
  totalItems += pendingAboCount;
  
  if (countEl) countEl.textContent = totalItems;
  
  if (cart.size === 0 && cartKuren.size === 0 && pendingAboCount === 0) {
    content.innerHTML = `
      <div class="einkauf-empty">
        <div class="einkauf-empty-icon">🛒</div>
        <div class="einkauf-empty-text">Dein Warenkorb ist noch leer</div>
        <button class="einkauf-empty-btn" onclick="switchScreen('productsScreen')" data-i18n="btn.shop">Einkaufen</button>
      </div>
    `;
    summaryEl.innerHTML = '';
    return;
  }
  
  let html = '';
  let subtotal = 0;
  
  // Reguläre Produkte
  cart.forEach((qty, productId) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;

    subtotal += parseFloat(product.price) * qty;
    const ref = cartReferrals.get(productId);

    html += `
      <div class="einkauf-item">
        <div class="einkauf-item-icon" onclick="openProductDetail('${productId}')">${product.icon}</div>
        <div class="einkauf-item-info" onclick="openProductDetail('${productId}')">
          <div class="einkauf-item-name">${product.name}</div>
          <div class="einkauf-item-brand">${product.brand}</div>
          ${ref ? `<div style="font-size:10px;color:#16a34a;margin-top:2px">💊 Empfohlen von ${ref.beraterName}</div>` : ''}
          <div class="einkauf-item-price">€${parseFloat(product.price).toFixed(2)}</div>
        </div>
        <div class="einkauf-cart-qty">
          <button class="einkauf-qty-btn" onclick="updateCartEinkauf('${productId}', -1)">−</button>
          <span class="einkauf-qty-value">${qty}</span>
          <button class="einkauf-qty-btn" onclick="updateCartEinkauf('${productId}', 1)">+</button>
        </div>
        <button class="einkauf-remove-btn" onclick="removeCartEinkauf('${productId}')">🗑️</button>
      </div>
    `;
  });

  // Kuren
  cartKuren.forEach((item, kurId) => {
    const kur = item.kur;
    const qty = item.qty;
    const kurPrice = kur.price || 49.90;
    subtotal += kurPrice * qty;
    
    html += `
      <div class="einkauf-item einkauf-item-kur">
        <div class="einkauf-item-icon" onclick="openKurKatalogDetail('${kurId}')">${kur.icon}</div>
        <div class="einkauf-item-info" onclick="openKurKatalogDetail('${kurId}')">
          <div class="einkauf-item-name">${kur.name}</div>
          <div class="einkauf-item-brand">🌿 ${kur.duration} Tage Kur</div>
          <div class="einkauf-item-price">€${kurPrice.toFixed(2)}</div>
        </div>
        <div class="einkauf-cart-qty">
          <button class="einkauf-qty-btn" onclick="updateKurCartEinkauf('${kurId}', -1)">−</button>
          <span class="einkauf-qty-value">${qty}</span>
          <button class="einkauf-qty-btn" onclick="updateKurCartEinkauf('${kurId}', 1)">+</button>
        </div>
        <button class="einkauf-remove-btn" onclick="removeKurCartEinkauf('${kurId}')">🗑️</button>
      </div>
    `;
  });
  
  // Pending Abos im Warenkorb
  subscriptions.forEach((sub, productId) => {
    if (sub.status !== 'pending') return;
    
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    const originalPrice = parseFloat(product.price) * (sub.quantity || 1);
    const aboPrice = sub.price;
    subtotal += aboPrice;
    
    const qtyText = sub.quantity > 1 ? `${sub.quantity}× ` : '';
    const intervalText = sub.frequency || 'Monatlich';
    
    html += `
      <div class="einkauf-item einkauf-item-abo">
        <div class="einkauf-item-icon" onclick="openProductDetail('${productId}')">${product.icon}</div>
        <div class="einkauf-item-info" onclick="openProductDetail('${productId}')">
          <div class="einkauf-item-name">${qtyText}${product.name}</div>
          <div class="einkauf-item-abo-badge">🔄 Abo • ${intervalText} • 8% Rabatt</div>
          <div class="einkauf-item-prices">
            <span class="einkauf-item-price-old">€${originalPrice.toFixed(2)}</span>
            <span class="einkauf-item-price-abo">€${aboPrice.toFixed(2)}</span>
          </div>
        </div>
        <button class="einkauf-remove-btn" onclick="removeAboFromCart('${productId}')">🗑️</button>
      </div>
    `;
  });
  
  content.innerHTML = html;
  
  const shipping = subtotal >= 49 ? 0 : 4.90;
  const total = subtotal + shipping;
  
  summaryEl.innerHTML = `
    <div class="einkauf-summary-row">
      <span data-i18n="cart.subtotal">Zwischensumme</span>
      <span>€${subtotal.toFixed(2)}</span>
    </div>
    <div class="einkauf-summary-row">
      <span data-i18n="cart.shipping">Versand</span>
      <span>${shipping === 0 ? 'Kostenlos ✓' : '€' + shipping.toFixed(2)}</span>
    </div>
    ${subtotal < 49 ? `<div class="einkauf-summary-row shipping-hint">Noch €${(49 - subtotal).toFixed(2)} bis kostenloser Versand</div>` : ''}
    <div class="einkauf-summary-row total">
      <span data-i18n="cart.total">Warenkorb Gesamt</span>
      <span>€${total.toFixed(2)}</span>
    </div>
  `;
}

function renderEinkaufAbos() {
  const content = document.getElementById('einkaufAboContent');
  const countEl = document.getElementById('einkaufAboCount');
  
  // Sync remaining values
  syncSubscriptionsWithAutoReplen();
  
  // Count only active abos (not pending)
  let activeAboCount = 0;
  subscriptions.forEach(sub => {
    if (sub.status !== 'pending') activeAboCount++;
  });
  
  if (countEl) countEl.textContent = activeAboCount;
  
  if (activeAboCount === 0) {
    content.innerHTML = `
      <div class="einkauf-empty">
        <div class="einkauf-empty-icon">🔄</div>
        <div class="einkauf-empty-text">Spare mit regelmäßigen Lieferungen!</div>
        <button class="einkauf-empty-btn" onclick="switchScreen('productsScreen')">Abo starten</button>
      </div>
    `;
    return;
  }
  
  let html = '';
  
  subscriptions.forEach((sub, productId) => {
    // Skip pending abos - they show in cart
    if (sub.status === 'pending') return;
    
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    // Check if waiting for delivery
    const supp = mySupplements.find(s => s.id === productId);
    const isWaiting = supp?.status === 'waiting';
    
    // Dynamic interval text
    let intervalText = sub.frequency || 'Monatlich';
    if (sub.intervalMonths === 2) intervalText = 'Alle 2 Monate';
    else if (sub.intervalMonths === 3) intervalText = 'Alle 3 Monate';
    else if (sub.interval === 'dynamic' && sub.daysSupply) {
      const weeks = Math.round(sub.daysSupply / 7);
      intervalText = `Alle ~${weeks} Wochen`;
    }
    
    // Quantity text
    const qtyText = sub.quantity > 1 ? `${sub.quantity}× ` : '';
    
    // Aktives Abo
    const autoItem = typeof autoReplenItems !== 'undefined' ? autoReplenItems.get(productId) : null;
    const remaining = autoItem ? autoItem.remaining : (sub.remaining || 50);
    const levelClass = remaining > 50 ? 'high' : remaining > 25 ? 'medium' : 'low';
    
    if (isWaiting) {
      // Waiting for delivery - show special card
      html += `
        <div class="einkauf-abo-item waiting" style="background: linear-gradient(135deg, #eff6ff, #dbeafe); border: 2px dashed #3b82f6;">
          <div class="einkauf-item-icon">${product.icon}</div>
          <div class="einkauf-abo-info">
            <div class="einkauf-abo-name">${qtyText}${product.name}</div>
            <div class="einkauf-abo-details">
              <span>📦 Warte auf Lieferung</span>
            </div>
          </div>
          <div class="einkauf-abo-right" style="flex-direction: column; gap: 8px;">
            <button class="order-delivered-btn" onclick="event.stopPropagation(); markAboArrived('${productId}')">
              ✅ Ist angekommen
            </button>
          </div>
        </div>
      `;
    } else {
      // Regular active abo
      html += `
        <div class="einkauf-abo-item" onclick="openProductDetail('${productId}')">
          <div class="einkauf-item-icon">${product.icon}</div>
          <div class="einkauf-abo-info">
            <div class="einkauf-abo-name">${qtyText}${product.name}</div>
            <div class="einkauf-abo-details">
              <span>🔄 ${intervalText}</span>
              <span>📅 ${sub.nextDelivery}</span>
            </div>
            <div class="einkauf-abo-progress">
              <div class="einkauf-abo-progress-bar ${levelClass}" style="width: ${remaining}%"></div>
              <span class="einkauf-abo-remaining">${remaining}% übrig</span>
            </div>
          </div>
          <div class="einkauf-abo-right">
            <div class="einkauf-abo-price">
              <div class="einkauf-abo-price-value">€${sub.price.toFixed(2)}</div>
              <div class="einkauf-abo-price-interval">pro Lieferung</div>
            </div>
            <span class="einkauf-abo-status ${sub.status}">${sub.status === 'active' ? '✓ Aktiv' : '⏸️ Pausiert'}</span>
          </div>
        </div>
    `;
    }
  });
  
  content.innerHTML = html;
}

function renderPendingOrders() {
  const section = document.getElementById('einkaufOrdersSection');
  const content = document.getElementById('einkaufOrdersContent');
  const countEl = document.getElementById('einkaufOrdersCount');
  
  if (!section || !content) return;
  
  const orderCount = pendingOrders.size;
  if (countEl) countEl.textContent = orderCount;
  
  if (orderCount === 0) {
    section.style.display = 'none';
    return;
  }
  
  section.style.display = 'block';
  
  let html = '';
  
  pendingOrders.forEach((order, orderId) => {
    const itemsList = order.items.map(item => 
      `${item.qty > 1 ? item.qty + '× ' : ''}${item.name}${item.isAbo ? ' (Abo)' : ''}`
    ).join(', ');
    
    const firstItem = order.items[0];
    const moreCount = order.items.length - 1;
    
    var invoiceBtn = '';
    if (order.dbId && order.invoiceLexofficeId) {
      invoiceBtn = '<button onclick="downloadInvoice(\'' + order.dbId + '\')" style="font-size:11px;padding:4px 10px;border:1px solid var(--border);border-radius:6px;background:white;cursor:pointer;margin-right:6px">Rechnung</button>';
    }

    html += `
      <div class="einkauf-order-item">
        <div class="order-icon">📦</div>
        <div class="order-info">
          <div class="order-title">${firstItem.name}${moreCount > 0 ? ` +${moreCount} weitere` : ''}</div>
          <div class="order-meta">
            <span>Bestellt am ${order.orderDate}</span>
            <span>€${order.total.toFixed(2)}</span>
          </div>
        </div>
        <div style="display:flex;align-items:center;gap:4px">
          ${invoiceBtn}
          <button class="order-delivered-btn" onclick="markOrderDelivered('${orderId}')">
            ✓ Angekommen
          </button>
        </div>
      </div>
    `;
  });
  
  content.innerHTML = html;
}

// Rechnung als PDF aus lexoffice laden
async function downloadInvoice(dbOrderId) {
  if (!supabase || !currentUser) { showToast('Bitte einloggen'); return; }
  showToast('Rechnung wird geladen...');
  try {
    var token = (await supabase.auth.getSession()).data.session?.access_token || '';
    var res = await fetch(SUPPTREE_CONFIG.SUPABASE_URL + '/functions/v1/get-invoice-pdf', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
      body: JSON.stringify({ orderId: dbOrderId })
    });
    if (res.headers.get('content-type')?.includes('application/pdf')) {
      // PDF direkt als Blob empfangen und herunterladen
      var blob = await res.blob();
      var url = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = url;
      a.download = 'Rechnung-' + dbOrderId.substring(0, 8) + '.pdf';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      showToast('Rechnung heruntergeladen');
    } else {
      var data = await res.json();
      showToast(data.error || 'Rechnung nicht verfügbar', 'error');
    }
  } catch (e) {
    console.error('Invoice download error:', e);
    showToast('Rechnung konnte nicht geladen werden', 'error');
  }
}

function markOrderDelivered(orderId) {
  const order = pendingOrders.get(orderId);
  if (!order) return;
  
  // Produkte zum "Angekommen"-Dialog vorbereiten
  const itemsToAdd = order.items.filter(item => {
    // Prüfen ob bereits in Supps
    if (!mySupplements) return true;
    return !mySupplements.some(s => s.id === item.productId);
  });
  
  // Alle existierenden Supplements sammeln für Arrived-Dialog (Robur)
  const arrivedIds = [];
  if (mySupplements) {
    order.items.forEach(item => {
      const supp = mySupplements.find(s => s.id === item.productId);
      if (supp) {
        // Stock auffüllen & Status auf waiting setzen für Arrived-Dialog
        supp.status = 'waiting';
        arrivedIds.push(item.productId);
      }
    });
    if (arrivedIds.length > 0) saveMySupplements();
  }

  // Supabase: Status auf 'delivered' setzen
  if (order.dbId && supabase && currentUser) {
    supabase.from('orders').update({ status: 'delivered' }).eq('id', order.dbId)
      .then(function(res) { if (res.error) console.error('Order deliver update error:', res.error); })
      .catch(function(e) { console.error('Order deliver update:', e); });
  }

  // Bestellung als geliefert markieren und entfernen
  pendingOrders.delete(orderId);
  savePendingOrders();
  renderPendingOrders();
  try { renderEinkaufAbos(); } catch(e) {}

  if (itemsToAdd.length === 0 && arrivedIds.length === 0) {
    showToast('📦 Lieferung bestätigt!');
    return;
  }

  // Wenn nur existierende Items (kein neues Produkt), direkt Arrived-Dialog starten
  if (itemsToAdd.length === 0 && arrivedIds.length > 0) {
    _waitingSuppQueue = arrivedIds;
    processWaitingSuppQueue();
    return;
  }
  
  // Dialog anzeigen
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:100001;display:flex;align-items:center;justify-content:center;padding:20px;';
  modal.id = 'deliveryModal';

  const itemsHtml = itemsToAdd.map(item => `
    <div class="delivery-item" style="display: flex; align-items: center; gap: 12px; padding: 10px; background: var(--cream); border-radius: 7px; margin-bottom: 8px;">
      <span style="font-size: 24px;">${item.icon}</span>
      <div style="flex: 1;">
        <div style="font-weight: 600;">${item.name}</div>
        <div style="font-size: 12px; color: var(--text-muted);">${item.brand}</div>
      </div>
      <label style="display: flex; align-items: center; gap: 8px;">
        <input type="checkbox" checked data-product-id="${item.productId}" data-dose="${item.dosePerDay || 1}" class="delivery-checkbox" style="width: 20px; height: 20px;">
      </label>
    </div>
  `).join('');

  modal.innerHTML = `
    <div style="background:white;border-radius:14px;max-width:340px;width:100%;padding:32px 24px;text-align:center;box-shadow:0 20px 60px rgba(0,0,0,0.3);max-height:80vh;overflow-y:auto;">
      <div style="font-size:48px;margin-bottom:12px;">📦</div>
      <h3 style="font-size:20px;font-weight:700;margin:0 0 8px;">Lieferung angekommen!</h3>
      <p style="margin-bottom: 16px; color: var(--text-muted);">Welche Produkte möchtest du zum Einnahme-Planer hinzufügen?</p>
      
      <div style="margin-bottom: 20px;">
        ${itemsHtml}
      </div>
      
      <div style="display: flex; flex-direction: column; gap: 10px;">
        <button id="addSelectedToSupps" style="padding: 14px; background: linear-gradient(135deg, var(--green-accent), #34d399); color: white; border: none; border-radius: 7px; font-weight: 600; cursor: pointer;">
          ✅ Ausgewählte zum Planer hinzufügen
        </button>
        <button id="skipAddToSupps" style="padding: 14px; background: var(--cream); color: var(--text-dark); border: none; border-radius: 7px; font-weight: 500; cursor: pointer;">
          Überspringen
        </button>
      </div>
    </div>
  `;
  
  document.body.appendChild(modal);
  
  // Event Listeners
  document.getElementById('addSelectedToSupps').onclick = function() {
    const checkboxes = modal.querySelectorAll('.delivery-checkbox:checked');
    let addedCount = 0;
    
    // Always load fresh from localStorage
    const saved = localStorage.getItem('suppTreeMySupplements');
    if (saved) {
      mySupplements = JSON.parse(saved);
    } else if (!mySupplements) {
      mySupplements = [];
    }
    
    
    checkboxes.forEach(cb => {
      const productId = cb.dataset.productId;
      const dosePerDay = parseInt(cb.dataset.dose) || 1;
      const item = itemsToAdd.find(i => i.productId === productId);
      
      
      if (item) {
        // Check if already exists
        const exists = mySupplements.some(s => s.id === item.productId);
        if (!exists) {
          // Use consistent structure with demo supplements
          const packSize = 60; // Default
          mySupplements.push({
            id: item.productId,
            name: item.name,
            icon: item.icon,
            brand: item.brand,
            dosagePerDay: dosePerDay,
            stock: packSize,
            packSize: packSize,
            source: 'shop',
            time: 'auto',
            autoAbo: item.isAbo || false,
            roburScheduled: true,
            hasAbo: item.isAbo || false,
            notes: item.isAbo ? 'Abo-Produkt' : ''
          });
          addedCount++;
        }
      }
    });
    
    
    if (addedCount > 0) {
      saveMySupplements();
      // Update calendar with new supplements
      try { updateAllScheduledIntakes(); } catch(e) {}
      showToast(`✅ ${addedCount} Produkt${addedCount > 1 ? 'e' : ''} zum Planer hinzugefügt!`);
      try { renderMySupplements(); } catch(e) {}
      try { renderMeinSuppsOverview(); } catch(e) {}
    }
    
    modal.remove();
    // Existierende Supplements durch Arrived-Dialog führen
    if (arrivedIds.length > 0) {
      _waitingSuppQueue = arrivedIds;
      setTimeout(() => processWaitingSuppQueue(), 400);
    }
  };

  document.getElementById('skipAddToSupps').onclick = function() {
    modal.remove();
    // Existierende Supplements durch Arrived-Dialog führen
    if (arrivedIds.length > 0) {
      _waitingSuppQueue = arrivedIds;
      setTimeout(() => processWaitingSuppQueue(), 400);
    } else {
      showToast('📦 Lieferung bestätigt!');
    }
  };
}

function removeAboFromCart(productId) {
  subscriptions.delete(productId);
  saveSubscriptions();
  renderEinkaufCart();
  renderEinkaufAbos();
  updateAllBadges();
  updateEinkaufCheckoutBar();
  
  // Update subscribe button if viewing this product
  if (currentProduct && currentProduct.id === productId) {
    updateSubscribeButtonState();
  }
  
  showToast('Abo entfernt');
}

function updateEinkaufCheckoutBar() {
  const bar = document.getElementById('einkaufCheckoutBar');
  const totalEl = document.getElementById('einkaufCheckoutTotal');
  const itemsEl = document.getElementById('einkaufCheckoutItems');
  
  // Check for pending abos
  let pendingAboCount = 0;
  subscriptions.forEach(sub => {
    if (sub.status === 'pending') pendingAboCount++;
  });
  
  if (cart.size === 0 && cartKuren.size === 0 && pendingAboCount === 0) {
    bar.classList.remove('visible');
    return;
  }
  
  let subtotal = 0;
  let totalItems = 0;
  
  // Reguläre Produkte
  cart.forEach((qty, productId) => {
    const product = products.find(p => p.id === productId);
    if (product) {
      subtotal += parseFloat(product.price) * qty;
      totalItems += qty;
    }
  });
  
  // Kuren
  cartKuren.forEach((item, kurId) => {
    const kurPrice = item.kur.price || 49.90;
    subtotal += kurPrice * item.qty;
    totalItems += item.qty;
  });
  
  // Pending Abos
  subscriptions.forEach((sub, productId) => {
    if (sub.status === 'pending') {
      subtotal += sub.price;
      totalItems += 1;
    }
  });
  
  const shipping = subtotal >= 49 ? 0 : 4.90;
  const total = subtotal + shipping;
  
  totalEl.textContent = '€' + total.toFixed(2);
  itemsEl.textContent = totalItems + ' Artikel';
  bar.classList.add('visible');
}

function updateNavEinkaufBadge() {
  updateNavPackageIcon();
  updateNavHeartIcon();
}

// Einkauf Screen Actions
function addFavToCartEinkauf(productId) {
  quickAddToCart(productId);
  renderEinkaufFavorites();
  renderEinkaufCart();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
}

function addAllFavsToCartEinkauf() {
  favorites.forEach(productId => {
    if (!cart.has(productId)) {
      quickAddToCart(productId);
    }
  });
  renderEinkaufFavorites();
  renderEinkaufCart();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
  showToast('Alle Favoriten hinzugefügt!');
}

function removeFavEinkauf(productId) {
  favorites.delete(productId);
  favCount = favorites.size;
  saveFavorites();
  updateAllBadges();
  renderEinkaufFavorites();
  renderProductsGridNew();
  updateNavEinkaufBadge();
  showToast('Aus Favoriten entfernt');
}

function updateCartEinkauf(productId, delta) {
  const currentQty = cart.get(productId) || 0;
  const newQty = currentQty + delta;
  
  if (newQty <= 0) {
    removeCartEinkauf(productId);
    return;
  }
  
  cart.set(productId, newQty);
  cartCount += delta;
  saveCart();
  updateAllBadges();
  renderEinkaufCart();
  renderEinkaufFavorites();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
}

function removeCartEinkauf(productId) {
  const qty = cart.get(productId) || 0;
  cart.delete(productId);
  cartCount -= qty;
  saveCart();
  // Referral entfernen wenn vorhanden
  if (cartReferrals.has(productId)) {
    cartReferrals.delete(productId);
    saveCartReferrals();
  }
  updateAllBadges();
  renderEinkaufCart();
  renderEinkaufFavorites();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
  showToast('Aus Warenkorb entfernt');
}

// Kuren im Warenkorb
function updateKurCartEinkauf(kurId, delta) {
  const item = cartKuren.get(kurId);
  if (!item) return;
  
  const newQty = item.qty + delta;
  
  if (newQty <= 0) {
    removeKurCartEinkauf(kurId);
    return;
  }
  
  item.qty = newQty;
  cartCount += delta;
  updateAllBadges();
  renderEinkaufCart();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
}

function removeKurCartEinkauf(kurId) {
  const item = cartKuren.get(kurId);
  if (!item) return;
  
  cartCount -= item.qty;
  cartKuren.delete(kurId);
  updateAllBadges();
  renderEinkaufCart();
  updateEinkaufCheckoutBar();
  updateNavEinkaufBadge();
  showToast('Kur aus Warenkorb entfernt');
}

// ===============================
// CHECKOUT SYSTEM
// ===============================
let checkoutState = {
  step: 1,
  subtotal: 0,
  shipping: 0,
  shippingType: 'standard',
  pointsDiscount: 0,
  usePoints: false,
  hasAboItems: false,
  aboSavings: 0,
  selectedAddressIndex: -1,
  selectedAddress: null,
  selectedPaymentIndex: -1,
  selectedPayment: null,
  agbAccepted: false,
  widerrufAccepted: false,
  itemsHtml: ''
};

function startCheckout() {
  // Login erforderlich für Checkout
  if (!requireLogin('🔐 Bitte melde dich an, um zu bestellen')) return;

  // Calculate cart totals
  let subtotal = 0;
  let itemCount = 0;
  let hasAboItems = false;
  
  // Count pending abos
  let pendingAboCount = 0;
  subscriptions.forEach(sub => {
    if (sub.status === 'pending') pendingAboCount++;
  });
  
  // Check if cart has items
  if (cart.size === 0 && cartKuren.size === 0 && pendingAboCount === 0) {
    showToast('Dein Warenkorb ist leer!');
    return;
  }
  
  // Build items list HTML
  let itemsHtml = '';
  
  // Regular cart items
  cart.forEach((qty, productId) => {
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    const itemTotal = parseFloat(product.price) * qty;
    subtotal += itemTotal;
    itemCount += qty;
    
    itemsHtml += `
      <div class="checkout-item">
        <div class="checkout-item-icon">${product.icon}</div>
        <div class="checkout-item-info">
          <div class="checkout-item-name">${escapeHtml(product.name)}</div>
          <div class="checkout-item-meta">${qty}x €${parseFloat(product.price).toFixed(2)}</div>
        </div>
        <div class="checkout-item-price">€${itemTotal.toFixed(2)}</div>
      </div>
    `;
  });
  
  // Kuren items
  cartKuren.forEach((item, kurId) => {
    const kur = item.kur;
    const qty = item.qty;
    const kurPrice = kur.price || 49.90;
    const itemTotal = kurPrice * qty;
    subtotal += itemTotal;
    itemCount += qty;
    
    itemsHtml += `
      <div class="checkout-item">
        <div class="checkout-item-icon">${kur.icon}</div>
        <div class="checkout-item-info">
          <div class="checkout-item-name">${escapeHtml(kur.name)}</div>
          <div class="checkout-item-meta">🌿 ${kur.duration} Tage Kur • ${qty}x €${kurPrice.toFixed(2)}</div>
        </div>
        <div class="checkout-item-price">€${itemTotal.toFixed(2)}</div>
      </div>
    `;
  });
  
  // Pending Abo items only (not active ones)
  let aboSavings = 0;
  
  subscriptions.forEach((sub, productId) => {
    if (sub.status !== 'pending') return;
    
    const product = products.find(p => p.id === productId);
    if (!product) return;
    
    const qty = sub.quantity || 1;
    const originalPrice = parseFloat(product.price) * qty;
    const discountedPrice = sub.price; // Already discounted price for all quantities
    const savings = originalPrice - discountedPrice;
    aboSavings += savings;
    
    subtotal += discountedPrice;
    itemCount += qty;
    hasAboItems = true;
    
    // Quantity text
    const qtyText = qty > 1 ? `${qty}× ` : '';
    const qtyMeta = qty > 1 ? `${qty} Packungen • ` : '';
    
    itemsHtml += `
      <div class="checkout-item checkout-item-abo">
        <div class="checkout-item-icon">${product.icon}</div>
        <div class="checkout-item-info">
          <div class="checkout-item-name">${qtyText}${escapeHtml(product.name)}</div>
          <div class="checkout-item-meta">🔄 Abo • ${qtyMeta}8% Rabatt</div>
        </div>
        <div class="checkout-item-price">
          <span style="text-decoration: line-through; color: #9ca3af; font-size: 12px;">€${originalPrice.toFixed(2)}</span>
          <span style="color: var(--green-accent); font-weight: 600;">€${discountedPrice.toFixed(2)}</span>
        </div>
      </div>
    `;
  });
  
  // Store abo savings
  checkoutState.aboSavings = aboSavings;

  // Calculate shipping (standard default)
  const shipping = subtotal >= 49 ? 0 : 4.90;

  // Store state
  checkoutState.subtotal = subtotal;
  checkoutState.shipping = shipping;
  checkoutState.shippingType = 'standard';
  checkoutState.pointsDiscount = 0;
  checkoutState.usePoints = false;
  checkoutState.hasAboItems = hasAboItems;
  checkoutState.itemsHtml = itemsHtml;

  // Reset multi-step state
  checkoutState.step = 1;
  checkoutState.agbAccepted = false;
  checkoutState.widerrufAccepted = false;

  // Pre-select default address
  const addresses = coGetAddresses();
  const defaultAddrIdx = addresses.findIndex(a => a.isDefault);
  if (defaultAddrIdx !== -1) {
    checkoutState.selectedAddressIndex = defaultAddrIdx;
    checkoutState.selectedAddress = addresses[defaultAddrIdx];
  } else if (addresses.length > 0) {
    checkoutState.selectedAddressIndex = 0;
    checkoutState.selectedAddress = addresses[0];
  } else {
    checkoutState.selectedAddressIndex = -1;
    checkoutState.selectedAddress = null;
  }

  // Pre-select default payment
  const payments = coGetPayments();
  const defaultPayIdx = payments.findIndex(m => m.isDefault);
  if (defaultPayIdx !== -1) {
    checkoutState.selectedPaymentIndex = defaultPayIdx;
    checkoutState.selectedPayment = payments[defaultPayIdx];
  } else if (payments.length > 0) {
    checkoutState.selectedPaymentIndex = 0;
    checkoutState.selectedPayment = payments[0];
  } else {
    checkoutState.selectedPaymentIndex = -1;
    checkoutState.selectedPayment = null;
  }

  // Open full-screen checkout at step 1
  coGoToStep(1);
  document.getElementById('coFullscreen').classList.add('visible');
  lockBody();
}

function closeCheckout() {
  document.getElementById('coFullscreen').classList.remove('visible');
  unlockBody();
  // Reset checkboxes
  const agb = document.getElementById('coAgbCheckbox');
  const wid = document.getElementById('coWiderrufCheckbox');
  const aboCb = document.getElementById('coAboCheckbox');
  if (agb) agb.checked = false;
  if (wid) wid.checked = false;
  if (aboCb) aboCb.checked = false;
}

// ===== MULTI-STEP CHECKOUT NAVIGATION =====

function coGoToStep(step) {
  checkoutState.step = step;

  // Update stepper indicators
  for (let i = 1; i <= 4; i++) {
    const el = document.getElementById('coStep' + i);
    if (!el) continue;
    el.classList.remove('active', 'completed');
    if (i < step) el.classList.add('completed');
    if (i === step) el.classList.add('active');
  }

  // Show/hide panels
  for (let i = 1; i <= 4; i++) {
    const panel = document.getElementById('coPanel' + i);
    if (panel) panel.classList.toggle('active', i === step);
  }

  // Update header title
  const titles = { 1: 'Lieferadresse', 2: 'Versandart', 3: 'Zahlungsmethode', 4: 'Bestellung prüfen' };
  document.getElementById('coHeaderTitle').textContent = titles[step] || 'Kasse';

  // Show/hide back button
  document.getElementById('coBackBtn').style.visibility = step === 1 ? 'hidden' : 'visible';

  // Toggle footer buttons
  document.getElementById('coNextBtn').style.display = step < 4 ? 'block' : 'none';
  document.getElementById('coOrderBtn').style.display = step === 4 ? 'block' : 'none';

  // Render step content
  if (step === 1) coRenderAddresses();
  if (step === 2) coRenderShipping();
  if (step === 3) coRenderPayments();
  if (step === 4) coRenderSummary();

  // Scroll to top
  const body = document.getElementById('coBody');
  if (body) body.scrollTop = 0;
}

function coNextStep() {
  const step = checkoutState.step;

  if (step === 1 && !checkoutState.selectedAddress) {
    showToast('Bitte wähle eine Lieferadresse');
    return;
  }
  if (step === 3 && !checkoutState.selectedPayment) {
    showToast('Bitte wähle eine Zahlungsmethode');
    return;
  }

  if (step < 4) coGoToStep(step + 1);
}

function coGoBack() {
  if (checkoutState.step > 1) {
    coGoToStep(checkoutState.step - 1);
  } else {
    closeCheckout();
  }
}

// ===== STEP 1: LIEFERADRESSE =====

function coGetAddresses() {
  const saved = localStorage.getItem('suppTreeAddresses');
  return saved ? JSON.parse(saved) : [
    { id: 1, label: 'Zuhause', firstName: 'Max', lastName: 'Mustermann', street: 'Musterstraße 123', extra: '', zip: '12345', city: 'Musterstadt', country: 'DE', isDefault: true },
    { id: 2, label: 'Arbeit', firstName: 'Max', lastName: 'Mustermann', street: 'Firmenweg 456', extra: '3. Etage', zip: '12345', city: 'Musterstadt', country: 'DE', isDefault: false }
  ];
}

function coRenderAddresses() {
  const addresses = coGetAddresses();
  const container = document.getElementById('coAddressList');
  if (!container) return;
  const icons = { 'Zuhause': '🏠', 'Arbeit': '🏢', 'Familie': '👨‍👩‍👧', 'Freunde': '👥', 'Neu': '📍' };

  container.innerHTML = addresses.map((addr, idx) => `
    <div class="co-selectable-card ${checkoutState.selectedAddressIndex === idx ? 'selected' : ''}" onclick="coSelectAddress(${idx})">
      <div class="co-card-icon">${icons[addr.label] || '📍'}</div>
      <div class="co-card-info">
        <span class="co-card-name">${escapeHtml(addr.label) || 'Adresse'}</span>
        <span class="co-card-detail">${escapeHtml(addr.firstName)} ${escapeHtml(addr.lastName)}</span>
        <span class="co-card-detail">${escapeHtml(addr.street)}${addr.extra ? ', ' + escapeHtml(addr.extra) : ''}</span>
        <span class="co-card-detail">${escapeHtml(addr.zip)} ${escapeHtml(addr.city)}</span>
      </div>
      <div class="co-card-check">✓</div>
    </div>
  `).join('');
}

function coSelectAddress(index) {
  const addresses = coGetAddresses();
  checkoutState.selectedAddressIndex = index;
  checkoutState.selectedAddress = addresses[index];
  coRenderAddresses();
}

function coToggleNewAddress() {
  const form = document.getElementById('coNewAddressForm');
  if (!form) return;
  const show = form.style.display === 'none';
  form.style.display = show ? 'block' : 'none';
  if (show) {
    ['coAddrFirstName','coAddrLastName','coAddrStreet','coAddrExtra','coAddrZip','coAddrCity'].forEach(id => {
      const el = document.getElementById(id);
      if (el) { el.value = ''; el.classList.remove('input-error'); }
    });
    const country = document.getElementById('coAddrCountry');
    if (country) country.value = 'DE';
  }
}

function coSaveNewAddress() {
  const required = {
    coAddrFirstName: 'Vorname',
    coAddrLastName: 'Nachname',
    coAddrStreet: 'Straße',
    coAddrZip: 'PLZ',
    coAddrCity: 'Stadt'
  };
  let hasError = false;
  Object.keys(required).forEach(id => {
    const el = document.getElementById(id);
    if (!el || !el.value.trim()) {
      if (el) el.classList.add('input-error');
      hasError = true;
    }
  });
  if (hasError) { showToast('Bitte alle Pflichtfelder ausfüllen'); return; }

  const zip = document.getElementById('coAddrZip').value.trim();
  const country = (document.getElementById('coAddrCountry') || {}).value || 'DE';
  if (country === 'DE' && !/^\d{5}$/.test(zip)) {
    document.getElementById('coAddrZip').classList.add('input-error');
    showToast('Bitte gültige PLZ eingeben (5 Ziffern)');
    return;
  }

  const saved = localStorage.getItem('suppTreeAddresses');
  let addresses = saved ? JSON.parse(saved) : [];
  const newAddr = {
    id: Date.now(),
    label: 'Neu',
    firstName: document.getElementById('coAddrFirstName').value.trim(),
    lastName: document.getElementById('coAddrLastName').value.trim(),
    street: document.getElementById('coAddrStreet').value.trim(),
    extra: (document.getElementById('coAddrExtra') || {}).value || '',
    zip: zip,
    city: document.getElementById('coAddrCity').value.trim(),
    country: country,
    isDefault: addresses.length === 0
  };
  addresses.push(newAddr);
  saveAddresses(addresses);

  checkoutState.selectedAddressIndex = addresses.length - 1;
  checkoutState.selectedAddress = newAddr;

  document.getElementById('coNewAddressForm').style.display = 'none';
  coRenderAddresses();
  showToast('Adresse gespeichert');
}

// ===== STEP 2: VERSANDART =====

function coRenderShipping() {
  const subtotal = checkoutState.subtotal;
  const standardFree = subtotal >= 49;
  const standardPrice = standardFree ? 0 : 4.90;
  const expressPrice = 9.90;

  const today = new Date();
  const addDays = (d, n) => { const r = new Date(d); r.setDate(r.getDate() + n); return r; };
  const fmt = (d) => d.getDate().toString().padStart(2,'0') + '.' + (d.getMonth()+1).toString().padStart(2,'0') + '.';

  const container = document.getElementById('coShippingOptions');
  if (!container) return;

  container.innerHTML = `
    <div class="co-shipping-option ${checkoutState.shippingType === 'standard' ? 'selected' : ''}" onclick="coSelectShipping('standard')">
      <div class="co-shipping-icon">📦</div>
      <div class="co-shipping-info">
        <div class="co-shipping-name">Standardversand</div>
        <div class="co-shipping-detail">3-5 Werktage</div>
        <div class="co-shipping-delivery">Lieferung ca. ${fmt(addDays(today,3))} – ${fmt(addDays(today,5))}</div>
      </div>
      <div class="co-shipping-price ${standardFree ? 'free' : ''}">${standardFree ? 'Kostenlos' : '€' + standardPrice.toFixed(2)}</div>
    </div>
    <div class="co-shipping-option ${checkoutState.shippingType === 'express' ? 'selected' : ''}" onclick="coSelectShipping('express')">
      <div class="co-shipping-icon">🚀</div>
      <div class="co-shipping-info">
        <div class="co-shipping-name">Expressversand</div>
        <div class="co-shipping-detail">1-2 Werktage</div>
        <div class="co-shipping-delivery">Lieferung ca. ${fmt(addDays(today,1))} – ${fmt(addDays(today,2))}</div>
      </div>
      <div class="co-shipping-price">€${expressPrice.toFixed(2)}</div>
    </div>
  `;
}

function coSelectShipping(type) {
  checkoutState.shippingType = type;
  checkoutState.shipping = type === 'express' ? 9.90 : (checkoutState.subtotal >= 49 ? 0 : 4.90);
  coRenderShipping();
}

// ===== STEP 3: ZAHLUNGSMETHODE =====

function coGetPayments() {
  const saved = localStorage.getItem('suppTreePaymentMethods');
  return saved ? JSON.parse(saved) : [
    { id: 1, type: 'paypal', name: 'PayPal', detail: 'max@example.com', isDefault: true },
    { id: 2, type: 'sepa', name: 'SEPA-Lastschrift', detail: 'DE89 •••• •••• 1234', isDefault: false }
  ];
}

// ═══ PAYMENT INTEGRATION: Stripe + PayPal ═══
var _stripe = null;
var _stripeElements = null;
var _stripeCardElement = null;
var _selectedPaymentType = 'card'; // 'card', 'paypal', 'sepa'

function initStripe() {
  if (_stripe) return _stripe;
  if (typeof Stripe !== 'undefined' && SUPPTREE_CONFIG.STRIPE_PK && !SUPPTREE_CONFIG.STRIPE_PK.includes('HIER')) {
    _stripe = Stripe(SUPPTREE_CONFIG.STRIPE_PK);
  }
  return _stripe;
}

function coRenderPayments() {
  const container = document.getElementById('coPaymentList');
  if (!container) return;

  var html = '';

  // Payment-Type Auswahl
  html += '<div style="display:flex;gap:8px;margin-bottom:16px">';
  html += '<button onclick="selectPaymentType(\'card\')" class="co-selectable-card" style="flex:1;padding:12px;text-align:center;cursor:pointer;border-radius:10px;border:2px solid ' + (_selectedPaymentType === 'card' ? 'var(--green-accent)' : 'var(--border)') + ';background:' + (_selectedPaymentType === 'card' ? '#f0fdf4' : 'white') + '"><div style="font-size:20px">💳</div><div style="font-size:11px;font-weight:600;margin-top:4px">Kreditkarte</div></button>';
  html += '<button onclick="selectPaymentType(\'paypal\')" class="co-selectable-card" style="flex:1;padding:12px;text-align:center;cursor:pointer;border-radius:10px;border:2px solid ' + (_selectedPaymentType === 'paypal' ? '#0070ba' : 'var(--border)') + ';background:' + (_selectedPaymentType === 'paypal' ? '#f0f8ff' : 'white') + '"><div style="font-size:20px">🅿️</div><div style="font-size:11px;font-weight:600;margin-top:4px">PayPal</div></button>';
  html += '<button onclick="selectPaymentType(\'sepa\')" class="co-selectable-card" style="flex:1;padding:12px;text-align:center;cursor:pointer;border-radius:10px;border:2px solid ' + (_selectedPaymentType === 'sepa' ? 'var(--green-accent)' : 'var(--border)') + ';background:' + (_selectedPaymentType === 'sepa' ? '#f0fdf4' : 'white') + '"><div style="font-size:20px">🏦</div><div style="font-size:11px;font-weight:600;margin-top:4px">SEPA</div></button>';
  html += '</div>';

  // Stripe Card Element
  if (_selectedPaymentType === 'card') {
    html += '<div id="stripeCardContainer" style="background:white;border:1px solid var(--border);border-radius:10px;padding:14px">';
    html += '<div id="stripe-card-element" style="min-height:40px"></div>';
    html += '<div id="stripe-card-errors" style="color:#dc2626;font-size:12px;margin-top:8px"></div>';
    html += '</div>';
    html += '<div style="font-size:11px;color:var(--text-muted);margin-top:8px;text-align:center">🔒 Sichere Zahlung via Stripe</div>';
  }

  // PayPal Info
  if (_selectedPaymentType === 'paypal') {
    html += '<div style="background:#fff8e1;border:1px solid #ffd54f;border-radius:10px;padding:16px;text-align:center">';
    html += '<div style="font-size:13px;color:#5d4037">Du wirst im letzten Schritt zu PayPal weitergeleitet.</div>';
    html += '</div>';
  }

  // SEPA
  if (_selectedPaymentType === 'sepa') {
    html += '<div id="stripeSepaContainer" style="background:white;border:1px solid var(--border);border-radius:10px;padding:14px">';
    html += '<div id="stripe-iban-element" style="min-height:40px"></div>';
    html += '<div id="stripe-iban-errors" style="color:#dc2626;font-size:12px;margin-top:8px"></div>';
    html += '</div>';
    html += '<div style="font-size:10px;color:var(--text-muted);margin-top:8px">Durch Angabe deiner IBAN erteilst du SuppTree GmbH ein SEPA-Lastschriftmandat.</div>';
  }

  container.innerHTML = html;
  checkoutState.selectedPayment = { type: _selectedPaymentType, name: _selectedPaymentType === 'card' ? 'Kreditkarte' : _selectedPaymentType === 'paypal' ? 'PayPal' : 'SEPA', detail: _selectedPaymentType === 'card' ? 'Stripe' : _selectedPaymentType === 'paypal' ? 'PayPal Express' : 'Lastschrift' };

  // Stripe Elements mounten (nach DOM-Update)
  setTimeout(function() {
    if (_selectedPaymentType === 'card') mountStripeCard();
    if (_selectedPaymentType === 'sepa') mountStripeIban();
  }, 50);
}

function selectPaymentType(type) {
  _selectedPaymentType = type;
  coRenderPayments();
}

function mountStripeCard() {
  var stripe = initStripe();
  if (!stripe) {
    var el = document.getElementById('stripe-card-element');
    if (el) el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">Stripe wird geladen... (API Key in config.js setzen)</div>';
    return;
  }
  _stripeElements = stripe.elements({ locale: 'de' });
  _stripeCardElement = _stripeElements.create('card', {
    style: {
      base: { fontSize: '16px', color: '#1e293b', fontFamily: 'system-ui, -apple-system, sans-serif', '::placeholder': { color: '#94a3b8' } },
      invalid: { color: '#dc2626' }
    }
  });
  _stripeCardElement.mount('#stripe-card-element');
  _stripeCardElement.on('change', function(e) {
    var errEl = document.getElementById('stripe-card-errors');
    if (errEl) errEl.textContent = e.error ? e.error.message : '';
  });
}

function mountStripeIban() {
  var stripe = initStripe();
  if (!stripe) return;
  _stripeElements = stripe.elements({ locale: 'de' });
  var ibanElement = _stripeElements.create('iban', {
    supportedCountries: ['SEPA'],
    style: { base: { fontSize: '16px', color: '#1e293b', '::placeholder': { color: '#94a3b8' } } }
  });
  ibanElement.mount('#stripe-iban-element');
}

function coSelectPayment(index) {
  // Legacy-Kompatibilität
  checkoutState.selectedPaymentIndex = index;
}

function coToggleNewPayment() {
  // Nicht mehr benötigt mit neuer Payment-UI
}

function coAddPayment(type) {
  selectPaymentType(type === 'card' || type === 'credit' ? 'card' : type);
}

// ═══ PAYMENT PROCESSING ═══
async function processPayment(amount, orderId, description, type) {
  if (_selectedPaymentType === 'paypal') {
    return processPayPalPayment(amount, orderId, description, type);
  }
  return processStripePayment(amount, orderId, description, type);
}

async function processStripePayment(amount, orderId, description, type) {
  var stripe = initStripe();
  if (!stripe) throw new Error('Stripe nicht verfügbar. Bitte API Key in config.js setzen.');

  // 1. PaymentIntent via Edge Function erstellen
  var email = currentUser ? (currentUser.email || '') : '';
  var res = await fetch(SUPPTREE_CONFIG.SUPABASE_URL + '/functions/v1/create-payment', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + (supabase ? (await supabase.auth.getSession()).data.session?.access_token : ''),
    },
    body: JSON.stringify({ amount: amount, orderId: orderId, customerEmail: email, description: description, type: type || 'product' })
  });
  var data = await res.json();
  if (data.error) throw new Error(data.error);

  // 2. Payment bestätigen mit Stripe.js
  var result;
  if (_selectedPaymentType === 'card' && _stripeCardElement) {
    result = await stripe.confirmCardPayment(data.clientSecret, {
      payment_method: { card: _stripeCardElement }
    });
  } else {
    result = await stripe.confirmPayment({
      clientSecret: data.clientSecret,
      confirmParams: { return_url: window.location.origin + '/checkout-success' },
      redirect: 'if_required'
    });
  }

  if (result.error) throw new Error(result.error.message);
  return { success: true, paymentIntentId: data.paymentIntentId };
}

async function processPayPalPayment(amount, orderId, description, type) {
  if (typeof paypal === 'undefined') throw new Error('PayPal nicht verfügbar. Bitte Client ID in config.js setzen.');

  return new Promise(function(resolve, reject) {
    // PayPal Button in Modal rendern
    var overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:999999;display:flex;align-items:center;justify-content:center';
    var modal = document.createElement('div');
    modal.style.cssText = 'background:white;border-radius:16px;padding:24px;max-width:400px;width:90%';
    modal.innerHTML = '<div style="text-align:center;margin-bottom:16px"><div style="font-size:16px;font-weight:700">PayPal Zahlung</div><div style="font-size:13px;color:var(--text-muted)">€' + amount.toFixed(2) + '</div></div><div id="paypal-button-container"></div><button onclick="this.closest(\'div[style]\').remove()" style="width:100%;padding:10px;margin-top:12px;border:1px solid var(--border);border-radius:8px;background:white;cursor:pointer;font-size:13px">Abbrechen</button>';
    overlay.appendChild(modal);
    overlay.onclick = function(e) { if (e.target === overlay) { overlay.remove(); reject(new Error('Abgebrochen')); } };
    document.body.appendChild(overlay);

    paypal.Buttons({
      style: { layout: 'vertical', color: 'gold', shape: 'rect', label: 'pay' },
      createOrder: function(data, actions) {
        return actions.order.create({
          purchase_units: [{ amount: { value: amount.toFixed(2), currency_code: 'EUR' }, description: description || 'SuppTree Bestellung' }]
        });
      },
      onApprove: function(data) {
        overlay.remove();
        // PayPal Order server-side capturen
        fetch(SUPPTREE_CONFIG.SUPABASE_URL + '/functions/v1/capture-paypal', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ paypalOrderId: data.orderID, orderId: orderId })
        }).then(function(r) { return r.json(); })
          .then(function(result) {
            if (result.success) resolve({ success: true, paypalOrderId: data.orderID });
            else reject(new Error(result.error || 'PayPal Capture fehlgeschlagen'));
          })
          .catch(reject);
      },
      onCancel: function() { overlay.remove(); reject(new Error('PayPal Zahlung abgebrochen')); },
      onError: function(err) { overlay.remove(); reject(err); }
    }).render('#paypal-button-container');
  });
}

// ===== STEP 4: ZUSAMMENFASSUNG & LEGAL =====

function coRenderSummary() {
  // Items
  const itemsList = document.getElementById('coItemsList');
  if (itemsList) itemsList.innerHTML = checkoutState.itemsHtml;

  // Address
  const addr = checkoutState.selectedAddress;
  const addrEl = document.getElementById('coSummaryAddress');
  if (addrEl && addr) {
    addrEl.innerHTML = `${escapeHtml(addr.firstName)} ${escapeHtml(addr.lastName)}<br>${escapeHtml(addr.street)}${addr.extra ? ', ' + escapeHtml(addr.extra) : ''}<br>${escapeHtml(addr.zip)} ${escapeHtml(addr.city)}`;
  }

  // Shipping
  const shipEl = document.getElementById('coSummaryShipping');
  if (shipEl) {
    const name = checkoutState.shippingType === 'express' ? 'Expressversand (1-2 Werktage)' : 'Standardversand (3-5 Werktage)';
    const cost = checkoutState.shipping === 0 ? 'Kostenlos' : '€' + checkoutState.shipping.toFixed(2);
    shipEl.textContent = name + ' — ' + cost;
  }

  // Payment
  const pay = checkoutState.selectedPayment;
  const payEl = document.getElementById('coSummaryPayment');
  if (payEl && pay) {
    payEl.textContent = pay.name + ' (' + pay.detail + ')';
  }

  // Price breakdown
  const { subtotal, shipping, aboSavings } = checkoutState;
  const total = Math.max(0, subtotal + shipping);

  const subEl = document.getElementById('coSubtotal');
  if (subEl) subEl.textContent = '€' + subtotal.toFixed(2);

  const shipCostEl = document.getElementById('coShippingCost');
  if (shipCostEl) shipCostEl.textContent = shipping === 0 ? 'Kostenlos' : '€' + shipping.toFixed(2);

  const totalEl = document.getElementById('coTotal');
  if (totalEl) totalEl.textContent = '€' + total.toFixed(2);

  const savingsRow = document.getElementById('coAboSavingsRow');
  const savingsEl = document.getElementById('coAboSavings');
  if (savingsRow && aboSavings > 0) {
    savingsRow.style.display = 'flex';
    if (savingsEl) savingsEl.textContent = '-€' + aboSavings.toFixed(2);
  } else if (savingsRow) {
    savingsRow.style.display = 'none';
  }

  // Abo-Bedingungen anzeigen wenn Abos im Warenkorb
  const aboConditions = document.getElementById('coAboConditions');
  const aboConditionsText = document.getElementById('coAboConditionsText');
  const aboCheckboxLabel = document.getElementById('coAboCheckboxLabel');
  const hasAbos = checkoutState.hasAboItems;

  if (hasAbos && aboConditions && aboConditionsText) {
    let aboHtml = '';
    subscriptions.forEach((sub, productId) => {
      if (sub.status !== 'pending') return;
      const product = products.find(p => p.id === productId);
      if (!product) return;
      const qty = sub.quantity > 1 ? sub.quantity + 'x ' : '';
      aboHtml += `<div style="margin-bottom:8px;">
        <strong>${qty}${product.name}</strong><br>
        Lieferintervall: ${sub.frequency || 'Monatlich'}<br>
        Abo-Preis: &euro;${sub.price.toFixed(2)} pro Lieferung (8% Rabatt)<br>
        Jederzeit k&uuml;ndbar &mdash; keine Mindestlaufzeit
      </div>`;
    });
    aboConditionsText.innerHTML = aboHtml;
    aboConditions.style.display = 'block';
    if (aboCheckboxLabel) aboCheckboxLabel.style.display = 'flex';
  } else {
    if (aboConditions) aboConditions.style.display = 'none';
    if (aboCheckboxLabel) aboCheckboxLabel.style.display = 'none';
  }

  // Reset legal checkboxes
  const agb = document.getElementById('coAgbCheckbox');
  const wid = document.getElementById('coWiderrufCheckbox');
  const aboCb = document.getElementById('coAboCheckbox');
  if (agb) agb.checked = false;
  if (wid) wid.checked = false;
  if (aboCb) aboCb.checked = false;
  checkoutState.agbAccepted = false;
  checkoutState.widerrufAccepted = false;
  coUpdateOrderButton();
}

function coUpdateOrderButton() {
  const agb = document.getElementById('coAgbCheckbox');
  const wid = document.getElementById('coWiderrufCheckbox');
  const aboCb = document.getElementById('coAboCheckbox');
  checkoutState.agbAccepted = agb ? agb.checked : false;
  checkoutState.widerrufAccepted = wid ? wid.checked : false;

  // Abo-Checkbox nur prüfen wenn Abos im Warenkorb
  let aboOk = true;
  if (checkoutState.hasAboItems && aboCb) {
    aboOk = aboCb.checked;
  }

  const btn = document.getElementById('coOrderBtn');
  if (!btn) return;
  if (checkoutState.agbAccepted && checkoutState.widerrufAccepted && aboOk) {
    btn.disabled = false;
    btn.classList.remove('disabled');
  } else {
    btn.disabled = true;
    btn.classList.add('disabled');
  }
}

