async function placeOrder() {
  // Login erforderlich
  if (!requireLogin('🔐 Bitte melde dich an, um zu bestellen')) return;

  // Legal compliance check
  if (!checkoutState.agbAccepted || !checkoutState.widerrufAccepted) {
    showToast('Bitte akzeptiere die AGB und Widerrufsbelehrung');
    return;
  }

  const { subtotal, shipping, pointsDiscount, hasAboItems, usePoints } = checkoutState;
  const total = Math.max(0, subtotal + shipping - pointsDiscount);

  // Check if has kuren before clearing
  const hasKuren = cartKuren.size > 0;

  // Create order with all items
  const orderId = 'ORD-' + Date.now();
  const orderDate = new Date();
  const formatDate = (date) => {
    return `${date.getDate().toString().padStart(2, '0')}.${(date.getMonth() + 1).toString().padStart(2, '0')}.${date.getFullYear()}`;
  };

  const orderItems = [];

  // Add regular cart items to order
  cart.forEach((qty, productId) => {
    const product = products.find(p => p.id === productId);
    if (product) {
      orderItems.push({
        productId: productId,
        name: product.name,
        icon: product.icon,
        brand: product.brand,
        qty: qty,
        price: parseFloat(product.price),
        isAbo: false,
        dosePerDay: 1
      });
    }
  });

  // Collect pending Abos for order
  subscriptions.forEach((sub, productId) => {
    if (sub.status === 'pending') {
      const product = products.find(p => p.id === productId);
      if (product) {
        orderItems.push({
          productId: productId,
          name: product.name,
          icon: product.icon,
          brand: product.brand,
          qty: sub.quantity || 1,
          price: sub.price,
          isAbo: true,
          dosePerDay: sub.dosePerDay || 1
        });
      }
    }
  });

  if (orderItems.length === 0) {
    showToast('Warenkorb ist leer');
    return;
  }

  // Referral-Daten extrahieren
  var referralPartner = null;
  var referralChannel = null;
  var referralRate = 0;
  cartReferrals.forEach(function(ref) {
    if (!referralPartner && ref.beraterId) {
      referralPartner = { id: ref.beraterId, name: ref.beraterName || '' };
      referralChannel = 'qr';
      referralRate = 0.10;
    }
  });
  if (!referralPartner) {
    try {
      var beraterList = JSON.parse(localStorage.getItem('suppTreeMeineBerater') || '[]');
      if (beraterList.length > 0) {
        referralPartner = { id: beraterList[0].id, name: beraterList[0].name || '' };
        referralChannel = 'link';
        referralRate = 0.07;
      }
    } catch(e) {}
  }

  var itemsSummary = orderItems.map(function(i) { return i.qty + 'x ' + i.name; }).join(', ');
  var selectedAddr = checkoutState.selectedAddress;

  // ═══ PAYMENT FLOW ═══
  // 1. Loading-State anzeigen
  var orderBtn = document.getElementById('coOrderBtn');
  var btnOrigText = orderBtn ? orderBtn.innerHTML : '';
  if (orderBtn) {
    orderBtn.disabled = true;
    orderBtn.innerHTML = '<span style="display:inline-flex;align-items:center;gap:8px"><span class="spinner" style="width:16px;height:16px;border:2px solid rgba(255,255,255,0.3);border-top-color:white;border-radius:50%;animation:spin 0.6s linear infinite;display:inline-block"></span> Zahlung wird verarbeitet...</span>';
  }

  try {
    // 2. Order in Supabase erstellen (Status: pending)
    var dbOrderId = null;
    var supabaseOrder = await placeOrderToSupabase({
      orderId: orderId,
      subtotal: subtotal,
      shippingCost: shipping,
      discountAmount: 0,
      pointsUsed: usePoints ? (checkoutState.pointsUsed || 0) : 0,
      pointsDiscount: pointsDiscount,
      taxAmount: +(total - total / 1.19).toFixed(2),
      total: total,
      pointsEarned: Math.floor(total),
      shippingType: checkoutState.shippingType || 'standard',
      customerName: selectedAddr ? ((selectedAddr.firstName || '') + ' ' + (selectedAddr.lastName || '')).trim() : '',
      sellerName: '',
      itemsSummary: itemsSummary,
      partnerId: referralPartner ? referralPartner.id : null,
      partnerName: referralPartner ? referralPartner.name : null,
      channel: referralChannel,
      provisionRate: referralRate,
      billingAddress: selectedAddr ? {
        street: selectedAddr.street || '',
        zip: selectedAddr.zip || selectedAddr.postalCode || '',
        city: selectedAddr.city || '',
        country: selectedAddr.country || 'DE'
      } : null
    }, orderItems);

    if (supabaseOrder && supabaseOrder.id) {
      dbOrderId = supabaseOrder.id;
    }

    // 3. Payment verarbeiten (Stripe/PayPal)
    if (total > 0) {
      await processPayment(total, dbOrderId || orderId, 'SuppTree Bestellung #' + orderId, 'product');
    }

    // ═══ ZAHLUNG ERFOLGREICH ═══

    // Process Kuren
    cartKuren.forEach((item, kurId) => {
      for (let i = 0; i < item.qty; i++) {
        addPurchasedKur(kurId, 'ST-' + Date.now() + '-' + i);
      }
    });

    // Add to mySupplements with 'waiting' status
    cart.forEach((qty, productId) => {
      const product = products.find(p => p.id === productId);
      if (product) {
        const existingIndex = mySupplements.findIndex(s => s.id === productId);
        if (existingIndex === -1) {
          mySupplements.push({
            id: productId, name: product.name, icon: product.icon, brand: product.brand,
            dosagePerDay: 1, stock: 60, packSize: 60, source: 'shop', time: 'auto',
            autoAbo: false, roburScheduled: true, hasAbo: false, status: 'waiting'
          });
        }
      }
    });

    // Activate pending Abos
    subscriptions.forEach((sub, productId) => {
      if (sub.status === 'pending') {
        const product = products.find(p => p.id === productId);
        const nextDelivery = new Date();
        nextDelivery.setMonth(nextDelivery.getMonth() + (sub.intervalMonths || 1));
        sub.status = 'active';
        sub.nextDelivery = formatDate(nextDelivery);
        if (product) {
          const existingIndex = mySupplements.findIndex(s => s.id === productId);
          if (existingIndex === -1) {
            mySupplements.push({
              id: productId, name: product.name, icon: product.icon, brand: product.brand,
              dosagePerDay: sub.dosePerDay || 1, stock: 60, packSize: 60, source: 'shop', time: 'auto',
              autoAbo: true, roburScheduled: true, hasAbo: true, status: 'waiting'
            });
          } else {
            mySupplements[existingIndex].status = 'waiting';
            mySupplements[existingIndex].hasAbo = true;
          }
        }
      }
    });
    saveSubscriptions();
    saveMySupplements();

    // localStorage-Fallback
    pendingOrders.set(orderId, {
      items: orderItems, orderDate: formatDate(orderDate), status: 'paid', total: total,
      shippingAddress: selectedAddr, shippingType: checkoutState.shippingType,
      shippingCost: checkoutState.shipping, paymentMethod: checkoutState.selectedPayment,
      dbId: dbOrderId
    });
    savePendingOrders();

    // Berater-Empfehlungen als "gekauft" markieren
    try {
      const purchasedPlanIds = new Set();
      cartReferrals.forEach((ref) => { if (ref.planId) purchasedPlanIds.add(ref.planId); });
      if (purchasedPlanIds.size > 0) {
        const _plaene = mbGetPlaene();
        let changed = false;
        purchasedPlanIds.forEach(pid => {
          const p = _plaene.find(x => x.id === pid);
          if (p && !p.hasPurchased) { p.hasPurchased = true; changed = true; }
        });
        if (changed) mbSavePlaene(_plaene);
      }
      cartReferrals.clear();
      saveCartReferrals();
    } catch(e) {}

    // Clear cart and kuren
    cart.clear();
    cartKuren.clear();
    cartCount = 0;
    saveCart();

    // Close checkout
    closeCheckout();

    // Show success
    showOrderConfirmation(total, hasAboItems, hasKuren);

    // Refresh displays
    renderEinkaufCart();
    renderEinkaufAbos();
    renderPendingOrders();
    updateNavEinkaufBadge();
    updateAllBadges();
    updateEinkaufCheckoutBar();

  } catch (paymentError) {
    // ═══ ZAHLUNG FEHLGESCHLAGEN ═══
    console.error('Payment error:', paymentError);
    if (orderBtn) {
      orderBtn.disabled = false;
      orderBtn.innerHTML = btnOrigText;
    }
    // Button wieder aktivierbar machen
    coUpdateOrderButton();
    showToast('Zahlung fehlgeschlagen: ' + (paymentError.message || 'Unbekannter Fehler'), 'error');
  }
}

function showOrderConfirmation(total, hasAbo, hasKuren = false) {
  const kurenHint = hasKuren ? `
    <div style="background: linear-gradient(135deg, #dcfce7, #bbf7d0); padding: 12px; border-radius: 7px; margin-bottom: 12px; font-size: 13px;">
      🌿 Deine Kur(en) findest du unter "Mein" → Kuren
    </div>
  ` : '';

  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:100001;display:flex;align-items:center;justify-content:center;padding:20px;';
  overlay.innerHTML = `
    <div style="background:white;border-radius:14px;max-width:340px;width:100%;padding:32px 24px;text-align:center;box-shadow:0 20px 60px rgba(0,0,0,0.3);animation:fadeInUp 0.3s ease;">
      <div style="font-size:48px;margin-bottom:12px;">🎉</div>
      <h3 style="font-size:20px;font-weight:700;margin:0 0 8px;">Bestellung erfolgreich!</h3>
      <p style="color:#6b7280;margin:0 0 20px;font-size:14px;">Vielen Dank für deine Bestellung über €${total.toFixed(2)}</p>
      ${kurenHint}
      <div style="background:linear-gradient(135deg,#ede9fe,#ddd6fe);padding:12px;border-radius:7px;margin-bottom:20px;font-size:13px;color:#6b21a8;">
        📦 Markiere deine Produkte als "Angekommen" sobald sie geliefert wurden
      </div>
      <button onclick="this.closest('div[style*=fixed]').remove(); openSTFeature('mysupplements');" style="width:100%;padding:14px;background:var(--green-accent);color:white;border:none;border-radius:7px;font-size:15px;font-weight:600;cursor:pointer;">
        Zu Meine Supplements →
      </button>
    </div>
  `;

  document.body.appendChild(overlay);
}

// Floating Search - Show on scroll up, hide on scroll down
let lastScrollY = 0;
let ticking = false;

function handleScroll() {
  const floatingSearch = document.getElementById('floatingSearch');
  const searchSection = document.getElementById('searchSection');
  const homeScreen = document.getElementById('homeScreen');
  
  if (!floatingSearch || !searchSection || !homeScreen) return;
  if (!homeScreen.classList.contains('active')) {
    floatingSearch.classList.remove('visible');
    return;
  }
  
  const currentScrollY = window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop || 0;
  const searchRect = searchSection.getBoundingClientRect();
  const searchHidden = searchRect.bottom < 0;
  
  if (!searchHidden) {
    // Original search still visible
    floatingSearch.classList.remove('visible');
  } else if (currentScrollY < lastScrollY - 3) {
    // Scrolling UP
    floatingSearch.classList.add('visible');
  } else if (currentScrollY > lastScrollY + 3) {
    // Scrolling DOWN
    floatingSearch.classList.remove('visible');
  }
  
  lastScrollY = currentScrollY;
  ticking = false;
}

window.addEventListener('scroll', function() {
  if (!ticking) {
    window.requestAnimationFrame(handleScroll);
    ticking = true;
  }
}, { passive: true });

document.addEventListener('scroll', function() {
  if (!ticking) {
    window.requestAnimationFrame(handleScroll);
    ticking = true;
  }
}, { passive: true });

function changeQty(delta) {
  quantity = Math.max(1, quantity + delta);
  document.getElementById('qtyValue').textContent = quantity;
}

function addDetailToCart() {
  if (!currentProduct) return;
  const currentQty = cart.get(currentProduct.id) || 0;
  cart.set(currentProduct.id, currentQty + quantity);
  cartCount += quantity;
  saveCart();
  updateHeaderCartBadges();

  const btn = document.querySelector('.add-to-cart-btn');
  createFlyingCartItem(btn);
  showToast(`${currentProduct.name} zum Warenkorb hinzugefügt`);
}

function shareProduct() {
  if (!currentProduct) return;
  
  const shareData = {
    title: currentProduct.name,
    text: `Schau dir ${currentProduct.name} bei SuppTree an!`,
    url: `https://supptree.de/produkt/${currentProduct.id}`
  };
  
  // Try native share first (works on mobile with HTTPS)
  if (navigator.share && window.isSecureContext) {
    navigator.share(shareData).catch(err => {
      // If native share fails, use fallback
      showShareSheet(shareData);
    });
  } else {
    // Show share sheet with options
    showShareSheet(shareData);
  }
}

function showShareSheet(shareData) {
  // Update product preview
  document.getElementById('shareProductIcon').textContent = currentProduct?.icon || '💊';
  document.getElementById('shareProductName').textContent = shareData.title;
  document.getElementById('shareProductUrl').textContent = shareData.url;
  
  // Set up share button handlers
  const url = shareData.url;
  const text = shareData.text;
  
  document.getElementById('shareWhatsApp').onclick = () => shareVia('whatsapp', url, text);
  document.getElementById('shareTelegram').onclick = () => shareVia('telegram', url, text);
  document.getElementById('shareFacebook').onclick = () => shareVia('facebook', url, text);
  document.getElementById('shareTwitter').onclick = () => shareVia('twitter', url, text);
  document.getElementById('shareEmail').onclick = () => shareVia('email', url, text);
  document.getElementById('shareSMS').onclick = () => shareVia('sms', url, text);
  document.getElementById('shareCopyLink').onclick = () => copyShareLink(url);
  document.getElementById('shareQR').onclick = () => shareVia('qr', url, text);
  
  // Show sheet
  document.getElementById('shareOverlay').classList.add('visible');
  document.getElementById('shareSheet').classList.add('visible');
  lockBody();
}

function closeShareSheet() {
  document.getElementById('shareOverlay').classList.remove('visible');
  document.getElementById('shareSheet').classList.remove('visible');
  unlockBody();
}

function shareVia(platform, url, text) {
  const encodedUrl = encodeURIComponent(url);
  const encodedText = encodeURIComponent(text);
  
  let shareUrl;
  switch(platform) {
    case 'whatsapp':
      shareUrl = `https://wa.me/?text=${encodedText}%20${encodedUrl}`;
      break;
    case 'telegram':
      shareUrl = `https://t.me/share/url?url=${encodedUrl}&text=${encodedText}`;
      break;
    case 'facebook':
      shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}`;
      break;
    case 'twitter':
      shareUrl = `https://twitter.com/intent/tweet?text=${encodedText}&url=${encodedUrl}`;
      break;
    case 'email':
      shareUrl = `mailto:?subject=${encodedText}&body=${encodedText}%0A%0A${encodedUrl}`;
      break;
    case 'sms':
      // Works on mobile
      shareUrl = `sms:?body=${encodedText}%20${encodedUrl}`;
      break;
    case 'qr':
      // Show QR code modal
      showQRCode(url);
      return;
  }
  
  if (shareUrl) {
    window.open(shareUrl, '_blank');
  }
  closeShareSheet();
}

function showQRCode(url) {
  closeShareSheet();
  
  // Create QR code modal
  const overlay = document.createElement('div');
  overlay.id = 'qrOverlay';
  overlay.className = 'overlay visible';
  overlay.onclick = closeQRCode;
  
  const modal = document.createElement('div');
  modal.id = 'qrModal';
  modal.className = 'qr-modal';
  modal.innerHTML = `
    <div class="qr-modal-content">
      <button class="qr-close" onclick="closeQRCode()">✕</button>
      <h3>QR-Code scannen</h3>
      <div class="qr-code-container">
        <img src="https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(url)}" alt="QR Code">
      </div>
      <p class="qr-url">${url}</p>
    </div>
  `;
  
  document.body.appendChild(overlay);
  document.body.appendChild(modal);
  lockBody();
}

function closeQRCode() {
  const modal = document.getElementById('qrModal');
  const overlay = document.getElementById('qrOverlay');
  if (modal) modal.remove();
  if (overlay) overlay.remove();
  unlockBody();
}

function copyShareLink(url) {
  if (navigator.clipboard) {
    navigator.clipboard.writeText(url).then(() => {
      showToast('🔗 Link kopiert!');
    });
  } else {
    // Fallback for older browsers
    const textArea = document.createElement('textarea');
    textArea.value = url;
    document.body.appendChild(textArea);
    textArea.select();
    document.execCommand('copy');
    document.body.removeChild(textArea);
    showToast('🔗 Link kopiert!');
  }
  closeShareSheet();
}

function addToMySupplementsDetail() {
  if (!currentProduct) return;
  
  // Ensure supplements are loaded
  ensureSupplementsLoaded();
  
  const btn = document.getElementById('addToSuppsBtn');
  
  // Check if already in supplements
  const existingSuppIndex = mySupplements.findIndex(s => s.id === currentProduct.id || s.shopProductId === currentProduct.id);
  
  if (existingSuppIndex === -1) {
    // Create supplement data
    const newSupplement = {
      id: currentProduct.id,
      shopProductId: currentProduct.id,
      name: currentProduct.name,
      icon: currentProduct.icon,
      brand: currentProduct.brand,
      source: 'shop',
      dosagePerDay: 1,
      stock: 60,
      packSize: 60,
      time: 'auto',
      autoAbo: false,
      roburScheduled: true
    };
    
    // Update button immediately for feedback
    btn.classList.add('added');
    btn.innerHTML = `
      <span class="supps-icon">✅</span>
      <div class="supps-text">
        <strong>Zu meinen Supps hinzugefügt!</strong>
        <span>In Meine Supplements anzeigen</span>
      </div>
      <span class="supps-arrow">→</span>
    `;
    
    // Check if product has active subscription
    if (hasActiveSubscription(currentProduct.id)) {
      // Direct add - subscription active
      newSupplement.status = 'active';
      newSupplement.startDate = new Date().toISOString();
      newSupplement.addedAt = new Date().toISOString();
      
      mySupplements.push(newSupplement);
      saveMySupplements();
      updateAllScheduledIntakes();
      
      showToast('✅ Hinzugefügt! (Abo aktiv)');
    } else {
      // Open the "When do you start?" dialog
      openSuppStartDialog(newSupplement);
    }
  } else {
    // Already added - navigate to Meine Supplements directly
    openSTFeature('mysupplements');
    showToast('💊 Bereits in deinen Supps');
  }
}
// Debug: Find what's blocking clicks (call from console: debugClick())
function debugClick() {
  document.body.style.cursor = 'crosshair';
  document.body.addEventListener('click', function debugHandler(e) {
    const elements = document.elementsFromPoint(e.clientX, e.clientY);
    elements.forEach((el, i) => {
      const styles = window.getComputedStyle(el);
    });
    document.body.style.cursor = '';
    document.body.removeEventListener('click', debugHandler);
  }, { once: true });
}

