// ===============================
// FLYING ANIMATION
// ===============================
let heartAnimationInProgress = false;

function createFlyingItem(startElement, type) {
  // Animation läuft - Herz nicht sofort aktualisieren
  heartAnimationInProgress = true;
  const rect = startElement.getBoundingClientRect();
  const flyingItem = document.createElement('div');
  flyingItem.className = 'flying-heart';
  flyingItem.textContent = '❤️';
  flyingItem.style.left = rect.left + rect.width / 2 + 'px';
  flyingItem.style.top = rect.top + rect.height / 2 + 'px';
  flyingItem.style.transform = 'translate(-50%, -50%) scale(1)';
  flyingItem.style.opacity = '1';
  document.body.appendChild(flyingItem);

  // Ziel ist das Nav-Icon in der Bottom-Nav
  const targetIcon = document.getElementById('navFavCartIcon');
  if (!targetIcon) {
    flyingItem.remove();
    updateAllBadges();
    return;
  }
  const targetRect = targetIcon.getBoundingClientRect();

  requestAnimationFrame(() => {
    flyingItem.style.left = targetRect.left + targetRect.width / 2 + 'px';
    flyingItem.style.top = targetRect.top + targetRect.height / 2 + 'px';
    flyingItem.style.transform = 'translate(-50%, -50%) scale(0.3)';
    flyingItem.style.opacity = '0.5';
  });

  // Warten bis Animation fertig ist (800ms), dann Herz entfernen und ausfüllen
  setTimeout(() => {
    flyingItem.remove();
    // Animation fertig - jetzt darf Herz aktualisiert werden
    heartAnimationInProgress = false;
    updateNavHeartIcon();
    updateAllBadges();
  }, 850);
}

// Fliegende Warenkorb-Animation
let cartAnimationInProgress = false;

function createFlyingCartItem(startElement) {
  cartAnimationInProgress = true;
  const rect = startElement.getBoundingClientRect();
  const flyingItem = document.createElement('div');
  flyingItem.className = 'flying-cart';
  flyingItem.textContent = '📦';
  flyingItem.style.position = 'fixed';
  flyingItem.style.fontSize = '24px';
  flyingItem.style.zIndex = '999999';
  flyingItem.style.pointerEvents = 'none';
  flyingItem.style.transition = 'all 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94)';
  flyingItem.style.left = rect.left + rect.width / 2 + 'px';
  flyingItem.style.top = rect.top + rect.height / 2 + 'px';
  flyingItem.style.transform = 'translate(-50%, -50%) scale(1)';
  flyingItem.style.opacity = '1';
  document.body.appendChild(flyingItem);

  const targetIcon = document.getElementById('navFavCartIcon');
  if (!targetIcon) {
    flyingItem.remove();
    cartAnimationInProgress = false;
    updateAllBadges();
    return;
  }
  const targetRect = targetIcon.getBoundingClientRect();

  requestAnimationFrame(() => {
    flyingItem.style.left = targetRect.left + targetRect.width / 2 + 'px';
    flyingItem.style.top = targetRect.top + targetRect.height / 2 + 'px';
    flyingItem.style.transform = 'translate(-50%, -50%) scale(0.3)';
    flyingItem.style.opacity = '0.5';
  });

  // Warten bis Animation fertig ist, dann entfernen und Paket im Icon anzeigen
  setTimeout(() => {
    flyingItem.remove();
    cartAnimationInProgress = false;
    updateNavPackageIcon();
    updateAllBadges();
  }, 850);
}

// Nav-Paket Icon aktualisieren (bis 3 Pakete als Pyramide, ab 4 Zähler)
function updateNavPackageIcon() {
  const packagesEl = document.getElementById('navComboPackages');
  const cartCountEl = document.getElementById('navCartCount');
  if (!packagesEl || !cartCountEl) return;

  let totalCartItems = 0;
  cart.forEach(qty => totalCartItems += qty);
  cartKuren.forEach(item => totalCartItems += item.qty);
  subscriptions.forEach(sub => { if (sub.status === 'pending') totalCartItems++; });

  if (totalCartItems === 0) {
    // Warenkorb leer
    packagesEl.innerHTML = '';
    cartCountEl.style.display = 'none';
  } else if (totalCartItems <= 3) {
    // 1-3 Produkte: Pakete als Pyramide + Zähler
    let html = '';
    for (let i = 1; i <= totalCartItems; i++) {
      html += `<span class="pkg pkg-${i}">📦</span>`;
    }
    packagesEl.innerHTML = html;
    packagesEl.classList.add('pop');
    setTimeout(() => packagesEl.classList.remove('pop'), 300);
    // Zähler ab 1 anzeigen
    cartCountEl.textContent = totalCartItems;
    cartCountEl.style.display = 'flex';
    cartCountEl.classList.add('pop');
    setTimeout(() => cartCountEl.classList.remove('pop'), 300);
  } else {
    // 4+ Produkte: 3 Pakete Pyramide + Zähler
    packagesEl.innerHTML = '<span class="pkg pkg-1">📦</span><span class="pkg pkg-2">📦</span><span class="pkg pkg-3">📦</span>';
    cartCountEl.textContent = totalCartItems > 99 ? '99+' : totalCartItems;
    cartCountEl.style.display = 'flex';
    cartCountEl.classList.add('pop');
    setTimeout(() => cartCountEl.classList.remove('pop'), 300);
  }
}

// Nav-Herz Icon aktualisieren (leer oder gefüllt) + Zähler
function updateNavHeartIcon() {
  const heartIcon = document.getElementById('navComboHeart');

  if (heartIcon) {
    if (favorites.size > 0) {
      // Zahl im Herz anzeigen
      const count = favorites.size > 99 ? '99+' : favorites.size;
      heartIcon.textContent = count;
      heartIcon.classList.add('filled', 'has-count');
      setTimeout(() => heartIcon.classList.remove('filled'), 400);
    } else {
      heartIcon.textContent = '🤍';
      heartIcon.classList.remove('has-count');
    }
  }
}

function updateBadge(badge, count) {
  if (!badge) return;
  badge.textContent = count > 99 ? '99+' : count;
  badge.classList.toggle('visible', count > 0);
}

function updateAllBadges() {
  // Count pending abos for cart badge
  let pendingAboCount = 0;
  subscriptions.forEach(sub => {
    if (sub.status === 'pending') pendingAboCount++;
  });

  // Update nav badge
  updateNavEinkaufBadge();

  // Update nav heart icon (filled or empty) - NICHT während Animation!
  if (!heartAnimationInProgress) {
    const heartIcon = document.getElementById('navComboHeart');
    if (heartIcon) {
      if (favorites.size > 0) {
        // Zahl im Herz anzeigen
        const count = favorites.size > 99 ? '99+' : favorites.size;
        heartIcon.textContent = count;
        heartIcon.classList.add('has-count');
      } else {
        heartIcon.textContent = '🤍';
        heartIcon.classList.remove('has-count');
      }
    }
  }

  // Update nav package icons (show/hide) - NICHT während Animation!
  if (!cartAnimationInProgress) {
    const packagesEl = document.getElementById('navComboPackages');
    const cartCountEl = document.getElementById('navCartCount');
    if (packagesEl && cartCountEl) {
      let totalCartItems = 0;
      cart.forEach(qty => totalCartItems += qty);
      cartKuren.forEach(item => totalCartItems += item.qty);
      subscriptions.forEach(sub => { if (sub.status === 'pending') totalCartItems++; });

      if (totalCartItems === 0) {
        packagesEl.innerHTML = '';
        cartCountEl.style.display = 'none';
      } else if (totalCartItems <= 3) {
        // Pyramide: 1-3 Pakete + Zähler
        let html = '';
        for (let i = 1; i <= totalCartItems; i++) {
          html += `<span class="pkg pkg-${i}">📦</span>`;
        }
        packagesEl.innerHTML = html;
        cartCountEl.textContent = totalCartItems;
        cartCountEl.style.display = 'flex';
      } else {
        // 4+ Produkte: volle Pyramide + Zähler
        packagesEl.innerHTML = '<span class="pkg pkg-1">📦</span><span class="pkg pkg-2">📦</span><span class="pkg pkg-3">📦</span>';
        cartCountEl.textContent = totalCartItems > 99 ? '99+' : totalCartItems;
        cartCountEl.style.display = 'flex';
      }
    }
  }

  // Update header cart badges on detail screens
  updateHeaderCartBadges();
}

function updateHeaderCartBadges() {
  let totalCartItems = 0;
  cart.forEach(qty => totalCartItems += qty);
  cartKuren.forEach(item => totalCartItems += item.qty);
  
  // Count pending abos
  subscriptions.forEach(sub => {
    if (sub.status === 'pending') totalCartItems++;
  });
  
  // Update all header cart badges
  const badges = ['productDetailCartBadge', 'kurDetailCartBadge'];
  badges.forEach(id => {
    const badge = document.getElementById(id);
    if (badge) {
      badge.textContent = totalCartItems;
      badge.classList.toggle('visible', totalCartItems > 0);
    }
  });
}
