// Home screen fav/cart buttons (product cards)
document.querySelectorAll('.btn-fav').forEach(btn => {
  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    const product = this.dataset.product;
    if (favorites.has(product)) {
      favorites.delete(product);
      favCount--;
      this.classList.remove('active');
    } else {
      favorites.add(product);
      favCount++;
      this.classList.add('active');
      createFlyingItem(this, 'heart');
    }
    updateAllBadges();
  });
});

document.querySelectorAll('.btn-cart').forEach(btn => {
  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    const product = this.dataset.product;
    const currentQty = cart.get(product) || 0;
    cart.set(product, currentQty + 1);
    cartCount++;
    createFlyingItem(this, 'cart');
  });
});

