function resetAllAppData() {
  // Save language preference before reset
  const savedLanguage = localStorage.getItem('supptree-language');
  
  const keysToRemove = [
    'suppTreeQuizData',
    'suppTreePausedQuiz',
    'suppTreePoints', 
    'suppTreeMySupplements',
    'suppTreeMedications',
    'suppTreeShifts',
    'suppTreeShiftConfig',
    'suppTreeUserProfile',
    'suppTreePersonalData',
    'suppTreeAvatar',
    'suppTreeRecentSearches',
    'suppTreeBookmarks',
    'suppTreeAnalyses',
    'suppTreeSavedAnalyses',
    'suppTreeScheduledIntakes',
    'suppTreeRedeemedRewards',
    'suppTreeBloodValues',
    'supptree_trainingHistory',
    'darkMode',
    // Kuren & Pläne
    'suppTreeKuren',
    'suppTreePurchasedKuren',
    'suppTreePurchasedKurenDemoShown',
    'suppTreeCustomSleepTimes',
    'suppTreeCustomEntries',
    'suppTreeTrainingPlan',
    'suppTreeTrainingLogs',
    // Abos & Einkauf
    'suppTreeSubscriptions',
    'suppTreeAutoReplenItems',
    'suppTreeFavorites',
    'suppTreeCart',
    // Onboarding
    'suppTreeCalendarOnboardingDismissed'
  ];
  
  keysToRemove.forEach(key => localStorage.removeItem(key));
  
  // Also remove date-specific keys (completed items, notes)
  const allKeys = Object.keys(localStorage);
  allKeys.forEach(key => {
    if (key.startsWith('suppTree_completed_') || 
        key.startsWith('suppTree_notes_') ||
        key.startsWith('suppTree_')) {
      localStorage.removeItem(key);
    }
  });
  
  // Set flag so demo data doesn't reload
  localStorage.setItem('suppTreeWasReset', 'true');
  
  // Restore language preference
  if (savedLanguage) {
    localStorage.setItem('supptree-language', savedLanguage);
  }
  
}

