// ===============================
// HERO BANNER CAROUSEL
// ===============================
let currentHeroBanner = 0;
let heroBannerInterval = null;
const HERO_BANNER_COUNT = 4;
const HERO_BANNER_DURATION = 4000; // 4 Sekunden

function goToHeroBanner(index) {
  currentHeroBanner = index;
  const track = document.getElementById('heroBannerTrack');
  const dots = document.querySelectorAll('.hero-dot');
  
  if (track) {
    track.style.transform = `translateX(-${index * 100}%)`;
  }
  
  dots.forEach((dot, i) => {
    dot.classList.toggle('active', i === index);
  });
  
  // Reset auto-rotation timer
  resetHeroBannerTimer();
}

function nextHeroBanner() {
  const next = (currentHeroBanner + 1) % HERO_BANNER_COUNT;
  goToHeroBanner(next);
}

function startHeroBannerRotation() {
  if (heroBannerInterval) clearInterval(heroBannerInterval);
  heroBannerInterval = setInterval(nextHeroBanner, HERO_BANNER_DURATION);
}

function resetHeroBannerTimer() {
  if (heroBannerInterval) clearInterval(heroBannerInterval);
  heroBannerInterval = setInterval(nextHeroBanner, HERO_BANNER_DURATION);
}

function initHeroBanner() {
  const carousel = document.getElementById('heroBannerCarousel');
  if (!carousel) return;
  
  // Touch/Swipe support
  let touchStartX = 0;
  let touchEndX = 0;
  
  carousel.addEventListener('touchstart', (e) => {
    touchStartX = e.changedTouches[0].screenX;
  }, { passive: true });
  
  carousel.addEventListener('touchend', (e) => {
    touchEndX = e.changedTouches[0].screenX;
    handleHeroBannerSwipe();
  }, { passive: true });
  
  function handleHeroBannerSwipe() {
    const diff = touchStartX - touchEndX;
    if (Math.abs(diff) > 50) {
      if (diff > 0) {
        // Swipe left - next
        goToHeroBanner((currentHeroBanner + 1) % HERO_BANNER_COUNT);
      } else {
        // Swipe right - prev
        goToHeroBanner((currentHeroBanner - 1 + HERO_BANNER_COUNT) % HERO_BANNER_COUNT);
      }
    }
  }
  
  // Start auto-rotation
  startHeroBannerRotation();
}

async function initApp() {
  console.log(`🔧 APP_MODE: ${APP_MODE}`);

  // Supabase initialisieren (wenn verfügbar)
  try {
    initSupabase();
  } catch(e) {
    console.log('Supabase nicht verfügbar:', e);
  }

  // Auth prüfen — wenn eingeloggt: Profil laden. Sonst: Marktplatz frei browsebar
  if (supabase) {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
        currentUser = session.user;
        await loadUserProfile();
        await loadUserDataFromSupabase();
        startCustomerRealtime();
        updateUIForLoggedInUser();
      } else {
        updateUIForLoggedOutUser();
      }
    } catch(e) {
      console.warn('Auth-Check fehlgeschlagen:', e);
      updateUIForLoggedOutUser();
    }
  }

  // QR-Ref-Parameter (?ref=SELLER_NR) speichern für Provision-Zuordnung
  try {
    var refParam = new URLSearchParams(window.location.search).get('ref');
    if (refParam) {
      localStorage.setItem('suppTreePartnerRef', refParam);
      localStorage.setItem('suppTreePartnerRefDate', new Date().toISOString());
      console.log('🔗 Partner-Ref gespeichert:', refParam);
    }
  } catch(e) {}
  
  // Hero Banner initialisieren
  initHeroBanner();
  
  // Warenkorb & Favoriten immer laden (auch für Gäste)
  loadCart();
  loadFavorites();

  // Persönliche Daten nur laden wenn eingeloggt
  if (currentUser) {
    if (supabase) {
      await ensureSupplementsLoaded();
    } else {
      ensureSupplementsLoaded();
    }
    loadPointsData();
    loadQuizData();
    loadSubscriptions();
    syncAbosToSupplements();
    loadPendingOrders();
    initAutoReplenItems();
    try { updateDailyStock(); } catch(e) {}
  }
  
  // Load shift data for caffeine warning
  if (typeof loadShiftConfig === 'function') loadShiftConfig();
  if (typeof loadSavedShifts === 'function') loadSavedShifts();

  // Meine Berater Demo-Daten laden
  try { mbLoadDemoData(); } catch(e) { }
  
  // Load medications data
  const savedMeds = localStorage.getItem('suppTreeMedications');
  if (savedMeds) {
    myMedications = JSON.parse(savedMeds);
  }

  // Load Ampelsystem interaction data (JSON files)
  try {
    await loadInteractionData();
  } catch(e) {
    console.warn('Ampelsystem: Daten-Laden fehlgeschlagen', e);
  }
  
  // Load health profile data
  const savedHealthProfile = localStorage.getItem('suppTreeHealthProfile');
  if (savedHealthProfile) {
    healthProfileData = JSON.parse(savedHealthProfile);
  }
  
  // Load training history
  const savedTraining = localStorage.getItem('supptree_trainingHistory');
  if (savedTraining) {
    trainingHistory = JSON.parse(savedTraining);
  }
  
  // Init dark mode and language
  initDarkMode();
  setTimeout(initLanguage, 50);
  
  // Apply translations
  applyI18n();
  
  // Render grids
  renderProductsGrid();
  try {
    renderProductsGridNew();
  } catch(e) {
    console.error('Error rendering products:', e);
  }
  updateGreeting();
  
  // Delayed inits (need DOM to be ready)
  setTimeout(() => {
    initSymptomChecker();
    initKnowledgeHub();
    if (currentUser) {
      initHomePage();
      initWeek7Preview();
      updateSTPlusStats();
      renderRecentTraining();
      try { renderHomeNewEmpfehlungen(); } catch(e) {}
      showPersonalHomeSections();
    } else {
      updateHomeGreeting();
      // Teaser-Karte statt persönlicher Sektionen
      hidePersonalHomeSections();
    }
  }, 100);
  
  // Event listeners setup
  setupEventListeners();
}

function setupEventListeners() {
  // Robur auto schedule toggle
  const roburToggle = document.getElementById('roburAutoSchedule');
  if (roburToggle) {
    roburToggle.addEventListener('change', updateRoburSchedulePreview);
  }
  
  // Health profile "none" checkbox logic
  document.querySelectorAll('[data-hp-intol]').forEach(cb => {
    cb.addEventListener('change', function() {
      if (this.dataset.hpIntol === 'none' && this.checked) {
        // Uncheck all other intolerances
        document.querySelectorAll('[data-hp-intol]:not([data-hp-intol="none"])').forEach(other => {
          other.checked = false;
        });
      } else if (this.dataset.hpIntol !== 'none' && this.checked) {
        // Uncheck "none" if another is selected
        const noneCheckbox = document.querySelector('[data-hp-intol="none"]');
        if (noneCheckbox) noneCheckbox.checked = false;
      }
      updateHealthCompleteness();
    });
  });
  
  // Auto-Abo toggle in "Add Supplement" form
  const addAboToggle = document.getElementById('addWithAutoAbo');
  if (addAboToggle) {
    addAboToggle.addEventListener('change', function() {
      const settings = document.getElementById('addAboSettings');
      if (settings) {
        settings.style.display = this.checked ? 'block' : 'none';
      }
    });
  }
  
  // Supplement detail buttons
  const reorderBtn = document.getElementById('reorderSupplementBtn');
  const deleteBtn = document.getElementById('deleteSupplementBtn');
  if (reorderBtn) {
    reorderBtn.addEventListener('click', function(e) {
      e.stopPropagation();
      reorderSupplement();
    });
  }
  if (deleteBtn) {
    deleteBtn.addEventListener('click', function(e) {
      e.stopPropagation();
      deleteSupplement();
    });
  }
  
  // Auto-Abo toggle with full functionality
  const autoAboToggle = document.getElementById('autoAboToggle');
  if (autoAboToggle) {
    autoAboToggle.addEventListener('change', function() {
      const supp = mySupplements.find(s => s.id === currentSupplementId);
      if (!supp) return;
      
      supp.autoAbo = this.checked;
      const settings = document.getElementById('autoAboSettings');
      if (settings) settings.style.display = this.checked ? 'block' : 'none';
      
      if (this.checked && supp.source === 'external') {
        showToast('Hinweis: Für Auto-Abo wechsle zu einem Shop-Produkt');
        this.checked = false;
        supp.autoAbo = false;
        if (settings) settings.style.display = 'none';
        return;
      }
      
      if (this.checked) {
        const threshold = document.getElementById('aboThreshold');
        supp.aboThreshold = threshold ? parseInt(threshold.value) || 14 : 14;
        showToast('🔄 Auto-Abo aktiviert! Du sparst 8%');
      } else {
        showToast('Auto-Abo deaktiviert');
      }
      
      saveMySupplements();
      renderMySupplements('all');
      updateSupplementStats();
    });
  }
  
  // Abo threshold select
  const thresholdSelect = document.getElementById('aboThreshold');
  if (thresholdSelect) {
    thresholdSelect.addEventListener('change', function() {
      const supp = mySupplements.find(s => s.id === currentSupplementId);
      if (!supp) return;
      supp.aboThreshold = parseInt(this.value);
      saveMySupplements();
      showToast(`Nachbestellung bei ${this.value} Tagen Vorrat`);
    });
  }
  
  // Dosage time select
  const dosageTimeSelect = document.getElementById('dosageTime');
  if (dosageTimeSelect) {
    dosageTimeSelect.addEventListener('change', function() {
      const supp = mySupplements.find(s => s.id === currentSupplementId);
      if (!supp) return;
      supp.time = this.value;
      saveMySupplements();
    });
  }
  
  // Filter chips
  document.querySelectorAll('.filter-chip-new').forEach(chip => {
    chip.addEventListener('click', () => {
      document.querySelectorAll('.filter-chip-new').forEach(c => c.classList.remove('active'));
      chip.classList.add('active');
    });
  });
  
  // Repeat checkbox toggle
  const repeatCheckbox = document.getElementById('repeatShift');
  if (repeatCheckbox) {
    repeatCheckbox.addEventListener('change', function() {
      const options = document.getElementById('repeatOptions');
      options.style.display = this.checked ? 'flex' : 'none';
      if (this.checked && selectedDate) {
        const endDate = new Date(selectedDate);
        endDate.setDate(endDate.getDate() + 28);
        document.getElementById('repeatUntil').value = formatDate(endDate);
      }
    });
  }
}

