let selectedEntryTextColor = '#1f2937';
let editingEntryId = null;
let selectedEntryDate = null;

function openAddTimelineEntry() {
  editingEntryId = null;
  selectedEntryDate = null;
  document.getElementById('entrySheetTitle').textContent = 'Neuer Eintrag';
  document.getElementById('entryName').value = '';
  document.getElementById('entryTime').value = '08:00';
  document.getElementById('entryNote').value = '';
  document.getElementById('entryRepeat').checked = false;
  document.getElementById('entrySaveAsTemplate').checked = false;
  
  // Reset icon
  selectedEntryIcon = '💊';
  document.getElementById('selectedEntryIcon').textContent = '💊';
  document.getElementById('entryIconPicker').classList.remove('show');
  
  document.querySelectorAll('#entryIconPicker .icon-option').forEach(o => o.classList.remove('selected'));
  const defaultIcon = document.querySelector('#entryIconPicker .icon-option[data-icon="💊"]');
  if (defaultIcon) defaultIcon.classList.add('selected');
  
  // Reset colors
  selectedEntryBgColor = '#ffffff';
  selectedEntryTextColor = '#262626';
  document.querySelectorAll('#entryBgColors .color-dot').forEach(d => d.classList.remove('selected'));
  document.querySelector('#entryBgColors .color-dot[data-color="#ffffff"]')?.classList.add('selected');
  document.querySelectorAll('#entryTextColors .color-dot').forEach(d => d.classList.remove('selected'));
  document.querySelector('#entryTextColors .color-dot[data-color="#262626"]')?.classList.add('selected');
  updateEntryPreview();
  
  // Prevent body scroll
  document.body.classList.add('no-scroll');
  
  document.getElementById('addEntryOverlay').classList.add('active');
  document.getElementById('addEntrySheet').classList.add('active');
}

function toggleIconPicker() {
  const picker = document.getElementById('entryIconPicker');
  picker.classList.toggle('show');
}

// Spontane Mahlzeit Funktionen
function openMealTypeSelector() {
  const selector = document.getElementById('mealTypeSelector');
  if (selector) {
    selector.classList.add('show');
  }
}

function closeMealTypeSelector() {
  const selector = document.getElementById('mealTypeSelector');
  if (selector) {
    selector.classList.remove('show');
  }
}

function selectMealType(mealType, icon, name) {
  closeMealTypeSelector();
  
  // Setze Icon und Name
  selectedEntryIcon = icon;
  document.getElementById('selectedEntryIcon').textContent = icon;
  document.getElementById('entryName').value = name;
  
  // Setze passende Farben für Mahlzeiten
  const mealColors = {
    breakfast: { bg: '#fef3c7', text: '#b45309' },
    brunch: { bg: '#fed7aa', text: '#c2410c' },
    lunch: { bg: '#dcfce7', text: '#15803d' },
    dinner: { bg: '#dbeafe', text: '#1d4ed8' },
    snack: { bg: '#fce7f3', text: '#be185d' },
    nightsnack: { bg: '#f3e8ff', text: '#7c3aed' }
  };
  
  const colors = mealColors[mealType] || { bg: '#ffffff', text: '#262626' };
  selectEntryBgColor(colors.bg);
  selectEntryTextColor(colors.text);
  
  // Setze sinnvolle Standardzeit basierend auf Mahlzeit-Typ
  const now = new Date();
  const hours = now.getHours();
  let defaultTime = '12:00';
  
  switch(mealType) {
    case 'breakfast':
      defaultTime = hours < 10 ? `${String(hours + 1).padStart(2, '0')}:00` : '09:00';
      break;
    case 'brunch':
      defaultTime = '10:30';
      break;
    case 'lunch':
      defaultTime = hours < 14 ? '12:30' : `${String(hours).padStart(2, '0')}:30`;
      break;
    case 'dinner':
      defaultTime = hours < 20 ? '19:00' : `${String(hours).padStart(2, '0')}:00`;
      break;
    case 'snack':
      defaultTime = `${String(hours).padStart(2, '0')}:${String(Math.floor(now.getMinutes() / 15) * 15).padStart(2, '0')}`;
      break;
    case 'nightsnack':
      defaultTime = '23:00';
      break;
  }
  
  document.getElementById('entryTime').value = defaultTime;
  
  // Speichere Mahlzeit-Typ für später
  document.getElementById('entryName').dataset.mealType = mealType;
  
  updateEntryPreview();
}

// Spontane Mahlzeiten speichern/laden
function getSpontaneousMeals(dateStr) {
  const key = `suppTree_spontaneousMeals_${dateStr}`;
  return JSON.parse(localStorage.getItem(key) || '[]');
}

function saveSpontaneousMeal(dateStr, meal) {
  const key = `suppTree_spontaneousMeals_${dateStr}`;
  const meals = getSpontaneousMeals(dateStr);
  
  // Prüfe ob gleiche Mahlzeit schon existiert
  const existingIndex = meals.findIndex(m => m.type === meal.type);
  if (existingIndex >= 0) {
    meals[existingIndex] = meal; // Update
  } else {
    meals.push(meal);
  }
  
  localStorage.setItem(key, JSON.stringify(meals));
}

// Hilfsfunktion: Mahlzeit-Zeit für einen Tag ermitteln
function getMealTimeForDay(dateStr, mealType) {
  // Erst prüfen ob spontane Mahlzeit eingetragen ist
  const spontaneous = getSpontaneousMeals(dateStr);
  const spontMeal = spontaneous.find(m => m.type === mealType || 
    (mealType === 'breakfast' && m.type === 'brunch')); // Brunch ersetzt Frühstück
  if (spontMeal && spontMeal.time) {
    return spontMeal.time;
  }
  
  // Sonst Schicht-basierte Mahlzeit
  const shift = shifts[dateStr] || 'off';
  const config = shiftConfig[shift];
  if (config && config.meals) {
    const mealConfig = config.meals[mealType];
    if (mealConfig && mealConfig.enabled && mealConfig.time) {
      return mealConfig.time;
    }
  }
  
  return null; // Keine Mahlzeit zu dieser Zeit
}

// Prüft ob eine Mahlzeit aktiviert ist (Schicht oder spontan)
function isMealEnabledForDay(dateStr, mealType) {
  // Spontane Mahlzeiten überschreiben Schicht-Config
  const spontaneous = getSpontaneousMeals(dateStr);
  if (spontaneous.some(m => m.type === mealType)) {
    return true;
  }
  
  const shift = shifts[dateStr] || 'off';
  const config = shiftConfig[shift];
  if (config && config.meals) {
    const mealConfig = config.meals[mealType];
    return mealConfig && mealConfig.enabled;
  }
  
  return false;
}

function selectEntryIcon(icon) {
  selectedEntryIcon = icon;
  document.getElementById('selectedEntryIcon').textContent = icon;
  
  document.querySelectorAll('#entryIconPicker .icon-option').forEach(o => o.classList.remove('selected'));
  const selected = document.querySelector(`#entryIconPicker .icon-option[data-icon="${icon}"]`);
  if (selected) selected.classList.add('selected');
  
  document.getElementById('entryIconPicker').classList.remove('show');
  updateEntryPreview();
}

function selectEntryBgColor(color) {
  selectedEntryBgColor = color;
  document.querySelectorAll('#entryBgColors .color-dot').forEach(d => d.classList.remove('selected'));
  document.querySelector(`#entryBgColors .color-dot[data-color="${color}"]`)?.classList.add('selected');
  updateEntryPreview();
}

function selectEntryTextColor(color) {
  selectedEntryTextColor = color;
  document.querySelectorAll('#entryTextColors .color-dot').forEach(d => d.classList.remove('selected'));
  document.querySelector(`#entryTextColors .color-dot[data-color="${color}"]`)?.classList.add('selected');
  updateEntryPreview();
}

function updateEntryPreview() {
  const previewItem = document.getElementById('entryPreviewItem');
  const previewIcon = document.getElementById('entryPreviewIcon');
  const previewName = document.getElementById('entryPreviewName');
  const nameInput = document.getElementById('entryName');
  
  if (previewItem) {
    previewItem.style.background = selectedEntryBgColor || '#ffffff';
    previewItem.style.borderColor = (selectedEntryBgColor === '#ffffff' || !selectedEntryBgColor) ? 'var(--cream-dark)' : selectedEntryBgColor;
  }
  if (previewIcon) {
    previewIcon.textContent = selectedEntryIcon || '💊';
  }
  if (previewName) {
    previewName.style.color = selectedEntryTextColor || '#262626';
    const name = nameInput?.value?.trim();
    previewName.textContent = name || 'Dein Eintrag';
  }
}

// Update preview when typing name
document.addEventListener('DOMContentLoaded', function() {
  const entryNameInput = document.getElementById('entryName');
  if (entryNameInput) {
    entryNameInput.addEventListener('input', updateEntryPreview);
  }
});

function useQuickTemplate(icon, name) {
  selectedEntryIcon = icon;
  document.getElementById('selectedEntryIcon').textContent = icon;
  document.getElementById('entryName').value = name;
  document.getElementById('entryName').focus();
  
  document.querySelectorAll('#entryIconPicker .icon-option').forEach(o => o.classList.remove('selected'));
  const selected = document.querySelector(`#entryIconPicker .icon-option[data-icon="${icon}"]`);
  if (selected) selected.classList.add('selected');
  
  // Update preview
  updateEntryPreview();
}

function closeAddTimelineEntry() {
  document.getElementById('addEntryOverlay').classList.remove('active');
  document.getElementById('addEntrySheet').classList.remove('active');
  document.getElementById('entryIconPicker').classList.remove('show');
  
  // Re-enable body scroll
  document.body.classList.remove('no-scroll');
}

function saveTimelineEntry() {
  const nameInput = document.getElementById('entryName');
  const name = nameInput.value.trim();
  const time = document.getElementById('entryTime').value;
  const note = document.getElementById('entryNote').value.trim();
  const repeat = document.getElementById('entryRepeat').checked;
  const saveAsTemplate = document.getElementById('entrySaveAsTemplate').checked;
  const mealType = nameInput.dataset.mealType;
  
  if (!name) {
    nameInput.classList.add('input-error');
    showToast('⚠️ Bitte gib einen Namen ein');
    nameInput.focus();
    return;
  }
  
  nameInput.classList.remove('input-error');
  
  const dateStr = selectedEntryDate || formatDate(new Date());
  
  // Wenn es eine Mahlzeit ist, separat speichern
  if (mealType) {
    const meal = {
      type: mealType,
      name: name,
      time: time,
      icon: selectedEntryIcon,
      date: dateStr
    };
    saveSpontaneousMeal(dateStr, meal);
    
    // Lösche mealType nach dem Speichern
    delete nameInput.dataset.mealType;
    
    closeAddTimelineEntry();
    renderDayPlanner();
    render7DayPreview();
    showToast(`${name} um ${time} eingetragen – Supplements werden angepasst!`);
    return;
  }
  
  // Normale Einträge
  const entries = JSON.parse(localStorage.getItem('suppTreeCustomEntries') || '[]');
  
  const entry = {
    id: editingEntryId || Date.now().toString(),
    name,
    time,
    note,
    icon: selectedEntryIcon,
    bgColor: selectedEntryBgColor,
    textColor: selectedEntryTextColor,
    repeat,
    date: selectedEntryDate || null
  };
  
  if (editingEntryId) {
    const idx = entries.findIndex(e => e.id === editingEntryId);
    if (idx !== -1) entries[idx] = entry;
  } else {
    entries.push(entry);
  }
  
  localStorage.setItem('suppTreeCustomEntries', JSON.stringify(entries));
  
  // Save as template if checked
  if (saveAsTemplate) {
    saveEntryAsTemplate(entry);
  }
  
  closeAddTimelineEntry();
  renderDayPlanner();
  render7DayPreview();
  showToast(editingEntryId ? 'Eintrag aktualisiert' : 'Eintrag hinzugefügt');
}

function saveEntryAsTemplate(entry) {
  const templates = JSON.parse(localStorage.getItem('suppTreeEntryTemplates') || '[]');
  const existingIdx = templates.findIndex(t => t.name === entry.name);
  
  const template = {
    name: entry.name,
    icon: entry.icon,
    note: entry.note,
    bgColor: entry.bgColor,
    textColor: entry.textColor
  };
  
  if (existingIdx !== -1) {
    templates[existingIdx] = template;
  } else if (templates.length < 10) {
    templates.push(template);
  }
  
  localStorage.setItem('suppTreeEntryTemplates', JSON.stringify(templates));
}

function renderEntryTemplates() {
  const container = document.getElementById('entryTemplatesContainer');
  if (!container) return;
  
  const templates = JSON.parse(localStorage.getItem('suppTreeEntryTemplates') || '[]');
  
  if (templates.length === 0) {
    container.innerHTML = '';
    return;
  }
  
  container.innerHTML = templates.map((t, idx) => `
    <div class="entry-template-chip" 
         style="background: ${t.bgColor}; color: ${t.textColor}; border-color: ${t.textColor}30"
         onclick="applyEntryTemplate(${idx})">
      <span>${t.icon}</span>
      <span>${t.name}</span>
      <span class="template-delete-btn" onclick="event.stopPropagation(); deleteEntryTemplate(${idx})">✕</span>
    </div>
  `).join('');
}

function applyEntryTemplate(idx) {
  const templates = JSON.parse(localStorage.getItem('suppTreeEntryTemplates') || '[]');
  const template = templates[idx];
  if (!template) return;
  
  document.getElementById('entryName').value = template.name;
  document.getElementById('entryNote').value = template.note || '';
  
  selectedEntryIcon = template.icon;
  selectedEntryBgColor = template.bgColor;
  selectedEntryTextColor = template.textColor;
  
  // Update UI selections
  document.querySelectorAll('#entryIconPicker .icon-option').forEach(o => {
    o.classList.toggle('selected', o.dataset.icon === template.icon);
  });
  document.querySelectorAll('#entryBgColorPicker .color-option').forEach(o => {
    o.classList.toggle('selected', o.dataset.color === template.bgColor);
  });
  document.querySelectorAll('#entryTextColorPicker .color-option').forEach(o => {
    o.classList.toggle('selected', o.dataset.color === template.textColor);
  });
  
  showToast('Vorlage geladen');
}

function deleteEntryTemplate(idx) {
  showConfirmDialog('Vorlage löschen', 'Möchtest du diese Vorlage wirklich löschen?', 'Löschen', function() {
    const templates = JSON.parse(localStorage.getItem('suppTreeEntryTemplates') || '[]');
    templates.splice(idx, 1);
    localStorage.setItem('suppTreeEntryTemplates', JSON.stringify(templates));
    renderEntryTemplates();
    showToast('Vorlage gelöscht');
  }, true);
}

// Icon picker clicks
document.addEventListener('click', function(e) {
  if (e.target.classList.contains('icon-option') && e.target.closest('#entryIconPicker')) {
    document.querySelectorAll('#entryIconPicker .icon-option').forEach(o => o.classList.remove('selected'));
    e.target.classList.add('selected');
    selectedEntryIcon = e.target.dataset.icon;
  }
  if (e.target.classList.contains('color-option') && e.target.closest('#entryBgColorPicker')) {
    document.querySelectorAll('#entryBgColorPicker .color-option').forEach(o => o.classList.remove('selected'));
    e.target.classList.add('selected');
    selectedEntryBgColor = e.target.dataset.color;
  }
  if (e.target.classList.contains('color-option') && e.target.closest('#entryTextColorPicker')) {
    document.querySelectorAll('#entryTextColorPicker .color-option').forEach(o => o.classList.remove('selected'));
    e.target.classList.add('selected');
    selectedEntryTextColor = e.target.dataset.color;
  }
});

// ===============================
// 7-DAY PREVIEW
// ===============================
function toggleWeekPreview() {
  const section = document.getElementById('weekPreviewSection');
  if (section) {
    section.classList.toggle('expanded');
    if (section.classList.contains('expanded')) {
      renderWeekPreview();
    }
  }
}

function renderWeekPreview() {
  const container = document.getElementById('weekPreviewContent');
  if (!container) return;
  
  const today = new Date();
  const dayNamesShort = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
  
  let html = '';
  
  for (let i = 1; i <= 7; i++) {
    const day = new Date(today);
    day.setDate(today.getDate() + i);
    const dateStr = formatDate(day);
    const dayId = `day-accordion-${i}`;
    
    const shift = shifts[dateStr];
    const shiftInfo = shift ? shiftConfig[shift] : null;
    const items = getItemsForDay(dateStr, shift);
    const itemCount = items.length;
    const hasTraining = items.some(it => it.entryId && it.entryId.startsWith('plan_'));

    html += `
      <div class="day-accordion ${hasTraining ? 'expanded' : ''}" id="${dayId}">
        <div class="day-accordion-header" onclick="toggleDayAccordion('${dayId}')">
          <div class="day-accordion-left">
            <div class="day-accordion-date">
              <span class="day-accordion-weekday">${dayNamesShort[day.getDay()]}</span>
              <span class="day-accordion-day">${day.getDate()}</span>
            </div>
            <div class="day-accordion-info">
              <span class="day-accordion-shift">${shiftInfo ? shiftInfo.name : 'Frei'}</span>
              <span class="day-accordion-count">${itemCount} ${itemCount === 1 ? 'Eintrag' : 'Einträge'}${hasTraining ? ' · 🏋️' : ''}</span>
            </div>
          </div>
          <div class="day-accordion-right">
            ${shiftInfo ? `<span class="day-accordion-badge" style="background: ${shiftInfo.color || '#94a3b8'}">${shiftInfo.name?.substring(0,1) || 'F'}</span>` : ''}
            <span class="day-accordion-arrow">›</span>
          </div>
        </div>
        <div class="day-accordion-content">
          ${items.length > 0 ? `
            <div class="day-accordion-items">
              ${items.map(item => {
                const isTrainingItem = item.entryId && item.entryId.startsWith('plan_');
                if (isTrainingItem) {
                  return `
                  <div class="day-item" data-entry-id="${item.entryId}" onclick="openCalendarEntry('${item.entryId}')" style="background:#dbeafe;border:1.5px solid #93c5fd;cursor:pointer;border-radius:7px;padding:10px 12px;position:relative">
                    <span class="day-item-time" style="color:#1e40af">${item.time}</span>
                    <span class="day-item-icon">${item.icon}</span>
                    <div style="flex:1">
                      <span class="day-item-name" style="color:#1e40af;font-weight:700">${item.name}</span>
                      ${item.entryNote ? `<div style="font-size:9px;color:#3b82f6;margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:180px">${item.entryNote}</div>` : ''}
                    </div>
                    <span style="color:#3b82f6;font-size:14px">›</span>
                  </div>`;
                }
                const bgStyle = item.bgColor ? 'background:' + item.bgColor + ';' : '';
                const clickable = item.entryId ? true : false;
                const onclick = clickable ? `onclick="openCalendarEntry('${item.entryId}')"` : '';
                const dataAttr = clickable ? `data-entry-id="${item.entryId}"` : '';
                return `
                <div class="day-item" style="${bgStyle}${clickable ? 'cursor:pointer;' : ''}" ${onclick} ${dataAttr}>
                  <span class="day-item-time" ${item.textColor ? `style="color: ${item.textColor}"` : ''}>${item.time}</span>
                  <span class="day-item-icon">${item.icon}</span>
                  <span class="day-item-name" ${item.textColor ? `style="color: ${item.textColor}"` : ''}>${item.name}</span>
                </div>`;
              }).join('')}
              <div class="day-add-buttons">
                <button class="day-add-btn supplement" onclick="openAddSupplementForDay('${dateStr}')">💊 Supplement</button>
                <button class="day-add-btn entry" onclick="openAddEntryForDay('${dateStr}')">📝 Eintrag</button>
              </div>
            </div>
          ` : `
            <div class="day-empty-state">
              <p>Keine Einträge für diesen Tag</p>
              <div class="day-add-buttons">
                <button class="day-add-btn supplement" onclick="openAddSupplementForDay('${dateStr}')">💊 Supplement</button>
                <button class="day-add-btn entry" onclick="openAddEntryForDay('${dateStr}')">📝 Eintrag</button>
              </div>
            </div>
          `}
        </div>
      </div>
    `;
  }
  
  container.innerHTML = html;

  // Event-Delegation für klickbare Items (robuster als inline onclick)
  container.querySelectorAll('[data-entry-id]').forEach(el => {
    el.addEventListener('click', function(e) {
      e.stopPropagation();
      const eid = this.getAttribute('data-entry-id');
      if (eid) openCalendarEntry(eid);
    });
  });
}

function render7DayPreview() { try { renderWeekPreview(); } catch(e) {} }

function toggleDayAccordion(dayId) {
  const el = document.getElementById(dayId);
  if (!el) return;
  el.classList.toggle('expanded');
}

function getItemsForDay(dateStr, shift) {
  const items = [];
  
  // Get shift info for wake/sleep times
  let shiftInfo = { ...(shiftConfig[shift] || shiftConfig['off']) };
  
  // Prüfe ob custom sleep time für diesen Tag existiert
  const customSleepTimes = JSON.parse(localStorage.getItem('suppTreeCustomSleepTimes') || '{}');
  if (customSleepTimes[dateStr]) {
    shiftInfo.sleep = customSleepTimes[dateStr];
  }

  // Prüfe ob custom wake time für diesen Tag existiert
  const customWakeTimes = JSON.parse(localStorage.getItem('suppTreeCustomWakeTimes') || '{}');
  if (customWakeTimes[dateStr]) {
    shiftInfo.wake = customWakeTimes[dateStr];
  }

  const wakeTime = shiftInfo.wake || '08:00';
  const sleepTime = shiftInfo.sleep || '23:00';
  
  // ADD WAKE UP ENTRY
  let wakeInstruction = 'Freier Tag';
  if (shiftInfo.name && shiftInfo.start && shiftInfo.end) {
    wakeInstruction = `${shiftInfo.name} (${shiftInfo.start} - ${shiftInfo.end})`;
  } else if (shiftInfo.name) {
    wakeInstruction = shiftInfo.name;
  }
  
  items.push({
    name: 'Aufstehen',
    time: wakeTime,
    icon: '🌅',
    type: 'info-wake',
    dose: wakeInstruction
  });
  
  // Get scheduled supplements - ALWAYS recalculate to get fresh data
  // Ensure supplements are loaded first
  if (typeof ensureSupplementsLoaded === 'function') {
    ensureSupplementsLoaded();
  }
  
  let dayIntakes = [];
  if (typeof scheduleSupplementsForDate === 'function') {
    try { 
      dayIntakes = scheduleSupplementsForDate(dateStr); 
    } catch(e) {
      // Error scheduling supplements - ignore
    }
  }
  
  if (dayIntakes && dayIntakes.length > 0) {
    dayIntakes.forEach(intake => {
      // Build dose info based on form
      let doseInfo = '';
      const count = parseInt(intake.capsules) || 1;
      let form = intake.form || 'capsule';
      
      // Auto-detect form from name if not set
      if (!intake.form) {
        const name = (intake.name || '').toLowerCase();
        if (name.includes('tropfen') || name.includes('drops') || name.includes('öl')) {
          form = 'drops';
        } else if (name.includes('spray')) {
          form = 'spray';
        } else if (name.includes('pulver') || name.includes('powder') || name.includes('kreatin') || name.includes('creatine')) {
          form = 'powder';
        } else if (name.includes('softgel') || name.includes('fischöl') || name.includes('fish oil') || name.includes('omega')) {
          form = 'softgel';
        } else if (name.includes('gummi') || name.includes('gummy')) {
          form = 'gummy';
        } else if (name.includes('tablette') || name.includes('tablet')) {
          form = 'tablet';
        }
      }
      
      // Custom dose unit takes priority
      if (intake.doseUnit) {
        doseInfo = intake.doseUnit;
      } else {
        const formLabels = {
          'capsule': { s: 'Kapsel', p: 'Kapseln' },
          'tablet': { s: 'Tablette', p: 'Tabletten' },
          'softgel': { s: 'Softgel', p: 'Softgels' },
          'drops': { s: 'Tropfen', p: 'Tropfen' },
          'spray': { s: 'Sprühstoß', p: 'Sprühstöße' },
          'powder': { s: 'Portion', p: 'Portionen' },
          'liquid': { s: 'ml', p: 'ml' },
          'gummy': { s: 'Gummibärchen', p: 'Gummibärchen' },
          'lozenge': { s: 'Lutschtablette', p: 'Lutschtabletten' }
        };
        const label = formLabels[form] || formLabels['capsule'];
        doseInfo = `${count} ${count === 1 ? label.s : label.p}`;
      }
      
      // Add instruction if with food
      if (intake.withFood) {
        const hasFatWarning = (intake.warnings || []).some(w => w.toLowerCase().includes('fetthaltig'));
        doseInfo += hasFatWarning ? ' • Mit fetthaltiger Mahlzeit' : ' • Mit dem Essen';
      }
      
      // Add dose index info for multiple intakes
      let doseIndexInfo = '';
      if (intake.totalDoses && intake.totalDoses > 1) {
        doseIndexInfo = ` (${intake.doseIndex}/${intake.totalDoses})`;
      }
      
      items.push({
        name: intake.name,
        time: intake.customTime || intake.time,
        icon: intake.icon || '💊',
        type: 'supplement',
        dose: doseInfo + doseIndexInfo,
        reason: intake.reason || '',
        reasonDetail: intake.reasonDetail || '',
        suppId: intake.suppId,
        doseIndex: intake.doseIndex,
        totalDoses: intake.totalDoses
      });
    });
  } else if (typeof mySupplements !== 'undefined' && mySupplements.length > 0) {
    mySupplements.filter(s => !s.status || s.status !== 'waiting').forEach(supp => {
      const count = parseInt(supp.dosagePerDay) || 1;
      let form = supp.form || 'capsule';
      
      // Auto-detect form from name
      const name = (supp.name || '').toLowerCase();
      if (name.includes('tropfen') || name.includes('drops')) form = 'drops';
      else if (name.includes('spray')) form = 'spray';
      else if (name.includes('pulver') || name.includes('kreatin')) form = 'powder';
      else if (name.includes('softgel') || name.includes('omega')) form = 'softgel';
      
      const formLabels = {
        'capsule': { s: 'Kapsel', p: 'Kapseln' },
        'tablet': { s: 'Tablette', p: 'Tabletten' },
        'softgel': { s: 'Softgel', p: 'Softgels' },
        'drops': { s: 'Tropfen', p: 'Tropfen' },
        'spray': { s: 'Sprühstoß', p: 'Sprühstöße' },
        'powder': { s: 'Portion', p: 'Portionen' }
      };
      const label = formLabels[form] || formLabels['capsule'];
      const doseInfo = `${count} ${count === 1 ? label.s : label.p}`;
      
      items.push({
        name: supp.name,
        time: '08:00',
        icon: supp.icon || '💊',
        type: 'supplement',
        dose: doseInfo
      });
    });
  }
  
  // ADD SLEEP ENTRY
  items.push({
    name: 'Schlafen gehen',
    time: sleepTime,
    icon: '😴',
    type: 'info-sleep',
    dose: 'Gute Nacht! 🌙'
  });
  
  // === AKTIVE KUREN/PLÄNE SUPPLEMENTS ===
  const kuren = JSON.parse(localStorage.getItem('suppTreeKuren') || '[]');
  
  kuren.forEach(kur => {
    // Prüfe ob Kur an diesem Tag aktiv ist
    if (kur.startDate <= dateStr && kur.endDate >= dateStr) {
      // Partner-Kuren haben detaillierte Supplements mit relativen Zeiten
      if (kur.type === 'partner' && kur.supplements) {
        kur.supplements.forEach(supp => {
          // Berechne Zeit basierend auf Schicht
          const calculatedTime = supp.timing 
            ? calculateKurTime(supp.timing, shift, shiftInfo)
            : supp.time || '08:00';
          
          items.push({
            name: supp.name,
            time: calculatedTime,
            icon: supp.icon || '💊',
            type: 'kur',
            kurName: kur.name,
            kurIcon: kur.icon,
            label: supp.label || ''
          });
        });
      } else if (kur.supplements && Array.isArray(kur.supplements)) {
        // Standard-Kuren: Supplements relativ zur Schicht verteilen
        const timings = ['wake+30', 'meal2', 'sleep-60', 'meal3'];
        kur.supplements.forEach((suppName, idx) => {
          const timing = timings[idx % timings.length];
          const calculatedTime = calculateKurTime(timing, shift, shiftInfo);
          items.push({
            name: suppName,
            time: calculatedTime,
            icon: kur.icon || '💊',
            type: 'kur',
            kurName: kur.name
          });
        });
      }
    }
  });
  
  // Get custom entries
  const customEntries = JSON.parse(localStorage.getItem('suppTreeCustomEntries') || '[]');
  customEntries.forEach(entry => {
    if (entry.repeat || entry.date === dateStr) {
      items.push({
        name: entry.name,
        time: entry.time,
        icon: entry.icon || '📝',
        type: 'custom',
        bgColor: entry.bgColor,
        textColor: entry.textColor,
        entryId: entry.id || null,
        entryNote: entry.note || '',
        entryDate: entry.date || null
      });
    }
  });
  
  // Get spontaneous meals for this day
  const spontaneousMeals = getSpontaneousMeals(dateStr);
  spontaneousMeals.forEach(meal => {
    items.push({
      name: meal.name,
      time: meal.time,
      icon: meal.icon || '🍽️',
      type: 'meal',
      mealType: meal.type
    });
  });
  
  // === MEDIKAMENTE in Tagesansicht einbinden ===
  try {
    const medsForDay = getMedicationsForDate(dateStr);
    medsForDay.forEach(med => {
      items.push({
        name: med.label ? med.label.split(' (')[0] : med.name || 'Medikament',
        time: med.time,
        icon: med.icon || '💊',
        type: 'medication',
        dose: med.instruction ? (instructionLabels[med.instruction] || '') : '',
        medId: med.id || null
      });
    });
  } catch(e) {
    console.warn('Medikamente fuer Tag laden fehlgeschlagen:', e);
  }

  // === TRAININGS-TIMING: Supplements auf Trainingstagen zeitlich anpassen ===
  // Prüfe ob an diesem Tag ein Training stattfindet
  const trainingEntry = items.find(it => it.type === 'custom' && it.entryId && it.entryId.startsWith('plan_'));
  if (trainingEntry) {
    const [trH, trM] = (trainingEntry.time || '09:00').split(':').map(Number);
    const trainingMin = trH * 60 + trM;

    // Hole alle Supplement-Pläne mit Trainings-Timing
    try {
      const allPlaene = mbGetPlaene();
      const suppPlans = allPlaene.filter(p => p.type === 'supplement' && p.supplements);
      suppPlans.forEach(sp => {
        sp.supplements.forEach(supp => {
          if (!supp.training) return;
          // Berechne die richtige Zeit
          const offsetMin = supp.training.hours * 60;
          let targetMin = supp.training.relation === 'pre' ? trainingMin - offsetMin : trainingMin + offsetMin;
          targetMin = Math.max(0, Math.min(targetMin, 23 * 60 + 59));
          const targetHH = String(Math.floor(targetMin / 60)).padStart(2, '0');
          const targetMM = String(targetMin % 60).padStart(2, '0');
          const targetTime = targetHH + ':' + targetMM;

          // Finde passende tägliche Supplements (Name-Match, case-insensitive)
          const suppNameLow = supp.name.toLowerCase();
          items.forEach(item => {
            if (item.type === 'supplement') {
              const itemNameLow = (item.name || '').toLowerCase();
              if (itemNameLow.includes(suppNameLow) || suppNameLow.includes(itemNameLow)) {
                item.time = targetTime;
                const tLabel = supp.training.relation === 'pre' ? 'vor' : 'nach';
                const tStr = supp.training.hours < 1 ? Math.round(supp.training.hours * 60) + ' Min' : supp.training.hours + 'h';
                item.trainingNote = tStr + ' ' + tLabel + ' dem Training';
              }
            }
          });
        });
      });
    } catch(e) {}
  }

  // Sort by time considering shift wake time as start of day
  const wakeMinutes = parseInt(wakeTime.split(':')[0]) * 60 + parseInt(wakeTime.split(':')[1]);
  
  items.sort((a, b) => {
    const [aH, aM] = (a.time || '00:00').split(':').map(Number);
    const [bH, bM] = (b.time || '00:00').split(':').map(Number);
    let aMin = aH * 60 + aM;
    let bMin = bH * 60 + bM;
    
    // Adjust times relative to wake time
    // If a time is before wake time, it's "later" in the day (add 24h)
    if (aMin < wakeMinutes) aMin += 24 * 60;
    if (bMin < wakeMinutes) bMin += 24 * 60;
    
    return aMin - bMin;
  });
  
  return items;
}

