let trainingPlan = {};
let trainingLogs = {};
let selectedTrainingDay = 'mo';

function initTrainingPlan() {
  const saved = localStorage.getItem('suppTreeTrainingPlan');
  if (saved) trainingPlan = JSON.parse(saved);
  
  const savedLogs = localStorage.getItem('suppTreeTrainingLogs');
  if (savedLogs) trainingLogs = JSON.parse(savedLogs);
  
  renderTrainingDay();
}

function selectTrainingDay(day) {
  selectedTrainingDay = day;
  document.querySelectorAll('.day-tab').forEach(tab => {
    tab.classList.toggle('active', tab.dataset.day === day);
  });
  renderTrainingDay();
}

function renderTrainingDay() {
  const content = document.getElementById('trainingDayContent');
  const emptyState = document.getElementById('trainingEmpty');
  if (!content) return;
  
  const dayExercises = trainingPlan[selectedTrainingDay] || [];
  
  if (dayExercises.length === 0) {
    if (content) content.style.display = 'none';
    if (emptyState) emptyState.style.display = 'block';
    return;
  }
  
  if (content) content.style.display = 'block';
  if (emptyState) emptyState.style.display = 'none';
  
  content.innerHTML = dayExercises.map(ex => `
    <div class="exercise-card">
      <div class="exercise-header">
        <span class="exercise-icon">${ex.icon || '🏋️'}</span>
        <div class="exercise-info">
          <h4>${ex.name}</h4>
          <p>${ex.sets} Sätze × ${ex.reps} Wdh</p>
        </div>
      </div>
    </div>
  `).join('');
}

