// ================================
// ERNÄHRUNGSPLAN FUNKTIONEN
// ================================

let nutritionData = {};
let waterGlasses = 0;

function initNutritionPlan() {
  const saved = localStorage.getItem('suppTreeNutritionData');
  if (saved) nutritionData = JSON.parse(saved);
  
  updateNutritionUI();
  updateWaterGlasses();
}

function updateNutritionUI() {
  const todayStr = formatDate(new Date());
  const today = nutritionData[todayStr] || { calories: 0, protein: 0, carbs: 0, fat: 0 };
  
  const targets = { calories: 2000, protein: 150, carbs: 200, fat: 70 };
  
  // Update calorie ring
  const percent = Math.min(100, (today.calories / targets.calories) * 100);
  const ring = document.getElementById('caloriesRing');
  if (ring) ring.setAttribute('stroke-dasharray', `${percent}, 100`);
  
  const caloriesEl = document.getElementById('caloriesValue');
  if (caloriesEl) caloriesEl.textContent = today.calories;
  
  // Update macro bars
  ['protein', 'carbs', 'fat'].forEach(macro => {
    const bar = document.getElementById(`${macro}Bar`);
    const current = document.getElementById(`${macro}Current`);
    if (bar) bar.style.width = Math.min(100, (today[macro] / targets[macro]) * 100) + '%';
    if (current) current.textContent = today[macro];
  });
}

function toggleMealExpand(meal) {
  const card = document.getElementById(`${meal}Card`);
  if (card) card.classList.toggle('expanded');
}

function openAddFood(meal) {
  showToast(`Essen zu ${meal} hinzufügen kommt bald!`);
}

function toggleWaterGlass(index) {
  const glasses = document.querySelectorAll('.water-glass');
  
  // If clicking a filled glass at the end, unfill it
  // Otherwise, fill all up to and including clicked glass
  const isCurrentlyFilled = glasses[index]?.classList.contains('filled');
  const isLastFilled = index === waterGlasses - 1;
  
  if (isCurrentlyFilled && isLastFilled) {
    waterGlasses = index;
  } else {
    waterGlasses = index + 1;
  }
  
  updateWaterGlasses();
  saveWaterProgress();
}

function updateWaterGlasses() {
  const glasses = document.querySelectorAll('.water-glass');
  glasses.forEach((glass, i) => {
    glass.classList.toggle('filled', i < waterGlasses);
  });
  
  const amountEl = document.getElementById('waterAmount');
  if (amountEl) {
    const liters = (waterGlasses * 0.3).toFixed(1);
    amountEl.textContent = `${liters} / 2.5 L`;
  }
}

function saveWaterProgress() {
  const todayStr = formatDate(new Date());
  localStorage.setItem('suppTreeWater_' + todayStr, waterGlasses.toString());
}

function changeNutritionDay(delta) {
  showToast('Tagesnavigation kommt bald');
}

function openNutritionSettings() {
  showToast('Ernährungs-Einstellungen');
}

// ===============================
// SUPPLEMENT INFO SHEET (Timeline)
// ===============================

function openSupplementInfoSheet(suppId, name, time, dose, reason, icon, uniqueId) {
  // Find supplement in mySupplements
  const supp = mySupplements.find(s => s.id === suppId || s.name === name);
  
  // Use uniqueId if provided, otherwise fallback to name
  const checkId = uniqueId || name;
  
  // Get supplement rules for detailed info
  const rules = getSupplementRules(name);
  
  // Get completion status - use uniqueId for checking
  const dateStr = formatDate(currentPlannerDate);
  const completedKey = `suppTree_completed_${dateStr}`;
  const completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
  const isDone = completed.includes(checkId);
  
  // Build tips list from rules
  const tips = [];
  
  // Add warnings as tips
  if (rules.warnings && rules.warnings.length > 0) {
    rules.warnings.forEach(w => {
      tips.push({ icon: '💡', text: w });
    });
  }
  
  // Add avoid with info
  if (rules.avoidWith && rules.avoidWith.length > 0) {
    tips.push({ icon: '⚠️', text: `Nicht zusammen mit: ${rules.avoidWith.join(', ')}` });
  }
  
  // Add withFood info
  if (rules.withFood) {
    tips.push({ icon: '🍽️', text: 'Mit einer Mahlzeit einnehmen' });
  } else if (rules.withFood === false) {
    tips.push({ icon: '💧', text: 'Auf nüchternen Magen oder zwischen Mahlzeiten' });
  }
  
  // Add fat soluble info
  if (rules.fatSoluble) {
    tips.push({ icon: '🥑', text: 'Fettlöslich – mit fetthaltiger Nahrung einnehmen' });
  }
  
  // Add no breakfast tip if available
  if (rules.noBreakfastTip) {
    tips.push({ icon: '☀️', text: rules.noBreakfastTip });
  }
  
  // Add coffee restriction if available
  if (rules.coffeeRestriction) {
    tips.push({ icon: '☕', text: rules.coffeeRestriction });
  }
  
  const tipsHTML = tips.length > 0 ? `
    <div class="supp-info-section">
      <h4>📝 Tipps zur Einnahme</h4>
      <div class="supp-info-tips">
        ${tips.map(t => `
          <div class="supp-tip-item">
            <span class="supp-tip-icon">${t.icon}</span>
            <span class="supp-tip-text">${t.text}</span>
          </div>
        `).join('')}
      </div>
    </div>
  ` : '';
  
  // Get timing info
  const optimalTime = time || '08:00';
  const timingReason = rules.optimalTimeReason || rules.singleReason || 'Basierend auf optimaler Aufnahme und Verträglichkeit.';
  
  // Build split info if available
  let splitInfoHTML = '';
  if (rules.canSplit && rules.splitReason) {
    splitInfoHTML = `
      <div class="supp-info-section">
        <h4>📊 Verteilung</h4>
        <div class="supp-info-card split-info">
          <p>${rules.splitReason}</p>
        </div>
      </div>
    `;
  } else if (rules.singleReason && !rules.optimalTimeReason) {
    splitInfoHTML = `
      <div class="supp-info-section">
        <h4>ℹ️ Gut zu wissen</h4>
        <div class="supp-info-card">
          <p>${rules.singleReason}</p>
        </div>
      </div>
    `;
  }
  
  // Partner-Empfehlung: Trainings-Timing vom Berater
  let partnerInfoHTML = '';
  try {
    const allPlaene = mbGetPlaene();
    const beraterList = mbGetBerater();
    allPlaene.filter(p => p.type === 'supplement' && p.supplements).forEach(sp => {
      const matchedSupp = sp.supplements.find(s => {
        const sLow = s.name.toLowerCase();
        const nLow = name.toLowerCase();
        return nLow.includes(sLow) || sLow.includes(nLow);
      });
      if (matchedSupp) {
        const berater = beraterList.find(b => b.id === sp.beraterId);
        const bName = berater ? berater.name : 'Berater';
        const bAvatar = berater ? berater.avatar : '👨‍⚕️';
        let timingHTML = '';
        if (matchedSupp.training) {
          const tLabel = matchedSupp.training.relation === 'pre' ? 'vor' : 'nach';
          const tH = matchedSupp.training.hours;
          const tStr = tH < 1 ? Math.round(tH * 60) + ' Min' : tH + 'h';
          timingHTML = `<div style="display:inline-flex;align-items:center;gap:4px;padding:4px 10px;background:#dbeafe;border-radius:7px;font-size:12px;color:#1e40af;font-weight:600;margin-top:6px">🏋️ ${tStr} ${tLabel} dem Training</div>`;
        }
        partnerInfoHTML = `
          <div class="supp-info-section">
            <h4>${bAvatar} Empfehlung von ${bName}</h4>
            <div class="supp-info-card" style="background:#f0fdf4;border:1px solid #bbf7d0">
              <div style="font-weight:600;color:#166534;font-size:13px">${matchedSupp.name}</div>
              <div style="font-size:12px;color:#15803d;margin-top:2px">${matchedSupp.dose}</div>
              ${matchedSupp.reason ? `<div style="font-size:11px;color:#166534;margin-top:4px">${matchedSupp.reason}</div>` : ''}
              ${timingHTML}
            </div>
          </div>`;
      }
    });
  } catch(e) {}

  // Create sheet HTML
  const sheetId = 'suppInfoSheet';
  let existingSheet = document.getElementById(sheetId);
  if (existingSheet) existingSheet.remove();
  
  const overlayId = 'suppInfoOverlay';
  let existingOverlay = document.getElementById(overlayId);
  if (existingOverlay) existingOverlay.remove();
  
  const sheetHTML = `
    <div class="supp-info-overlay active" id="${overlayId}" onclick="closeSupplementInfoSheet()"></div>
    <div class="supp-info-sheet active" id="${sheetId}">
      <div class="supp-info-header">
        <div class="supp-info-icon">${icon || supp?.icon || '💊'}</div>
        <div class="supp-info-title">
          <h3>${name}</h3>
          <span class="supp-info-dose">${dose || (supp ? supp.dosagePerDay + 'x täglich' : '')}</span>
        </div>
        <button class="supp-info-close" onclick="closeSupplementInfoSheet()">✕</button>
      </div>
      
      <div class="supp-info-content">
        ${partnerInfoHTML}

        ${reason ? `
          <div class="supp-info-section">
            <h4>🎯 Warum jetzt?</h4>
            <div class="supp-info-card">
              <p>${reason}</p>
            </div>
          </div>
        ` : ''}

        <div class="supp-info-section">
          <h4>⏰ Optimale Einnahme</h4>
          <div class="supp-info-timing">
            <div class="timing-label">Empfohlene Zeit</div>
            <div class="timing-value">${time || optimalTime}</div>
            <div class="timing-reason">${timingReason}</div>
          </div>
        </div>
        
        ${tipsHTML}
        ${splitInfoHTML}
      </div>
      
      <div class="supp-info-actions">
        ${formatDate(currentPlannerDate) <= formatDate(new Date()) ? `
          <button class="supp-info-btn primary ${isDone ? 'done' : ''}" onclick="toggleSupplementFromSheet('${checkId.replace(/'/g, "\\'")}', '${name.replace(/'/g, "\\'")}')">
            ${isDone ? '✓ Eingenommen' : '💊 Jetzt einnehmen'}
          </button>
        ` : `
          <button class="supp-info-btn primary" disabled style="opacity:0.5;cursor:not-allowed">
            📅 Geplant für ${formatDate(currentPlannerDate) === formatDate(new Date()) ? 'heute' : new Date(currentPlannerDate).toLocaleDateString('de-DE', {weekday:'short', day:'2-digit', month:'2-digit'})}
          </button>
        `}
        ${suppId ? `
          <button class="supp-info-btn secondary" onclick="openSupplementScheduleFromInfo('${suppId}', '${name.replace(/'/g, "\\'")}')">
            ⚙️ Verteilung anpassen
          </button>
        ` : ''}
      </div>
    </div>
  `;
  
  document.body.insertAdjacentHTML('beforeend', sheetHTML);
  lockBody();
}

function closeSupplementInfoSheet() {
  const sheet = document.getElementById('suppInfoSheet');
  const overlay = document.getElementById('suppInfoOverlay');

  if (sheet) {
    sheet.classList.remove('active');
    setTimeout(() => sheet.remove(), 300);
  }
  if (overlay) {
    overlay.classList.remove('active');
    setTimeout(() => overlay.remove(), 300);
  }
  // currentPlannerDate auf heute zurücksetzen
  currentPlannerDate = new Date();
  unlockBody();
}

function toggleSupplementFromSheet(uniqueId, displayName) {
  const name = displayName || uniqueId;
  const dateStr = formatDate(currentPlannerDate);
  const completedKey = `suppTree_completed_${dateStr}`;
  let completed = JSON.parse(localStorage.getItem(completedKey) || '[]');
  
  const isDone = completed.includes(uniqueId);
  
  if (isDone) {
    completed = completed.filter(n => n !== uniqueId);
  } else {
    completed.push(uniqueId);
  }
  
  localStorage.setItem(completedKey, JSON.stringify(completed));
  
  // Update button in sheet
  const btn = document.querySelector('.supp-info-btn.primary');
  if (btn) {
    if (!isDone) {
      btn.classList.add('done');
      btn.innerHTML = '✓ Eingenommen';
      showToast(`${name} eingenommen ✓`);
    } else {
      btn.classList.remove('done');
      btn.innerHTML = '💊 Jetzt einnehmen';
    }
  }
  
  // Update timeline
  renderDayPlanner();
  renderWeekOverview();
}

