function showSupplementReason(name, reason) {
  if (!reason) {
    showToast('Keine Details verfügbar');
    return;
  }
  
  // Show a simple toast with the reason for now
  const modal = document.createElement('div');
  modal.className = 'reason-modal';
  modal.innerHTML = `
    <div class="reason-modal-content">
      <div class="reason-modal-header">
        <h4>💡 ${name}</h4>
        <button onclick="this.closest('.reason-modal').remove()">✕</button>
      </div>
      <p>${reason}</p>
    </div>
  `;
  
  // Add styles inline
  modal.style.cssText = `
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0,0,0,0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 100000;
    padding: 20px;
  `;
  
  const content = modal.querySelector('.reason-modal-content');
  content.style.cssText = `
    background: white;
    border-radius: 7px;
    padding: 20px;
    max-width: 350px;
    width: 100%;
    box-shadow: 0 10px 40px rgba(0,0,0,0.2);
  `;
  
  const header = modal.querySelector('.reason-modal-header');
  header.style.cssText = `
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 12px;
  `;
  
  header.querySelector('h4').style.cssText = `
    font-size: 16px;
    font-weight: 700;
    color: #166534;
    margin: 0;
  `;
  
  header.querySelector('button').style.cssText = `
    background: #f3f4f6;
    border: none;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    cursor: pointer;
    font-size: 14px;
  `;
  
  modal.querySelector('p').style.cssText = `
    font-size: 14px;
    color: #374151;
    line-height: 1.6;
    margin: 0;
  `;
  
  modal.onclick = function(e) {
    if (e.target === modal) modal.remove();
  };
  
  document.body.appendChild(modal);
}

let currentScheduleSuppId = null;

function openSupplementScheduleSheet(suppId, suppName) {
  if (!suppId) {
    // Toggle for simple check
    showToast('✓ ' + suppName);
    return;
  }
  
  currentScheduleSuppId = suppId;
  
  // Find supplement
  const supp = mySupplements.find(s => s.id === suppId);
  if (!supp) {
    showToast('Supplement nicht gefunden');
    return;
  }
  
  const rules = getSupplementRules(supp.name);
  const totalCapsules = supp.dosagePerDay || 1;
  const currentMode = supp.distributionMode || 'auto';
  
  // Check if user skips breakfast
  const skipBreakfast = localStorage.getItem('suppTreeSkipBreakfast') === 'true';
  
  // Build distribution preview
  const canSplit = rules.canSplit !== false;
  const splitThreshold = rules.splitThreshold || 3;
  
  let autoPreview = '';
  if (canSplit && totalCapsules >= splitThreshold) {
    const dist = calculateDistribution(totalCapsules, 'morning', rules, false, false);
    autoPreview = dist.map(d => `${d.count}x ${d.reason.replace(/\s*\(\d+\/\d+\)/, '')}`).join(', ');
  } else {
    autoPreview = `${totalCapsules}x zum optimalen Zeitpunkt`;
  }
  
  // Get form label
  const formLabels = {
    'capsule': totalCapsules === 1 ? 'Kapsel' : 'Kapseln',
    'tablet': totalCapsules === 1 ? 'Tablette' : 'Tabletten',
    'softgel': 'Softgels',
    'drops': 'Tropfen',
    'spray': 'Sprühstöße',
    'powder': totalCapsules === 1 ? 'Portion' : 'Portionen'
  };
  const formLabel = formLabels[supp.form] || 'Einheiten';
  
  // Build noBreakfast tip if applicable
  const noBreakfastSection = rules.noBreakfastTip ? `
    <div class="supp-schedule-tip ${skipBreakfast ? 'highlighted' : ''}">
      <div class="tip-header">
        <span class="tip-icon">🥣</span>
        <span class="tip-title">Kein Frühstück?</span>
        <label class="tip-toggle">
          <input type="checkbox" id="skipBreakfastToggle" ${skipBreakfast ? 'checked' : ''} onchange="toggleSkipBreakfast(this.checked)">
          <span class="tip-toggle-slider"></span>
        </label>
      </div>
      <p class="tip-text">${rules.noBreakfastTip}</p>
    </div>
  ` : '';
  
  // Create sheet HTML
  const sheetHTML = `
    <div class="supp-schedule-overlay active" onclick="closeSupplementScheduleSheet()"></div>
    <div class="supp-schedule-sheet active" id="suppScheduleSheet">
      <div class="supp-schedule-header">
        <h3>${supp.icon || '💊'} ${supp.name}</h3>
        <button class="supp-schedule-close" onclick="closeSupplementScheduleSheet()">✕</button>
      </div>
      
      <div class="supp-schedule-content">
        <div class="supp-schedule-info">
          <h4>💡 Warum diese Zeit?</h4>
          <p>${rules.optimalTimeReason || rules.singleReason || 'Optimaler Zeitpunkt basierend auf dem Supplement-Typ.'}</p>
        </div>
        
        ${noBreakfastSection}
        
        <div class="supp-schedule-section">
          <h4>📊 Verteilung (${totalCapsules} ${formLabel}/Tag)</h4>
          <div class="distribution-options">
            <label class="distribution-option ${currentMode === 'auto' ? 'selected' : ''}" onclick="selectDistributionMode('auto')">
              <input type="radio" name="distMode" value="auto" ${currentMode === 'auto' ? 'checked' : ''}>
              <div class="distribution-option-radio"></div>
              <div class="distribution-option-content">
                <div class="distribution-option-title">🤖 Optimal verteilt</div>
                <div class="distribution-option-desc">${canSplit && totalCapsules >= splitThreshold ? rules.splitReason || 'Wissenschaftlich optimierte Verteilung' : rules.singleReason || 'Eine Einnahme zum optimalen Zeitpunkt'}</div>
                <div class="distribution-option-preview">${autoPreview}</div>
              </div>
            </label>
            
            <label class="distribution-option ${currentMode === 'all-at-once' ? 'selected' : ''}" onclick="selectDistributionMode('all-at-once')">
              <input type="radio" name="distMode" value="all-at-once" ${currentMode === 'all-at-once' ? 'checked' : ''}>
              <div class="distribution-option-radio"></div>
              <div class="distribution-option-content">
                <div class="distribution-option-title">📦 Alle auf einmal</div>
                <div class="distribution-option-desc">${totalCapsules} ${formLabel} zu einer Zeit</div>
                ${canSplit && totalCapsules >= splitThreshold ? '<div class="distribution-option-preview" style="color: #f59e0b;">⚠️ Nicht optimal für die Aufnahme</div>' : '<div class="distribution-option-preview">✓ Kein Nachteil bei dieser Dosis</div>'}
              </div>
            </label>
            
            <label class="distribution-option ${currentMode === 'custom' ? 'selected' : ''}" onclick="selectDistributionMode('custom')">
              <input type="radio" name="distMode" value="custom" ${currentMode === 'custom' ? 'checked' : ''}>
              <div class="distribution-option-radio"></div>
              <div class="distribution-option-content">
                <div class="distribution-option-title">✏️ Individuell</div>
                <div class="distribution-option-desc">Eigene Zeiten festlegen</div>
              </div>
            </label>
          </div>
        </div>
        
        <div class="custom-schedule-editor ${currentMode === 'custom' ? 'active' : ''}" id="customScheduleEditor">
          <div id="customScheduleItems">
            ${renderCustomScheduleItems(supp)}
          </div>
          <button class="custom-schedule-add" onclick="addCustomScheduleItem()">+ Weitere Zeit hinzufügen</button>
        </div>
        
        ${rules.warnings && rules.warnings.length > 0 ? `
        <div class="supp-schedule-section">
          <h4>⚠️ Hinweise</h4>
          <div style="background: #fef3c7; border-radius: 7px; padding: 12px;">
            ${rules.warnings.map(w => `<div style="font-size: 13px; color: #92400e; margin-bottom: 4px;">• ${w}</div>`).join('')}
          </div>
        </div>
        ` : ''}
      </div>
      
      <div class="supp-schedule-footer">
        <button class="supp-schedule-save" onclick="saveSupplementSchedule()">Speichern</button>
      </div>
    </div>
  `;
  
  // Remove existing sheet if any
  const existingOverlay = document.querySelector('.supp-schedule-overlay');
  if (existingOverlay) existingOverlay.remove();
  const existingSheet = document.getElementById('suppScheduleSheet');
  if (existingSheet) existingSheet.remove();
  
  // Lock body scroll
  document.body.classList.add('sheet-open');
  
  // Add to DOM
  document.body.insertAdjacentHTML('beforeend', sheetHTML);
}

function toggleSkipBreakfast(skip) {
  localStorage.setItem('suppTreeSkipBreakfast', skip ? 'true' : 'false');
  
  // Update UI
  const tip = document.querySelector('.supp-schedule-tip');
  if (tip) {
    tip.classList.toggle('highlighted', skip);
  }
  
  // Recalculate schedules
  updateAllScheduledIntakes();
  
  showToast(skip ? '🥣 Einnahme auf Mittagessen verschoben' : '🍳 Einnahme mit Frühstück');
}

function renderCustomScheduleItems(supp) {
  const customSchedule = supp.customSchedule || [];
  const totalCapsules = supp.dosagePerDay || 1;
  
  if (customSchedule.length === 0) {
    // Default: one entry with all capsules
    return `
      <div class="custom-schedule-item" data-index="0">
        <input type="time" value="08:00" class="custom-time">
        <input type="number" value="${totalCapsules}" min="1" max="${totalCapsules}" class="custom-count"> Stk.
        <button onclick="removeCustomScheduleItem(this)" style="background: none; border: none; font-size: 18px; cursor: pointer; opacity: 0.5;">🗑️</button>
      </div>
    `;
  }
  
  return customSchedule.map((item, idx) => `
    <div class="custom-schedule-item" data-index="${idx}">
      <input type="time" value="${item.time}" class="custom-time">
      <input type="number" value="${item.count}" min="1" max="${totalCapsules}" class="custom-count"> Stk.
      <button onclick="removeCustomScheduleItem(this)" style="background: none; border: none; font-size: 18px; cursor: pointer; opacity: 0.5;">🗑️</button>
    </div>
  `).join('');
}

function addCustomScheduleItem() {
  const container = document.getElementById('customScheduleItems');
  const items = container.querySelectorAll('.custom-schedule-item');
  const newIdx = items.length;
  
  const newItem = document.createElement('div');
  newItem.className = 'custom-schedule-item';
  newItem.dataset.index = newIdx;
  newItem.innerHTML = `
    <input type="time" value="12:00" class="custom-time">
    <input type="number" value="1" min="1" max="10" class="custom-count"> Stk.
    <button onclick="removeCustomScheduleItem(this)" style="background: none; border: none; font-size: 18px; cursor: pointer; opacity: 0.5;">🗑️</button>
  `;
  
  container.appendChild(newItem);
}

function removeCustomScheduleItem(btn) {
  const item = btn.closest('.custom-schedule-item');
  const container = document.getElementById('customScheduleItems');
  if (container.querySelectorAll('.custom-schedule-item').length > 1) {
    item.remove();
  } else {
    showToast('Mindestens eine Zeit benötigt');
  }
}

function selectDistributionMode(mode) {
  // Update UI
  document.querySelectorAll('.distribution-option').forEach(opt => {
    opt.classList.toggle('selected', opt.querySelector('input').value === mode);
  });
  
  // Show/hide custom editor
  const editor = document.getElementById('customScheduleEditor');
  if (editor) {
    editor.classList.toggle('active', mode === 'custom');
  }
}

let _suppInfoWasOpen = false;

function openSupplementScheduleFromInfo(suppId, suppName) {
  // Info-Sheet nur ausblenden, nicht zerstören
  const infoSheet = document.getElementById('suppInfoSheet');
  const infoOverlay = document.getElementById('suppInfoOverlay');
  if (infoSheet) infoSheet.style.display = 'none';
  if (infoOverlay) infoOverlay.style.display = 'none';
  _suppInfoWasOpen = true;
  openSupplementScheduleSheet(suppId, suppName);
}

function closeSupplementScheduleSheet() {
  const overlay = document.querySelector('.supp-schedule-overlay');
  const sheet = document.getElementById('suppScheduleSheet');

  document.body.classList.remove('sheet-open');

  if (overlay) {
    overlay.classList.remove('active');
    setTimeout(() => overlay.remove(), 300);
  }
  if (sheet) {
    sheet.classList.remove('active');
    setTimeout(() => sheet.remove(), 300);
  }

  currentScheduleSuppId = null;

  // Info-Sheet wiederherstellen wenn es vorher offen war
  if (_suppInfoWasOpen) {
    _suppInfoWasOpen = false;
    const infoSheet = document.getElementById('suppInfoSheet');
    const infoOverlay = document.getElementById('suppInfoOverlay');
    if (infoSheet) infoSheet.style.display = '';
    if (infoOverlay) infoOverlay.style.display = '';
  } else {
    unlockBody();
  }
}

function saveSupplementSchedule() {
  if (!currentScheduleSuppId) return;
  
  const suppIdx = mySupplements.findIndex(s => s.id === currentScheduleSuppId);
  if (suppIdx === -1) return;
  
  // Get selected mode
  const selectedMode = document.querySelector('.distribution-option.selected input')?.value || 'auto';
  
  mySupplements[suppIdx].distributionMode = selectedMode;
  
  // If custom, save the schedule
  if (selectedMode === 'custom') {
    const items = document.querySelectorAll('.custom-schedule-item');
    const customSchedule = [];
    
    items.forEach((item, idx) => {
      const time = item.querySelector('.custom-time')?.value || '08:00';
      const count = parseInt(item.querySelector('.custom-count')?.value) || 1;
      
      customSchedule.push({
        time: time,
        count: count,
        index: idx + 1,
        reason: 'Individuell eingestellt'
      });
    });
    
    mySupplements[suppIdx].customSchedule = customSchedule;
  } else {
    // Clear custom schedule
    mySupplements[suppIdx].customSchedule = null;
  }
  
  // Save and update
  saveMySupplements();
  updateAllScheduledIntakes();
  renderDayPlanner();
  
  closeSupplementScheduleSheet();
  showToast('✓ Einnahmezeit gespeichert');
}

