// Entdecken State
let ekSelectedCat=null;
let ekSelectedSubcat=null;
let ekSelectedPractitioner=null;
let ekMap=null;
let ekMarkers=[];
let ekSearchPlz='';
let ekUserLat=48.135;
let ekUserLng=11.582;

// Dashboard: 5 Kategorie-Cards rendern
function renderDashEntdecken(){
  const c=document.getElementById('ekDashCategories');
  if(!c) return;
  c.innerHTML=ekCategories.map((cat,i)=>{
    const count=ekPractitioners.filter(p=>p.mainCat===cat.id).length;
    return `<div class="ek-dash-card${i===0?' full':''}" style="background:${cat.color}" onclick="ekOpenCategory('${cat.id}')">
      <div class="ek-dash-card-count">${count} Anbieter</div>
      <div class="ek-dash-card-icon">${cat.icon}</div>
      <div class="ek-dash-card-name">${cat.name}</div>
      <div class="ek-dash-card-desc">${cat.desc}</div>
    </div>`;
  }).join('');
}

// Kategorie öffnen → Unterkategorien-Screen
function ekOpenCategory(catId){
  ekSelectedCat=ekCategories.find(c=>c.id===catId);
  ekSelectedSubcat=null;
  switchScreen('entdeckenCatScreen');
}

// Unterkategorien-Screen rendern
function renderEntdeckenCat(){
  if(!ekSelectedCat){ekSelectedCat=ekCategories[0];}
  const cat=ekSelectedCat;
  document.getElementById('ekCatTitle').textContent=cat.icon+' '+cat.name;
  let html=`<div class="ek-cat-subtitle">${cat.desc}</div>`;
  html+='<div class="ek-subcat-list">';
  cat.subcats.forEach(sc=>{
    const cnt=ekPractitioners.filter(p=>p.categories.includes(sc.id)).length;
    html+=`<div class="ek-subcat-item" onclick="ekOpenSubcat('${sc.id}')">
      <div class="ek-subcat-item-avatar" style="background:${cat.color}">${sc.icon}</div>
      <div class="ek-subcat-item-info">
        <div class="ek-subcat-item-name">${sc.name}</div>
        <div class="ek-subcat-item-desc">${sc.desc||''}</div>
        <div class="ek-subcat-item-count">📍 ${cnt} in deiner Nähe</div>
      </div>
      <div class="ek-subcat-item-arrow">→</div>
    </div>`;
  });
  html+='</div>';
  // Meine Termine Schnellzugriff
  html+=`<div class="ek-cat-section-title">Meine Termine</div>
  <div style="padding:0 16px 20px">
    <div style="display:flex;align-items:center;gap:10px;padding:14px;background:var(--white);border-radius:var(--radius-xl);box-shadow:var(--shadow-card);cursor:pointer" onclick="openAlleTermine()">
      <span style="font-size:20px">📋</span>
      <span style="font-size:14px;font-weight:600">Meine Termine anzeigen</span>
      <span style="margin-left:auto;font-size:18px;color:var(--text-muted)">→</span>
    </div>
  </div>`;
  document.getElementById('ekCatContent').innerHTML=html;
}

// Unterkategorie öffnen → Karten-Screen
function ekOpenSubcat(subcatId){
  ekSelectedSubcat=subcatId;
  switchScreen('entdeckenMapScreen');
}

// Karten-Screen rendern
function renderEntdeckenMap(){
  if(!ekSelectedCat){ekSelectedCat=ekCategories[0];}
  const cat=ekSelectedCat;
  document.getElementById('ekMapTitle').textContent=cat.name;
  // Reset PLZ
  document.getElementById('ekPlzInput').value='';
  document.getElementById('ekPlzClear').style.display='none';
  document.getElementById('ekSearchCity').textContent='';
  ekSearchPlz='';
  // Render Unterkategorie-Chips
  ekRenderSubcatChips();
  // Anbieter filtern und anzeigen
  ekApplySubcatFilter();
}

// Horizontale Filter-Chips rendern
function ekRenderSubcatChips(){
  const cat=ekSelectedCat;
  const chips=document.getElementById('ekSubcatChips');
  let html='<div class="ek-subcat-chip'+(ekSelectedSubcat===null?' active':'')+'" onclick="ekSetSubcat(null)">Alle</div>';
  cat.subcats.forEach(sc=>{
    const isActive=ekSelectedSubcat===sc.id;
    html+='<div class="ek-subcat-chip'+(isActive?' active':'')+'" onclick="ekSetSubcat(\''+sc.id+'\')">'+sc.icon+' '+sc.name+'</div>';
  });
  chips.innerHTML=html;
}

// Unterkategorie-Chip wechseln
function ekSetSubcat(subcatId){
  ekSelectedSubcat=subcatId;
  ekRenderSubcatChips();
  ekApplySubcatFilter();
}

// Zentrale Filterlogik
function ekApplySubcatFilter(){
  const cat=ekSelectedCat;
  let pracs=ekPractitioners.filter(p=>p.mainCat===cat.id);
  if(ekSelectedSubcat){
    pracs=pracs.filter(p=>p.categories.includes(ekSelectedSubcat));
  }
  // PLZ-Filter anwenden
  const plzVal=document.getElementById('ekPlzInput').value;
  pracs.forEach(p=>{p._distance=ekCalcDistance(ekUserLat,ekUserLng,p.lat,p.lng);});
  if(plzVal.length===5){pracs=pracs.filter(p=>p._distance<=50);}
  pracs.sort((a,b)=>a._distance-b._distance);
  // Ergebnisanzahl aktualisieren
  document.getElementById('ekResultCount').textContent=pracs.length;
  // Karte initialisieren und Marker setzen
  ekInitMap();
  ekUpdateMap(pracs);
  ekRenderPractitionerList(pracs);
}

// Leaflet-Karte initialisieren (lazy)
function ekInitMap(){
  if(ekMap){
    setTimeout(()=>ekMap.invalidateSize(),150);
    return;
  }
  ekMap=L.map('ekMapContainer',{zoomControl:true,scrollWheelZoom:true,attributionControl:true}).setView([ekUserLat,ekUserLng],11);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{
    attribution:'&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
    maxZoom:18
  }).addTo(ekMap);
  setTimeout(()=>ekMap.invalidateSize(),200);
}

// Marker auf der Karte aktualisieren
function ekUpdateMap(pracs){
  ekMarkers.forEach(m=>ekMap.removeLayer(m));
  ekMarkers=[];
  pracs.forEach(p=>{
    const icon=L.divIcon({
      html:'<div class="ek-map-pin '+p.mainCat+'">'+p.avatar+'</div>',
      className:'',
      iconSize:[36,36],
      iconAnchor:[18,18],
      popupAnchor:[0,-20]
    });
    const marker=L.marker([p.lat,p.lng],{icon:icon}).addTo(ekMap);
    marker.bindPopup(`<div class="ek-popup">
      <div class="ek-popup-name">${p.name}</div>
      <div class="ek-popup-title">${p.title}</div>
      <div class="ek-popup-meta">
        ${ekRenderStars(p.rating)} ${p.rating} · ${p.reviews} Bewertungen<br>
        📍 ${p.city} · ${ekFormatDistance(p._distance)}
      </div>
      <button class="ek-popup-btn" onclick="ekOpenPractitioner(${p.id})">Profil ansehen →</button>
    </div>`);
    ekMarkers.push(marker);
  });
  if(ekMarkers.length>0){
    const group=L.featureGroup(ekMarkers);
    ekMap.fitBounds(group.getBounds().pad(0.15));
  }
}

// PLZ-Suche
function ekFilterByPlz(val){
  ekSearchPlz=val;
  const clearBtn=document.getElementById('ekPlzClear');
  const cityEl=document.getElementById('ekSearchCity');
  clearBtn.style.display=val.length>0?'flex':'none';
  if(val.length>=2){
    const prefix=val.substring(0,2);
    const coords=plzCoords[prefix];
    if(coords){
      ekUserLat=coords.lat;
      ekUserLng=coords.lng;
      cityEl.textContent=coords.name;
      if(ekMap) ekMap.setView([coords.lat,coords.lng],11);
    }
  }
  ekApplySubcatFilter();
}

// PLZ zurücksetzen
function ekClearPlz(){
  document.getElementById('ekPlzInput').value='';
  ekSearchPlz='';
  ekUserLat=48.135;ekUserLng=11.582;
  document.getElementById('ekPlzClear').style.display='none';
  document.getElementById('ekSearchCity').textContent='';
  ekApplySubcatFilter();
}

// Haversine-Entfernungsberechnung (km)
function ekCalcDistance(lat1,lng1,lat2,lng2){
  const R=6371;
  const dLat=(lat2-lat1)*Math.PI/180;
  const dLng=(lng2-lng1)*Math.PI/180;
  const a=Math.sin(dLat/2)*Math.sin(dLat/2)+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLng/2)*Math.sin(dLng/2);
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}

// Anbieter-Liste mit aufklappbaren Details rendern
function ekRenderPractitionerList(pracs){
  const c=document.getElementById('ekPractitionerList');
  if(pracs.length===0){
    c.innerHTML='<div class="ek-empty"><div class="ek-empty-icon">🔍</div><div class="ek-empty-text">Keine Anbieter in dieser Kategorie gefunden.<br>Versuchen Sie eine andere PLZ.</div></div>';
    return;
  }
  let html='<div class="ek-list-title">Anbieter in der Nähe</div>';
  pracs.forEach(p=>{
    const cat=ekCategories.find(c=>c.id===p.mainCat);
    const bgColor=cat?cat.color:'#f3f4f6';
    // Vereinfachte Tags statt Service-Liste (Interesse wecken)
    const svcTags=p.services&&p.services.length>0
      ? p.services.map(s=>s.name).join(' · ')
      : '';
    const modeLabels={praxis:'🏥 Vor Ort',video:'📹 Online',phone:'📞 Telefon'};
    const modeTags=p.modes?p.modes.map(m=>modeLabels[m]||m).join(' · '):'';
    html+=`<div class="ek-prac-card" id="ekPrac${p.id}" onclick="ekTogglePracDetail(${p.id},event)">
      <div class="ek-prac-card-top">
        <div class="ek-prac-avatar" style="background:${bgColor}">${p.avatar}</div>
        <div class="ek-prac-info">
          <div class="ek-prac-name">${p.name}${p.verified?' <span class="ek-prac-verified">✓ Verifiziert</span>':''}</div>
          <div class="ek-prac-title">${p.title}</div>
          <div class="ek-prac-meta">
            <span class="ek-prac-meta-item">${ekRenderStars(p.rating)} ${p.rating}</span>
            <span class="ek-prac-meta-item">📍 ${p.city}</span>
            <span class="ek-prac-meta-item">${p.reviews} Bew.</span>
          </div>
        </div>
        <div class="ek-prac-distance">${ekFormatDistance(p._distance)}</div>
      </div>
      <div class="ek-prac-detail">
        ${svcTags?`<div style="font-size:12px;color:var(--text-muted);margin-bottom:8px;line-height:1.5">${svcTags}</div>`:''}
        ${modeTags?`<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px">${p.modes.map(m=>`<span style="padding:3px 8px;background:var(--bg-card);border-radius:7px;font-size:10px;font-weight:500;color:var(--text-muted)">${modeLabels[m]||m}</span>`).join('')}</div>`:''}
        <button class="ek-prac-profil-btn" onclick="event.stopPropagation();ekOpenPractitioner(${p.id})">Profil ansehen →</button>
      </div>
    </div>`;
  });
  c.innerHTML=html;
}

// Anbieter-Card aufklappen
function ekTogglePracDetail(pracId,e){
  if(e.target.closest('.ek-prac-profil-btn')) return;
  const card=document.getElementById('ekPrac'+pracId);
  if(!card) return;
  const wasOpen=card.classList.contains('open');
  document.querySelectorAll('.ek-prac-card.open').forEach(c=>c.classList.remove('open'));
  if(!wasOpen) card.classList.add('open');
}

