// Terminanfrage → Bottom Sheet öffnen
function ekRequestAppointment(pracId){
  ekOpenTerminAnfrage(pracId);
}

// Profil teilen
function ekShareProfile(){
  const p=ekSelectedPractitioner;
  if(!p) return;
  if(navigator.share){
    navigator.share({title:p.name+' – '+p.title,text:'Schau dir diesen Anbieter auf SuppTree an: '+p.name,url:window.location.href});
  } else {
    navigator.clipboard.writeText(p.name+' – '+p.title+' ('+p.city+')').then(()=>showToast('Link kopiert!'));
  }
}

// Sterne-Bewertung rendern
function ekRenderStars(rating){
  const full=Math.floor(rating);
  const half=rating%1>=0.5?1:0;
  return '⭐'.repeat(full)+(half?'⭐':'');
}

// Entfernung formatieren
function ekFormatDistance(km){
  if(km<1) return '< 1 km';
  if(km<10) return km.toFixed(1)+' km';
  return Math.round(km)+' km';
}

// ═══════════════════════════════════════════════════════════════
// TERMINANFRAGE (Appointment Request) System
// ═══════════════════════════════════════════════════════════════

let taCurrentPrac = null;
let taSelectedServiceIdx = 0;
let taSelectedMode = null;

// localStorage Helfer
function taGetAnfragen(){ return JSON.parse(localStorage.getItem('suppTreeKundenAnfragen')||'[]'); }
function taSaveAnfragen(list){ localStorage.setItem('suppTreeKundenAnfragen',JSON.stringify(list)); }

// Bottom Sheet öffnen
function ekOpenTerminAnfrage(pracId, serviceIdx){
  const prac = ekPractitioners.find(p=>p.id===pracId);
  if(!prac) return;
  taCurrentPrac = prac;
  taSelectedServiceIdx = typeof serviceIdx==='number' ? serviceIdx : 0;
  taSelectedMode = prac.modes[0] || 'praxis';
  taRenderSheet();
  lockBody();
  document.getElementById('taOverlay').classList.add('visible');
  document.getElementById('taSheet').classList.add('visible');
}

// Bottom Sheet schließen
function closeTerminAnfrage(){
  document.getElementById('taOverlay').classList.remove('visible');
  document.getElementById('taSheet').classList.remove('visible');
  unlockBody();
  taCurrentPrac = null;
}

// Sheet-Inhalt rendern
function taRenderSheet(){
  const p = taCurrentPrac;
  if(!p) return;
  const modeLabels = {praxis:'🏥 Vor Ort',video:'📹 Video',phone:'📞 Telefon'};

  // Morgen als Mindestdatum
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate()+1);
  const minDate = tomorrow.toISOString().split('T')[0];

  let html = '';

  // Anbieter-Info
  html += `<div class="ta-provider-info">
    <div class="ta-provider-avatar">${p.avatar}</div>
    <div class="ta-provider-details">
      <div class="ta-provider-name">${p.name}</div>
      <div class="ta-provider-title">${p.title}</div>
    </div>
  </div>`;

  // Service-Auswahl
  html += '<div class="ta-section-label">💼 Leistung auswählen</div>';
  html += '<div class="ta-service-list">';
  p.services.forEach((s,i) => {
    const sel = i===taSelectedServiceIdx ? ' selected' : '';
    html += `<div class="ta-service-option${sel}" onclick="taSelectService(${i})">
      <div class="ta-service-radio"></div>
      <div class="ta-service-info">
        <div class="ta-service-name">${s.name}</div>
        <div class="ta-service-meta">⏱ ${s.duration} Min.</div>
      </div>
      <div class="ta-service-price">${s.price} €</div>
    </div>`;
  });
  html += '</div>';

  // Modus-Auswahl
  html += '<div class="ta-section-label">📍 Terminart</div>';
  html += '<div class="ta-mode-chips">';
  p.modes.forEach(m => {
    const sel = m===taSelectedMode ? ' selected' : '';
    html += `<div class="ta-mode-chip${sel}" onclick="taSelectMode('${m}')">${modeLabels[m]||m}</div>`;
  });
  html += '</div>';

  // Verfügbarkeit (Freitext)
  html += '<div class="ta-section-label">⏰ Deine Verfügbarkeit <span style="color:var(--danger)">*</span></div>';
  html += '<textarea class="ta-message-input" id="taVerfuegbarkeit" placeholder="z.B. Ich arbeite im Schichtdienst, kann nur morgens. Mittwoch und Freitag wären ideal." maxlength="300" rows="3" style="min-height:80px"></textarea>';
  html += '<div style="font-size:11px;color:var(--text-muted);margin-top:4px">Der Anbieter schlägt dir basierend darauf einen konkreten Termin vor.</div>';

  // Nachricht (optional)
  html += '<div class="ta-section-label">💬 Nachricht (optional)</div>';
  html += '<textarea class="ta-message-input" id="taNachricht" placeholder="Beschreibe kurz dein Anliegen..." maxlength="500"></textarea>';

  // Preis-Info
  const svc = p.services[taSelectedServiceIdx];
  html += `<div class="ta-price-summary">
    <span class="ta-price-label">${svc.name} · ${svc.duration} Min.</span>
    <span class="ta-price-value">${svc.price} €</span>
  </div>`;

  // Disclaimer + Stornierungsbedingungen
  html += `<div class="ta-disclaimer">Der Anbieter erhält deine Anfrage mit Verfügbarkeit und schlägt dir einen passenden Termin vor. Nach Bestätigung und Zahlung ist der Termin verbindlich.</div>`;
  html += `<div class="ta-disclaimer" style="margin-top:6px;background:#fef3c7;border:1px solid #fcd34d;color:#92400e">
    <strong>Stornierungsbedingungen:</strong><br>
    ✅ Kostenlose Stornierung bis 24h vor dem Termin<br>
    ⚠️ Unter 24h: 50% Stornogebühr<br>
    ❌ Nicht erschienen (No-Show): 100% werden berechnet
  </div>`;

  // Submit
  html += '<button class="ta-submit-btn" onclick="taSubmitAnfrage()">Anfrage senden</button>';

  document.getElementById('taSheetContent').innerHTML = html;
}

// Service auswählen
function taSelectService(idx){
  taSelectedServiceIdx = idx;
  taRenderSheet();
}

// Modus auswählen
function taSelectMode(mode){
  taSelectedMode = mode;
  // Chips aktualisieren
  document.querySelectorAll('.ta-mode-chip').forEach(chip => {
    chip.classList.toggle('selected', chip.textContent.includes(
      mode==='praxis'?'Vor Ort':mode==='video'?'Video':'Telefon'
    ));
  });
}

// Anfrage absenden
function taSubmitAnfrage(){
  const p = taCurrentPrac;
  if(!p) return;
  const svc = p.services[taSelectedServiceIdx];

  // Verfügbarkeit ist Pflicht
  const verfuegbarkeit = document.getElementById('taVerfuegbarkeit').value.trim();
  if(!verfuegbarkeit){
    showToast('Bitte gib deine Verfügbarkeit an');
    return;
  }

  const nachricht = document.getElementById('taNachricht').value.trim();

  // Anfrage-Objekt erstellen
  const anfrage = {
    id: 'ka_'+Date.now(),
    practitionerId: p.id,
    practitionerName: p.name,
    practitionerAvatar: p.avatar,
    practitionerTitle: p.title,
    practitionerCity: p.city,
    service: {name:svc.name, price:svc.price, duration:svc.duration},
    mode: taSelectedMode,
    verfuegbarkeit: verfuegbarkeit,
    message: nachricht,
    status: 'pending',
    terminVorschlag: null,
    zahlung: null,
    paidAt: null,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    partnerAnfrageId: null  // Wird ggf. vom Partner-System gelinkt
  };

  // In localStorage speichern
  const anfragen = taGetAnfragen();
  anfragen.unshift(anfrage);
  taSaveAnfragen(anfragen);

  // Supabase: Buchung erstellen
  if (supabase && currentUser) {
    supabase.from('bookings').insert({
      customer_id: currentUser.id,
      customer_name: currentUser.user_metadata?.name || currentUser.email || '',
      partner_id: p.id,
      partner_name: p.name,
      service: svc.name,
      price: svc.price,
      duration: svc.duration,
      mode: taSelectedMode,
      customer_message: verfuegbarkeit,
      notes: nachricht,
      status: 'requested'
    }).select().single().then(function(res) {
      if (res.data) {
        anfrage.dbId = res.data.id;
        taSaveAnfragen(taGetAnfragen().map(function(a) { return a.id === anfrage.id ? anfrage : a; }));
      }
      if (res.error) console.error('Booking insert:', res.error);
    }).catch(function(e) { console.error('Booking insert:', e); });
  }

  // Sheet schließen + Bestätigung
  closeTerminAnfrage();
  showToast('📅 Anfrage an '+p.name+' gesendet!');

  // Meine Anfragen aktualisieren falls sichtbar
  renderEkMeineAnfragen();
}

// Anfrage stornieren
function taCancelAnfrage(id){
  const anfragen = taGetAnfragen();
  const idx = anfragen.findIndex(a=>a.id===id);
  if(idx<0) return;
  anfragen[idx].status = 'cancelled';
  anfragen[idx].updatedAt = new Date().toISOString();
  taSaveAnfragen(anfragen);
  renderEkMeineAnfragen();
  showToast('Anfrage storniert');
}

// "Meine Anfragen" im meinScreen rendern
function renderEkMeineAnfragen(){
  const container = document.getElementById('ekMeineAnfragen');
  if(!container) return;

  const anfragen = taGetAnfragen();
  const aktiv = anfragen.filter(a=>a.status!=='cancelled');

  if(aktiv.length===0){
    container.innerHTML = '';
    return;
  }

  // Bridge: prüfe ob Partner-Seite Terminvorschläge geschrieben hat
  aktiv.forEach(a=>{
    if(a.status==='confirmed' && a.terminVorschlag){
      const terminDT = new Date(a.terminVorschlag.date+'T'+a.terminVorschlag.time);
      const now = new Date();
      // Termin liegt in der Vergangenheit → als "done" markieren
      if(terminDT < now && (now - terminDT) > 2*60*60*1000){
        a.status = 'done';
        a.updatedAt = new Date().toISOString();
        taSaveAnfragen(anfragen);
      }
    }
  });

  const statusLabels = {
    pending:'⏳ Warte auf Antwort',
    termin_vorgeschlagen:'📅 Terminvorschlag!',
    confirmed:'✅ Bestätigt & Bezahlt',
    declined:'❌ Abgelehnt',
    cancelled:'🚫 Storniert',
    storniert:'↩️ Storniert',
    noshow:'⛔ Nicht erschienen'
  };

  const statusColors = {
    pending:'#f59e0b',
    termin_vorgeschlagen:'#3b82f6',
    confirmed:'#22c55e',
    storniert:'#f59e0b',
    noshow:'#dc2626'
  };

  let html = '<div style="font-size:13px;font-weight:700;color:var(--text-dark);margin-bottom:8px;padding:0 16px">Meine Anfragen & Termine</div>';
  html += '<div style="padding:0 16px">';

  aktiv.slice(0,10).forEach(a => {
    const modeIcons = {praxis:'🏥',video:'📹',phone:'📞'};
    const svcName = a.service ? a.service.name : (a.serviceName||'');
    const svcPrice = a.service ? a.service.price : (a.servicePrice||0);
    const color = statusColors[a.status]||'#9ca3af';

    html += `<div class="ta-anfrage-card status-${a.status}" style="border-left:3px solid ${color}" onclick="taShowAnfrageDetail('${a.id}')">
      <div class="ta-anfrage-avatar">${a.practitionerAvatar}</div>
      <div class="ta-anfrage-info">
        <div class="ta-anfrage-name">${a.practitionerName}</div>
        <div class="ta-anfrage-service">${modeIcons[a.mode]||''} ${svcName} · ${svcPrice} €</div>`;

    // Terminvorschlag anzeigen
    if(a.status==='termin_vorgeschlagen' && a.terminVorschlag){
      const tv = a.terminVorschlag;
      const artLabels = {praxis:'Vor Ort',video:'Video',phone:'Telefon',home:'Hausbesuch'};
      html += `<div style="background:#dbeafe;border-radius:7px;padding:8px 10px;margin-top:6px">
        <div style="font-size:11px;font-weight:700;color:#1e40af;margin-bottom:4px">Terminvorschlag vom Anbieter:</div>
        <div style="font-size:12px;font-weight:600">${tv.date ? new Date(tv.date+'T00:00:00').toLocaleDateString('de-DE',{weekday:'long',day:'numeric',month:'long'}) : ''} um ${tv.time} Uhr</div>
        <div style="font-size:11px;color:#3b82f6">${tv.dauer} Min · ${artLabels[tv.art]||tv.art} · €${tv.preis||svcPrice}</div>
        <div style="display:flex;gap:6px;margin-top:8px">
          <button onclick="event.stopPropagation();taAcceptTermin('${a.id}')" style="flex:1;padding:8px;background:#22c55e;color:white;border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer">✅ Akzeptieren & Bezahlen</button>
          <button onclick="event.stopPropagation();taDeclineTermin('${a.id}')" style="padding:8px 12px;background:#fee2e2;color:#dc2626;border:none;border-radius:7px;font-size:12px;cursor:pointer">✕</button>
        </div>
      </div>`;
    } else if(a.status==='confirmed' && a.terminVorschlag){
      const tv = a.terminVorschlag;
      const terminDT = new Date(tv.date+'T'+tv.time);
      const hoursUntil = (terminDT - new Date()) / (1000*60*60);
      const canCancel = hoursUntil > 0;
      const isFree = hoursUntil > 24;
      html += `<div style="background:#dcfce7;border-radius:7px;padding:8px 10px;margin-top:6px">
        <div style="font-size:12px;font-weight:600;color:#166534">📅 ${tv.date ? new Date(tv.date+'T00:00:00').toLocaleDateString('de-DE',{weekday:'long',day:'numeric',month:'long'}) : ''} · ${tv.time} Uhr</div>
        <div style="font-size:11px;color:#15803d;margin-top:2px">💳 Bezahlt · €${a.zahlung?a.zahlung.amount:svcPrice}</div>
        ${canCancel ? `<div style="display:flex;align-items:center;gap:6px;margin-top:6px">
          <button onclick="event.stopPropagation();taCancelTermin('${a.id}')" style="padding:6px 12px;background:${isFree?'#fef3c7':'#fee2e2'};color:${isFree?'#92400e':'#dc2626'};border:none;border-radius:7px;font-size:11px;cursor:pointer">${isFree?'Kostenlos stornieren':'Stornieren (50% Gebühr)'}</button>
        </div>` : ''}
      </div>`;
    } else if(a.status==='storniert' && a.storno){
      const s = a.storno;
      html += `<div style="background:#fef3c7;border-radius:7px;padding:8px 10px;margin-top:6px">
        <div style="font-size:11px;font-weight:600;color:#92400e">↩️ Storniert am ${new Date(s.stornoAt).toLocaleDateString('de-DE')}</div>
        ${s.type==='kostenlos' ? '<div style="font-size:11px;color:#166534;margin-top:2px">✅ Volle Rückerstattung: €'+s.refund+'</div>' : '<div style="font-size:11px;color:#dc2626;margin-top:2px">Stornogebühr: €'+s.fee+' · Rückerstattung: €'+s.refund+'</div>'}
      </div>`;
    } else if(a.status==='noshow'){
      html += `<div style="background:#fee2e2;border-radius:7px;padding:8px 10px;margin-top:6px">
        <div style="font-size:11px;font-weight:600;color:#dc2626">⛔ Nicht erschienen</div>
        <div style="font-size:11px;color:#991b1b;margin-top:2px">Der volle Betrag von €${a.zahlung?a.zahlung.amount:svcPrice} wird einbehalten.</div>
      </div>`;
    }

    html += `</div>
      <div class="ta-status-badge ${a.status}" style="color:${color};font-size:10px">${statusLabels[a.status]||a.status}</div>
    </div>`;
  });

  html += '</div>';
  container.innerHTML = html;
}

// Terminvorschlag akzeptieren → Bestätigung + Zahlung (gleichzeitig)
async function taAcceptTermin(id){
  const anfragen = taGetAnfragen();
  const a = anfragen.find(x=>x.id===id);
  if(!a || !a.terminVorschlag) return;

  const tv = a.terminVorschlag;
  const price = tv.preis || (a.service ? a.service.price : 0);
  const svcName = a.service ? a.service.name : '';
  const dateStr = tv.date ? new Date(tv.date+'T00:00:00').toLocaleDateString('de-DE',{weekday:'long',day:'numeric',month:'long'}) : '';

  // Zahlungs-Bestätigung mit Stornierungsbedingungen
  if(!confirm(`Termin bestätigen & bezahlen?\n\n${svcName}\n${dateStr} um ${tv.time} Uhr\n${tv.dauer} Min\n\nBetrag: ${price > 0 ? '€' + price : 'Kostenlos'}\n\nStornierungsbedingungen:\n- Kostenlose Stornierung bis 24h vorher\n- Unter 24h: 50% Stornogebühr\n- Nicht erschienen: 100% werden berechnet\n\nMit OK wird die Zahlung ausgeführt.`)) return;

  try {
    // Payment verarbeiten wenn Preis > 0
    if (price > 0) {
      showToast('Zahlung wird verarbeitet...');
      await processPayment(price, a.dbId || id, svcName + ' - Termin ' + dateStr, 'termin');
    }

    // Bestätigung + Zahlung
    a.status = 'confirmed';
    a.paidAt = new Date().toISOString();
    a.zahlung = {amount: price, method: _selectedPaymentType || 'stripe', paidAt: a.paidAt, status: price > 0 ? 'paid' : 'free'};
    a.updatedAt = new Date().toISOString();
    taSaveAnfragen(anfragen);

    // Supabase: Bestätigung + Zahlung
    if (supabase && currentUser && a.dbId) {
      supabase.from('bookings').update({
        status: 'confirmed',
        zahlung: a.zahlung,
        booking_date: tv.date || (tv.optionen && tv.optionen[0] ? tv.optionen[0].date : null)
      }).eq('id', a.dbId).then(function(res) {
        if (res.error) console.error('Booking confirm:', res.error);
      });
    }

    renderEkMeineAnfragen();
    showToast('Bezahlt & bestätigt! Termin ist verbindlich.');

  } catch (paymentError) {
    console.error('Termin payment error:', paymentError);
    showToast('Zahlung fehlgeschlagen: ' + (paymentError.message || 'Unbekannter Fehler'), 'error');
  }
}

// Terminvorschlag ablehnen
function taDeclineTermin(id){
  const anfragen = taGetAnfragen();
  const a = anfragen.find(x=>x.id===id);
  if(!a) return;

  a.status = 'declined';
  a.terminVorschlag = null;
  a.updatedAt = new Date().toISOString();
  taSaveAnfragen(anfragen);

  // Supabase: Ablehnung
  if (supabase && currentUser && a.dbId) {
    supabase.from('bookings').update({ status: 'declined' }).eq('id', a.dbId)
      .then(function(res) { if (res.error) console.error('Booking decline:', res.error); });
  }

  renderEkMeineAnfragen();
  showToast('Terminvorschlag abgelehnt');
}

// Termin stornieren (bestätigte Termine)
function taCancelTermin(id){
  const anfragen = taGetAnfragen();
  const a = anfragen.find(x=>x.id===id);
  if(!a || !a.terminVorschlag) return;

  const tv = a.terminVorschlag;
  const price = a.zahlung ? a.zahlung.amount : (a.service ? a.service.price : 0);
  const terminDateTime = new Date(tv.date+'T'+tv.time);
  const now = new Date();
  const hoursUntil = (terminDateTime - now) / (1000*60*60);

  let stornoText = '';
  let stornoFee = 0;
  let refund = price;

  if(hoursUntil > 24){
    stornoText = '✅ Kostenlose Stornierung (mehr als 24h vorher)\n\nDu erhältst eine volle Rückerstattung von €'+price+'.';
    stornoFee = 0;
    refund = price;
  } else if(hoursUntil > 0){
    stornoFee = Math.round(price * 0.5);
    refund = price - stornoFee;
    stornoText = '⚠️ Späte Stornierung (unter 24h vorher)\n\nStornogebühr: €'+stornoFee+' (50%)\nRückerstattung: €'+refund;
  } else {
    stornoText = '❌ Der Termin liegt in der Vergangenheit und kann nicht mehr storniert werden.';
    return showToast('Termin kann nicht mehr storniert werden');
  }

  const dateStr = tv.date ? new Date(tv.date+'T00:00:00').toLocaleDateString('de-DE',{weekday:'long',day:'numeric',month:'long'}) : '';
  if(!confirm(`Termin stornieren?\n\n📅 ${dateStr} um ${tv.time} Uhr\n${a.service?a.service.name:''}\n\n${stornoText}\n\nMöchtest du wirklich stornieren?`)) return;

  a.status = 'storniert';
  a.storno = {
    stornoAt: new Date().toISOString(),
    hoursBeforeTermin: Math.max(0, Math.round(hoursUntil)),
    fee: stornoFee,
    refund: refund,
    type: hoursUntil > 24 ? 'kostenlos' : 'spaet'
  };
  a.updatedAt = new Date().toISOString();
  taSaveAnfragen(anfragen);

  // Supabase: Stornierung
  if (supabase && currentUser && a.dbId) {
    supabase.from('bookings').update({
      status: 'cancelled',
      storno: a.storno
    }).eq('id', a.dbId).then(function(res) {
      if (res.error) console.error('Booking cancel:', res.error);
    });
  }

  renderEkMeineAnfragen();
  if(stornoFee > 0){
    showToast('Termin storniert. Stornogebühr: €'+stornoFee);
  } else {
    showToast('Termin kostenlos storniert. Volle Rückerstattung.');
  }
}

// Anfrage-Detail anzeigen
function taShowAnfrageDetail(id){
  const anfragen = taGetAnfragen();
  const a = anfragen.find(x=>x.id===id);
  if(!a) return;

  if(a.status==='pending'){
    const modeLabels = {praxis:'Vor Ort',video:'Video',phone:'Telefon'};
    if(confirm('Anfrage bei '+a.practitionerName+'\n\n'+(a.service?a.service.name:'')+ ' ('+(a.service?a.service.price:0)+' €)\n'+modeLabels[a.mode]+'\n\nVerfügbarkeit: '+a.verfuegbarkeit+'\n\nMöchtest du diese Anfrage stornieren?')){
      taCancelAnfrage(id);
    }
  } else if(a.status==='termin_vorgeschlagen'){
    // Klick auf Karte zeigt die Buttons schon inline
  } else if(a.status==='confirmed'){
    // Stornieren anbieten
    taCancelTermin(id);
  } else if(a.status==='storniert' && a.storno){
    const s = a.storno;
    showToast(s.type==='kostenlos' ? '✅ Kostenlos storniert' : '⚠️ Storniert · Gebühr: €'+s.fee);
  }
}

